DROP TABLE IF EXISTS `t_book_chapter`;
CREATE TABLE `t_book_chapter`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `book_id` bigint NOT NULL COMMENT '所属书ID',
  `chapter_idx` int NOT NULL COMMENT '章节序号(0=前言)',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '章节标题',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '章节内容',
  `word_count` int NULL DEFAULT 0 COMMENT '字数',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_book_chapter`(`book_id` ASC, `chapter_idx` ASC) USING BTREE,
  CONSTRAINT `t_book_chapter_ibfk_1` FOREIGN KEY (`book_id`) REFERENCES `t_book` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 78 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '书本章节表' ROW_FORMAT = Dynamic;

