INSERT INTO `t_book_chapter` VALUES (2, 13, 0, '前言/引子', '书名：全民穿越！我在末日世界养城兽\n作者：三水华光\nbook_id=7525419385083661337\n状态：连载\n评分：6.1\n字数：159173\n章节：75\n分类：科幻末世\n标签：穿越|末世|宠物|多女主\n在读：18.4万人在读\n简介：\n【末日+多女主+城兽】\n林风发现自己穿越了，幸存者组成一个个逃亡队伍向着未知方向逃亡。\n好消息是，自己是一个觉醒者，在队伍里处于核心地位，身边美女不断。\n坏消息是，自己觉醒的是一个垃圾御兽能力，本命契约是一只毫无战斗能力的小乌龟。\n现在自己被踢出了核心圈子，平日里攀附在自己身边的女人也相继离开。\n更糟糕的是断水断粮了，眼看就要活不下去了。\n恭喜你觉醒觉醒天赋……\n林风……？\n双天赋？\n事情似乎变得有趣起来', 307, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (3, 13, 1, '第 1章 全民穿越', '　　腰子强化中心...\n\n　　脑子寄存处……\n\n　　一辆大巴车有节奏地轻微晃动着！\n\n　　“砰砰砰！砰砰砰！”\n\n　　车门被砸得震天响，伴随而来的是一个粗犷的声音传来。\n\n　　“开门，快开门！”\n\n　　“林风，队长喊你开会，赶紧的。”\n\n　　林风的动作一顿，身下传来一声娇嗔。\n\n　　“别管他！”女人柔软的手臂缠上林风的脖子，声音甜的发腻。\n\n　　“让他们再等一会嘛。”\n\n　　另外一个女人从背后贴了上来，温热的身体像一条美女蛇。\n\n　　“就是……正在兴头上呢……”\n\n　　林风深吸一口气，止住接下来的动作，有些无奈地叹了一口气。\n\n　　说实话，这种日子，林风以前想都不敢想。\n\n　　一周前，林风还是一个在人才市场挤破头找不到工作的应届毕业生，兜里掏不出五百块钱，租住在城中村一个不到十平方的隔断间里，连请喜欢的女孩吃顿像样的饭都要犹豫半天。\n\n　　一周后，蓝星全人类忽然就穿越到这个末日世界，现在的他不仅不需要工作，还被整个车队上千人供养着，住的是改装后的大巴车，吃的是车队里保存最好的罐头和食物，身边躺着的女人不止两个，而且个个都算是美人。\n\n　　命运这东西，有时候真的说不清啊。\n\n　　“小乖乖，等我回来。”\n\n　　林风在身下女人的额头上亲了一口，又转身亲了身后那个，这才笑嘻嘻地说。\n\n　　“估计是队长找我有急事，等我处理完了，咱们继续，哈哈哈……”\n\n　　两女依依不舍的松开手，林风这才从温柔乡中挣脱出来，手忙脚乱的的找衣服。\n\n　　T恤才套上，裤子拉链都没拉上，外面又传来了敲门声。\n\n　　“林风，你他妈到底来不来？”\n\n　　“来了来了！”林风立马应了一声，最后在女人的挺翘上捏了一把，引起一阵娇嗔声，这才跳下了车。\n\n　　车门打开的瞬间，昏黄的光线涌了进来，林风眯了眯眼睛，手里还提着一只巴掌大的小乌龟，跟着那个来叫他的壮汉往车队中央走去。\n\n　　壮汉走得很快，林风几乎要小跑才能跟上，一边走还一边整理衣服，又用手理了理头发。\n\n　　一路上，车队里的人都在看着他们。\n\n　　有羡慕的眼神，有讨好的笑脸，也有不加掩饰的嫉妒以及鄙夷，林风对于这些目光一律视而不见，脸上挂着那副懒洋洋的笑容。\n\n　　车队很大，一千多号人，车辆排着长龙，最外围是各种皮卡，货车改装的车辆，上面焊着铁架等防护物品，上面还沾染了黑色的血迹，车顶上站着手持钢刀长矛等武器的守卫。\n\n　　车队中间停靠着各种汽车，甚至是自行车，车队此时正在停留休整。\n\n　　林风被带到一辆改装过的豪华房车面前，这是队长王烈和这个车队里觉醒者开会的地方。\n\n　　壮汉敲了敲车门，里面传来一个沉稳的声音：“进来！”\n\n　　车门打开，林风跟着一起走了进去。\n\n　　房车内部空间很大，被改造成了一个移动会议室，一圈沙发围着一个固定的桌子，桌子上还铺着一张绘制的简易地图。\n\n　　此时已经有7个人坐在里面了，加上林风和那个壮汉，正好是车队里全部的九名觉醒者。\n\n　　林风的目光快速扫过这些人。\n\n　　坐在最里面的是一个四十岁左右的男人，国字脸，浓眉大眼，目光沉稳锐利，他是这支队伍的队长，王烈。\n\n　　他是一名雷电系异能觉醒者，攻击力在所有人中最强。整个车队这一千多人能在混乱中维持秩序，还能在一次次怪物袭击中存活下来，王烈的雷电异能功不可没。\n\n　　右手边坐着两个男人，林风跟他们不太熟，一个叫郭逸，觉醒的机械系异能，整个车队还能维持运转，多亏了他能维修和改装车辆，另外一个叫江声，觉醒的是植物催生，在关键时刻能派上大用场。\n\n　　他左手边坐着一个二十多岁的年轻女人，短发，叫方玲，觉醒的是速度强化，敏捷高得吓人，负责侦查和突袭。\n\n　　方玲旁边坐着三个女人，年纪最大的那个三十五六岁，风韵犹存，尤其是那一对车灯惹人眼球，叫陈敏，据说觉醒的是精神感知，是队伍里的预警系统。\n\n　　她旁边的一个二十五六岁的女人，长发，面容姣好，一双大长腿堪称腿玩年的典范，配上S的身材和纤细的腰肢，林风每次看到她都暗暗咽口水，这个女人叫沈雨桐。她觉醒的能力很特别，似乎能预知危险，还能测绘附近的地图，对方话不多，但每次开口都是重要信息，也是车队能安稳走到现在的主要原因。\n\n　　最后一个女人，林风的目光在她身上停了一下。\n\n　　董雨，二十一岁，觉醒的是……嗯，怎么说呢，她说的是身体强化，具体表现是皮肤变得坚韧，可也防御不了刀砍，也就力气比普通人大几倍，但是跟来喊自己的那个壮汉，刘铁柱的力量强化比起来，简直就是天壤之别。\n\n　　她长得还算好看，微胖身材，但是……怎么说呢，在几人当中的存在感最低，而且每次看林风的眼神都像要吃人一样。\n\n　　林风理解她为什么这么恨自己。\n\n　　同样是觉醒者，同样的能力偏弱，最重要的是，两人的爱好十分统一，都喜欢美女，而现实就是他林风住着豪华大巴车里，美女环绕，吃的是最好的食物，喝干净的水。\n\n　　而她董雨虽然也是核心队伍的一员，但没有人巴结她，没有人讨好她，车队的美女赶着往林风身边凑。\n\n　　凭什么？\n\n　　就凭他林风长得好看？\n\n　　不过，这也是事实，林风从不否认，在学校的时候，就是公认的校草，一米八五的个子，剑眉星目，鼻梁高挺，笑起来带着一个懒洋洋的痞气，能把小姑娘迷得神魂颠倒，论颜值也就比在座的各位读者姥爷略逊一筹。\n\n　　但没关系。\n\n　　因为林风同样是觉醒者，颜值高，会哄女人开心，反而比董雨这种人更受欢迎。\n\n　　这就是现实。\n\n　　“哟，来了？”陈敏靠在沙发上，翘着二郎腿，黑丝包裹的美腿一览无余，十分吸引眼球，看着林风衣衫不整的样子，调侃道。\n\n　　“又忙着呢？林大帅哥精力真是旺盛，要不要姐姐给你去去火。”\n\n　　林风笑了笑，没有接话，找了个空位坐下来，他主要是有色心没色胆，曾经车队里有一个老总仗着身份调戏对方，结果嘛，一个眼神过去，那个老总连同身边的保镖一起木愣愣的直接冲进怪物群里，被撕扯得尸骨无存，那惨叫声现在还记忆犹新。\n\n　　所以千万别招惹女人，尤其是一个漂亮还心狠手辣的女人，这哪是精神感知，明明就是精神控制，从那以后林风在这女人面前彻底老实了，万一哪天一觉醒来人没了都不知道。\n\n　　“人都到齐了。”王烈开口了，声音不大，但很沉稳，让人不容忽视。\n\n　　“今天叫大家来，是有几件事要商量！”', 2435, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (4, 13, 2, '第2章 完了！被踢出核心队伍了', '　　林风坐在沙发上，手指无意识地在乌龟壳上摩挲着，小乌龟缩着脑袋和四肢，整个缩在壳里，任由林风把玩。\n\n　　王烈开始说着车队目前的状况。\n\n　　物资储备还剩多少，车辆的耗损情况，人员伤亡数据，以及灰雾的移动轨迹，还有灰雾的追赶速度。\n\n　　林风听着听着就开始走神，眼睛不由自主地开始偷瞄。\n\n　　这些东西跟他关系不大，物资分配有人管，车辆维修有人管，灰雾的移动方向和地图有沈雨桐提供情报，危险预警有陈敏，他林风要做的就是在会议上无条件点头，然后继续过自己的舒服日子。\n\n　　“最重要的是。”王烈的语气突然变得沉重了一些。\n\n　　“灰雾正在加速移动，按目前的速度，最多还有5天，我们就会被追上。”\n\n　　会议的气氛一下子紧张起来，林风也收敛起懒散的神色。\n\n　　灰雾。\n\n　　那是这个世界最恐怖的东西。\n\n　　灰色的雾气，不知道从哪来，也不知道为什么会出现，灰雾笼罩的区域，普通生灵触之即死，不是慢慢死去，而是在接触灰雾的瞬间，血肉消融，连惨叫都来不及发出。\n\n　　灰雾里面还有更恐怖的东西。\n\n　　没有人说得清那是什么，因为见过的人已经死了，只有觉醒者能依靠异能勉强待上几分钟，但身处其中就能感知到那些雾气中那些扭曲的，疯狂的存在。\n\n　　灰雾仿佛是活着的，它们是饥饿的，它们在移动，在追着幸存者跑。\n\n　　人类唯一能做的，就是逃。\n\n　　不停的逃，在灰雾追上之前拼命地逃。\n\n　　“前方三百公里，那里有一片高地。”王烈指着桌子上的简易地图说道。\n\n　　“根据雨桐妹子的测绘，那里有一片城市废墟，最重要的是，有一座加油站，视野开阔，如果能尽快赶到那里，我们的车队不仅能获得汽油，还能喘口气。”\n\n　　“三百公里？”陈敏皱起秀眉，“车队现在的状态，一天能走五十公里就不错了，赶到那里最少要六天，万一路上出点状况……”\n\n　　“所以我们需要加快速度。”王烈说。\n\n　　接下来就是各种讨论，路线规划，车辆调配，人员安排，最少要所有人都能搭上车，而不是用两条腿赶路。\n\n　　林风听着听着又开始走神。\n\n　　这些事跟他有什么关系，他又不开车，又不会修车，又不带路。\n\n　　自己只需要坐在大巴车里就行了。\n\n　　会议进行到后面，王烈话锋一转。\n\n　　“另外，还有一件事。”\n\n　　他的目光扫过所有人，最后停留在林风身上。\n\n　　忽然。\n\n　　林风心里突然涌起一股不好的预感。\n\n　　“关于我们核心成员的资源配置问题。”王烈的语气很平静，就像在说一件很普通的事情。\n\n　　“我决定，从今天开始，重新调整觉醒者的待遇标准。”\n\n　　林风坐直了身体。\n\n　　“标准很简单，以战斗贡献为核心。”\n\n　　这话一出，林风的心猛地沉了下去。\n\n　　“什么意思？”刘铁柱问，但嘴角已经挂上了笑。\n\n　　“意思就是，”王烈看向林风，目光十分平静，平静到近乎冷漠。\n\n　　“能力不足以参加战斗的觉醒者，又没有辅助能力的，将不再享有核心成员的待遇。”\n\n　　沉默。\n\n　　房车里的空气仿佛凝固了。\n\n　　林风张了张嘴，想说点什么，但那喉咙里似乎被什么东西堵住了。\n\n　　“队……队长，你这是要把我……”\n\n　　“不是针对你，”王烈打断了林风，“是针对所有能力不足的觉醒者。”\n\n　　林风的目光下意识看向其他人。\n\n　　方林低着头，不说话。\n\n　　郭逸和江声这两个男人互相看了一眼，然后移开了视线。\n\n　　陈敏面无表情地看向窗外。\n\n　　沈雨桐的嘴角微微动了一下，但什么都没说。\n\n　　董雨？她在笑。\n\n　　那种压抑了很久，终于等到了今天，幸灾乐祸的笑。\n\n　　“为什么？”林风问道。\n\n　　“为什么？”说话的不是王烈，而是那个来敲车门的刘铁柱，他靠在沙发上，双手抱胸，笑容里带着不加掩饰的恶意。\n\n　　“林风，你还好意思问为什么，你说为什么？”\n\n　　“你干啥啥不行，吃啥啥不剩，”刘铁柱一字一顿地说。\n\n　　“御兽天赋，契约了乌龟，那乌龟有什么用，能打架吗？能搬东西吗？能探路吗？什么都不能！你凭什么享受核心成员的待遇？”\n\n　　林风的脸烧了起来。\n\n　　林风也知道刘铁柱说得对，但被这么直白地说出来，还是让人难以接受，但他有什么办法，穿越当初就觉醒了这个天赋，翻遍整个营地就找到了这么一只活物。\n\n　　不契约这乌龟，还能契约啥？\n\n　　拉觉醒者入伙，庇护普通幸存者，制定规则，也不是他林风提的，自己全程除了登记觉醒者天赋，跟点头同意外，好像啥也没干吧。\n\n　　“我，我目前确实没有战斗能力，但我也是觉醒者……”\n\n　　“觉醒者怎么了？”刘铁柱冷笑，他同样嫉妒林风的颜值建模，凭什么好处都他一个人占了，他刘铁柱也是男人。\n\n　　“觉醒者就该吃白食，你看人家郭逸，同样是觉醒者，维修、改装车辆，再看看江声，能催生植物，种土豆那叫一个6，再看看你，你他妈除了睡女人，还会干什么？”\n\n　　林风的嘴唇动了一下。\n\n　　他想说，我也不是完全没用，我可以干体力活，搬物资这些，从来没有抱怨过……\n\n　　林风想了半天，实在想不出自己除了觉醒者这个身份之外，和普通人有什么区别，自己能做的普通人也能做，只是觉醒后，力气大了一点，有了能力后，能硬扛灰雾几分钟罢了。\n\n　　“够了。”王烈抬手制止了刘铁柱的嘲讽，他看向林风的目光里没有恶意，但也没有同情。\n\n　　“林风，我念在大家都是觉醒者，之前对你是睁一只眼闭一只眼，但现在物资越来越紧张，灰雾越追越近，每一份食物，每一份物资都要用在刀刃上，我没有办法继续养着……”他顿了一下，“养着没有战斗力的人。”\n\n　　林风感觉自己的心脏被攥住一般，我这是被抛弃了，当初说好的一视同仁，平均分配呢？\n\n　　“从今天起，”王烈宣布。\n\n　　“收回分配给林风的大巴车，以及所有物资配额，从此刻起，你不再是核心成员。”\n\n　　“但是……”', 2224, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (5, 13, 3, '第3章 白蹭的，不亏', '　　王烈话锋一转，“念在同为觉醒者一场，你不需要像普通人那样，每次外出收获上缴一半，你自己找到的，都是你自己的。”\n\n　　林风傻眼了。\n\n　　“队……队长……”\n\n　　“就这样。”王烈摆摆手，不再看林风，“会议结束，都散了吧。”\n\n　　其他人都站起来，陆续走出房车。\n\n　　经过林风身边的时候，有人面无表情，有人假装没有看见，有人——比如董雨，故意放慢脚步，用一种近乎怜悯的目光看着林风。\n\n　　“林大帅哥，”董雨轻声说着，声音里带着说不出的快意，“以后要自己去挖野菜了，注意怪物哦。”\n\n　　她走了……\n\n　　车厢里只剩下林风一个人，手里捏着小乌龟，久久没有动。\n\n　　林风穿过车队回大巴车的时候，已经有一些人知道消息了，消息传得比风还快，这就是车队的特色，八卦永远是传播速度最快的信息。\n\n　　一路上，无数双眼睛盯着林风看。\n\n　　有人幸灾乐祸，有冷漠的，最让林风难受的是，那些曾经讨好他，巴结他的人，现在看他的眼神就像看一堆垃圾。\n\n　　林风回到大巴车前，发现车门口已经站了两个巡逻队队员。\n\n　　“林风，”其中一个面无表情地说。\n\n　　“队长命令我们接收这辆车，你的私人物品我们已经搬出来了。”\n\n　　林风看着车旁边堆着的东西，几件换洗的衣服，一条毛毯，一个双肩包，除了这就别无他物了。\n\n　　这就是林风现在全部的家当。\n\n　　“我能上去拿点东西吗？”林风问道\n\n　　“巡逻队员对视了一眼，摇了摇头。”\n\n　　“抱歉，这是命令。”\n\n　　林风深吸一口气，弯腰把地上的东西塞进背包里。\n\n　　就在这时，大巴车的门打开了。\n\n　　两个女人从车上走下来。\n\n　　她们已经穿好了衣服，头发也重新梳理过，看起来端庄而体面，看到林风的时候，脸上闪过一丝尴尬，但很快就消失了。\n\n　　“林风，”其中一个女人，刚才还在他身下娇喘，此时却用平淡的语气说道：“那个……我们以后就不跟你了。”\n\n　　林风看着她，没有说话。\n\n　　“你也别怪我们。”另一个女人接话，声音十分冷淡，好似曾经那个娇媚的人不是她一般。\n\n　　“你现在不是车队的核心成员了，跟着你没前途，我们总要活下去，对吧？”\n\n　　说完，两人转身就走。\n\n　　她们走的方向，是核心队伍的区域，林风看着她们走到了董雨身边。\n\n　　董雨正靠在一辆大巴车旁边，手里拿着一个苹果在啃，看到两个女人走过来，她抬起头，嘴角慢慢地翘起来。\n\n　　她看着林风，眼神写满了“你的现在是我的了”。\n\n　　两个女人围着董雨，嘘寒问暖，给她捏肩捶背，那股殷勤劲，比之前伺候林风的时候还要卖力。\n\n　　林风移开目光，心里暗骂，死白鹤，你有那功能嘛，小爷的女人都抢。\n\n　　林风又看向另外一边。\n\n　　不远处一个30岁左右的男人拉着一个女人快步离开，那女人回头看林风，眼神复杂，但脚步没有停。\n\n　　那个女人，是她男人主动送上林风车上的，为了从林风这里多获得一点物资。\n\n　　现在林风倒了，他当然要把自己老婆要回去。\n\n　　林风笑了笑。\n\n　　也罢。\n\n　　反正也白蹭了车队一个星期的资源，足够了，这几天的日子是以前想都不敢想的。\n\n　　林风没有怨恨谁，只是心里说不难过是假的。\n\n　　谁让自己的实力不济呢。\n\n　　“就剩下你跟我了。”\n\n　　林风看向抱在怀里的小乌龟。\n\n　　就在这时候，车队里的大喇叭响了。\n\n　　“所有人员注意，所有人员注意，车队停留时间还剩最后6小时，灰雾正在加速靠近，所有有能力外出寻找物资的人员，抓紧时间，重复……”\n\n　　林风的肚子突然叫了一声。\n\n　　这才想起来，自己一上午都在车里，还没来得及吃东西，刚才跟那两个女人打了两场，体力消耗巨大，现在胃里空空的。\n\n　　虽然林风觉醒了，体质比普通人强出数筹，但消耗也大，此时饿得发慌。\n\n　　“不行，得立马去找点吃的。”\n\n　　林风把包背上，在车队里找了根被人遗弃的木棍，跟着外出寻找物资的人群，朝着车队外面走去。\n\n　　车队停在一片荒地上。\n\n　　灰色的土地，稀疏的树木，远处天空灰蒙蒙的，分不清是阴天还是灰雾。\n\n　　放眼望去，物资？这里能找到什么物资。\n\n　　能吃的野菜早就被前面的大队伍挖光了，能喝的早就被收集了，能用的东西早就被捡走了。\n\n　　唯一还有生机的，是远处的一座小山丘，山丘上长着一些绿色的植物，那里应该还有。\n\n　　林风跟着人群往山丘的方向走。\n\n　　怀里抱着小乌龟，手提木棍，不急不缓的跟上。\n\n　　“哟，这不是觉醒者大人吗？”\n\n　　身后传来一个阴阳怪气的声音。\n\n　　林风回头，看到几个人正看着自己笑。\n\n　　为首的是个光头大汉，满脸横肉，穿着一件破夹克，林风认识他，这个人叫赵虎，是车队里负责物资搬运队的一个小头目。\n\n　　以前赵虎见到林风，点头哈腰，一口一个“林哥”叫得亲热。\n\n　　现在？\n\n　　“怎么跟我们一起出来挖野菜了？”赵虎笑呵呵的走过来，上下打量林风，那眼神就像在看什么有趣的东西。\n\n　　“哦……我听说你被队长开除了？”\n\n　　“听谁说的？”林风问。\n\n　　“听谁说的不重要，”赵虎嘿嘿一笑，“重要的是真的假的，你是不是被踢出核心队伍了？”\n\n　　他身后的几个人也跟着笑。\n\n　　林风没有回话，转身继续走。\n\n　　赵虎跟上来，凑到林风身边，压低声音说：“林风，说实话，我早就看你不顺眼了，不就长了张小白脸吗？凭什么你吃香的喝辣的，现在好了，原形毕露了吧？”\n\n　　林风的脚步不停。\n\n　　“不过你也别太难过，实在不行，来我这干搬运工，一天一顿野菜团子，管饱，怎么样，赏你口饭吃。”\n\n　　他身后的人笑得更响了。\n\n　　林风顿住脚步，转头看着赵虎。脸上没有什么表情。\n\n　　“老赵啊，你脸上有东西。”\n\n　　赵虎一愣：“什么？”\n\n　　“垃圾，你脸上有垃圾。”\n\n　　赵虎下意识地伸手去擦。\n\n　　林风转身就走。\n\n　　赵虎擦了半天，什么都没有擦掉，这才反应林风是在骂他，他脸色一沉，正要发作，但林风已经走远了。\n\n　　山丘看起来不远，走起来却不近，林风在荒地上走着，肚子饿得咕咕叫。\n\n　　路上遇到的人越来越多，都是外出寻找生存物资的。\n\n　　大部分人看到林风，都会多看两眼，然后小声议论。\n\n　　“这就是那个觉醒者？”', 2362, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (6, 13, 4, '第4章 这是？新天赋！', '　　“这就是那个觉醒者？”\n\n　　“听说被开除了。”\n\n　　“活该，一个没用的废物，凭什么住大巴车？”\n\n　　林风听在耳朵里，心里谈不上愤怒，更多的反而是一股荒谬感。\n\n　　几天前，他还是这些人仰望的对象，几天后，他就成了这些人嘲笑的目标。\n\n　　真是讽刺。\n\n　　林风低头看了看手里的小乌龟。\n\n　　小乌龟还是那副半死不活的样子，缩在壳里，一动不动。\n\n　　“你倒是争气点啊。”\n\n　　小乌龟当然不会回答，林风叹了一口气，继续往前走。\n\n　　山丘下。\n\n　　此时已经聚集了不少人，林风走近了才发现，这座小山丘比他远远看到的要大得多，山坡上稀稀疏疏长着一些绿色的植物，放眼望去，山脚下全是人，男男女女，老老少少，一个个弯着腰，在地里翻找。\n\n　　林风在山脚站定，观察了一下。\n\n　　这种植物他认识。\n\n　　穿越过来已经一周了，活下来的人早就把能吃的东西试验了个遍。\n\n　　怎么实验的？\n\n　　很简单，吃下去还活着的，就是能吃的。\n\n　　听起来很残酷，但这就是末日。\n\n　　这种植物在这个世界分布很广，外形跟蓝星的菠菜长得差不多，只是叶片更厚更宽，颜色也更深，墨绿色，这种东西无毒，能吃，但是味道苦涩得要命，嚼在嘴里又苦又涩。\n\n　　但不管多难吃，总比饿死强，车队里好东西都集中在核心成员手里，江声虽然能催生植物，但催生的土豆，数量十分稀少，十分宝贵，不可能分出来给整个车队，而普通人不吃就得饿死。\n\n　　林风的目光却没有在这野菜上停留太久。\n\n　　“这东西，我才不吃。”林风十分嫌弃地移开目光。\n\n　　视线越过那些弯腰挖野菜的人，落在了山坡上一片长势特别茂盛的植物丛中。\n\n　　那里有动静。\n\n　　一只蝗虫趴在一片叶子上，大口大口地啃食着。\n\n　　这可不是普通的蝗虫，它的体型比蓝星的蝗虫大了好几倍，足足有十厘米长，通体呈现一种诡异的暗绿色，后腿粗壮有力，上面还长着一根根倒刺。\n\n　　变异蝗虫。\n\n　　这种东西以野菜为食，所以哪里有野菜，哪里就有它们的身影。\n\n　　对普通人来说，变异蝗虫是一个不小的威胁，它的冲撞力极强，十几斤的力道撞击在人身上，皮肉立马青一块紫一块，而且咬合力很强，一口就能撕下一大块肉来。\n\n　　而且这东西经常成群结队的出现，如果被一群围攻，普通人独自面对基本没有生还的可能。\n\n　　但对林风来说，不过就是一棍子的事。\n\n　　觉醒者哪怕再水，一旦觉醒，体质就是普通成年男性的两倍，力量，速度，反应都远超常人，一只落单的变异蝗虫，林风还真不放在眼里。\n\n　　更重要的是……\n\n　　变异蝗虫能吃，而且味道出奇的好，林风曾经作为车队的核心成员，分到过不少变异烤蝗虫，那金黄色的外壳，酥脆的口感，咬开口露出里面白嫩的肉质，鲜香扑鼻。\n\n　　林风想起蓝星某求生专家的名言，掐头去尾，嘎嘣脆，蛋白质是牛肉的好几倍。\n\n　　不回忆还好，一回忆，林风的肚子叫得更响了。\n\n　　林风咽了咽口水，握紧了手里的木棍。\n\n　　“这东西是我的了。”\n\n　　林风没有急着动手，而是先观察了一下周围的情况，山脚下的人都在专心挖野菜，几名手持武器的巡逻队员扫视着守卫，预防随时可能出现的危险。\n\n　　这末日世界，危险无处不在。\n\n　　林风弯下腰，借着山坡上的杂草和灌木掩护，悄悄地朝着那只变异蝗虫靠近，为了防止被发现，还动用了体内微量的灵能掩盖自身气息。\n\n　　十米。\n\n　　八米\n\n　　三米\n\n　　变异蝗虫的触角动了动，似乎察觉到什么，它停止了啃食，两条粗壮的后腿微微弓起，准备弹射起飞。\n\n　　就是现在！\n\n　　林风猛地窜出，三米的距离眨眼靠近，手中的木棍抡圆了砸下去。\n\n　　“啪！”\n\n　　一声脆响传来。\n\n　　变异蝗虫刚弹跳起来，还没来得及展开翅膀，就被一棍子精准地敲碎了脑袋。\n\n　　它抽搐了几下，便不再动弹，睡得十分安详。\n\n　　林风长出了一口气，弯腰把蝗虫捡起来，在手里掂了掂。】\n\n　　嗯，还挺沉，至少三四两重。\n\n　　个头不小，肉量可观。\n\n　　就在林风为找到食物而开心的时候，一道提示音在脑海里响起。\n\n　　【击杀变异蝗虫一只，获得进化点0.1.】\n\n　　林风的动作僵住了。\n\n　　整个人像是被雷劈中一般，愣在了原地。\n\n　　什么？\n\n　　林风集中精神，调动属于自己的个人面板，这是每个觉醒者都有的本能。\n\n　　一道光幕在脑海中展开。\n\n　　林风\n\n　　天赋：御兽\n\n　　本命御兽：玄龟（1/1）\n\n　　【属性】\n\n　　体质：10\n\n　　力量：10\n\n　　敏捷：10\n\n　　精神：10\n\n　　灵能：1\n\n　　隐藏天赋已激活：无限进化（注：击杀任何生灵皆可获得进化点，进化点可用于御兽的进化）\n\n　　【当前进化点：0.1】\n\n　　林风的心脏狂跳。\n\n　　无限进化？\n\n　　击杀生灵获得进化点？\n\n　　林风重新看向小乌龟，这只巴掌大小的小乌龟，自从契约后就一直缩头缩脑，自己还以为它这辈子就这个德行了。\n\n　　竟然能进化，而且是不限次数的无限进化。\n\n　　一股巨大的惊喜涌上心头。\n\n　　觉醒御兽能力已经整整一周了，这一周里，林风把小乌龟带上车队，除了偶尔拿出来晒晒太阳，摸摸龟壳，自己竟然什么都没有做过。\n\n　　自己竟然从来没有想过要带着小乌龟去战斗。\n\n　　为什么？因为林风觉得这只乌龟没有战斗能力，又舍不得带它去送死，毕竟是自己的龟。\n\n　　再说了，林风从穿越的第一天起，就一直顺风顺水的，当初穿越的时候，就听见“蓝星已坠入灰雾大世界，尽量远离灰雾的侵蚀……”这几句话外，什么提示都没有。\n\n　　虽说有几千人穿越在同一个地方，但除了一开始的混乱外，人群里王烈觉醒了强大的雷电异能，遇到了同为觉醒者的沈雨桐几人。\n\n　　然后以强大的能力震慑所有人，迅速组建起了队伍，然后就是登记能力，寻找觉醒者，林风自然是随大流，报上自己的觉醒能力后，和其他几位觉醒者一起成了车队的核心成员。\n\n　　加上沈雨桐的预知危险与测绘地图能力，团队很快便做出决定，召集起所有愿意跟随的人，寻找车辆和物资，一路前行。\n\n　　因为核心成员的身份，他们发现林风没有战斗能力，就没有安排他战斗。\n\n　　再加上几千人搜索物资，他们自认也不需要他外出寻找物资，也不需要他面对危险。\n\n　　有着整个团队的供养，加上队伍初组建，很多制度都未完善，这几天核心成员都是平分物资，林风直接就躺平了，除了搬运物资的时候卖卖苦力外，到现在一次战斗都没有。\n\n　　自然也就没有发现自己这个隐藏天赋。', 2454, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (7, 13, 5, '第5章 小乌龟首次进化', '　　这就导致了林风竟然一直没有发现自己的这个隐藏天赋，足足浪费了一周的时间。\n\n　　如果从第一天就开始猎杀变异怪物，现在小乌龟会进化到什么程度？\n\n　　林风的拳头慢慢握紧，懊恼无比。\n\n　　算了。\n\n　　想这些没用，重要的是，现在知道就行了。\n\n　　为时不晚。\n\n　　林风的嘴角慢慢翘起来，一个标准的龙王微笑出现，然后咧开，最后变成了一声压抑不住的笑。\n\n　　“哈哈哈……”\n\n　　直到笑弯了腰，笑得眼泪都出来了。\n\n　　远处几人听到笑声，纷纷转过头来，当他们看到是林风在山坡上像疯了一样在笑的时候，面面相觑。\n\n　　“那不是被队长开除核心队员的觉醒者吗？”\n\n　　“是啊，怎么笑成这样？”\n\n　　“不会是受什么刺激了，疯了吧？”\n\n　　“唉，也难怪，从天上掉下来，换谁谁受得了，更不要说还是一个小年轻，心灵脆弱的很……”\n\n　　“可怜人啊……”\n\n　　林风才不管他们在说什么，笑了好一会，才终于停下来，用手背擦了擦眼角的泪水，深吸一口气。\n\n　　“我就说，我的御兽天赋怎么可能那么水？原来在这里等着我。”\n\n　　林风重新打开个人面板，仔细研究起进化的使用规则。\n\n　　他很快便找到了小乌龟的进化选项。\n\n　　【本命御兽：玄龟（未命名）】\n\n　　进化所需进化点：10点。（注，本命御兽进化将反馈宿主相应的四维属性，并获得御兽的部分对应能力）\n\n　　竟然需要10点？\n\n　　一只变异蝗虫给0.1，也就是说，现在还需要击杀99只。\n\n　　林风看着手里的蝗虫，眼睛发亮。\n\n　　区区99只蝗虫而已，这东西虽然不好找，但山丘这么大，野菜这么多，变异蝗虫肯定不会少。\n\n　　林风看着山脚那些还在挖野菜的人，那些人看到变异蝗虫都躲着走，生怕被咬。\n\n　　但自己可不怕。\n\n　　林风的四维属性可是普通人的两倍，一只落单的变异蝗虫而已，对自己来说就是一个移动的进化点。\n\n　　“开工。”\n\n　　林风从背包里翻出一个网兜把蝗虫装进去，挂在背包侧边，提着木棍就往山坡更高处走去。\n\n　　林风走的路线都避着人群，尽量不引起其他人的注意，毕竟有些人可不知道，哪怕是最低级的觉醒者也比普通人强得多，虽然被发现了也没什么，但多一事不如少一事。\n\n　　林风一边走，一边仔细观察周围的猎物，变异蝗虫以这种野菜为食，所以哪里的野菜长得茂密，哪里就可能有变异蝗虫。\n\n　　很快，林风便有了发现，在一丛特别茂密的野菜中间，一只变异蝗虫正埋头啃食，吃得头都不抬。\n\n　　林风屏住呼吸，调动灵能，慢慢靠近。\n\n　　“啪！”\n\n　　第二只到手。\n\n　　【击杀变异蝗虫一只，获得进化点0.1，当前进化点0.2。】\n\n　　林风的嘴角泛起的笑意更大了。\n\n　　继续。\n\n　　此刻的林风就像一个专注的猎人，在山坡上穿梭，寻找着下一个目标。\n\n　　第三只！\n\n　　第五只！\n\n　　大约四五个小时过去，林风已经杀了99只变异蝗虫。\n\n　　【当前进化点：9.9】\n\n　　还差最后一只，林风此时已经来到了山丘顶部。\n\n　　从这里看去，远处的车队长龙里，已经升起了篝火，看来吃完饭，车队就要出发了，得赶快抓紧时间。\n\n　　就在这时候，林风注意到一处石头后面有一片特别茂密的野菜丛，那里的野菜比别处高出半截，叶片肥厚，颜色墨绿得发黑。\n\n　　而且，最关键的是，那里趴着一只变异蝗虫。\n\n　　林风靠近后，趁变异蝗虫不注意的瞬间，猛地砸下去。\n\n　　啪！\n\n　　懵逼，不伤脑。\n\n　　因为整个头都炸了，随着这只变异蝗虫的脑袋炸裂，提示声响起。\n\n　　【击杀变异蝗虫一只，获得进化点：0.1，当前进化点：10，提示进化点满足进化条件，是否立即为本命御兽进化？】\n\n　　“是！”\n\n　　林风在心里狂喊，见证奇迹的时刻到了。\n\n　　就在林风确认的瞬间，手里的小乌龟猛地一沉。\n\n　　“哎——”\n\n　　小乌龟直接从手里掉在了地上。\n\n　　发出“咚！”的一声闷响。\n\n　　林风低头看去，原本只有巴掌大小的小乌龟，此刻已经膨胀到了脸盆大小，龟壳变得黑亮黑亮的，上面还隐约浮现出一些神秘的纹路。\n\n　　四肢从壳里伸出，粗壮有力，爪子锋利如钩，尾部也变长了，末端还有一个骨质的尖刺。\n\n　　最让林风震撼的是，这只小乌龟原本总是眯着的小眼睛，此刻变得清澈明亮，瞳孔中隐约有光芒流转。\n\n　　这是？\n\n　　成精了？\n\n　　林风能感觉到一股奇异的联系，能感知到对方的大概状态，还有一股莫名的孺慕之情。\n\n　　这进化能力简直绝了。\n\n　　就在林风惊讶的同时，一股温热的气息流转周身，身体不由自主地紧绷起来。\n\n　　【御兽本次进化获得反馈，体质+4，力量+3，敏捷+4，精神+2，灵能+3】\n\n　　整个过程大约持续了十几秒，然后温热的气流缓缓退去，取而代之的是一种前所未有的轻松感，林风感觉自己的身体变得更有力了。\n\n　　当即打开面板查看。\n\n　　林风\n\n　　【属性】\n\n　　体质：14\n\n　　力量：13\n\n　　敏捷：14\n\n　　精神：12\n\n　　灵能：4\n\n　　天赋：御兽（1/1）无限进化\n\n　　本命御兽：玄龟(下次进化需要100点进化点)\n\n　　等级：1级\n\n　　体质：40\n\n　　力量：30\n\n　　敏捷：36\n\n　　精神：18\n\n　　灵能：30\n\n　　解锁能力1：食土（注：可以通过土壤获得生存所需。）\n\n　　进化后的反馈属性竟然加了这么多？\n\n　　让林风没有想到的是，除了体质外，敏捷反馈竟然也不少，足足4点。\n\n　　这意味着什么？\n\n　　意味着这只乌龟，跑起来贼快。\n\n　　我进化出一只敏捷龟？\n\n　　林风低头打量起地上这只小乌龟，不对，现在应该叫大乌龟了。\n\n　　对方也用那双明亮的眼睛看着林风，还用头蹭了蹭林风的小腿。\n\n　　“我似乎还没有给你起名字，叫什么？小龟？似乎也行，要不叫小玄吧，走了，让我抱你回家。”\n\n　　林风看车队停留的时间差不多了，准备抱起对方往回赶。\n\n　　“哎呦，卧槽，这么重！”\n\n　　林风差点摔一个踉跄。\n\n　　“小玄子，给老子起来，自己爬，抱不动了……”\n\n　　林风抬手拍了一下对方的龟壳。\n\n　　小玄四条粗壮的腿撑起身体，稳稳地站起来，看起来就像一个小堡垒似的，自带一股沉稳的气势。\n\n　　就在一人一龟准备往回走的时候，\n\n　　“沙沙沙……”\n\n　　泥土翻动的声音从林风脚下传来。', 2362, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (8, 13, 6, '第6章 回车队', '　　林风的笑容瞬间凝固，想也不想立刻往旁边跳去。\n\n　　只见一条裂缝从原来站立的地方蔓延开来，泥土往两边翻涌，\n\n　　然后——\n\n　　一张巨大的口器破土而出。\n\n　　那是一只足有半人长的甲虫状生物，通体漆黑，甲壳泛起油亮的光泽，它的头部似乎没有眼睛，只有一对巨大的镰刀状颚，不停地开合，发出咔咔咔的声音。\n\n　　这恐怖的大杀器，一看就不好对付，别说人了，就是钢筋都能夹断。\n\n　　小玄的反应比林风更快，立刻挡在了林风面前。\n\n　　“咔！”\n\n　　一声脆响，就像是金属碰撞的声音，龟壳纹丝不动，\n\n　　那只甲虫见自己引以为傲的镰刀颚丝毫奈何不了面前的龟壳，似乎被激怒了，它的身体拼命扭动，六条腿在地面上拖出一道道深深的沟壑，试图把小玄掀翻。\n\n　　但似乎低估了小玄的重量，小玄稳如磐石般站在地面。\n\n　　林风紧了紧手里的木棍，盯着甲虫暴露的腹部，那里没有甲壳覆盖，只有一层相对柔软的膜状组织。\n\n　　“小玄，稳住！”\n\n　　林风手里的木棍像一根标枪一样投掷过去，精准地命中甲虫暴露的腹部。\n\n　　“噗呲……”\n\n　　所谓大力出奇迹，木棍穿透了那层薄膜，深深地扎进它的体内，绿色的体液喷射而出。\n\n　　甲虫发出一声尖利的嘶鸣，身体剧烈抽搐，它转过头，对准了林风所在的方向，镰刀状的巨颚疯狂开合，冲着林风冲了过来，似乎要把他拦腰夹成两节。\n\n　　林风下意识地往一边躲避，16点的敏捷让林风轻松闪过甲虫的攻击，甲虫擦着林风的衣角冲了过去，巨颚扑了个空。\n\n　　小玄再次挡在了林风面前，猛地张开口，一口咬住甲虫的一条前腿。\n\n　　“咔嚓！”\n\n　　骨节发出断裂的声音。\n\n　　甲虫吃痛后，疯狂地扭动身体，但被小玄死死咬住，丝毫不给对方脱身的机会，林风趁这个机会，从旁边抱起一个大石头，冲到甲虫侧面，对准它那已经被木棍捅穿的腹部，狠狠地砸了下去。\n\n　　一下，接着一下。\n\n　　绿色的液体溅了林风一身，甲虫挣扎得越来越微弱，直到它的身体停止了抽搐。\n\n　　【击杀变异锹甲虫一只，获得进化点：0.5】\n\n　　听到击杀的提示音，林风大口大口地喘着气，一屁股坐在了地上，看着那只死透的变异锹甲虫，又看了看身边同样被溅了一身绿色液体的小玄。\n\n　　林风重重地吐出一口气，刚才多亏了小玄，实在是太危险了，一个不慎就要命丧当场，现在想想都有些害怕。\n\n　　不过在看到0.5进化点的时候，他又笑了。\n\n　　越强的怪物给的进化点越多，这意味着，只要不停地杀，御兽就会不停地进化下去，他们就能不停的变强，直到在这个世界安稳地生存下去。\n\n　　他林风再也不用看任何人的脸色，也不会被任何人抛弃。\n\n　　虽然林风并不怨恨王烈他们，但毕竟事情发生在自己身上，也知道这么做没有错，可心里始终有个疙瘩。\n\n　　再一想到那些一见到自己失势后就立马抛弃自己的女人，还有那些平日里巴结自己的人，林风心里冷漠了几分，虽然自己不吃亏，也确实爽了好几天。\n\n　　可事情发生就发生了，最多就是让林风的道德观再次下降了一个档次，认识到最重要的一件事，那就是男人一定要有实力。\n\n　　林风弯腰捡起半人长的变异锹甲虫尸体，这个可是肉，可不能浪费。\n\n　　“走吧，小玄。”\n\n　　林风拍了拍它坚硬的龟壳。\n\n　　变异锹甲虫的尸体还挺沉，少说也有五六十斤，不过以林风目前的属性来说，拖拽起来很轻松。\n\n　　小轩迈着四条粗壮的腿，不紧不慢地跟在林风身后，速度丝毫不慢。\n\n　　一路下山，林风遇到了不少同样往回赶的人。\n\n　　这些人三三两两的结伴而行，手里提着用衣服、布料做成的袋子，里面鼓鼓囊囊的塞满了野菜，甚至有些人做的口袋太大了，不得不两个抬着走。\n\n　　看得出来，他们此刻的脸上都扬着笑容，对于他们来说，能挖到足够的野菜，就意味着接下来的几天不会饿肚子。\n\n　　在这末日的世界里，这确实是值得高兴的事。\n\n　　“嘿，今天运气真不错，挖了满满一兜！”\n\n　　“我也是，这片山丘的野菜长得真不错，要是车队能多停留两天就好了。”\n\n　　“想得美，灰雾可不会等你。”\n\n　　“额……也是，不过至少两三天不用发愁了。”\n\n　　这些人说说笑笑地走着，擦肩而过的时候，目光不经意间扫过林风。\n\n　　然后，挂在脸上的笑容凝固了。\n\n　　所有人的脚步都慢下来，甚至有的人脚步都停了下来。\n\n　　他们的视线先是落在林风手里拖着的那只巨大的变异锹甲虫尸体上，瞳孔骤缩，那对镰刀状的巨颚在光线下泛着幽冷的光泽，一看就知道是能轻易夹断人骨头的凶器。\n\n　　然后，他们的视线移到了林风背包侧面挂着的那一个大网兜上。\n\n　　网兜里面密密麻麻的装满了变异蝗虫，暗绿色的蝗虫挤在一起，有些蝗虫的后腿露在外面，上面的倒刺清晰可见。\n\n　　那么多？\n\n　　这怕是有好几十只，甚至上百只吧！\n\n　　这些人不知道林风具体杀了多少，但他们能看到那满满的一网兜，少说也有三四十斤重。\n\n　　空气安静了几秒。\n\n　　有人下意识地咽了咽口水，不止是想吃，还有震惊。\n\n　　“这……不是那个被首领踢出核心成员的那个觉醒者吗？”\n\n　　“是啊，不是说他没有战斗能力吗？”\n\n　　没有战斗能力？\n\n　　没有战斗能力的人能背着那么大一网兜变异蝗虫回来？没有战斗能力的人能把一只半人长的变异甲虫拖回来？\n\n　　你看看那变异甲虫的巨颚，看看那甲壳的厚度，再看看那6条粗壮的腿，那么长的倒刺，这种东西是好惹的？\n\n　　顿时，这些人觉得手里提着的野菜不香了。\n\n　　“这就是觉醒者的实力吗？”有人喃喃地说，声音里带着深深的羡慕和一丝苦涩。“哪怕是没有战斗能力的觉醒者，哪怕被踢出了核心队伍，也这么强……”\n\n　　“我们辛辛苦苦挖了一整天野菜，还比不上人家的一根手指头。”\n\n　　“别说了，这就是命，快走吧，回去还得整理呢，车队快出发了。”\n\n　　人群散开，但每一个经过林风身边的人，都会忍不住多看两眼，那眼神里有羡慕，有敬畏，还有渴望……\n\n　　林风对这些目光熟视无睹，继续拖着变异锹甲虫往车队走。\n\n　　前面出现一队巡逻队员。', 2315, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (9, 13, 7, '第7章 这就是现实', '　　五个人腰里别着对讲机，提着一根根自制的武器，负责外围警戒巡逻，同时也负责在车队停留期间外出收集物资时排查危险，并顺便保护收集物资的人。\n\n　　当然，遇到真正的危险的时候，还是得几名觉醒者出手。\n\n　　“今天收获不错，搞了3只变异蝗虫！”\n\n　　“回去烤一只，剩下的换成别的存起来，我告诉你，这可是好东西，那几位觉醒者大人都眼馋的稀罕物。”\n\n　　“嘿嘿，老张，你不是说晚上要去公交车上找个妹子乐呵乐呵？”\n\n　　“嘿嘿，可不是嘛，攒了好几天物资了，今晚可得……”\n\n　　说话的人忽然卡壳了。\n\n　　他的目光越过同伴的肩膀，看到了不远处正朝这边走来的林风，准确的说，是看到了林风手里拖着的锹甲虫尸体和林风背包侧边挂着的那一大网兜蝗虫。\n\n　　他不可置信地揉了揉眼睛，确认自己没有看错。\n\n　　一大网兜变异蝗虫。\n\n　　一只半人长的甲虫。\n\n　　一个人！\n\n　　我他妈的没有看错吧。\n\n　　其他几个巡逻队员也注意到了同伴的异样，纷纷停下脚步，脸上的表情从刚才的兴奋变成了呆滞，从呆滞变成了震惊。\n\n　　他们五个人，全副武装，配合默契，小心翼翼地蹲守半天，才猎杀了3只变异蝗虫，就这3只，已经让他们觉得今天运气爆棚，走路都带风了。\n\n　　结果转头一看，好家伙。\n\n　　人家一个人就搞了那么大一网兜，还有一只变异甲虫。\n\n　　那个队员下意识地看了看自己手里提着的3只蝗虫，又看了看林风那一大网兜，默默的用衣服把蝗虫盖住。\n\n　　这还炫耀个屁啊！\n\n　　“这人……”其中一个巡逻队员开口道：“传言不是说他因为没有战斗能力，跟普通人没啥区别吧，才被首领开除核心队伍了吗？你告诉我，没有战斗能力的人能一个人干掉一只锹甲虫？”\n\n　　没有人回答他的问题。\n\n　　因为大家想起了一件事情。\n\n　　就在三天前，车队经过一片废弃村庄的时候，也遭到了一只变异锹甲虫的袭击，那一次，车队足足损失了两辆汽车，死了十几个人，那些人的惨叫声还在耳边响起，最后还是首领王烈亲自赶到，一连三道雷电下去，才把那东西给劈死。\n\n　　那还是车队最强者，王烈出手的情况下。\n\n　　而现在，林风一个人，就干掉了一只。\n\n　　“这个消息……是不是哪里不对？”\n\n　　就在这时候，人群里有一个光头大汉悄悄的往后退了两步，试图把自己缩在同伴身后。\n\n　　赵虎，他此刻的脸色很难看，准确地说，是有青有白，纯被吓的。\n\n　　赵虎是跟着巡逻队一起出来的，负责搬运物资，刚才他在后面磨蹭了一会儿，没想到一抬头就看到了这幅场景。\n\n　　赵虎的脑子里“嗡”的一声，他想起几个小时前，还在林风面前耀武扬威，嘲笑对方，甚至大言不惭让对方来自己手下当搬运工，一天一顿野菜团子管饱。\n\n　　现在想来，他那张脸都在发烫，人家几个小时内就能击杀那么多变异蝗虫，还能单挑一只变异锹甲虫，你让人家来你手下当搬运工？\n\n　　你配吗？\n\n　　赵虎恨不得给自己两个大嘴巴子。\n\n　　他缩着脖子，弓着背，试图在人群中不引人注目的偷偷溜走。\n\n　　“看不见我，看不见我，看不见我……”他一边走，一边在心里默念。\n\n　　林风确实没有注意到赵虎。\n\n　　说实话，林风现在根本没有心思管这些，现在满脑子就一件事。\n\n　　饿……\n\n　　林风已经大半天没有吃东西了，早上才跟两个女人消耗了大量体力，又高强度的猎杀了几个小时蝗虫，还经历了一次生死搏杀，现在只感觉饿得发慌。\n\n　　现在只想赶紧回到车队，烤蝗虫，吃个饱。\n\n　　至于赵虎，那种小角色，林风自始至终都没有放在眼里，一个只会搬东西的光头大汉而已，说句不好听的，就凭现在的小玄，一口下去就能咬断对方一条胳膊。\n\n　　不对，小玄可是正经御兽，怎么能拿来和这种人作比较？\n\n　　林风加快地脚步。\n\n　　“风哥，风哥！”\n\n　　忽然背后传来一个殷勤的声音。\n\n　　林风回头，看到是一个二十多岁的年轻男人正小跑着追上来，脸上堆满了笑，这人身上穿着一件沾满各种污渍的迷彩服，长得普通，但眼神活泛。\n\n　　“风哥，您回来了！我来拿，我来拿！”灵说着就要去接林风手里的锹甲虫，殷勤得不行，“您歇着就行，这些粗活哪能让您干？”\n\n　　林风挑了挑眉，没说话，他大概明白了对方的想法。\n\n　　这一停顿的功夫，又有几个人反应过来了。\n\n　　一个中年男人快步跑过来，脸上同样挂着殷勤的笑：“风哥！您背包我给您拿着，看你累的，歇一歇。”\n\n　　这些人都是人精，尤其是经过几天的末日洗礼。\n\n　　他们看到了林风的实力，知道就算被踢出了核心队伍，这个人也比他们这些普通人强出太多太多，在末日世界里。\n\n　　跟着强者走，总没有错。\n\n　　更何况，林风那满满一网兜蝗虫，随便漏一点，就够他们吃饱饭了。\n\n　　林风看着面前这两人，心里没有太多的波澜。\n\n　　换做几天前，那个刚出社会的愣头青，可能还会感动一下，但经历了今天这一连串事情后，林风对人性有了更清醒的认识。\n\n　　这些人巴结他，是因为他手里的物资。\n\n　　不过林风并不反感，谁都喜欢听好听的，被奉承。\n\n　　这就是人性，这是末日，林风不要别人的真心，只需要别人有用就行。\n\n　　“行。”林风把手里拖着的锹甲虫尸体往年轻男人手里一递，“拿好了。”\n\n　　对方接过来，差点没坠一个踉跄，这锹甲虫比他想象的还要重得多，但他咬了咬牙，硬生生扛住了，脸上那讨好的笑容纹丝未动。\n\n　　林风又把背包卸下来，丢给那个中年男人。\n\n　　“跟上。”\n\n　　然后从网兜里掏出两只变异蝗虫，一人扔了一只。\n\n　　两人接过蝗虫，眼睛都亮了，连连道谢。\n\n　　“谢谢风哥，谢谢风哥！”\n\n　　其他人见状，懊恼得直拍大腿，他们刚才也想到了，就犹豫了那么一两秒，机会就被别人抢在了前头。\n\n　　那可是变异蝗虫啊，就算自己舍不得吃，拿去后勤处，换5斤野菜团子，能多吃两三天。', 2229, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (10, 13, 8, '第8章 眼馋', '　　“风哥，我也可以帮忙！”\n\n　　“风哥，让我也来吧，我力气大！”\n\n　　“风哥——”\n\n　　林风摆摆手，没有理会。\n\n　　林风拍了拍小玄，让小玄跟上，一人一龟在前，两个临时搬运工在后，在一路的恭维声中，穿过营地，朝着车队走去。\n\n　　一路上，看到这一幕的人很多，表情各异，有人惊讶，有人嫉妒，有人……\n\n　　但林风不在乎。\n\n　　现在只想赶紧回去，烤蝗虫，吃饭。\n\n　　回到营地里，篝火已经一堆一堆的燃起来，橘红色的火光在末日里显得格外温暖，人们围坐在篝火旁，架着锅，煮着野菜混合着一切能吃的东西。\n\n　　空气中弥漫着野菜苦涩和怪异的味道，期间还夹杂着几声孩子的哭闹和女人的低语。\n\n　　林风随便找了一处空地，示意年轻人把锹甲虫放下，又从中年男人手里接过背包。\n\n　　环视四周，从旁边搬了几块石头，随便垒了一下，一个简易的烤肉台子就做好了，又从附近捡了些枯枝干草，那个年轻人和中年男人很有眼色，一个帮忙搭火堆，一个帮忙找干柴，手脚麻利得很。\n\n　　火很快升了起来。\n\n　　林风从网兜里掏出变异蝗虫，挑了十几只个头大的让年轻人去处理。\n\n　　“处理一下，然后串起来，一会烤。”\n\n　　年轻人“哎”了一声，从怀中掏出一把小刀，蹲在地上开始处理蝗虫，他干活很利索，三两下就把蝗虫的翅膀和内脏去掉，用树枝串好。\n\n　　就在这时候，林风忽然想到了什么，对着年轻人说道：\n\n　　“你，拿十只蝗虫去营地里换点盐回来，能做不？”\n\n　　“风哥放心，包在我身上！”\n\n　　林风从网兜里数出10只变异蝗虫，递给对方，他接过蝗虫，转身就往营地中心跑去。\n\n　　中年男人在旁边羡慕地看着，但也没有闲着，主动去附近多捡了些柴火回来。\n\n　　大约十来分钟，年轻人气喘吁吁地跑回来。\n\n　　他手里捧着一个小袋子，脸上全是兴奋的神色。\n\n　　“风哥！您看！”\n\n　　对方把袋子打开，里面不仅有半包盐，还有一小包孜然粉跟辣椒面。\n\n　　“可以啊。”林风有些意外，对方还能找到这好东西。\n\n　　“嘿嘿，”年轻人挠挠头，笑道：“我跟几个后勤的人换的，他们听说是您要，都很痛快。”\n\n　　当然他没有说的是，那十只变异蝗虫引起了不小的轰动。\n\n　　林风接过盐和调料，满意地点点头。\n\n　　“办的漂亮。”\n\n　　林风又拿出一只蝗虫，去换了点水，把盐化在水里，把串好的蝗虫浸泡了一会盐水，架在火上，开始烤。\n\n　　火焰舔舐着蝗虫的甲壳，发出滋滋的声响，不一会，一股浓郁的香味就开始在空气中弥漫开来。\n\n　　蛋白质在高温下焦化，内含的油脂滴在火焰上产生的香气，直往人的鼻子里钻。\n\n　　周围的人纷纷转过头来，尤其是那些坐在篝火旁啃着苦涩野菜的人们，手里的动作全部停了下来。\n\n　　他们伸长脖子，使劲嗅着空气中的香味，喉结上下滚动，眼睛直勾勾地看着林风这边。\n\n　　孩子们最先忍不住。\n\n　　“妈妈，好香啊……”一个小女孩扯着母亲的衣角，眼巴巴看着林风的方向。\n\n　　“别看，那不是我们的，”母亲把孩子搂进怀里，自己却忍不住咽了一口口水。\n\n　　几个离得近的男人站起来，伸着脖子往这边看，眼睛里全是渴望，有挣扎，也有忌惮。\n\n　　车队里的规矩是严酷的。\n\n　　自从穿越到这个末日世界以来，为了争夺食物，为了活下去，人类之间爆发过无数次冲突，最初的那几千人里，有一半不是死在怪物手里，也不是死在灰雾里，而是死在自己同类的手里。\n\n　　所以车队建立后，为了控制混乱，维持稳定，就定下了一条铁律，严禁抢夺他人财物，违者死。\n\n　　这一条规矩，是用一条条人命堆出来的。\n\n　　起初有人不信邪，觉得自己够狠够强，被抓住后，当场处决，一次，两次……慢慢的，所有人都明白了，这条规矩是不容触犯的。\n\n　　现在，无论多饿，无论有多馋，大部分人都不敢动手。\n\n　　但这香味直直地钻进鼻腔里，有人忍不住了。\n\n　　一个四十来岁的男人搓着手，满脸堆笑地朝着林风走来。\n\n　　“风……风哥，能不能让我也尝一块。”\n\n　　林风抬起头，看了他一眼，眼神很平静，没有任何情绪，就像在看一块石头。\n\n　　男人被这目光看得心里发毛，下意识地后退了半步，但那香味太勾人了，他咬了咬牙，又说。\n\n　　“我……我可以用东西跟你换，真的，你看这个！”\n\n　　他手忙脚乱地从手腕上撸下来一块手表，举到林风面前。\n\n　　“你看，这是劳力士，真的，穿越前我花了好几十万买的，我用这块表跟你换两口吃的，行不行？”\n\n　　火光映照在表盘上，反射出金色的光芒。\n\n　　林风伸手接过。\n\n　　手表的分量很沉，表盘完好无损，指针还在滴答滴答的走着，林风认识这个牌子，穿越前，这表确实是他想都不敢想的奢侈品。\n\n　　几十万？\n\n　　在这末日世界里，一块几十万的手表还不如一块压缩饼干值钱。\n\n　　不过这块表确实有个用处，那就是看时间，这个世界没有信号，手机几乎无用，能看时间的东西还真不多。\n\n　　“行！”\n\n　　林风把手表揣进兜里，指了指正在烤的蝗虫。\n\n　　“换2只。”\n\n　　男人的眼神一下子亮了：“真的？两只，谢谢风哥！谢谢风哥！”\n\n　　他正要伸手去拿，忽然又想到什么，小心翼翼地问：“风哥，能不能多换两只？”\n\n　　“不换拉到。”\n\n　　林风把手表又递了回去，语气十分平淡。\n\n　　“你应该知道现在吃的东西有多珍贵吧？”\n\n　　男人连忙摆摆手，把手表往林风怀里推。\n\n　　“换换换，两只就两只，谢谢风哥！”\n\n　　他从火上拿了两只烤得金黄的蝗虫，转身就跑，生怕林风反悔似的。\n\n　　这一幕被其他人看在眼里，顿时像捅了马蜂窝一般，一大群人围了过来。\n\n　　“风哥！我有东西，我也想跟你换……”\n\n　　“风哥，我这里有一把瑞士军刀，正品，跟你换一只行不行？”\n\n　　“风哥，我这里有条项链，是纯金的……”', 2207, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (11, 13, 9, '第9章 这烤肉真香', '　　人们从四面八方涌过来，手里举着五花八门的东西，各种金银首饰，打火机，钢笔，甚至还有口红……\n\n　　在这个末日里，大部分东西都没有任何使用价值。\n\n　　林风扫了一眼，挑了几样有用的，一把瑞士军刀，一个防风打火机，一盒没拆封的创可贴。\n\n　　其他东西，林风全部拒绝了。\n\n　　“风哥，求求你，我孩子已经两天没有吃东西了，那野菜一吃，他就吐……”\n\n　　“风哥，你行行好吧……”\n\n　　“就是，你这里这么多，分一点给我们尝尝吧，大家都是一个车队的……”\n\n　　林风越听越皱眉，看向那个中年人‘临时工’\n\n　　“把他们赶远点，别碍着我吃饭。”\n\n　　正在忙活的中年人，立刻站起身，挺起腰板，对人群挥手：“都散了，赶紧散了，风哥说不换就不换，都退后，退后，别影响风哥吃饭，小心我对你们不客气。”\n\n　　人群不甘心地散了，但那股香味还在空气中飘荡。\n\n　　越来越多的人围在远处，手里拿着野菜团子，眼巴巴的望着这边，一张张灰扑扑、写满了饥饿和渴望的脸。\n\n　　林风皆不为所动。\n\n　　林风拿起一串烤好的蝗虫，再撒上一点孜然粉和辣椒面，咬上一口。\n\n　　“咔嚓……”\n\n　　甲壳碎裂的声音清脆悦耳，金黄色的外壳裂开，露出里面白嫩嫩的肉，孜然和辣椒的香气混合着变异蝗虫肉本身的酥脆和鲜嫩，在口腔里炸开。\n\n　　一个字，\n\n　　绝了。\n\n　　香！\n\n　　实在是太香了。\n\n　　林风眯起眼睛，三两口就把一只蝗虫吃得干干净净。\n\n　　终于明白了那句话的真谛。\n\n　　高端的食材，往往只需要最简单的烹饪方式。\n\n　　林风以前在烧烤摊跟舍友也点过蚂蚱，那味道跟这个比，一个天上，一个地上。\n\n　　尤其是在这末日里，大部分连野菜都吃不饱，这已经算是人间美味了。\n\n　　林风又拿起第二只，\n\n　　第三只。\n\n　　林风虽然肚子很饿，但依然吃得不紧不慢，慢慢地咀嚼着，享受这难得的美食。\n\n　　至于在火堆旁忙活的两个临时工，林风一人分了他们两只，此刻他们吃得一脸满足，好像在天堂一般。\n\n　　林风看得一脸嫌弃，有那么夸张吗？\n\n　　林风足足吃掉十几只蝗虫，感觉还没有吃饱，心中暗想。\n\n　　“我现在这么能吃了吗，这起码两三斤了吧，觉醒后消耗就是大。”\n\n　　林风把目光落在那只锹甲虫身上，它的腿很粗壮，尤其是前面那两条腿，足足成人手臂长，关节处覆盖着厚厚的甲壳，内部应该有不少肉质。\n\n　　林风拿起那把刚换来的瑞士军刀，准备切一条下来烤了尝尝。\n\n　　“叮……”\n\n　　刀身与虫腿发出金属碰撞的声音，别说切下来，连一丝痕迹都没有。\n\n　　“这么硬？”\n\n　　好在也不是完全没有办法，锹甲虫其中一条前腿被小玄咬碎了，虽然还没有完全断裂，可那层坚硬的甲壳却完全碎了。\n\n　　他顺着碎裂的甲壳，用小刀狠狠用力，几下就把这条前腿从中间切了下来。\n\n　　里面的肉露了出来，颜色雪白，在火光下泛着微微的光泽。\n\n　　林风切下一小片，放在火上烤了烤。\n\n　　肉片很快卷曲起来，表面变得焦黄，散发出一种完全不同于蝗虫的香味，让人忍不住分泌口水。\n\n　　林风吹了吹，放进嘴里。\n\n　　瞬间，林风的眼睛瞪大了。\n\n　　好吃。\n\n　　好吃到林风不知道怎么表达，只能说——这肉真香。\n\n　　吃了蝗虫后，林风以为自己吃到了末日世界最好吃的东西，但现在他发现自己错了。\n\n　　变异蝗虫是好吃，但跟这锹甲虫腿肉比起来，就像是馒头和大餐。\n\n　　林风仔细地咀嚼，眼睛微微眯起，嘴角不自觉地上扬。\n\n　　这才是人过的日子嘛……\n\n　　就在林风准备想办法再切下一块腿肉的时候\n\n　　忽然\n\n　　“哟，小帅哥……”一个慵懒，带着几分挑逗的声音从身后响起。\n\n　　“看不出来，你的日子过得不错啊？”\n\n　　林风的动作顿了一下。\n\n　　“有好吃的，也不分姐姐一点？”\n\n　　林风转过头，朝着发出声音的地方望去。\n\n　　只见，一双被黑色丝袜包裹的美腿首先映入眼帘，纤细的脚踝，匀称的小腿，线条流畅的向上延伸，没入一条包臀裙中。\n\n　　往上是被紧身T恤勾勒出盈盈一握的腰肢，和那令人挪不了眼睛的巨大车灯。\n\n　　陈敏靠在一辆轿车边上，一只手随意地撩了撩头发，风吹起她额前的碎发，露出那张艳丽的脸，三十多岁的女人，不知是保养得当，还是觉醒的原因，皮肤白嫩得像二十多岁的少女一般，尤其是那一双眼睛，自带勾魂夺魄的魅力。\n\n　　不仅有成熟女人的特有风情，还有少女般的柔情。\n\n　　好一个极品女人，哪怕是蓝星，这样的女人也十分少见，当然网络上看到的不算。\n\n　　“要是能盘一下……”\n\n　　此时，她正笑眯眯的看着林风，目光在林风和那一堆美食之间来回打量。\n\n　　林风一见是这女人，手里的肉差点没拿稳。\n\n　　心里暗骂自己一声，都什么时候了，还有心思想这些。\n\n　　这女人，自己惹不起。\n\n　　准确的说，是整个车队没有几个人敢惹她。\n\n　　陈敏，明面上说是精神感知觉醒者，表面上是预警能力，但实际上，在车队的几次“内部混乱整合”中，所有人都见识到了她的可怕之处。\n\n　　精神力方面的觉醒者，本来就诡异。\n\n　　加上死在她手里的人没有一百也有八十了。\n\n　　林风亲眼见过一次，有个壮汉仗着自己有点实力，在车队里抢了别人物资，还把一个女人拖到帐篷里，被抓到的时候，抵死不认账，梗着脖子说自己是冤枉的，叫嚣着要证据。\n\n　　陈敏只是看了她一眼。\n\n　　就一眼。\n\n　　那壮汉的眼神瞬间变得空洞，然后自言自语地把自己做过的事情一五一十地说出来，什么时候抢了谁的东西，什么时候欺负了那个女人，甚至小时候偷了邻居家多少钱都交代得清清楚楚。\n\n　　说完之后，顿时抽搐着七窍流血，倒地身亡。\n\n　　陈敏只是擦了擦手，轻描淡写地说了一句：“下一个！”', 2170, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (12, 13, 10, '第10章 诡晶', '　　从那以后，车队里再也没有人敢在她眼皮子底下犯事。\n\n　　不是不想，是不敢。\n\n　　现在这个女人就站在林风面前，差点让林风的汗毛都竖起来。\n\n　　“没有没有！”林风连忙站起来，脸上的笑容比哭还难看。\n\n　　“敏姐想吃，尽管来，我这多的是，来，坐坐坐！”\n\n　　林风一边说，一边把自己当凳子坐的石头墩子让了出来，还用袖子在上面擦了擦。\n\n　　陈敏也不客气，优雅地坐了下来，包臀裙随着动作微微往上提，露出一截被黑丝包裹的大腿。\n\n　　林风眼观鼻鼻观心，不敢多看。\n\n　　“小弟弟。”陈敏开口了，声音慵懒，“你……这是开发出自己的能力了？”\n\n　　她的目光落在林风脚边那只正在啃泥巴的小玄身上，仔细地打量了几秒，语气肯定地说道。\n\n　　“看来是的，都长这么大了，还能单独猎杀一只变异锹甲虫，实力很强啊。”\n\n　　林风谦虚地说道：“没有没有，侥幸，只是侥幸，敏姐叫我名字就行，或者喊我小风就可以。”\n\n　　小弟弟？\n\n　　你才小弟弟\n\n　　我一点也不小，不信你试试，保你哭爹喊娘的。\n\n　　当然这话林风只敢在心里吐槽，一个字也不敢说出来。\n\n　　陈敏笑了笑，目光越过林风，落在那只锹甲虫身上，眼睛微微亮了一下。\n\n　　“这可是好东西啊。”\n\n　　她站起身，走到锹甲虫旁边，蹲下来仔细打量着，那只巨大的虫子横躺在地上，腹部被木棍捅穿的伤口还往外冒着绿色的体液。\n\n　　陈敏伸出白嫩的手，握住其中一条完整的前腿，轻轻一掰。\n\n　　咔嚓！\n\n　　林风的眼睛猛地瞪大了。\n\n　　他看了什么，那根前腿，差不多手臂粗细，表面覆盖着厚厚的黑色甲壳，刚才用瑞士军刀砍下去，一点印子都没有留下，硬得离谱。\n\n　　而陈敏，那双看起来柔弱无骨的白嫩小手，就这么轻描淡写地——掰断了？\n\n　　而就跟掰断一根黄瓜似的。\n\n　　“愣着干嘛？”\n\n　　陈敏转头看向林风，扬了扬手里的虫腿：“刀借我一下。”\n\n　　林风张了张嘴，下巴差点没掉地上。\n\n　　下意识地把刀递过去，手都在微微发抖。\n\n　　不是怕，是震惊。\n\n　　我的敏姐姐哎，你不是巨型精神系能力吗？那白嫩嫩的小手，怎么就能这么轻松地把虫腿掰断？\n\n　　陈敏接过刀，熟练地捏碎虫腿，然后削开碎裂的甲壳，将里面的白肉整条取出来，切肉的动作又快又稳，三两下就把一条虫腿处理得干干净净。\n\n　　然后开始烤，不像林风那样切成小片地烤，而是把整条腿肉切成大块，串在树枝上，直接架在火上烤。\n\n　　很快烤肉的香味更浓了。\n\n　　林风看着陈敏在火堆旁忙碌的背影，刚才那一幕始终在脑子里回荡，消之不去，忍不住看看自己的手，又看了看小玄。\n\n　　小玄趴在地上，也不啃泥巴了，那双明亮的眼睛看着陈敏手里的烤肉。\n\n　　“怎么了？”陈敏似乎察觉到了林风的目光，也明白了他在想什么。\n\n　　“吓到了？”\n\n　　林风连忙摇头：“没有没有，就是……敏姐，你不是精神系的觉醒者吗？这力气……？”\n\n　　“哦，这个啊？”陈敏翻动着手里的烤肉，语气十分随意。\n\n　　“你不参加战斗，不知道也正常，以后你明白了。”\n\n　　她没有细说，林风也不好继续追问。\n\n　　陈敏把另外几条虫腿也卸下来，一起串上烤，很快七八串虫腿肉就整齐地架在了火堆上，滋滋冒着油光。\n\n　　“帮你一起烤了，省得你一个人折腾半天。”\n\n　　陈敏拍了拍手，重新坐回石头上。\n\n　　“待会你多吃点，这可是好东西。”\n\n　　“好东西？”林风一愣。\n\n　　陈敏没有解释，只是笑了笑，目光落在烤肉上，似乎在计算火候。\n\n　　大约过了十几分钟，虫腿肉烤好了，表面金黄微焦，油脂沿着树枝往下滴落，落在炭火上发出呲呲的声响。\n\n　　陈敏拿起一串，吹了吹，递给林风。\n\n　　“尝尝。”\n\n　　林风接过来，树枝上串着大坨大坨的烤肉，香气扑鼻。\n\n　　咬了一口，肉还有些烫，在舌尖翻滚了几下才咽了下去。\n\n　　“嗯，好吃，敏姐，你这手艺，这个……”林风竖起大拇指，毫不客气地夸奖道。\n\n　　才吃下两坨肉，一道提示在脑海响起。\n\n　　【使用变异锹甲虫腿肉，体质+1，当前体质15。】\n\n　　林风整个人愣住了，呆呆地看着手里这串肉，又看了看陈敏。\n\n　　陈敏正优雅地吃着自己手里那串肉，察觉到林风的目光，嘴角微微翘起。\n\n　　“知道了吧?”她咬一口肉，慢悠悠地说，“这些变异生物的肉，可不是单纯的能填饱肚子那么简单。”\n\n　　林风咽了咽口水，有些震惊。\n\n　　“多吃，能增加我们的属性。”陈敏继续说。“今天托你的福，姐姐我可是有口福了，这种能吃的变异生物可不多，大部分变异生物都不能吃，要么有毒，要么肉质根本没法入口，吃了轻者上吐下泻，重者当场丧命。”\n\n　　林风默默地又吃了两块。\n\n　　【体质+1，当前体质：16】\n\n　　又加了一点，这效果这么好？\n\n　　“这几天你也见过很多次袭击了吧？”陈敏一边吃一边说。\n\n　　“虽然大部分不能吃，但能吃的，只要吃下去，都能给我们增加属性，当然……”她顿了顿。\n\n　　接着说道：“除了这些外，还有一些东西也能提升我们的实力。”\n\n　　“什么东西？”林风下意识地问。\n\n　　“诡异！”\n\n　　林风手里的动作停了一下。\n\n　　诡异？\n\n　　林风想起来了，逃亡的车队一路上，白天要提防变异生物的袭击，到了晚上，还有一种更恐怖的东西。\n\n　　那就是诡异，这种东西浑身散发着黑色的雾气，车队里有不少人都是死在诡异手里。\n\n　　“就是那种夜晚出现的诡异东西。”\n\n　　“对，就是它，这种东西，最常见的就是动物诡异，不仅能影响人的精神，还很难杀，但是击杀后……能获得诡晶。”\n\n　　“诡晶！”这又是林风没有听过的新名词。\n\n　　“嗯，一种亮晶晶的，像珠子一样的东西。”陈敏从脖子上扯出一根红绳，红绳的末端从深深的沟壑里显现出来，是一个小小的布囊。\n\n　　她打开布囊倒出一样东西，放在掌心给林风看。\n\n　　林风凑过去，大约有弹珠那么大小一颗的白色珠子，表面光滑，珠子内部似乎有什么东西在流动。\n\n　　“这东西能提升我们的等级。”陈敏收回诡晶，将布囊重新放进胸口的位置，只隐隐还能看见一根细小的红绳。\n\n　　这女人，我还以为送我呢，又拿回去了，几个意思？\n\n　　不过看到布囊消失，他心里暗自吐槽，有必要藏这么严实吗？\n\n　　不过这‘诡晶’真白……', 2386, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (13, 13, 11, '第11章 我还没有上车', '　　“姐姐我现在可是2级觉醒者，就是靠这东西升上去的。”\n\n　　“二级觉醒者？”\n\n　　“你不知道也正常。”陈敏看出林风的疑惑。\n\n　　“之前你契约的只是一只没有战斗能力的乌龟，跟你说了也没用。”\n\n　　林风沉默了，现在脑子乱哄哄的。\n\n　　心里就一个想法，所以这一周以来，自己不止被蒙在鼓里，而且被彻底排除在了核心信息之外。\n\n　　变异生物的肉能增加属性，他不知道。\n\n　　击杀诡异能获得诡晶，他同样不知道。\n\n　　说好的平均分配呢，林风忽然觉得有些可笑。\n\n　　原来所谓的核心成员待遇，只是表面上给他分了一辆车、一些物资外，真正有价值的信息，能提升实力的资源，一样都没有他的份。\n\n　　或许是在自己契约小玄后，他们发现自己没用，就已经将自己排除在核心圈子外了吧。\n\n　　自己还在为获得物资沾沾自喜，在大巴车里睡女人，还觉得自己占了天大的便宜。\n\n　　结果别人在吃变异生物的肉提升属性，在猎杀诡异升级。\n\n　　而他什么都不知道。\n\n　　如果不是今天被踢出核心队伍，如果不是外出猎杀蝗虫发现了隐藏天赋，如果不是猎杀了锹甲虫遇到了陈敏。\n\n　　是不是得很久很久以后才知道这些？\n\n　　林风低下头，看着手里这串虫腿肉，忽然觉得嘴里的肉有些不是滋味。\n\n　　心里堵得慌。\n\n　　“怎么了？”陈敏的声音忽然柔和了一些，“心里不舒服？”\n\n　　林风摇摇头，深吸一口气，把剩下的肉一口吞掉，又从火堆上拿起一串。\n\n　　陈敏没有再说什么，安静的吃着烤肉，火光照在她的脸上，那张艳丽的面孔多了几分柔和。\n\n　　“敏姐！”林风突然开口。\n\n　　“嗯？”\n\n　　“为什么要告诉我这些？”\n\n　　陈敏抬起头，看着林风的眼睛，她的眼睛很漂亮，给人一种勾魂夺魄的感觉，看向林风的眼神里很清澈，没有算计，没有敷衍。\n\n　　“因为你早晚会知道，与其让别人用这些信息来拿捏你，不如我直接告诉你。”\n\n　　林风愣了一下。\n\n　　“再说了，”陈敏笑了笑，“今天你请我吃了一顿好的，我总得有点回礼吧？”\n\n　　“好了，别想太多。”陈敏站起身来，拍了拍裙子上的灰，“天色不早了，车队待会要出发了，你收拾一下。”\n\n　　她走了两步，忽然又停了下来，回头看着林风。\n\n　　“对了，小风弟弟。”\n\n　　“啊？”\n\n　　“你那只乌龟，”她的目光落在小玄身上，“好好养，能从巴掌大小长这么大，还能猎杀锹甲虫，它的能力，可能比你想象的还要强很多。”\n\n　　说完，她踩着高跟鞋，不紧不慢地走了。\n\n　　包臀裙勾勒出她纤细的腰肢和圆润的曲线，一双黑丝美腿在夜色中若隐若现。\n\n　　林风看着他的背影，忽然觉得这个女人也没有那么可怕。\n\n　　当然，也就那么一瞬间。\n\n　　下一秒林风就清醒了，这个女人不可怕？可怕的要命。\n\n　　林风重新坐下来，看着火堆上剩下的烤肉，又看了看脚边的小玄。\n\n　　“你可要争气点啊，我未来的生活好不好，可全看你了。”\n\n　　小玄用脑袋蹭了蹭林风的小腿，眼巴巴地看着火堆上的烤肉。\n\n　　林风想了想，拿起一串烤肉递给小玄。\n\n　　“吃吧，你可是我的大功臣。”\n\n　　林风都没有看清小玄的动作，手里的烤肉就消失不见了，眨眼间就到了小玄的嘴里。\n\n　　“艹，小心烫。”\n\n　　小玄没有理会林风的话，三两下就连肉带树枝一起吞进了肚子里，吃完又看向林风。\n\n　　林风彻底无语了。\n\n　　“真是猪八戒吃人参果，浪费……”\n\n　　“剩下的想都别想，喏，那边那个锹甲虫，归你了……”\n\n　　这烤肉能提升属性，可不能就这么浪费了，不过也不能因为小玄的天赋是吃土，就真让它吃土吧，自己还是有点良心的，反正这肉够自己吃了。\n\n　　就当废物利用吧。\n\n　　那两个献殷勤的临时工见陈敏走了，才小心地走上前说道。\n\n　　“风哥，车队的大喇叭喊了，还有十分钟出发，我叫姜坤，叫我阿坤就行，以后有什么事吩咐一声就行。”那个年轻人堆着笑脸说道。\n\n　　“风哥，你叫我老刘就行，有事吩咐一声，我们先去收拾东西了……”\n\n　　“嗯，去吧……”林风点点头。\n\n　　随着车队即将出发的广播发出后，人群开始骚动起来。\n\n　　所有人以最快的速度收拾东西，人们把白天挖来的野菜捆好，塞进包里，塞进车里，或绑在车上。\n\n　　有车的人拼命往车上装物资，检查车辆状态，三轮 车里堆满了大包小包的物品，然后用绳子仔细固定。\n\n　　孩子被塞进车厢里，哭闹声此起彼伏，女人低声哄着孩子，男人们沉默地忙碌着，没有人抱怨，没有人喊累。\n\n　　这个世界里，能活着已经是万幸了，哪还有力气抱怨？\n\n　　前方的车辆开始启动了。\n\n　　最前面的是几辆改装过的房车和大巴车，那是觉醒们的座驾，窗户上焊着铁栅栏，车顶还架着探照灯。\n\n　　紧跟着的是几辆皮卡和货车，车厢里站着巡逻队的成员，他们手持钢刀、长矛、自制弓箭等武器，目光警惕地看着车队两侧的黑夜。\n\n　　这些人负责外围警戒，每次遇到怪物袭击，他们都是最先冲上去的。\n\n　　好处则是无需像车队里其他人一样，需要去收集物资，也无需上交资源，每天都能从后勤处领取一定配额的食物，这些都是靠命换来的。\n\n　　再往后，就是各种各样的车辆了，越野车、轿车、面包车、三轮车、自行车，车上堆满了家当、被褥、衣物、锅碗瓢盆，甚至是收集来的零零散散的东西。\n\n　　车队很长，从前到后足足上千米，车灯一盏接着一盏的亮起来，在黑暗中形成一条蜿蜒的光带，像一条垂死的巨蛇一般，缓缓挪动。\n\n　　林风背上背包，手里还拿着几串烤肉，一边吃一边走，走了几步忽然站住。\n\n　　林风低头看了看自己，又看了看周围。\n\n　　所有人都坐在车上，哪怕是最普通的幸存者也有一辆自行车。\n\n　　而林风，他没车。\n\n　　“哎，我还没上车，我还没上车啊……”', 2186, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (14, 13, 12, '第12章 新路线', '　　林风看着前方车队离自己越来越远，没有人等他，也没有人记得他。\n\n　　“真是，人走茶凉啊。”\n\n　　林风用脚踢了踢在旁边啃食锹甲虫的小玄。\n\n　　“走啦，跟上。”\n\n　　小玄抬起头，嘴里叼着小半截锹甲虫的身体，四条腿一撑，站起身，不过嘴里还叼着锹甲虫，边走边啃。\n\n　　林风懒得管他了，反正是它自己杀的，吃就吃吧。\n\n　　前方车队的灯光为队伍指明了方向，林风不快不慢地跟在车队最后面，和那些骑自行车，踩三轮车的人保持着不远不近的距离。\n\n　　好在觉醒者的体质让他的速度一点不比骑车慢多少。\n\n　　林风走了十几分钟，感觉身体越来越轻松，那些烤肉带来的不仅仅是饱腹感，吃到肚子里，还有一股温热的气流在体内流淌，越走越有劲。\n\n　　林风看了看手腕上的手表。\n\n　　晚上七点二十分。\n\n　　天已经完全黑了，车队的车灯是唯一的光源，除此之外，四周一片漆黑，道路两旁是灰黑色的荒地，偶尔能看到几棵枯死的树，光秃秃的枝丫如同鬼手一般伸向天空。\n\n　　晚上的气温很低，林风紧了紧衣服，加快了脚步。\n\n　　……\n\n　　最前方，那辆豪华的房车里，八名觉醒者齐聚一堂。\n\n　　房车里弥漫着一股野菜汤的味道。\n\n　　王烈坐在沙发上，看着面前摊开的手绘地图，眉头凝成了一个川字，看起来心事重重。\n\n　　“汽油不多了。”郭逸率先开口，他是机械系觉醒者，负责车队的维修和车辆调配。\n\n　　“按这个消耗速度下去，最多3天，一大半的车都得趴窝。”\n\n　　“三天？”刘铁柱大声说道：“那怎么行，总不能靠两条腿跑路吧？”\n\n　　“你喊什么？”郭逸瞥了他一眼，“我也在想办法，汽油总不可能从天上掉下来吧？”\n\n　　“好了。”王磊抬手制止了两人的争执，目光转向一边角落里安静坐着的沈雨桐。\n\n　　“雨桐，你那边有没有什么提示？”\n\n　　沈雨桐伸手在地图上指了指，所有人的目光都落在她手指的位置。\n\n　　“沿着这条路走，大约70公里的地方，有一个小型废墟，应该是一个小镇，说不定能找到一些生存物资，还有一些能用的车辆。”\n\n　　“去那里需要70公里？”陈敏皱了皱眉\n\n　　“以现在车队的速度，走到那里至少要到天亮。”\n\n　　“对！”沈雨桐点点头，“这是附近最近的一个补给点了，再往前，200公里内都没有任何建筑，而且走这条路线，会比原先规划的路线，多出接近100公里。”\n\n　　陈丽安静下来。\n\n　　70公里听起来不远，但在这样的夜里，面对未知路况和随时可能遭遇的诡异袭击。\n\n　　这70公里可能就是一条生死线，而且要多绕行100公里，这……\n\n　　“我觉得可以去。”刘铁柱第一个表态，声音里带着急切。\n\n　　“车队里的物资不多了，这几天交上来的物资不是野菜就是野菜，我都快吃吐了。”\n\n　　他说着，伸手从桌子上拿起一个野菜团子，咬了一口，脸上露出痛苦的表情。\n\n　　“你们不知道我这几天怎么过的，”他嚼了两口，艰难地咽下去。\n\n　　“我觉醒的力量天赋消耗贼大，普通食物根本不够吃，我每天的配额早就吃完了，现在只能混着野菜吃，虽然难吃，但顶饿。”\n\n　　林风要是听到这番话，估计会笑出声来。\n\n　　原来觉醒者也吃野菜啊，原来你也会为食物发愁。\n\n　　你也有今天。\n\n　　“我也同意。”董雨开口了，“早点离开这鬼地方，这几天走在荒地上，连个人影都没有，总觉得不对劲。”\n\n　　郭逸和江声对视了一眼，也点点头。\n\n　　“那就这么定了，去这个废墟。”王烈最后拍板。\n\n　　沈雨桐又开口了：“不过，这条路线有不小的危险。”\n\n　　她在地图上画了一条线，从车队现在的位置指向废墟。\n\n　　“我们需要经过一片开阔的地带，那片区域有大量诡异的踪迹。”\n\n　　诡异\n\n　　这个词一出口，车里的气氛更加凝重了。\n\n　　“安排人做好战斗准备。”王烈沉声道。\n\n　　“让巡逻队加强警戒，陈敏，你负责全程感知，一旦发现异常，立刻通报。”\n\n　　陈敏点点头。\n\n　　“通知车队，调整方向，加快速度。”\n\n　　王烈说完这句话，看向车窗外，外面是无尽的黑暗，他不知道废墟里有人，也不知道路上会遇到什么危险。\n\n　　但他知道，不去，车队根本赶不到目的地，没有汽油，靠双腿根本不可能甩开灰雾，普通人需要觉醒者庇护，他们觉醒者何尝不是，遇到危险的时候，让车队末尾的普通人垫，。\n\n　　争取逃亡时间的同时有更多的精力去击杀变异生物、诡异，获取资源让自己变得更强，这其实是一种相互需要的关系。\n\n　　还有一句话没说，那就是一旦遇到危险情况，只要比别人跑得更快就行了。\n\n　　“全体注意，全体注意，车队即将调整方向，所有人加快速度，跟紧车队。”\n\n　　前方的车辆开始转向，从原本的直线行驶，拐上了一条更破旧的道路，路面坑坑洼洼，车轮碾过碎石发出咯吱咯吱的声音。\n\n　　车速明显快了起来。\n\n　　林风跟在车队后面，看着前面的车辆突然加速，差点没反应过来。\n\n　　“搞什么飞机？”\n\n　　但也加快了脚步。\n\n　　小玄啃完最后一块虫肉，四条腿蹬蹬蹬蹬地跑起来，丝毫不费力。\n\n　　好家伙，跑得比我快，要是真遇到危险，打不过也能跑。\n\n　　车队在黑暗中彻底加速前行，巡逻的皮卡开到了车队两侧，车顶上的巡逻队员握紧了手里的武器，甚至有人握刀的手心全是汗。\n\n　　没有人说话，只有引擎的轰鸣与车轮碾过路面的声响。\n\n　　林风跟在最后面，一点也不紧张，看着有车队在前面开路，还有觉醒者坐镇，就算有危险跟他一个被踢出队伍的人有什么关系，\n\n　　天塌下来也有高个子顶着。\n\n　　夜色越来越浓，林风深一脚浅一脚地跟在车队最后面。\n\n　　忽然觉得，这样也挺好，虽然没有在大巴车里过得舒服，但这种依靠自己的感觉，心里反而踏实得多。\n\n　　不知走了多久，林风抬起腕表，看了一下时间，11:59分。\n\n　　这时候前方的车队，忽然就停了下来……\n\n　　麻烦来了……', 2233, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (15, 13, 13, '第13章 猎杀诡异', '　　不是缓慢减速，而是突然刹车，轮胎和地面摩擦发出刺耳的声音，紧接着，喊杀声从车队前方传来。\n\n　　林风的脚步猛地停住。\n\n　　借着前方车灯的光线，他看到车队已经停了下来，车顶上有人大喊。\n\n　　“那边！那边也有。”\n\n　　“守住，守住！”还有声音在夜风中凄厉地嚎叫，像是被什么东西活活撕裂了。\n\n　　林风感觉到了，一种阴冷，让人汗毛倒竖的气息，从四面八方涌来。\n\n　　后背瞬间绷紧，他调动灵能附在双眼上。\n\n　　这是觉醒者最基本的灵能运用，能大幅度提升感知能力，甚至能看到普通人看不到的东西。\n\n　　当灵能涌入双眼的瞬间，世界变得清晰了。\n\n　　就在林风前方不到50米的地方，一只通体漆黑的生物正在快速跑来。\n\n　　它的样子像一只大型犬，浑身缠绕着黑色的雾气，眼睛是猩红色的，爪子像匕首一样锋利，最吓人的是它的嘴，从耳根裂开，露出两排密密麻麻像锯齿状一样的牙齿。\n\n　　林风下意识地后退两步，手伸到身后，摸到背包侧面挂着的那两只锹甲虫的巨颚。\n\n　　这东西是林风临走的时候，从甲虫尸体上卸下来的，当时锹甲虫被小玄吃掉大半，这对镰刀状的巨颚完好无损，锋利得能当刀使，林风收拾东西的时候，随手就挂在了背包上。\n\n　　没想到这么快就用上了。\n\n　　林风刚把巨颚从背包上解下来，手还没有握稳。\n\n　　一道黑色的身影从脚边咻的一下就窜出去了。\n\n　　林风低头一看，小玄不见了。\n\n　　“小玄！”\n\n　　林风喊了一声，但已经来不及了，眼睁睁看着小玄冲到这只诡异生物的面前。\n\n　　那只诡异显然没有预料到一只乌龟能有这样的速度，猩红的眼睛闪过一丝惊愕，但它的本能比脑子更快，那双匕首般的利爪已经朝小玄的龟壳挥了下去。\n\n　　“嗤……”\n\n　　爪子在龟壳上划过，发出刺耳的摩擦声，那声音让林风的牙根都发酸。\n\n　　但小玄毫无反应，躲都没有躲一下。\n\n　　小玄猛地张开嘴，一口咬在诡异的前腿上。\n\n　　咔嚓……\n\n　　不像是骨头断裂的声音，就像是脆弱的玻璃碎裂一样，诡异的那条腿，在小玄的咬合下直接炸开，化作一团黑雾。\n\n　　那东西，发出一声尖锐的吼声，林风的脑子嗡的一下，差点没有站稳。\n\n　　“这鬼东西。”\n\n　　等林风回过神来，小玄已经又一口咬下去，这次咬的是诡异的脖子。\n\n　　咔嚓……\n\n　　诡异那双猩红的眼睛以肉眼可见的速度暗淡下去，然后整个身体开始崩解，从被咬碎的脖子开始，裂纹像蛛网一样开始蔓延，最后砰的一声，化作一团黑雾，消散在夜风中。\n\n　　原地只留下一颗黄豆大小的珠子，泛着微弱的光芒。\n\n　　【击杀0级诡犬一只，获得进化点0.5，当前进化点：1】\n\n　　“杀诡异也有进化点？”\n\n　　后面想想也对，凭什么杀诡异就没有进化点呢。\n\n　　不过没有想到的是小玄会强到这个地步，从冲出去，到击杀，前后不过短短几秒钟。\n\n　　“小玄，干得漂亮。”\n\n　　林风跑上前去弯腰捡起地上那颗珠子。\n\n　　诡晶，\n\n　　这就是陈敏说的诡晶了吧。\n\n　　珠子只有黄豆大小，表面光滑。林风能感受到珠子里面有一股能量，并且自己能吸收这颗诡晶里的能量。\n\n　　那种感觉很奇妙，身体的本能告诉他，吸收它，就能变强。\n\n　　林风没有犹豫，握着诡晶，按照本能引导体内的灵能去触碰它，诡晶就像是融化了一样，顺着手臂涌入体内，那个能量最终汇聚在小腹的位置，在那里形成了一个小小的气旋。\n\n　　【吸收0级诡晶一枚】\n\n　　【觉醒者等级0级（5%）】\n\n　　林风的眼睛亮了，一颗诡晶给5%的进度，也就是说，再来19颗，就能成为1级觉醒者。\n\n　　1级觉醒者会产生什么变化呢？没有人告诉他，不过这并不妨碍林风那颗火热的心。\n\n　　林风看向前方的车队，那里的喊杀声震天，那里有更多的诡异。\n\n　　按照以前的规律，诡兽这种东西，一到夜晚就会变得活跃，尤其是午夜12点前后，它们会本能地朝着生气聚集的地方汇聚，人越多，生气越浓郁的地方，诡兽就越多。\n\n　　车队每天晚上都不得不摸黑前行，一旦停留的时间过久，诡异就会像潮水一样汇聚而来。\n\n　　而林风一手握住一根巨颚当做武器，对着身边的小玄喊了一声。\n\n　　“小玄，跟上。”\n\n　　十几个呼吸的功夫，林风就跑到了车队尾部。\n\n　　车队已经乱成了一锅粥。\n\n　　诡异的数量比林风想象的多得多，不是几只，而是几十上百只像老鼠一样的诡异。\n\n　　这东西体型还不小，一个个体型堪比家猫，数量多得惊人，冒着猩红光芒的眼睛，牙齿大得离谱。\n\n　　人群已经乱了。\n\n　　那些骑着自行车，蹬三轮的最先遭殃，诡异从黑暗中涌出来，扑向人群，锋利的牙齿咬住人的喉咙，手臂，大腿，惨叫声此起彼伏。\n\n　　人群疯狂地往车队中心跑去，自行车，三轮车，物资散落得到处都是，有人被绊倒了，还没来得及爬起来，就被几只诡异的东西扑倒。\n\n　　“开门，开门啊。”有人敲打汽车的窗户，试图躲进去，但车里的人紧闭车门，躲在车里瑟瑟发抖，根本不敢开。\n\n　　巡逻队的人正在抵抗。\n\n　　加装了防护栅栏的皮卡和货车上的巡逻队员，手持钢刀长矛，与爬上车架的诡异厮杀在一起，但他们的人数太少，车队太长，根本顾不过来，而且诡异太多了，它们还有诡异莫测的精神攻击，普通人根本防不住。\n\n　　林风冲过来的时候已经有好几十个人躺在地上了，眼睁睁地看着一只诡异鼠在撕扯一个小孩的喉咙，鲜血流了一地。\n\n　　林风的手不由自主地握紧了武器，不是因为愤怒。\n\n　　而是因为诡晶，每一只诡异老鼠体内都有一颗诡晶。\n\n　　“小玄，上。”\n\n　　林风大喝一声，手持镰刀状的巨颚，冲向了离他最近的一只诡异老鼠。\n\n　　那只诡兽正扑向一个倒地的女大学生，张开大嘴就要咬向对方喉咙，那女生眼里全是绝望的神情，就在这时候，林风一记巨颚劈下。\n\n　　“嗤……”\n\n　　巨颚直接切下诡异的脑袋，诡异的身体立马变成雾气消散，一个珠子落在对方胸口上……\n\n　　就在对方惊魂未定之际，林风直接从对方胸口捡起那颗掉落的诡晶，还顺手摸了一下。\n\n　　“不用谢，手感不错……”', 2301, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (16, 13, 14, '第14章 抢了个人头', '　　同时小玄那边也传来了击杀的提示声。\n\n　　【击杀诡鼠一只，获得进化点0.2】\n\n　　林风走过去捡起诡晶塞进兜里。\n\n　　“下一个。”\n\n　　一人一龟配合默契，主要是小玄在前面杀，林风负责捡诡晶。\n\n　　主要是小玄的效率太高了，几乎是一口一个，速度又快，转眼间，就干掉了十几只诡鼠。\n\n　　每击杀一只诡鼠，就意味着救下了一人，被林风救下的人瘫坐在地上，大口大口地喘着气，看向林风的眼神里有震惊，有感激，还有劫后余生的恍惚。\n\n　　“是……是那个被王烈首领踢出核心队伍的觉醒者？”\n\n　　“他怎么这么强？”\n\n　　当然也有反应快的，连连感激地说道。\n\n　　“谢谢风哥，谢谢……”\n\n　　林风懒得管他们的态度，一只诡鼠，就是0.2进化点，和一颗诡晶。\n\n　　小玄下次进化需要100点进化点，积少成多，更何况，这里的诡鼠还有大个的。\n\n　　林风的目光锁定在不远处，一只狗子大小的诡鼠。\n\n　　那东西正朝着一辆躲在公交车后面的人冲过去。\n\n　　“小玄，那个！”\n\n　　小玄朝着林风手指的方向看去，四条腿一蹬，像一颗炮弹般冲了过去。\n\n　　那只诡鼠刚张开嘴，小玄就已经撞在了它身上。\n\n　　诡鼠被撞飞出去，在地上翻滚了两圈。\n\n　　它还没有爬起来，小玄已经扑了上去，一口咬住它的脖子。\n\n　　“咔嚓。”\n\n　　【击杀1级诡鼠1只，获得进化点1，当前进化点：3.6】\n\n　　哈哈，1点！\n\n　　林风大喜，跑过去捡起地上的诡晶，比黄豆大了一圈，除了诡晶，还有一颗鼠牙，林风捡起来，没有发现有什么用途，管他的，先塞背包里。\n\n　　看来击杀后获得的进化点，是按实力划分的，击杀的诡异越强获得的就越多，而且1级诡异除了诡晶外，还会出现其他物品，也不知道能干什么。\n\n　　不过这种收获的感觉真爽！\n\n　　林风把诡晶塞进口袋里，正准备继续，忽然听到，一阵破空声。\n\n　　抬头望去，就看到陈敏正站在一辆大巴车车顶上，身前漂浮着一把小刀，那刀身只有巴掌大小。\n\n　　这是？精神控物？\n\n　　陈敏的手指微动，那把小刀就像闪电般飞了出去，精准地穿透了一只诡鼠的脑袋。\n\n　　小刀子在空中划过一道弧线，又贯穿了第二只。\n\n　　第三只\n\n　　第四只\n\n　　第五只，诡鼠当场炸开，化作一团黑气消散。\n\n　　一息之间，五只诡鼠，全部毙命。\n\n　　林风的眼珠子差点没掉出来。\n\n　　这女人之前还说自己觉醒的能力是精神感知，能洞察危险……\n\n　　骗鬼呢？\n\n　　谁家好人精神感知能隔空控物，这女人藏得真深。\n\n　　林风深吸一口气，朝着陈敏的方向喊了一声：“敏姐！”\n\n　　陈敏转过头，看到是林风，微微一愣，然后嘴角勾起一抹弧度。\n\n　　那笑容里有几分意外，还有几分赞赏。\n\n　　但她没有说话，因为又一波诡异涌上来了。\n\n　　林风也没有说话，转身朝着另外一个方向跑去，反正其他方位也有诡异，不能让这个女人把怪全抢了。\n\n　　灵带着小玄，在战场边缘游走，专挑落单的诡异下手。\n\n　　【击杀1级诡猫一只，获得进化点2点。】\n\n　　【击杀1级诡鼠一只，获得进化点1点。】\n\n　　【击杀1级诡……】\n\n　　诡晶一颗接着一颗地塞进口袋，期间还得到一对泛着荧光的猫眼。\n\n　　林风的心跳越来越快。\n\n　　不是紧张而是兴奋。\n\n　　因为除了一袋子诡晶之外，进化点已经来到了91.2，林风都记不清杀了多少只了，今天出现的诡异比前几天夜晚遇到的多太多了，就像捅了马蜂窝一般。\n\n　　就在这时……\n\n　　一道耀眼的雷光在战场中央炸开。\n\n　　“轰隆隆……”\n\n　　雷声震耳欲聋，电弧在地面蔓延，像一条条银蛇，瞬间笼罩了方圆数十米的区域。\n\n　　足足十几只诡异被雷电击中，连挣扎都没有，直接化作黑雾消散。\n\n　　林风抬起头，看到王烈站在房车顶上，右手高高举起，掌心凝聚着肉眼可见的电弧。\n\n　　随着手往前一推，一道手臂粗的雷电从掌心射出。\n\n　　又一道雷光落下。\n\n　　“轰……”\n\n　　这次的目标不是那些小诡异，而是正中央那个体型最大的东西。\n\n　　一只老鼠。\n\n　　但不是刚才林风杀的那些普通货色，而是足足一头牛犊那么大一只，浑身覆盖着漆黑如墨的黑气，猩红的眼睛像两盏灯笼，散发着恐怖的压迫感。\n\n　　鼠王？\n\n　　此时它身上已经有好几处焦黑的伤口，电弧在它皮毛上劈啪作响，黑色的雾气从伤口处不断逸散，即使伤成这样，依然在挣扎。\n\n　　它张开嘴发出尖锐的嘶吼声。\n\n　　林风的脑袋只感觉一阵剧烈的疼痛传来，那感觉就像有人拿着钉子在往太阳穴里钉。\n\n　　周围的普通人更加不堪，纷纷捂住脑袋，痛得直打滚，嘴里发出痛苦的惨叫声。\n\n　　王烈丝毫不慌，左手也举起来，双手合拢，掌心的雷光汇聚成一个球体，越来越大，越来越亮。\n\n　　然后他将那颗雷球扔了过去，与此同时，林风也把一把镰刀般的巨颚扔了过去。\n\n　　林风一手捂着头，想也不想，就把手里的巨颚对准鼠王的方向狠狠扔去。\n\n　　“嚎你妹啊，看刀，我弄死你……”\n\n　　“轰隆……”\n\n　　雷光炸裂，刺目的白光让林风不得不闭上眼睛。\n\n　　等林风再睁开眼睛的时候，鼠王已经不见了，原地只有一个被雷电炸出来的一个深坑，坑边的泥土还在冒烟，空气中弥漫着一股焦臭的味道。\n\n　　【击杀2级诡鼠王，获得进化点10，当前进化点101.2】\n\n　　“啊？”\n\n　　突如其来的提示让林风惊住了，不是，我就扔了一把刀过去，最多也就能扎个口子吧，这也有进化点，难道辅助击杀也算人头？。\n\n　　如果是这样的话，那我以后要抢人头了啊……\n\n　　不过看到王烈的目光看向自己后，林风顿时收起小心思，想也不想转头就走，别说战利品了，看都不敢去看一眼，连自己那只锹甲虫的巨颚都不要了。\n\n　　“看不见我，看不见我……”\n\n　　不是怂，是识时务，在末日世界里，活得久的人不一定是最能打的，而是最清楚自己有几斤几两的，不该自己的东西别去想。\n\n　　王烈自始至终都没有从房车顶上下来，或许看见林风了，但他没有在意……', 2264, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (17, 13, 15, '第15章 小乌龟终于可以骑了', '　　鼠王被击杀后，剩下的诡异很快便被清理干净了。\n\n　　荒野重新恢复了平静，地上躺着上百具尸体，浓郁的血腥味和属于诡异的腐臭味交织在一起，令人作呕。\n\n　　“所有人注意，所有人注意，休整10分钟，十分钟后车队出发，重复……”\n\n　　十分钟！\n\n　　连埋葬同伴的时间都没有。\n\n　　林风站在人群边缘，看着这一幕，什么都没有说。\n\n　　这就是末日。\n\n　　林风低头数着口袋里的诡晶，1级的足足70多颗，0级的没有细数，一两百颗怎么都有吧。\n\n　　背包里更是塞满了一堆诡异掉落的材料，十几颗鼠牙，一对猫眼……\n\n　　正准备找个地方坐下来吸收诡晶的时候，一阵嘈杂声传来。\n\n　　“这是我的，我先拿到了！”\n\n　　“放你娘的屁，我比你先看到！”\n\n　　“你们别抢，这是老张的东西，他人都没了……”\n\n　　“人没了就是无主的东西，凭什么不能拿？”\n\n　　林风转过头望去，看到几个男人围在一辆三轮车旁边，正在争抢车斗里的东西。\n\n　　三轮车歪倒在一旁，车的主人已经死了，就躺在旁边，眼睛还没有闭上。\n\n　　而那几个人，没有一个人去看他一眼。\n\n　　他们都在抢他的东西。\n\n　　野菜，小半袋面粉，几瓶水，一床破被子，这些在末日之前不值一提的东西，此刻却成了几个人争抢的目标。\n\n　　有人动手了，一拳打在另外一个的脸上，被打的也不甘示弱，抄起一根木棍就砸了过去。\n\n　　这样的场景不止一处，在许多失去主人的物资旁都在发生。\n\n　　“别打了，别打了！”有人在大喊，但没有人听。\n\n　　活着的人在争抢无主的物资，那些地上散落的背包，袋子，人们就像疯了一样扑上去，把能拿到的东西往自己怀里塞，有人在哭，有人在喊，有人在骂。\n\n　　死者的尸体被踩来踩去，没有人多看一眼。\n\n　　林风看了一会，移开了目光。\n\n　　在末日里，活着是第一位的。\n\n　　忽然，林风思维发散得有点远，他想到了自己那辆大巴车上的两个女人转身走向董雨的背影。\n\n　　还有那个被自己男人拉走的女人。\n\n　　活着的代价，就是就这样一点一点丢掉了在和平年代称作人性的东西。\n\n　　林风不知道此时自己心里面在想什么，有些说不上来。\n\n　　“小玄，走了……”\n\n　　林风拍了拍小玄的龟壳，朝着车队后方走去。\n\n　　找了一个安静的地方，从包里掏出一颗1级诡晶吸收起来。\n\n　　当前等级：0级15%\n\n　　“还不错，1级诡晶能提升10%的进度。”\n\n　　“就是比吸收0级诡晶的速度慢一点，来让我看看升级到1级是什么感觉。”\n\n　　林风一颗接着一颗的吸收诡晶。\n\n　　【提示：已满足晋级条件，是否晋级1级。】\n\n　　“晋级！”\n\n　　林风没有丝毫犹豫，在心里默念了一声。\n\n　　一股强烈的热流从小腹处爆发，沿着经脉涌向四肢百骸，从天灵盖到脚底板 ，整个过程持续了大约半分钟。\n\n　　林风感觉自己的感官变得更加敏锐了，在黑暗中能看到更远的地方，甚至能感觉到空气中游离的微薄能量。\n\n　　林风\n\n　　等级：1级（0%）\n\n　　体质：24\n\n　　力量：23\n\n　　敏捷：24\n\n　　精神：32\n\n　　灵能：34\n\n　　天赋1：御兽（本命御兽1/2）\n\n　　天赋2：无限进化（你的御兽能无限进化，并能选择一项御兽的能力作为自己的天赋能力）\n\n　　林风看到面板上的数字后，心里涌起一股强烈的喜悦。\n\n　　他变强了！\n\n　　只是从0级升级到1级，林风就能感觉到自己的实力提升了一大截，还有一个新的御兽空位，最近看看能不能再契约一只御兽。\n\n　　“对了，还有小玄，刚才抢了个人头，进化点够进化了。”\n\n　　“小玄，过来！”\n\n　　【本命御兽：玄龟（小玄）当前进化点：105，可进化。】\n\n　　“进化。”\n\n　　林风毫不犹豫地选择了进化。\n\n　　“嗡……”\n\n　　小玄的身体开始微微发光，不是那种刺眼的光芒，而是一种温润的光芒，从龟壳的纹路中透出来。\n\n　　然后，小玄的身体开始以肉眼可见的速度膨胀起来，脸盆大小的龟壳以肉眼可见的速度向外扩张，边缘的甲壳像是被无形的力量拉伸。\n\n　　龟壳一层层叠加、增厚，它的四肢变得更加粗壮有力，爪子锋利如钩，尾巴也变得更加粗长，皮肤上同时长出层层叠叠的角质化鳞甲。\n\n　　【获得进化反馈：体质：+36，力量：+27，敏捷：+22，精神：+26，灵能：+27】\n\n　　当光芒彻底散开的时候，林风整个人都愣住了，下意识地后退两步，眼睛瞪得溜圆。\n\n　　“我的个龟龟……”\n\n　　小玄现在的体型，大得离谱。\n\n　　原本只有脸盆大小的小乌龟，现在站起来，龟壳腹甲离地足足有一米多高，背甲顶部比林风还高出一个头。\n\n　　林风仰着头看着眼前的家伙。\n\n　　“你这也太猛了吧。”\n\n　　小玄显然对自己的新体型十分满意，兴奋地甩着尾巴，在地面上拍出“砰砰”的闷响，它低下头，用那颗硕大的脑袋往林风胸口蹭了过去。\n\n　　“砰！”\n\n　　“哎……哎哎哎……”\n\n　　林风直接被顶了一个趔趄，整个人往后退了两三步，差点一屁股坐在地上，好不容易才稳住身形。\n\n　　“啪！”\n\n　　气得林风反手就是两巴掌拍在对方脑袋上。\n\n　　“艹，悠着点！悠着点！你也不看看你现在多大的个？你要是再长大点，这要是被你蹭一下，我还不得飞出去？”\n\n　　小玄被拍了也不恼，反而发出‘咕咕’的声音，像是在笑。\n\n　　林风围着它转了两圈，越看越满意，越看眼睛越亮。\n\n　　“这不就是现成的载具吗？”\n\n　　今天用腿跟着车队走了差不多四五个小时，虽然说以林风现在的体质并不觉得累，但能偷懒享受，谁还想走路啊！\n\n　　尤其是现在的路况越来越差，坑坑洼洼的，走路还得低头看路，累都累死了。\n\n　　“小玄，趴下！”\n\n　　小玄闻言，立刻温顺地趴伏下来，巨大的龟壳贴到地面。\n\n　　林风双手撑住龟壳边缘，一个翻身就跨了上去，宽阔的背甲比想象中的还要大，椭圆形的龟甲宽度应该有一米五左右，长应该有两米多，而且背部也没有想象的那么陡峭，反而很平缓。\n\n　　这么大的面积，别说坐着了，就算身边再躺三四个美女，都没有问题。', 2282, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (18, 13, 16, '第16章 共享御兽天赋', '　　林风把背包往龟壳中央上一放，坐在龟甲上，整个人斜靠在背包上。\n\n　　“小玄，走着，跟上车队。”林风拍了拍龟壳。\n\n　　小玄四条腿一撑，站了起来。\n\n　　林风的身体微微晃了一下，很快就稳住了，然后他迈开腿，开始往前走，速度越来越快。\n\n　　林风坐在小玄背上，感觉着风呼呼地吹。小玄四条粗壮的腿交替迈动，每一步都跨出近一米的距离，速度快得像一匹小马驹在奔跑。\n\n　　而且很稳，非常稳。\n\n　　虽然是跟着车队最后面，地面坑坑洼洼的，但小玄的身体完美地吸收了颠簸，传到林风屁股底下的时候，只剩下细微的晃动，几乎可以忽略不计。\n\n　　“嗯~安逸，还是躺着舒服啊。”\n\n　　这叫风水轮流转，小时候我抱着你，现在该你驮着我了。\n\n　　小玄发出“吭哧”一声，似乎在抗议。\n\n　　“哈哈哈，抗议无效。”林风开心地笑了笑，把手枕在脑后，看着天上稀疏的星光，又抬手看了看手腕上的手表。\n\n　　凌晨一点五十分。\n\n　　距离天亮还有好几个小时。\n\n　　“来让我看看你现在的变化……”\n\n　　本命御兽：玄龟(下次进化需要1000点进化点，当前进化点：5)\n\n　　等级：2级\n\n　　体质：400\n\n　　力量：300\n\n　　敏捷：260\n\n　　精神：280\n\n　　灵能：300\n\n　　能力1：食土（注：可以通过吞噬矿物与土壤获得生存所需，大量吞噬矿物体型将大幅度增长。）\n\n　　解锁能力2：控土术（注：玄龟获得土系控制能力……）\n\n　　“这合理吗？玄龟的基础属性比自己这个主人强了十倍不止，而且又觉醒了一个控土术的能力……”\n\n　　“真是人比人气死人，这么强的龟，谁打得过，就算是王烈也不行吧。”\n\n　　“哦，这是我的龟啊，那没事了，今天起，我不吃牛肉……”\n\n　　林风长长的吐出一口浊气……\n\n　　“对了，我好像可以选一个御兽的能力成为自己的天赋，这控土术，就很不错。”\n\n　　【是否选取控土术作为自己的天赋？】\n\n　　“是！”\n\n　　这还需要犹豫吗？秒选。\n\n　　一股仿佛源自灵魂深处的波动在身体里炸响，然后涌遍全身，林风清晰地感知到不一样了。\n\n　　那就是似乎能操控周围的土系能量，尤其是与大地产生了共鸣一般。\n\n　　“小玄，停一下！”\n\n　　见小玄停下来后，林风意念一动，只见不远处的大地上。\n\n　　“噗噗噗……”连续冒出一根根土黄色的尖刺。\n\n　　然后尖刺消失，瞬间聚拢，化土为石，仿佛那里原本就是一块大石头一样。\n\n　　在这一瞬间，林风脑海里就想出了无数种攻击方式，比如化作流沙限制敌人，化作土墙阻挡攻击等等……\n\n　　这控土术简直太好用了，林风一一试验自己的想法，就像一个小孩子得到心爱的玩具一般，玩得不亦乐乎，直到精神力消耗一空，一股疲惫感传来，太阳穴一阵阵的疼，才停了下来。\n\n　　“卧槽，玩过头了，我先眯一下缓缓……”\n\n　　“小玄，走吧，记得跟上车队！”\n\n　　车队在远处亮起的灯光明灭不定，大巴车，卡车，三轮车，自行车……各种能动的载具连成一条歪歪扭扭的长龙，在夜色下缓慢前行。\n\n　　小玄的速度，比车队快得多，不到十分钟，就追上了尾巴上的三轮车，车斗上的人看到一个巨大的黑影从旁边冲过去，吓得差点从车上跳下。\n\n　　“卧槽，那是什么东西？”\n\n　　“大……大乌龟！”\n\n　　“操，那么大一只，不会是诡异吧！诡异来了！”\n\n　　林风被人吵醒，很不爽，揉着眼睛坐起来，冲着那些人摆摆手。\n\n　　“鬼叫什么，这是我的御兽……”\n\n　　那些人，这才看清龟背上还坐着个人，一个个的瞪大了眼睛，脸上的表情从惊恐变成了震惊。\n\n　　最终化作浓浓的羡慕。\n\n　　坐在一头巨大的乌龟上，这排面，比坐什么大巴车还拉风。\n\n　　“是……是林风？”\n\n　　“那个被首领踢出核心队伍的觉醒者？”\n\n　　“可是他那只乌龟不是只有巴掌大吗？怎么长这么大了？”\n\n　　“你问我，我问谁？”\n\n　　小玄从队伍旁边跑过去，一路上引来无数的目光，议论声此起彼伏，从车位一直传到车队前方，跑过一辆面包车的时候，车里的一个大姐手里的野菜团子都吓掉了。\n\n　　甚至有胆子大的人趴在车窗上大声问。\n\n　　“风哥，你这乌龟哪里弄的？”\n\n　　林风一概没理，让小玄跑到了车队靠前的位置，找到了自己曾经坐的那辆大巴车。\n\n　　林风往车窗里看去，驾驶座上坐着一个不认识的陌生男人，满脸胡子，正叼着一支没有点燃的烟，末日里，烟酒比粮食还贵，显然是一直含在嘴里舍不得抽。\n\n　　车里面被重新改造了一番，车厢里密密麻麻坐满了人。\n\n　　林风目光往车里扫视了一圈，曾经睡的那张大床不见了。\n\n　　曾经用过的天鹅绒被子也不见了，取而代之的是两排座位，上面坐着几个陌生女人，正抱着脏兮兮的背包打瞌睡。\n\n　　还有曾经珍藏起来的水果罐头和杂志也不见了，现在什么都没有了。\n\n　　“真是人走茶凉啊。”\n\n　　林风皱了皱眉头，说实话，小玄进化到2级后，本来是想仗着实力大增，回来拿点东西的。\n\n　　那张大床，还有那张天鹅绒被子，是他当初分配物资的时候，死皮赖脸地要来的，为此还少要不少吃的，整个车队独一份，连队长王烈都没有那么好的被子。\n\n　　本来打算要回来后，让小玄配合自己用控土术在龟背上建一个小房子，然后把床往里面一搁，那才叫真正的移动家园。\n\n　　想想都觉得舒服\n\n　　现在好了，连根毛都没剩下。\n\n　　小玄似乎也感受到了主人的情绪，脚步也慢了下来。\n\n　　“没事，走吧！”\n\n　　林风本来也没有打算再上那辆大巴车，有小玄在，谁还愿意坐车里，只是自己的东西就这样没了，心里难免有些膈应。\n\n　　小玄驮着林风，继续在车队里前行，巨大的体型，自然早就引起了几个觉醒者的注意。\n\n　　此时，豪华房车里，气氛有些微妙。\n\n　　窗帘被拉开一条缝隙，几个人轮流凑在窗前，看着车队里那只不急不缓的巨大乌龟。\n\n　　“这小子……”', 2222, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (19, 13, 17, '第17章 到达小镇', '　　“这小子……”陈敏第一个开口，声音里带着说不清道不明的情绪。\n\n　　“他那小乌龟，怎么一下子长这么大了？”\n\n　　没有人回答她。\n\n　　因为没有人知道答案，觉醒者的能力千奇百怪，谁会想到林风这个没什么作用的御兽师，现在能变得这么强。\n\n　　那只乌龟所有人都看过，不过是一只巴掌大、灰扑扑、整天缩在壳里睡觉的小东西，没想到会变得这么强。\n\n　　看看现在！\n\n　　那只乌龟的背甲目测至少两米多长，站起来比人还高，四条腿粗得像柱子，跑起来快得像马，那锋利的利爪，和凶悍的头颅，可以想象得到，这只乌龟的战斗力绝对不弱。\n\n　　这他妈的是一只什么怪物？\n\n　　“进化了，”王烈的声音有些低沉，“至少是2级御兽……”\n\n　　“2级？那不就是跟队长一个等级……”江声不可思议地说出声，还有一句话他不敢说，那就是队长王烈也才2级，搞不好现在队长都不一定能打得过林风的御兽。\n\n　　“我早就说过，那个人留不得，最开始就不应该留在核心队伍里面……”董雨的脸色顿时难看起来。\n\n　　原因很简单，她昨天才从林风那里抢了两个女人，现在那两个女人就在她大巴车里，伺候了她一下午。\n\n　　现在林风的实力这么强，如果他重新回到核心队伍里，那两个女人会怎么想？\n\n　　会不会跑回去。\n\n　　最关键的是，会不会给自己穿小鞋？\n\n　　董雨不敢想下去。\n\n　　“留不得？人家现在就在车队里，你还能把他赶走试试，就凭你那两把刷子，经得住他那乌龟一爪子不？”\n\n　　董雨被噎了一下，脸色更难看了。\n\n　　刘铁柱的脸色也不好看。\n\n　　至于原因，说起来有些难以启齿。\n\n　　那个少妇。\n\n　　就是当初被她男人主动送上车的那个少妇。\n\n　　林风被踢出核心队伍后，她男人第一时间就把她从林风身边拉走了，为了能在车队里获得更多的庇护和物资，那个男人又把他老婆送上了刘铁柱的床。\n\n　　刘铁柱本来是拒绝的……至少他现在是这么想的。\n\n　　但那少妇却是长得不错，三十不到，身材丰腴，说话的声音软糯糯的，一开口骨头就先酥了半边。\n\n　　再加上她男人在旁边点头哈腰，说：“柱哥不嫌弃，就让她伺候您……”\n\n　　刘铁柱就“勉为其难”地收下了。\n\n　　当时刘铁柱心里很享受，但如果林风回来了，接下来会发生什么他不敢想。\n\n　　刘铁柱不敢想，所以他也不希望林风重新回来。\n\n　　“不过我倒是觉得可以拉拢一下，那么大一只乌龟，这要是遇到大股诡异，往前面一挡，那就是一面活盾牌啊。”\n\n　　“你想多了，人家的御兽，凭什么给你当盾牌……”\n\n　　大家你一言我一语，谁也说服不了谁。\n\n　　沈雨桐没有说话，安静的坐在角落里，拿着一支笔在地图上画着什么。\n\n　　“好了！”王烈开口了。\n\n　　房车里安静下来，所有人的目光都落在他身上。\n\n　　王烈沉默了几秒，然后说道：“先到目的地去再说，等到了小镇，我找他谈谈。”\n\n　　他心里清楚得很，当时组建车队时，是他去拉拢的林风；后来林风好几天都没表现出觉醒者的价值，把林风踢出队伍也是他拍板的。\n\n　　虽然当时林风也没有什么异议，但这种事情搁谁身上都不舒服，现在人家的御兽变得这么猛，自己再舔着脸去拉人家回来，面子上实在过不去。\n\n　　但为了接下来的生存考量，他只能放下面子去找林风谈谈。\n\n　　其实大家心里面都明白，多一个觉醒者的力量，生存的保障就多了一分，从最初的几千人，到现在只剩一千多人的车队，可想而知有多么危险。\n\n　　尤其是现在夜晚的诡异越来越强，越来越多……\n\n　　房车里恢复了安静，只有引擎的轰鸣声和车轮碾过路面的声响，在夜色中回荡。\n\n　　车队一路走走停停，终于在黎明前到达了小镇外围。\n\n　　天还没有完全亮，小镇出现在众人眼前。\n\n　　自从蓝星坠入这个世界后，这是第二次遇到了蓝星的建筑，第一次就是他们穿越的地方，不仅找到了大量的车辆，还有丰富的物资，才让车队坚持到了现在。\n\n　　车队的喇叭响了起来。\n\n　　“全体注意，全体注意，前方到达修整点，所有车辆减速慢行，不要进入小镇中心，车队将停在小镇外围修整，等觉醒者肃清危险后再进入，重复……”\n\n　　车队缓缓停在小镇外围一处空地上，车辆一辆接着一辆的熄火。\n\n　　人们开始从车上下来，伸懒腰，活动筋骨，搭帐篷，赶了一夜的路，无论是精神还是身体都无比疲惫。\n\n　　这一夜，太漫长了。\n\n　　七十公里的路，走了整整一夜，遇到大规模诡异袭击，人员伤亡，物资损失，每个人都累得像散了架一样。\n\n　　没有人抱怨，因为末日世界里，能活着走到天亮，本身就是最大的幸运了\n\n　　很快，从大巴车下来的后勤人员，开始清点物资、人员，指挥大家搭建营地，开始工作。\n\n　　整个车队准确来说应该有3个梯队，第一梯队，就是核心成员，9名觉醒者，哦，不对，现在林风已经不是了，那就是8名觉醒者，掌握对抗变异生物与诡异的力量，同时引领车队前进的方向。\n\n　　掌握着车队里最好的物资和车辆，唯一的那辆改装豪华房车和几辆大巴车都是他们的。\n\n　　第二梯队，则是巡逻队员和后勤人员，巡逻队的待遇比后勤成员要好很多，发放武器，提供足以吃饱的食物，唯一的缺点就是伤亡最重，但依然有愿意为了吃饱饭选择拼命的，几乎都是男人。\n\n　　而后勤人员，大部分都是从巡逻队的亲属中选择的，负责统计物资，分配物资，搬运资源，每天也有不错的食物配额分配，相对安全很多。\n\n　　而第三梯队，就是大部分普通人，要么有自己的车，要么有一辆共享单车，跟在车队后面，明面上受车队保护，实际上每次断尾求生，被舍弃的都是他们。\n\n　　而每次收集的物资还要上缴一半到车队里，生存得最艰难。\n\n　　林风从小玄背上跳下来，活动了一下有些僵硬的脖子，在龟背上眯了好几个小时，此时精神还不错。\n\n　　小玄趴在地上，开始刨土，看起来精神头很好。\n\n　　林风望着小镇的方向，皱了皱眉头。\n\n　　太安静了，这个镇子安静得有些不对劲……', 2270, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (20, 13, 18, '第18章 物资告急', '　　太安静了，这个镇子安静得有些不对劲……\n\n　　本来还打算等天彻底亮了，带着小玄进镇子里搜刮一番，现在的小玄今非昔比，2级玄龟，各项属性都是自己的十余倍，加上控土术，就算遇到什么危险也不至于吃大亏。\n\n　　但现在站在这座小镇面前，林风忽然觉得，谨慎一点不是什么坏事。\n\n　　“算了，先看看情况再说。”\n\n　　林风觉得先不进去了，等车队里的其他觉醒者行动了再说，反正他不是一个人在送死，前面还有王烈他们盯着，自己在后面捡漏就行。\n\n　　没必要逞能。\n\n　　先吃东西，林风来到小玄跟前，它正趴在地上，用前爪刨出一个浅坑，然后低下头，张开嘴，咔嚓咔嚓的啃起土来。\n\n　　林风看得眼皮直跳。\n\n　　“你还真吃土啊？”\n\n　　小玄头也不抬，继续啃，土屑纷飞，像一台挖掘机。\n\n　　林风想起小玄的能力“食土“——可以通过吞噬矿物和土壤获得生存所需，并壮大体型。\n\n　　行吧，吃土就吃土，反正免费，不吃白不吃。\n\n　　林风懒得管，在附近转了一圈，找到一棵枯死的树。\n\n　　树干有大腿粗细，林风抬起腿，对准树干根部，就是一脚踹过去。\n\n　　“咔嚓……”\n\n　　树干应声而断。\n\n　　林风弯腰捡起枯树，拖着就往回走，这点重量，对林风来说就跟拎着玩似的。\n\n　　等拖回营地后，林风将枯木放地上，直接徒手劈碎。\n\n　　咔嚓，咔嚓，咔嚓……\n\n　　三两下功夫，一整棵树就变成了长短不一的柴火。\n\n　　不远处正在搭帐篷的人看到这一幕，眼睛都直了。\n\n　　“我艹，徒手劈木头？”\n\n　　“这就是觉醒者吗？这太猛了吧……”\n\n　　林风对周围的目光熟视无睹，找了一捆枯草，就掏出昨天从车队里换来的防风打火机，啪啪按了两下，火苗窜起来，很快便将枯枝引燃了。\n\n　　林风跑去小玄的背上，翻出昨天没吃完的变异蚂蚱，处理干净后就直接放在火上烤。\n\n　　炭火舔舐着蝗虫的甲壳，滋滋作响，香味很快就在空气中弥漫开来。\n\n　　林风一边烤一边等。\n\n　　等车队里的觉醒者商量出结果，等他们决定什么时候进镇子。\n\n　　反正他不急。\n\n　　…………\n\n　　与此同时，车队前方，那辆打头的豪华房车旁边，郭逸手里拿着一份后勤队员统计出来的报告，眉头拧得像麻花。\n\n　　“车队车辆大致情况统计出来了。”\n\n　　他走到王烈面前，把报告递了过去。\n\n　　“队长，现在我们车队的公共车辆还有房车1辆，大巴车7辆，其中2辆需要大修，不然跑不了多远，公交2辆，货车4辆，皮卡3辆，轿车11辆，……，大部分都需要维修……”\n\n　　王烈接过报告，等着郭逸继续说。\n\n　　“关键是汽油，现有的汽油储备，省着点用，最多还能撑5天，五天之后，一半以上的车都会趴窝。”\n\n　　“而且按目前的进度，五天我们到不了原定的目的地。”\n\n　　沈雨桐的声音从旁边传来。“下一个补给点在330公里外，以目前的速度，最少需要六天，前提是路上不再出现状况，我们的时间不多了，灰雾最多还有5天就追上来了。”\n\n　　5天，仅剩5天，如果路上再遇到一次像昨晚那样的诡异袭击，耽误了行程，不仅仅是汽油不够用，最关键的是灰雾……\n\n　　王烈的脸色沉了下来。\n\n　　“还有，”郭逸继续说，“除了我们的车辆，车队里的私人车辆太多了，我一个人根本忙不过来维修，我才1级，很多损伤的车辆，根本就没有备用零件，我修起来很吃力，而且一旦遇到需要大修的车辆就要花大半天时间……”\n\n　　他顿了顿，说出了自己的建议。\n\n　　“队长，我建议，属于我们的公共车辆，抛弃小型汽车，拆卸零件，集中资源改装货车和大巴车，然后把燃油集中起来，优先保障我们核心车辆的运转，我们不知道还要走多久，能省一点是一点，至于车队里的私人车辆我真无能为力了，毕竟我才一级。”\n\n　　这话一出，旁边的几个人都沉默了。\n\n　　他们都知道这意味着什么……\n\n　　那些骑着自行车，开着自驾车跟着车队的普通人，一旦车辆损坏，或者速度跟不上，那么在这个末日世界里，跟送死没有什么区别。\n\n　　王烈沉默了几秒，点了点头。\n\n　　“按你的意思来，你抓紧时间改造车辆，需要什么跟后勤说，让他们准备相应物资，然后……”\n\n　　“让人挤一挤吧……”\n\n　　郭逸点头：“没问题，如果专心改造核心车辆，我有把握把车子的性能提升一节，就是需要把轿车拆料作为改造材料……”\n\n　　就在这时，方玲从旁边走来，她的脸色有些疲惫。\n\n　　“队长，我统计了一下人数，经过昨晚的诡异袭击后，车队现在还剩975人！”\n\n　　王烈的手指微微动了一下。\n\n　　从最初的几千人，到现在不到一千人。\n\n　　每一次停下，每一次出发，都有人永远的留在了路上。\n\n　　这就是末日。\n\n　　“物资呢？”王烈问。\n\n　　方玲摇摇头：“不多了，车队现在几乎都是靠野菜在撑，那些挖回来的野菜，加上之前剩下的米面，最多还能撑三天。”\n\n　　“也就是说，我们必须在这个小镇找到足够的物资，还必须完成车辆改装，提升速度才能继续前进……”王烈的语气平静，就像是在陈述一个事实。\n\n　　“雨桐，小镇的危险等级，你能感知到吗？我看着有点不对劲。”\n\n　　沈雨桐抬起头，一双漂亮的眼睛望着小镇的方向，她的瞳孔似乎有什么东西在流转，像是星辰的光芒。\n\n　　“2级危险。”\n\n　　“2级？”刘铁柱的声音拔高了一些，“那不就是跟队长和敏姐一个等级？”\n\n　　沈雨桐没有理他，继续说：“但是……我感觉很不安。”\n\n　　“占星给我的反馈是2级，但我的直觉告诉我，事情没有那么简单，小镇里面……有什么东西在干扰我的感知。”\n\n　　王烈转向陈敏。\n\n　　“你呢？”\n\n　　陈敏闭上眼睛，她的精神力像一张无形的网，朝着小镇的方向延伸过去。\n\n　　片刻后，陈敏睁开眼睛，说道。\n\n　　“我的精神感知给我的反馈是……很危险。”\n\n　　“有多危险？”\n\n　　“我说不清楚，”陈敏摇摇头，“小镇的中心有一层雾挡在前面，我的精神无法靠近，但它直接告诉我，别进去。”\n\n　　队里两个拥有感知能力的觉醒者，都给出了相同的结论。\n\n　　危险！\n\n　　但车队必须获得补给，汽油快没了，食物快没了，如果不从镇子里找物资，所有人都会死在路上。\n\n　　王烈沉默了几秒，做出了决定。\n\n　　“你们准备一下，吃完早饭就进镇子，我去找林风谈谈……”', 2387, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (21, 13, 19, '第19章 合作', '　　清晨的空气还有些凉，王烈穿过停得密密麻麻的车辆，往营地边缘走去。\n\n　　林风的火堆很好找，王烈靠近的时候，看到林风手里正举着几串烤的焦黄的蚂蚱，旁边那个大坑里还趴着那头巨大的乌龟。\n\n　　近距离看，这只乌龟压迫感更强，小玄察觉到有人靠近，缓缓抬起头，铜铃大的眼睛盯着王烈看了两秒，又懒洋洋地低下头继续啃土。\n\n　　王烈心里嘀咕了一下，估算着这只乌龟的战斗力，面上不动声色地走了过来。\n\n　　林风早就看到他了，但没有起身，甚至动都没动弹一下，举起手里的蚂蚱晃了晃。\n\n　　“要不要来点？“\n\n　　王烈看着那串烤的焦黄的蚂蚱，沉默了两秒，接了过去。\n\n　　他记得第一次见林风的时候，这年轻人虽然不至于畏畏缩缩，但说话做事都带着一种小心翼翼的分寸感，生怕得罪了谁似的。\n\n　　现在呢，看到自己过来，连姿势都没有换，随口一句‘要不要来点’跟认识了八辈子的老熟人一样。\n\n　　这就是实力带来的底气吧。\n\n　　王烈咬了一口蚂蚱，出乎意料的香。\n\n　　“味道不错。”\n\n　　“那当然，”林风咬了一口，“我手艺还是可以的。”\n\n　　又是一阵沉默，林风知道王烈是来干什么的，但他不打算先开口。\n\n　　他现在不是那个一无是处、只知道在大巴车里逃避问题的废物了。\n\n　　林风现在有底气等对方先说话。\n\n　　王烈吃完一整串蚂蚱，把树枝丢进火堆里，终于开口了。\n\n　　“我承认，我小看你了。”\n\n　　林风没有接话，把手里那串也吃完了，随手用袖子擦了擦嘴。\n\n　　“我今天来找你，本来是想重新邀请你回核心队伍的。”\n\n　　王烈看着林风，火光在林风的脸上投下明暗交错的光影，又转头看了一眼旁边的小玄。\n\n　　“不过看你的样子，对我还有怨言。”\n\n　　林风笑了一下，没说是，也没说不是。\n\n　　“所以我也不强求。”王烈把目光移开，落在远处的小镇上。\n\n　　“我想说的是，同为觉醒者，共同的目的是活下去，如果再来一次，我还是会做同样的决定……”\n\n　　“你当时确实没有任何价值。”\n\n　　这话说得很直白。\n\n　　林风反而觉得舒服了一些，至少王烈没有说什么“当时我也没有办法”、“我也是为了车队考虑”之类的屁话。\n\n　　他就是明明白白的告诉你，你当时没用，所以我把你踢了。\n\n　　现在你有用了，所以我来找你。\n\n　　简单，直接，不装。\n\n　　“我们合作吧。”王烈伸出手\n\n　　“既然你还愿意跟着车队走，说明你也知道一个人单独的风险，我们各取所需，等一会清理小镇里的危险，获得的战利品各凭本事，如何？“\n\n　　林风没有立刻回答。\n\n　　他在想，合作，对自己而言，确实是最好的选择。\n\n　　林风确实需要车队，不是像那些普通人一样需要觉醒者的保护，恰恰相反，林风拥有的力量能庇护普通人，但是有一条林风自己解决不了——认路。\n\n　　这个世界没有导航，没有地标，连天空中的星辰都是陌生的，他看过沈雨桐绘制的地图，上面标注的路线弯弯绕绕。\n\n　　就像昨晚一样，从出发到这里不过区区70公里。\n\n　　70公里，如果在蓝星，开车不到一个小时的路程。\n\n　　可实际上呢，车队走走停停，绕来绕去，整整走了一夜，为什么，因为到处都是诡异盘踞的区域，直接扎进去就是找死。\n\n　　沈雨桐那个占星、绘测地图、预知危险和规划路线的能力，就是在密密麻麻的死亡陷阱中找出一条相对安全的路线，这种能力林风没有。\n\n　　虽说林风可以单干，但单干的下场就是像无头苍蝇一样在这鬼地方乱撞，最后扎进某个高阶诡异的领地，连怎么死的都不知道。\n\n　　而且，进小镇这种事情，一个人进去跟一群人进去的风险完全不同。\n\n　　就算遇到不可抗拒的危险，只要跑得比同伴快，不就行了\n\n　　“可以，”林风握住王烈的手，然后松开。“我们合作。”\n\n　　王烈的表情明显松了一些。\n\n　　“不过……”林风又开口了，“各凭本事是什么意思，我杀了诡异，获得的东西归我？”\n\n　　“对，各自击杀的收获归自己，找到的物资也一样。”\n\n　　“合作击杀呢？”\n\n　　“按出力比例分，如果我有需要的东西，补偿你等价值的其他物品。”\n\n　　林风想了想觉得这个方案还算公道。\n\n　　“行，没问题。”\n\n　　王烈谈完了，没有多留，转身走了。\n\n　　林风看着他的背影消失在人群中，默默地吃完了最后几串烤蝗虫。\n\n　　…………\n\n　　王烈回到房车那边的时候，其他几位成员已经聚集在一起了。\n\n　　方玲在检查自己的装备，两把匕首，一把弩，她将那把匕首绑在腿上插好，弩挂在腰间，动作利落。\n\n　　陈敏靠在车门上，手里把玩着那把银白色的小刀。\n\n　　刘铁柱做着热身运动，甩胳膊，踢腿，扭腰，他是力量型觉醒者，他的拳头就是最好的武器。\n\n　　董雨蹲在一边，脸色不太好看，但也没有再说反对的话。\n\n　　王烈走过来，目光扫过所有人。\n\n　　“雨桐，你留在营地，你没有攻击能力，但车队的领航需要你，这次的战利品，你占2成。”\n\n　　沈雨桐点点头，没有说话。\n\n　　“郭毅，你也留下，车队能正常运转全靠你，你占1成。”\n\n　　“江生，你也是，培育土豆的事不能停，你占0.5成。”\n\n　　江生点点头。\n\n　　“剩下的，”王烈看向方玲、陈敏、刘铁柱、董雨以及还在另外一边的林风，“我们按出力多少再进行分配。”\n\n　　没有人有异议。\n\n　　王烈看了看天色，今天的天气似乎不错，“该吃饭的去吃饭去，该准备的好好准备，半个小时后我们出发。”\n\n　　半小时后，林风骑着小玄，慢悠悠地来到小镇的入口。\n\n　　王烈几人已经在那里等候了，当小玄那巨大的身影一出现，所有人的目光齐刷刷地转了过来。\n\n　　除了王烈已经见过之外，其他人脸上的表情精彩极了。\n\n　　方玲手里的弩差点没拿稳，眼睛瞪得溜圆，看着那只比越野车只大不小的巨龟，嘴巴微微张开。\n\n　　“这是……你那只御兽？”方玲的声音都变了调。\n\n　　“不然呢？我就这一只御兽。”\n\n　　刘铁柱和董雨的脸色更难看了，离近看，这只乌龟的压迫感，比远远望去要强上好几倍。\n\n　　陈敏第一个反应过来，三步并作两步走过来，双手撑住龟壳边缘，一个利落的翻身，稳稳当当的坐在林风旁边。\n\n　　“林风弟弟。”她伸手摸了摸龟壳，整个人也惊讶无比。\n\n　　“我的个龟龟……你这乌龟打激素了吧？昨天我走的时候才脸盆大小，这……眨眼功夫就这么大了。”\n\n　　说完，她还趴在龟壳上，这摸摸那拍拍，嘴里啧啧称奇，丝毫没有注意到林风看她的目光。\n\n　　走光了啊，姐姐……\n\n　　这丰满，好想入股……\n\n　　陈敏环顾了一会龟壳上宽阔的空间，眼睛越来越亮，站起身，还跺了跺，胸口的起伏，看的林风一愣一愣的。\n\n　　眼泪不争气的从嘴角流下来。\n\n　　“这上面可真宽敞，这背甲上面还有石板？这是你弄得？可以啊，小弟弟，是不是可以在上面盖房子了？”', 2583, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (22, 13, 20, '第20章 把房顶掀了', '　　说话间，陈敏眼睛越来越亮，身体微微前倾，几乎要贴到林风的脸上，那双勾人的眼睛笑眯眯的看着林风。\n\n　　“你这乌龟再长大点，真的可以在上面盖个小房子了，嗯……林风弟弟，你说，姐姐搬你这里来住好不好？”\n\n　　林风的身体微微一僵，把脸从眼前的大灯上移开。\n\n　　“敏姐说笑了，你好好的大巴车补助，来我这凑什么热闹，再说，以后的事情还没影呢。”\n\n　　陈敏撅了噘嘴，手指戳着林风的胸口：“林风弟弟，你这是拒绝了？你是不是嫌弃姐姐老？”\n\n　　林风哪里敢接着话，嫌弃陈敏老？他嫌命长了还差不多。\n\n　　林风连连摆手，“哪里老了，敏姐永远十八，不对，是比十八岁的小姑娘还要漂亮，我最喜欢姐姐这样的女人了，成熟，有味道，还有……”\n\n　　“得得得，打住。”陈敏伸出手指，点在林风的额头。\n\n　　“人小鬼大，油嘴滑舌。”\n\n　　“那就这样说定了，等你的乌龟长大了，记得盖上城堡，给姐姐我留一个房间。”\n\n　　“好好好，我一定给你留。”林风连连点头，只想赶紧把这个话题翻过去。\n\n　　陈敏欣慰地拍了拍林风的肩膀，翻身从龟背上跳下去。\n\n　　王烈咳嗽了一声：“说正事。”\n\n　　他走到最前面，指着小镇的方向开口道。\n\n　　“我们的目的是清除小镇外围区域的危险，搜索物资，但是……”\n\n　　他的目光扫过所有人，最后在林风身上停顿了一下，继续开口：“不要进入小镇中心的位置，尤其是主街道，我们沿着外围区域扫荡搜索，一家一家的排查，遇到危险相互支援，不要冒进。”\n\n　　说完，王烈一挥手，率先走进了小镇。\n\n　　“小玄，跟上。”\n\n　　小玄不紧不慢地跟在队伍最后面，小镇里一片死寂。\n\n　　道路两旁横七竖八地停了不少车辆。\n\n　　但是没有人，路边的店铺是关着门的，楼上的窗户紧闭，窗帘拉得严严实实。\n\n　　就像整个小镇被凭空搬到这个世界一样，王烈走到第一栋房子面前，那是一栋2层的自建小楼。\n\n　　他冲方玲使了个眼色。\n\n　　方玲抽出匕首，握在手中，王烈一脚踹开门。\n\n　　“砰……”\n\n　　方玲闪身进入门内，几秒钟后，她从二楼的窗户探出头来，比了一个安全的手势，王烈几人才走进去。\n\n　　林风没有动，站在小玄背上，打量着小镇。\n\n　　十分钟后，王烈他们从房子里出来，手里多了几个袋子，方玲手里提着一袋米，大约十来斤，刘铁柱抱着两瓶油和一个塑料罐子，不知道往里面装了些什么。\n\n　　“没有什么好东西。”王烈摇摇头。\n\n　　他把东西堆在路边，继续往下一家走。\n\n　　接下来连续翻找了好几栋房子，都没有遇到危险，几人一合计，决定分开行动。\n\n　　于是，大家各自选择一栋房屋探索。\n\n　　林风看着他们一个个钻进楼里，不一会就搜索到不少物资堆在街道上，心里也火热起来。\n\n　　小镇外围区域大多都是两三层高的小楼，而主街道上面的房子明显好很多，而且一楼几乎都是一间间商铺，林风看着这些商铺双眼放光，但又想到王烈的提醒，算了。\n\n　　“小玄。”林风指着路边一栋三层的房屋说道。\n\n　　“把那屋顶给我掀了。”\n\n　　小玄的眼睛盯着那栋楼，没有丝毫犹豫，龟甲亮起土黄色的纹路。\n\n　　然后……\n\n　　轰隆……\n\n　　那栋房屋的屋顶直接从中间裂开，像是被一双无形手从两侧搬开，预制板、木板、砖块哗啦啦地往下掉。\n\n　　真……屋顶被掀了。\n\n　　动静大得整个小镇都能听见。\n\n　　王烈转过头，看见那栋被掀了屋顶的房子，眼角都抽了抽，却没有开口说什么……\n\n　　林风从缺口处往里看去，里面就是普通的家具，沙发、茶几、电视柜什么的，没有什么值钱的东西。\n\n　　林风见没有自己想要的东西，摆摆手。\n\n　　“小玄，继续，把房子拆了。”\n\n　　小玄的控土术再次发动，这一次威力更大。\n\n　　地面都泛起波纹，那栋房子，墙壁开始龟裂，砖块从墙体上剥离，整个过程丝滑无比，而那些从房屋主体上剥离的砖块，被小玄操控着，聚拢到一堆。\n\n　　然后……\n\n　　咔嚓咔嚓……\n\n　　林风“……”\n\n　　“不是，你就吃上啦？”\n\n　　而且还吃得津津有味，砖块在小玄的嘴里就像饼干一样，而承重的混凝土柱子被嚼得嘎吱作响。\n\n　　“好吧，混凝土也是土，你也是吃上好的了，钢筋拌混凝土是不是更香！！！”\n\n　　林风从小玄背上跳下来，走进被拆卸一空的废墟里。\n\n　　说实话，林风失算了，房子拆得是快，就是楼上的床啊，家具什么的，全掉下来砸烂了。\n\n　　最后才好不容易，从一个角落里找到一个蛇皮口袋，打开一看，竟然是大米，少说也有四五十斤。\n\n　　林风的眼睛一亮，这下吃的有着落了。\n\n　　然后又翻了翻周围，在一个橱柜里找到几块腊肉，还有一桶食用油，半袋盐……\n\n　　“不错，都是好东西。”\n\n　　林风把东西一样一样地搬出来，堆在小玄旁边。\n\n　　林风看着地上的物资，又看了看小玄宽阔的背，在小玄背上建个房子的想法越来越强烈。\n\n　　“小玄，”林风拍了拍小玄的龟壳。\n\n　　“你能在自己背上建一个石头房子吗？就是用控土术把泥土弄到背上，然后石化，做成墙壁和屋顶……”\n\n　　林风跟小玄沟通了好一会，把自己想法用精神力传给小玄。\n\n　　小玄似乎明白了林风的想法，开始行动。\n\n　　只见，地面开始松动，然后泥土像是被无形的手牵引一般，缓缓从地面升起流向龟背。\n\n　　一层一层的泥土开始堆积起来，在小玄的控制下，变得坚硬，最后化作平坦的灰色石头地面，就像一整块石头地砖一般，然后，大量的泥土继续往上涌动。\n\n　　从龟甲的边缘地面开始升起石墙。\n\n　　半米……一米……两米。\n\n　　墙壁最后足足达到3米高才停了下来，顶部开始合拢，形成一个屋顶，还特意留了一道门供林风进出，以及一扇窗户，最后把从这栋房屋上拆下来的玻璃和房门镶嵌在石墙里面，严丝合缝。\n\n　　完美！！！\n\n　　整个过程不超过十分钟，一个小房间就稳稳当当地建在了小玄背上。', 2230, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (23, 13, 21, '第21章 在龟背上建房子', '　　这间石头房子虽然不大，但用来堆放物资绰绰有余了。\n\n　　“哈哈，终于有个家了……”\n\n　　“等我物资收集得差不多了，然后在里面铺上被子，放上枕头，不就是现成的卧室了吗？”\n\n　　林风美滋滋的把大米，腊肉，油盐一样一样的搬进石头房间里，摆放得整整齐齐。\n\n　　他拍了拍手上的灰，满意得不得了。\n\n　　“小玄，走，下一家。”\n\n　　接下来的时间里，林风带着小玄在小镇外围，开始进行拆迁活动。\n\n　　主街道，林风虽然眼馋，但还是记着王烈的话，没有深入小镇当中。\n\n　　听人劝，吃饱饭……\n\n　　外围的房子可就遭老罪了。\n\n　　一路走过去，屋顶被掀开，没有危险，就继续拆墙面，林风也学聪明了，让小玄利用控土术，一点一点地拆墙面，尤其是承重墙不动，效率高得惊人的同时，房屋也不会倒塌。\n\n　　就这样房间里有什么东西一目了然。\n\n　　看上的东西，统统搬走。\n\n　　看不上的，留在原地，等后面车队里的人来搬运。\n\n　　而拆下来的砖块、混凝土，全部被小玄吞进了肚子里。\n\n　　王烈他们在挨家挨户地翻箱倒柜的时候，林风这边从拆房子，到里面的物资被搬走，短短十几分钟就能搞定一家。\n\n　　小玄的控土术实在太好用了。\n\n　　随着林风找到的东西越来越多，最后开始挑挑拣拣，发芽的土豆，不要，只带走容易保存的干货，比如木耳，干香菇，粉丝。\n\n　　要不就是一些罐头啊，饼干，这类的东西。\n\n　　随着物资收集的越来越多，林风的心里越来越踏实，就现在收集到的这些东西，自己一个人放开了吃，吃大半月都没有问题。\n\n　　而且这还是捡着好的挑，当然也不是林风不想全部拿走，主要是小玄背上的空间太小了啊，已经摆的满满当当的了。\n\n　　再说了，车队里还有将近千人呢，自己也不能全拿走，做人留一线，好歹都是蓝星的同胞，自己吃肉的时候，总得给人家留口汤喝。\n\n　　随着主街道两边的房屋被大家扫荡了一大半后，林风的眼光开始向着主街道的方向瞟。\n\n　　尤其是那里店铺上挂的招牌，超市，杂货铺，五金店，诊所，粮油店，服装店……\n\n　　林风的心跳加速了，林风站在又长大了一些的小玄背上，心里纠结了好一会。\n\n　　“我就进去一点点，应该没事吧？”\n\n　　林风看了看周围的环境，发现王烈他们在更远处搜索，没有人注意到他正盯着主街道。\n\n　　“小玄，走，沿着街边走，看到最近的那家便利店没，就拆一面墙，看一眼里面有什么，我们就出来。”\n\n　　小玄似乎感受到了林风的激动，迈开腿，踏上了主街道。\n\n　　它此时的脚步很轻很轻，一副探头探脑的样子。\n\n　　才踏上主街道，林风就感受到了一股阴冷的感觉，从街道深处弥漫出来。\n\n　　“小玄，就这里，别走了，快拆，发现不对，我们就赶紧跑……”\n\n　　小玄抬起头，土黄色的光芒亮起，无形的力量沿着地面蔓延到那个挂着便利店牌子的房子。\n\n　　墙壁开始龟裂，砖块松动，然后……\n\n　　轰隆。\n\n　　墙倒了。\n\n　　阳光猛地照进了那个房间里，\n\n　　然后……\n\n　　“啊啊啊啊啊……”\n\n　　凄厉的哀嚎声从里面传出来\n\n　　那声音，就像是指甲在黑板上刮过，再放大一百倍，声音凄厉到让人头皮发麻，耳朵嗡嗡作响。\n\n　　林风的瞳孔猛地放大。\n\n　　他看到了。\n\n　　在阳光照射进房间的瞬间，一团模糊的黑影暴露在光线中，在阳光的照射下，扭曲挣扎，像是被火灼烧到一样。\n\n　　哀嚎声一声接着一声，越来越尖锐，越来越凄厉 。\n\n　　然后\n\n　　嘭的一声，那团黑影炸开了，化作漫天黑气，在阳光下迅速消散。\n\n　　原地留下一颗珠子。\n\n　　【击杀1级怨灵，获得进化点1】\n\n　　林风先是愣住了，随即眼睛猛地亮起。\n\n　　怨灵？\n\n　　这个小镇里藏着的竟然是怨灵，怪不得小镇一点声音都没有，一片死寂，怨灵这东西昼伏夜出。\n\n　　白天它们会躲在封闭的黑暗空间里，到了晚上才会出来游荡。\n\n　　而他们的克星，就是阳光。\n\n　　而今天的天气似乎很好。\n\n　　林风看着这条主街道，嘴角不由自主地咧开了。\n\n　　“小玄！”\n\n　　“给我拆……”\n\n　　小玄听到命令后，仰起头，土黄色的光芒大盛。\n\n　　地面开始剧烈震动起来。\n\n　　街道两侧的房屋墙壁开始龟裂，卷帘门呼啦啦的掉落，招牌从高处砸下来，发出巨大的声响。\n\n　　一栋，两栋……\n\n　　小玄的控土术精准地控制着力量，前方300多米区域内的房屋，一栋栋的房顶被掀开，墙壁被拆掉。\n\n　　阳光大片大片地涌入被黑暗笼罩的房屋里。\n\n　　然后\n\n　　哀嚎声此起彼伏……\n\n　　啊……\n\n　　呜……\n\n　　无数凄厉的哀嚎汇成一片，那尖锐的声音听得人头皮发麻……\n\n　　随着一团又一团的黑影暴露在阳光下……\n\n　　【击杀1级怨灵，获得进化点+！……】\n\n　　【击杀级怨灵，获得……】\n\n　　一条又一条提示音响起，林风的脸上挂满了笑容……\n\n　　随着小玄的继续拆迁，更远处的屋顶开始掀翻。\n\n　　哀嚎越来越密集，越来越尖锐。\n\n　　“这鬼哭狼嚎的，挺好听……”\n\n　　“继续叫，我爱听，声音再大点……”\n\n　　此时的林风活像一个大变态。\n\n　　远处，王烈正在一栋两层小楼里，手里拿着一袋挂面，眉心都快拧成川字了。\n\n　　这里的物资比他预想的要少得多。\n\n　　就在这时候，地面震了一下，紧接着，他就听到了哀嚎声。\n\n　　不是一两声，而是一片，漫天的哀嚎声，凄厉得让人汗毛倒竖，听声音传来的方向，似乎是从主街道传来的。\n\n　　王烈脸色大变，连忙冲出房间，往声音传来的方向看去。\n\n　　然后，他看到了，小镇主街道的方向，一栋栋建筑的墙壁正在崩塌，屋顶被掀翻……\n\n　　他最不想看到的一幕发生了。\n\n　　“林……风……”\n\n　　王烈的怒吼声……', 2141, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (24, 13, 22, '第22章 满载而归', '　　林风转过头，就看到王烈从一栋小楼里冲出来，脸上挂着难看的表情，他身后跟着方玲和陈敏，两个人的表情也好不到哪去。\n\n　　有趣的是，方玲看着主街道那片被拆得七零八落的房子，像是看到了什么不可思议的东西。\n\n　　林风还冲王烈招招手，一脸无辜的样子。\n\n　　等他们走到近前，目光齐刷刷看向前面那片废墟。\n\n　　主街道前方300米的区域，两旁的建筑就像被一只巨手蹂躏了一样，房顶不见了，墙壁被拆卸一空，卷帘门七歪八扭的丢在地上，招牌碎裂一地，仅剩几根承重柱，支撑着房屋，俨然一个空架子。\n\n　　阳光照射在房间里，把每一个角落都照得透亮。\n\n　　地上散落着不少灰烬和亮晶晶的诡晶。\n\n　　“队长，找我有事？”林风从小玄的背上探出半个身子问道。\n\n　　“你知不知道你在干什么？”王烈的声音压得很低，心里的怒火都快压不住了。\n\n　　“拆房子，找物资，杀诡异啊。”\n\n　　林风拍了拍小玄，得意地说：“你看，效率还不错，这一片都处理得干干净净，都是小玄的功劳……”\n\n　　王烈的太阳穴跳得更厉害了，是不是我还要夸你几句？\n\n　　他深吸一口气，强压下心里的怒火，不气不气，气坏身体无人替。\n\n　　“我有没有说过，不要进小镇的中心区域，尤其是主街道。”\n\n　　“我没进啊，”林风摊了摊手，表情无辜极了。\n\n　　“你看……”\n\n　　林风指了指小玄站立的位置。\n\n　　王烈顺着他手指的方向看过去，愣了一下。\n\n　　只见小玄四条腿刚好踩在一条分界线上，外面的道路是老旧的灰色水泥路面，坑坑洼洼，裂缝里长着枯黄的野草，而主街道的路面明显是后来重新修整过的柏油路面。\n\n　　两条路之间有一条清晰的界缝，就像是一道天然的界限。\n\n　　真是一步也没有踏进去。\n\n　　王烈的嘴角不由自主地抽了抽。\n\n　　他想骂人，你他妈往里面拆了三百米，你知道吗？\n\n　　抬头看了一眼体型又变大了一圈的小玄，这畜生正歪着脑袋看着他，眼睛里居然带着一丝审视的意味，就好像是在打量这块肉够不够塞牙缝。\n\n　　“我他吗……”\n\n　　王烈把刚到嘴边的话又咽了回去，林风已经不是他手下的队员了，他没有资格教训林风，以林风现在的实力，准确地说，是这只乌龟目前的实力，他连教训的资格都没有，就算他全力出手，也不能破坏方圆三百米的街区啊。\n\n　　这乌龟，惹不起……\n\n　　“前面的区域可能会有高级怨灵，你这么大动静，万一把它引出来怎么办？”\n\n　　“我知道。”林风点点头，语气十分认真，“所以我停了，不拆了。”\n\n　　“不拆了？”王烈愣了一下，没有想到林风这么好说话。\n\n　　“嗯，不拆了。”林风拍了拍小玄背后的石头房子，“我的房间快装满了，再拆我也拿不走。”\n\n　　王烈这才把目光落在小玄背上那间石头房子里。\n\n　　从外面看，大约2米宽，3米高，3米长的样子，但是那道门是敞开的，往门内看去，里面的景象一览无余。\n\n　　大米，一袋一袋的大米整整齐齐的堆在墙角，少说也有四五百斤，还有面粉，同样鼓鼓囊囊的。\n\n　　还有挂墙上的那是什么？王烈咽了一口唾沫，腊肉，墙上挂着几串腊肉，被林风用塑料袋套着，油脂已经滴落在袋子里。\n\n　　这可是稀罕东西啊，就连他都没有找到。\n\n　　还有地上那一包包的是啥？干货——干木耳，干香菇，粉丝，堆满了一地。\n\n　　还有那些罐头，午餐肉罐头、水果罐头，甚至还有两罐奶粉。\n\n　　更不要说那些调味品，食用油、盐巴、酱油、醋……还有几瓶白酒。\n\n　　“我艹”\n\n　　刘铁柱脱口而出，嘴巴张得老大，脸上的表情精彩极了。\n\n　　方玲和陈敏也凑了过来，两个女人的眼睛同时亮了。\n\n　　“那是腊肉吗？好几块呢！”陈敏咽了咽口水。\n\n　　王烈沉默了好一会，把目光从那堆物资上移开，最后把目光落在林风身上。\n\n　　“拆都拆了，前面那些店铺里的东西你打算怎么分？”\n\n　　林风思索了片刻。\n\n　　“主要就是几家小卖铺东西多一点，我吃的囤得差不多了，你们安排人搬走吧，就是最前面那家粮油店，我感觉不对劲，没敢拆！”\n\n　　“你也有怕的时候？”王烈的声音听不出是嘲讽还是感慨。\n\n　　“那当然！”林风理直气壮：“我又不是愣头青，打不过的东西从来不碰。”\n\n　　王烈看了林风一眼，没有再说什么，对着方玲说道。\n\n　　“你回去安排后勤和巡逻队的人过来这里搬运物资，主街道这两边的东西全部搬走。”\n\n　　方玲点了点头。\n\n　　“还有小镇外围的房子已经没有危险了，让车队里的人自由探索，能找到多少算多少。”\n\n　　王烈又看向刘铁柱和董雨。\n\n　　“你们两个跟我去前面那家粮油店看看。“\n\n　　王烈走了几步，忽然停下来。\n\n　　“待会把物资搬回去后，有你一份。”\n\n　　“不用了，我够了，那些店铺里的东西你分，我就不掺和了。”\n\n　　王烈深深看了林风一眼，没有强求，转身走了，他作为一个2级雷电系觉醒者，也有自己的傲气，他倒要去看看那个粮油店里有什么。\n\n　　等人走了，林风直接跳下来，小跑着进去捡诡晶。\n\n　　一颗，两颗……\n\n　　林风把诡晶一颗颗的捡起来，然后装进口袋里，有些诡晶滚落在碎砖头堆里，林风扒开砖块也要把它翻出来。\n\n　　陈敏笑嘻嘻的凑了过来，蹲在林风旁边，帮他捡了几颗。\n\n　　“小风弟弟，你这一趟发了啊。”\n\n　　“嘿嘿，小发，小发，运气好而已。”林风也不客气，直接接过对方掌心里的诡晶，装进口袋里。\n\n　　陈敏翻了一个白眼：“你管这叫运气好？”\n\n　　运气好能拆掉方圆300米的房子？\n\n　　林风没有接话，站起来拍了拍膝盖上的灰，眼睛扫视了一圈，确认没有遗漏的诡晶后，忽然想起了什么，往一家服装店走去。\n\n　　边走边说：“敏姐，你不去给队长压阵吗？我觉得那个粮油店里的东西不好惹。”\n\n　　“怕什么？区区怨灵而已，别忘了队长可是雷电系异能，专克怨灵，只要不是3级怨灵，手拿把掐的事……”虽然这样说，可她还是去给王烈压阵去了。', 2250, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (25, 13, 23, '第23章 入不了你的眼？', '　　林风走进服装店里，在货架上翻了翻，找了两套深色的运动装，抖了抖上面的灰，收起来。\n\n　　身上这套衣服穿了好几天了，又是汗水又是变异生物的体液，味道大得林风自己都不好意思闻。\n\n　　最后又顺走了两双运动鞋，这才心满意足地走出服装店。\n\n　　“等回营地后，想办法洗个澡，换身干净的。”\n\n　　从服装店出来，看到对面有一家家纺店，林风眼睛亮了，三两步跑过去，在店里转了一圈后，最后选了一张乳胶床垫。\n\n　　厚度大约十厘米，宽1.8米，林风把床垫卷起来，用绳子捆好，这才扛着出了门，丢到小玄背上后，又返回店里，挑了一套被子，枕头，最后又抱了一床毛毯。\n\n　　最后想到什么，跑去便利店，搬了十几箱矿泉水。\n\n　　“这下齐活了，完美。”\n\n　　当石头房子里堆满了物资，林风的嘴角几乎快要咧到了耳朵根，从来就没有打过这么富裕的仗。\n\n　　“小玄，走，回营地。”\n\n　　等小玄走出小镇的时候，方玲已经带着人往这边赶来，上百人排成队伍，推着板车，扛着麻袋和绳子，浩浩荡荡的往主街道的方向走来。\n\n　　当他们看到林风骑着乌龟从对面走来时，纷纷让开道路，目光投向这只庞然大物，眼神里充满了敬畏和羡慕。\n\n　　林风对这些人视若无睹，坐在龟背上，翘着二郎腿，嘴里还叼着一根顺手在路边扯的狗尾巴草。\n\n　　“小玄，走快点，回去我要先找个地方洗澡。”\n\n　　小玄的脚步加快了一些，车队的临时营地出现在前方，当看到小玄那巨大的身影出现在视野里，营地里的嘈杂声猛地提高了一个度。\n\n　　“快看，那只大乌龟回来了！”\n\n　　“你看，背上还有个小房子，那是什么？”\n\n　　“觉醒者大人在乌龟上盖了一个家？”\n\n　　“卧槽，这也太牛了吧，好想住上面去，这样我就不用天天晚上骑车了……”\n\n　　“快去吧！小浪蹄子……说不定人家就喜欢你这一款呢。”\n\n　　营地里的男人几乎都去小镇上收集物资了，剩下一些女人议论纷纷，一个个望着林风，若有所思。\n\n　　小玄穿过营地，来到早上的那块空地上，林风这才从小玄背上跳下来。\n\n　　早上烧过的火堆，灰烬被风吹得散了一地。\n\n　　林风又重新把柴火堆好，用打火机点燃，很快火苗便蹿了起来。\n\n　　接下来林风开始从小玄背上的屋子里开始往外搬东西，连续搬了好几箱矿泉水，又翻找出来几包泡面和面包，加上几瓶矿泉水装袋子里。\n\n　　想洗个热水澡，单有水还不行，需要一个大铁桶烧水。\n\n　　林风提起袋子朝着营地中央走去，营地里肯定有人有铁桶，准备的这袋物资就是准备去换的。\n\n　　至于用矿泉水烧热水洗澡会不会太奢侈，现在物资充裕，奢侈一把怎么了，本来他林风就是一个喜欢享受的人。\n\n　　干嘛要没苦硬吃。\n\n　　营地里的车辆停得密密麻麻，SUV、轿车、三轮车、自行车横七竖八的挤在一起，人群在营地里忙着各自的事情，有的人整理仅剩的物资，有的人在生火做饭。\n\n　　林风穿过营地的时候，经过一辆改装过的公交车时，听到了一些声音。\n\n　　“嗯……啊……”\n\n　　女人的娇喘从车内传来。\n\n　　林风的脚步微微一顿，这辆车的窗户被粉红色的布帘遮得严严实实，车顶还挂着一串不知道从哪里弄来的彩灯。\n\n　　车外站着五六个女人，穿着暴露的吊带裙、超短裙、低胸装，浓妆艳抹，跟这营地里的环境格格不入。\n\n　　这辆车，林风知道。\n\n　　从逃亡的第三天起，它就变成了现在这个样子，车主是一个叫红姐的女人，听说以前干洗浴中心的，在逃亡途中，她用食物和上车为筹码，控制了几个活不下去的女人，做起了皮肉生意。\n\n　　车队里手里有点物资的男人，尤其是巡逻队的那帮人，没少在这辆车上消费。\n\n　　“哟……林风大人。”\n\n　　一个娇滴滴的声音从身后传来。\n\n　　林风回头，看到一个女人抽着一支女士香烟，从车后面走来。\n\n　　红姐！\n\n　　她穿着一件红色的紧身连衣裙，裙摆短得堪堪盖住大腿根部，脚下踩着一双黑色高跟鞋，走路的时候，腰肢扭得像水蛇，透出一股成熟的妩媚。\n\n　　“林风大人，你这是要去哪？”\n\n　　红姐走到林风的面前，目光先是在林风的帅脸上停留了一下，然后落在他手里提着的矿泉水和泡面上，然后眼睛微微一亮，奶油面包？这个是稀缺货。\n\n　　“哟，好东西啊。”\n\n　　红姐说话的时候，身子已经贴了上来，身上浓郁的香水味扑面而来，她伸手往公交车的方向一指，语气里带着几分殷勤。\n\n　　“大人，要不要安排两个姑娘陪你，我那几个姑娘可都是水灵灵的，保准让你满意。”\n\n　　林风顺着她手指的方向看去，那几个女人顿时会意，一个个搔首弄姿，有点撩头发，有点咬嘴唇，有点在冲他抛媚眼……\n\n　　说实话，这几个女人身材样貌都不错，在蓝星，这种级别的女人，哪个不是众星捧月的存在，少说也要几百万彩礼才能娶得起，而且还是有大把的男人抢着要。\n\n　　现在呢，几包泡面就能睡一次。\n\n　　林风本来就是一个小色皮，换前几天可能就心动了，但经历过被踢出队伍、女人转身就走的事情后。\n\n　　对于女人，林风有了新的认知，女人不可靠，但可以控制。\n\n　　而且，谁知道这几个女人接过多少客人，尤其是那些男人隔三差五就往这车上跑，有时候还几个人一起。\n\n　　红姐见林风没有说话，以为看不上，压低声音说：“怎么看不上这些，入不了觉醒者大人的眼。”\n\n　　林风摇摇头，倒也没有藏着掖着，直率的说：“入得了，但我不喜欢公交车。”\n\n　　红姐愣了一下，随即笑了，笑容里没有半分尴尬，甚至还往前凑了半分，林风顿时感觉手臂陷入一片柔软当中。\n\n　　红姐的嘴唇几乎要贴到林风的耳朵上，声音压得很低，只有两个人能听见。\n\n　　“车队里有几个艺术学院的学生……”', 2164, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (26, 13, 24, '第24章 送上门的肉，不吃白不吃', '　　“车队里有几个艺术学院的学生，长得那叫一个水灵，那腰，那腿，那皮肤……啧啧，最近日子过得老惨了，野菜都吃不饱，昨天车还坏了，盯上她们的人可不少。”\n\n　　红姐后退半步，笑呵呵地看向林风。“哎……都是可怜人，怪只怪这末日，大人要是愿意，我愿意为你牵线搭桥，只求大人能庇护我一二……”\n\n　　红姐说这话的时候，语气里认真了一些。\n\n　　她手底下有姑娘，不缺吃喝，但末日里，安全才是最重要的，车队里的觉醒者就那么几个，王烈太傲，刘铁柱太粗，董雨是个女的，虽然她不歧视弯的，但听说她手段有点变态，她可不想把手下的姑娘送上门去受折磨。\n\n　　郭逸和江声没有话语权，实力也不行。\n\n　　最后挑来挑去，眼前这个年轻人最合适，年龄不大，看着心不坏，最主要的是长得不错，看得她都为之心动。\n\n　　失了……\n\n　　而且今天她可是看见了他身边那头恐怖的御兽，那头大乌龟往那里一趴，安全性肉眼可见的提高。\n\n　　林风看着面前的红姐，心里对这个女人有了一番新的认识。\n\n　　有脑子，有眼光，有胆量……\n\n　　知道林风的实力大增后，立马提前押注。\n\n　　不过林风并不排斥，送上门的肉，不吃白不吃，今天我手下留情了，明天就被别人吃掉了。\n\n　　他以前还在核心队伍里的时候，就没拒绝过送上门的菜，今天一样不会，他又不是什么好人。\n\n　　好人在这末日世界里活不久……\n\n　　“行，你看着办，我先去换个提桶烧水洗个澡。”林风抬了抬手里的袋子。“我都快臭死了。”\n\n　　“哎呀……这不是巧了吗？”红姐一拍大腿。\n\n　　“我车上就有折叠浴桶，为了保持姑娘们的美貌，我可是花了不少心思弄到这个浴桶，全新的，都没用过几次。”\n\n　　“还有帐篷，我这还有帐篷，一会一起给大人送过去。”\n\n　　“你看你手里提着东西，多沉啊，我给你拿着……”\n\n　　红姐说着，她那双白嫩的手已经不动声色从林风手里接过袋子，动作自然得就像拿自家东西一样。\n\n　　林风看了她一眼，没说什么，转身就往回走，跟谁换不是换，反正结果都一样。\n\n　　红姐在后面喊了一声：“大人你先回去，东西我马上送过来。”\n\n　　红姐目送林风离开后，脸上的笑容收敛了几分，转身向车后面走去。\n\n　　“丽丽，小美，还有你们几个，你们的事我答应了，别在这站着了，跟我走，对了，把那个折叠浴桶带上，还有帐篷，烧水的锅也带上。”\n\n　　几个女生面面相觑，其中一个怯生生地问：“你真的答应我上车了，不会让我们做个……”\n\n　　“做不做，得看你们的表现，不想来，就回去……”\n\n　　“红姐，那我们是去哪？”\n\n　　“伺候贵人。”红姐没好气地说，“等会机灵点，别给我丢人，要是能把哪位伺候好了，以后咱们的日子就好过了……，要是做不到，那就跟其他姑娘一样，想上车，就别想有特权……”\n\n　　…………\n\n　　大约二十分钟后，红姐领着几个女人出现在林风的营地边。\n\n　　她身后跟着4个女人，每个人手里都拿着东西，这几个女人和刚才在大巴车旁边站着的那些不一样。\n\n　　她们脸上没有化妆，虽然有些脏，但依然掩盖不了那满满的胶原蛋白，年轻充满活力。\n\n　　小玄正趴在土坑里刨土，吃的咔嚓作响，看到有人过来，抬头看了一眼，又低下脑袋继续啃。\n\n　　几个女人看到这一幕，齐刷刷地倒吸了一口凉气。\n\n　　“天啊，好大……”\n\n　　另外一个女孩往后退了半步，“这……这真的不会咬人吗”\n\n　　“闭嘴！这是觉醒者大人的御兽，都给我安安静静的干活。”红姐低声呵斥了一句，转过头来的时候，脸上堆满了笑容。\n\n　　“林风大人，东西送来了。”\n\n　　红姐指挥她们开始搭帐篷，烧水，动作麻利。\n\n　　她们先把帐篷撑起来，里面的空间很大，容纳五六个人都没问题，防水防风，质量好得很。\n\n　　帐篷撑好后，几个女孩在里面铺了防潮垫，最后还在上面铺上一张软垫，意思自然不言而喻。\n\n　　最后才把浴桶支起来，浴桶折叠起来不占地方，撑开后大约半米高，能装一个人，设计得很巧妙，使用也很方便。\n\n　　“你们几个把那几箱矿泉水搬过来。”红姐指着堆在小玄附近的矿泉水说道。\n\n　　几个女孩小心翼翼地靠近小玄，生怕惊动了这只庞然大物，她们几乎是把矿泉水抱起就往回跑，脚步飞快，就像背后有东西在追一样。\n\n　　“真奢侈啊。”一个扎马尾的女孩小声嘀咕，“用矿泉水洗澡，这怕是要好几十瓶吧。”\n\n　　“你管人家的。”另外一个穿着JK装扮的圆脸女孩，撇了撇嘴，目光却一直在往小玄背上瞟。\n\n　　“哎，你看见那只大乌龟背上的房子了吗？里面好多物资啊，我还看到腊肉了……”\n\n　　说话间，她咽了咽口水。\n\n　　“我也看到了，好几块呢，挂在墙上，还有大米，罐头，好多呢……”\n\n　　“你别说了，我口水都要流出来了。”\n\n　　“我也是……我好久都没吃肉了，这几天吃野菜都要吃吐了。”\n\n　　几个女孩一边干活，一边小声议论，目光不时地往小玄背上的石头仓库瞟，眼睛里全是渴望。\n\n　　林风靠在折叠椅上，跷着二郎腿，悠哉得很，这把椅子也是红姐带过来的。\n\n　　红姐走过去，在林风旁边蹲下，说：\n\n　　“怎么样，这几个丫头你还满意吗？”\n\n　　“那个是艺术学院的？”\n\n　　“都是。”红姐朝几个女孩努了努嘴。\n\n　　“扎马尾那个叫小玉，学舞蹈的，身体软得很，那个穿JK装的叫小蕊，学声乐的，嗓子特别好，还有那个子最高的女孩叫小晴，学表演的，长得最漂亮。”\n\n　　红姐顿了顿说道：\n\n　　“还有一个晓丽，我给你安排在帐篷里了，那个丫头最水灵，我特意给你留的。”\n\n　　林风却伸出手掌，然后握拳。\n\n　　“我全都要……”', 2146, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (27, 13, 25, '第25章 我全都要', '　　“我全都要……”\n\n　　红姐只是笑了笑，没有多说什么，识趣地站起来。\n\n　　“行，大人你先洗着，我回去忙了，这几个丫头就托大人照顾了……”\n\n　　说完她踩着高跟鞋，扭着腰，走了。\n\n　　林风随后也站起身，然后往帐篷里走进去，浴桶里已经装满大半桶热水了，林风把身上的衣服直接脱了个精光，抬脚就跨进浴桶。\n\n　　水有些凉，但林风不在乎，把整个身体泡进桶里，长长地吐出一口气。\n\n　　舒服\n\n　　太舒服了。\n\n　　泡在温水里的感觉，就像在天堂一般。\n\n　　林风靠在浴桶边缘，闭上眼睛享受这难得的宁静。\n\n　　就在这时候，帐篷的帘子被掀开了，一个女孩端着一盆热水进来。\n\n　　“大人，水有点凉，我给你加点热的。”\n\n　　林风睁开眼睛，看向这个女孩。\n\n　　她穿着一件紧身牛仔裤，把修长的美腿绷得笔直，身材纤细，腰肢盈盈一握，但该有的地方有，白色的T恤被热水打湿，贴在身上，勾勒出饱满的曲线，长长的黑发垂落到腰间，增添了几分美感，再配上一副甜美的面容，大大的眼睛像是能说话一般，说话的声音很轻柔。\n\n　　给人一种干净、清纯、未经世事的青涩感。\n\n　　“你叫什么名字？”\n\n　　女孩低着头，把热水，慢慢倒进浴桶里，声音轻轻的。\n\n　　“晓丽，李晓丽。”\n\n　　林风没有继续说话，帐篷里安静了几秒。\n\n　　“大人……”晓丽咬着嘴唇，犹豫了好久，终于开口了。\n\n　　“红姐说……让我给你擦背……”\n\n　　“来吧！\n\n　　…………\n\n　　帐篷外面。\n\n　　圆脸女孩小蕊忽然往小玉身边凑了过来，压低声音说，“唉，你发现没有，晓丽不在这儿……”\n\n　　“真的唉，她人呢？”\n\n　　“被红姐安排去给那位大人搓澡了。”小蕊捂着嘴说。“说不定待会还要一起洗鸳鸯浴呢。”\n\n　　两个女孩对视一眼，脸上的表情满是羡慕。\n\n　　“我也想洗。”马尾女孩小玉抬起手臂闻了闻自己的衣服，皱起鼻子。\n\n　　“我都好几天没洗了，光顾着逃命，都快臭了。”\n\n　　“谁不是呢，”小蕊叹了口气，伸手搓了搓自己的胳膊，“我身上都结了一层泥了……”\n\n　　“你去问问红姐，能不能让我们也洗洗？”\n\n　　“你做梦呢？那是够觉醒者大人准备的，你算老几。”\n\n　　几个女孩一边打闹一边干活，目光时不时地往帐篷的方向瞟。\n\n　　忽然帐篷里的声音渐渐变了调。\n\n　　先是水声，哗啦、哗啦，浴桶里的水拍打着桶壁，发出有节奏的声响。\n\n　　然后是是断断续续的声音，好似被压抑在喉咙里发出的唔嘤……\n\n　　帐篷外的3个女孩耳朵齐刷刷地竖了起来。\n\n　　“你听……”小蕊最先蹲下，然后鬼使神差地把耳朵贴在帐篷边，脸上浮起一层淡淡的红晕。\n\n　　然后是小玉，最后是小晴，她比另外两个要矜持一些，站在原地，手里拿着一块抹布，假装在擦锅，但她的目光一直往帐篷的方向瞟，耳朵竖得比谁都高。\n\n　　三分钟后，她也蹲下了。\n\n　　“你听见了吗？”小蕊小声地问。\n\n　　“废话，我又不聋。”\n\n　　三个女孩对视一眼，脸上的表情精彩极了，脸红，眼睛亮，呼吸急促，想走又舍不得走。\n\n　　……删……\n\n　　三个女孩对视一眼，眼里皆是错愕，玩得这么花吗？\n\n　　“这……这也太久了？”小蕊看了一眼手上的腕表：“一个小时了，会不会坏掉？”\n\n　　“应该……不会吧。”\n\n　　“你们别说了……”小晴捂住脸，“我腿麻了。”\n\n　　“晓丽的嗓子……哑了。”小玉说道。\n\n　　“换我我也哑！”\n\n　　帐篷里的声音渐渐小了，三个女孩对视一眼，同时松了一口气，眼里有一种说不清道不明的失落情绪。\n\n　　心里在想，为什么红姐不安排她进帐篷里伺候林风，说不定进去洗澡，得享受的就是自己了，万一能留在觉醒者的身边，那就好了，安全，还有吃不完的食物。\n\n　　在这末日里她们太想进步了。\n\n　　她们正准备站起来，腿已经麻得不行，帐篷的布帘忽然从里面掀开。\n\n　　林风走了出来。\n\n　　此时林风已经换了一身干净的衣服，脸上带着懒洋洋的神情。\n\n　　目光往旁边一扫\n\n　　三个女孩正蹲在帐篷边上，姿势各异，一个个脸色泛红，就连耳朵和脖子都是红的。\n\n　　空气凝固了三秒。\n\n　　小蕊猛地站起来，但腿麻了，差点摔倒，小玉扶了她一把，两人踉踉跄跄的往后退了几步，\n\n　　“大……大人，我们什么都没有听见！”\n\n　　话一出口，她的脸更红了，小蕊此刻恨不得找个地缝钻进去。\n\n　　另外两个也好不到哪去，捂住脸，转身就跑。\n\n　　林风懒得理她们。\n\n　　他当然知道这几个小丫头在外面听墙角，隔着帐篷都能听到她们心跳加速的声音。\n\n　　反正人已经送过来了，都是迟早的事，不急。\n\n　　林风迈步走向小玄，它正趴在土坑里，这高度，刚好够林风直接走进它背上的房间里。\n\n　　房间里的物资堆得满满当当，林风从墙上取下一块腊肉，大约三四斤重。\n\n　　又提着一袋子大米，最后找了点干木耳和干香菇，用袋子装好，然后才出了房间。\n\n　　“你们谁会做饭？”\n\n　　几个女孩面面相觑。\n\n　　看了看腊肉，又看了看大米，咽了咽口水，嘴唇动了动，都没有出声。\n\n　　小蕊咬着手指，目光在那块腊肉上粘住了，她已经一周没吃过肉了。\n\n　　最后小晴犹豫了一下，迈着大长腿往前走了两步。\n\n　　“我……我会一点点。”\n\n　　她的颜值在几女中最高，尤其是那双修长的大长腿，没想到竟然还会做饭，真是难得。\n\n　　这在蓝星几乎是极度稀缺的物种了，末日前，哪个不是家里的宝贝，外面一堆男生讨好的对象，别说做饭，能把自己的衣服洗明白就算是优秀的了。\n\n　　“行。”林风点点头。\n\n　　“拿去做了，多做点，待会一起吃。”\n\n　　“一起吃”这三个字一出口，几个女孩的眼睛全亮了。\n\n　　“真的吗？”小玉和小蕊的声音有点发颤，这几天别说吃米饭和腊肉了，刚开始还好，还有一点零食，后面几天完全是靠野菜团子充饥。\n\n　　她们也不是没有向车队里其他人求助过，可那些男人一个个色眯眯的看着她们，妄想用一两包泡面都让她们屈服，做梦呢，她们在学校的时候，接送的哪个不是豪车。\n\n　　可是现在呢，能吃上米饭和腊肉，竟然让她们觉得幸福来了……', 2309, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (28, 13, 26, '第26章 磕到假药了吗？', '　　“去吧！”\n\n　　几个女孩如获至宝，捧着腊肉，提着米袋子就跑到火堆旁边。\n\n　　三个女孩分工明确，小蕊把干木耳和干香菇放在盆里，倒上用矿泉水烧的热水。\n\n　　小晴安排小玉淘米，然后把米饭蒸上，自己拿起腊肉开始处理。\n\n　　林风没有管他们怎么折腾，走到折叠椅旁边，一屁股坐了下去，躺在靠背上，翘起二郎腿。\n\n　　闭上眼睛，意识沉入个人面板上。\n\n　　林风\n\n　　等级：1级（0%）\n\n　　体质：60\n\n　　力量：50\n\n　　敏捷：46\n\n　　精神：58\n\n　　灵能：61\n\n　　昨晚诡兽袭击营地的时候，吸收了一部分诡晶，终于升到了1级，今天在小镇里，用拆房子的方式取巧又杀了一些怨灵，同样收获了不少。\n\n　　目前他总共有92颗1级诡晶，还有一两百颗0级的。\n\n　　林风从口袋里摸出一颗一级诡晶，握在掌心，开始吸收。\n\n　　清凉的能量从掌心涌入，大约1分钟后，这颗诡晶彻底暗淡下去，碎成粉末。\n\n　　【等级1级1%】\n\n　　“还行吧，1颗一级诡晶能增加百分之一的进度。”林风又掏出一颗0级的诡晶，握在手里吸收。\n\n　　不到一分钟就没了，一看等级丝毫变化都没有，随后又取出几颗吸收，还是没有变化。\n\n　　这次林风干脆抓了一把0级诡晶，黄豆大小的诡晶足足几十颗，在手心中化作粉末，林风再看等级。\n\n　　1级1%。\n\n　　“我怕是磕到假药了吧。”\n\n　　林风直接坐起来，不敢相信自己的眼睛。面板上的数据实实在在的显示，纹丝未动。\n\n　　“这啥情况啊，0级诡晶能吸收，但不涨进度。”\n\n　　林风不信邪地再次取出一颗0级诡晶，放缓了吸收速度，细微的能量融入身体，导入小腹丹田的位置。\n\n　　这次林风真真切切地感受到了变化，那就是毫无变化。\n\n　　具体来说，就是0级诡晶的能量质量太低了，导入身体后，一不能壮大本身的灵能体积，二不能引起身体的变化，也不能说浪费吧，最少能补充体内消耗的灵能。\n\n　　可惜了，0级诡晶不能像1级诡晶一样增加等级经验。\n\n　　想到这里，林风恨不得给自己一下。\n\n　　昨天为什么不先吸收0级诡晶啊。\n\n　　先吸收0级的，等经验涨到百分百的时候，再用1级的冲级，一点也不浪费。\n\n　　现在倒好，剩下一百多颗0级的诡晶用不了，1级也只有91颗了。\n\n　　“败家啊……”\n\n　　林风深吸一口气，不再纠结这个问题，反正诡异到处都是，到时候再杀几只就行了。\n\n　　重新取出1级诡晶，林风一颗接着一颗的吸收。\n\n　　几个女孩在忙碌，偶尔交谈几声，还偷偷往林风这边看。\n\n　　“小蕊，看什么呢，赶紧把木耳拿过来，炒菜了。”小晴没好气的说道。\n\n　　“一会你自荐枕席得了，一直盯着大人看。”\n\n　　“哪有，你们有没有发现，林风大人长得好帅，现在这个末日，长得又帅，又有实力，还能喂饱我，我喜欢又怎么样，难得你们不喜欢。”\n\n　　别看小蕊人小小的，胆子也比另外两个大多了，直言不讳地说道。\n\n　　“喂饱你那张嘴？”\n\n　　“小玉，你要死啊，看我不挠你，挠你……”\n\n　　“呵呵……别弄了，我错了，小蕊……哈哈哈……我错了……”\n\n　　女人之间开起黄腔比男人还要厉害得多，就没有她们不敢说的。\n\n　　帐篷内的晓丽醒来，伸手摸了摸软垫周围，摸了一个空，心里不由泛起一阵失落。\n\n　　想起来之前红姐交代她的话，任务是完成了，可她刚才直接累晕过去了，现在只感觉浑身酸软，这是她从未有过的体验。\n\n　　“这真是我能抓住的男人吗？”\n\n　　她再次扪心自问，最后摇摇头，甩开不该有的念头，然后被一阵炒腊肉的香气吸引。\n\n　　当晓丽从帐篷里出来的时候，走路的姿势有些别扭，脸上红扑扑的，整个人就像被浇灌的鲜花一样，容光焕发。\n\n　　小玉趁机挣脱小蕊的纠缠，跑过去拉着晓丽，轻声问道：“你没事吧？”\n\n　　晓丽摇摇头，没有说话，她的嗓子确实喊哑了，都不知道刚才的狂风暴雨怎么熬过来的。\n\n　　小蕊贼兮兮的凑过来：“晓丽……大不大？”\n\n　　这话一出，晓丽差点没站稳，脸更红了。\n\n　　“大……”\n\n　　“你们在哪里嘀咕什么呢？赶紧过来帮忙，马上菜好了。”\n\n　　“哦，来了，来了……”\n\n　　几女这才止住继续聊的私密话题。\n\n　　一个个凑到锅面前，深吸一口气。\n\n　　“香，太香了……”\n\n　　“嗯嗯，我待会要吃三碗饭……”\n\n　　“小蕊……去喊林风大人，小玉，把折叠桌子支起来。”\n\n　　“好嘞……”\n\n　　小蕊蹦蹦跳跳地跑过来……\n\n　　“林风大人，饭好了，可以吃饭了！”\n\n　　林风把手中的诡晶重新收回袋子里，站起身，低头打量了一下眼前这个女孩，这才仔细看清她的模样。\n\n　　小蕊大概到他肩膀的位置，一米六左右的样子，给人一种娇俏玲珑的感觉，穿着一身JK制服，白色衬衫，深蓝色的百褶裙，领口系着一个红色蝴蝶结，脚上踩着一双黑色小皮鞋，经过几天的逃亡，哪怕就在红姐那里经过简单清洁整理，身上依旧不可避免地有些脏。\n\n　　她的脸上是那种让人看了就想捏一把的小圆脸，脸颊带点婴儿肥，笑起来会露出两个浅浅的小酒窝，嘴唇饱满红润，最惹眼的还是那双眼睛，又圆又亮。\n\n　　整体看上去就像一个精致的洋娃娃，可爱得让人想抱着把玩一番。\n\n　　往下看去，犯规了啊……\n\n　　“好看吗？”小蕊的声音甜甜糯糯的，好听极了。\n\n　　林风收回目光，嘴角微微抽动了一下，没有接话。\n\n　　他刚才在吸收诡晶的时候，虽然闭着眼睛，但听力可没有关掉，这几个女孩在火堆边聊的那些话，他可是一个字都没有落下。\n\n　　什么“喂饱你那张嘴”、什么“大不大”……\n\n　　全是从这个看起来人畜无害的小妮子嘴里说出来的，\n\n　　真是人不可貌相。\n\n　　这么可爱的一个小姑娘，说话比男人还奔放。\n\n　　“走了走了，吃饭吃饭。”小蕊伸手想拉林风的袖子，伸到一半又缩了回去，似乎觉得不妥，转身蹦蹦跳跳地在前面带路。', 2218, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (29, 13, 27, '第27章 想留在你身边', '　　折叠桌子已经支起来了，刚好够几个人围坐，桌面上摆放了两个金属盆，里面满满当当装满了菜。\n\n　　一盆木耳炒肉，一盆香菇炒肉。\n\n　　腊肉被切得厚薄均匀，边缘微微卷起，焦香四溢，两盆菜份量都很足，堆得冒尖。\n\n　　看来是听进去了林风的话，让多做点，就真的做两大盆。\n\n　　旁边还有一大盆米饭，热气腾腾。\n\n　　“大人，你先尝尝。”小晴递过来一双筷子，眼睛里带着一丝紧张。\n\n　　林风接过筷子，夹了一块腊肉送进嘴里。\n\n　　咸香浓郁，嚼头十足。\n\n　　“还不错。”林风点点头。\n\n　　这话一出，几个女孩同时松了一口气。\n\n　　她们站在桌子旁边，眼巴巴的望着林风，手指绞在一起，喉咙里不约而同的发出轻微的吞咽声。\n\n　　尤其是小蕊的口水都快流出来了，嘴角亮晶晶的，眼睛一眨不眨的盯着那盘木耳炒肉，小嘴微张，那样，可爱极了……\n\n　　“都坐下吃饭吧，别客气。”\n\n　　几女对视一眼，小蕊第一个坐下，动作快得就像抢座位一样，眨眼间，小玉、晓丽她们也跟着坐下。\n\n　　一开始她们还维持着几分矜持，保持着淑女形象。\n\n　　但不到一分钟，矜持就绷不住了 。\n\n　　小蕊第一个绷不住了，夹起一块肥瘦相间的腊肉塞进嘴里，腮帮子鼓得像仓鼠，眼睛眯成月牙，发出一声满足的声音。\n\n　　“嗯……太好吃了。”小蕊一边吃，一边扒饭，嘴里塞得满满当当，话都说不利索。\n\n　　“我从来没有吃过这么好吃的饭。”\n\n　　“嗯嗯嗯！”小玉在旁边疯狂点头，筷子不停：“真的好香。”\n\n　　其他两女虽然没有说话，但碗里已经见底了，正在盛第二碗米饭，当然，是很懂事地先帮林风添完饭，这才给自己盛。\n\n　　林风看着几个女孩狼吞虎咽的样子，心里多少有些感慨。\n\n　　在蓝星的时候，她们吃得肯定比这好得多，这样的饭菜最多算是普通家庭的家常便饭，她们是艺术学院的学生，在正常的世界里，每天只需打扮得美美的，自然有豪车带她们出入高档餐厅，喝下午茶，吃精致的料理。\n\n　　可现在呢？\n\n　　她们连野菜都吃不饱，车队虽然会为一些弱势群体分配食物，但每天分到的食物，只够吊着一条命。\n\n　　现在一顿白米饭，一盆炒腊肉，就是天堂。\n\n　　吃着吃着，小晴的筷子忽然停住了，她低着头，肩膀微微颤抖，一滴眼泪从脸颊滑落，滴落在饭碗里。\n\n　　“怎么了？”林风放下筷子问道：“不好吃？”\n\n　　小晴摇摇头，用力地吸了吸鼻子，声音有些哽咽。\n\n　　“不是……是太好吃了……我怕……”\n\n　　“怕什么？”\n\n　　“怕以后再也吃不上这么好吃的饭了。”\n\n　　这句话引起了其他几人的共鸣。\n\n　　然后是小玉，鼻子一酸，眼泪啪嗒啪嗒的往下掉，她用手背擦了又擦，擦不干净……\n\n　　小蕊的嘴瘪了瘪，眼眶蓄满泪水。\n\n　　林风沉默了几秒，端起碗继续吃。\n\n　　这几天，他见过太多眼泪了，饿急了，抱着变异怪物生啃，死了的，跟不上车队，被抛弃，被诡异撕碎的，在车队里被其他人欺凌的……\n\n　　在这个末日里，眼泪是最廉价的东西，哭完了，日子还要过，路还要继续往前走……\n\n　　没有人会停留，也没有人等待。\n\n　　“林风大人。”小蕊忽然抬起头，抹了一把眼泪，语气十分坚定的说道。\n\n　　“我能……我能留在你身边吗？”\n\n　　林风手中的筷子没停，看了她一眼。\n\n　　“我很听话的，”小蕊的声音里带着哭腔，“我什么都能干，打扫卫生，洗衣服，做饭，虽然我做饭没有小晴姐好吃，但我可以学。”\n\n　　“只要……只要每天让我有饭吃就行，你让我干嘛就干嘛，真的，我很好养活的，我个子小，吃的少……”\n\n　　说着，比划了一下自己的身高，手指还在头顶上方比了一个很小的距离，表示自己真的很好养活，眼泪汪汪的样子可怜极了。\n\n　　小玉见状也连忙放下了碗，急切地说道：“我也一样，我会铺床叠被，会收拾屋子，还会按摩，我妈妈以前腰不好，我经常帮她按，她说我按得可好了！”\n\n　　小晴没有说话，但她用希冀的目光看着林风，眼睛里全是期盼。\n\n　　几个女孩的目光汇聚在林风身上，带着哀求的期盼。\n\n　　晓丽的嘴唇动了动，想说什么，但最终还是没有说出口，她现在连自己能不能留在林风身边都不知道，虽然他们已经有了亲密的关系，但那又如何，末日里抛妻弃子的大有人在，甚至拿老婆换物资的男人也不少。\n\n　　其实她们心里都清楚，如果林风不要她们，她们就只能回红姐的那辆公交车上去了。\n\n　　那辆车是那么好上的吗？想到她们以后要像那几个站在公交车前任人挑选的货物一样，要伺候那么多陌生的男人，有些甚至粗陋不堪，身上带着难闻的气味，甚至有的还会变态地折磨她们。\n\n　　她们心里就涌起一阵深深的恐惧。\n\n　　与其那样，还不如便宜的林风呢。\n\n　　至少他年轻，长得帅，还有实力，出手也大方，从这顿饭就能看出来。\n\n　　而回到红姐那边，她们的未来就注定是在一辆公交车、一张肮脏的床上，面对一个又一个客人，直到身体被消耗殆尽，像垃圾一样被扔掉。\n\n　　她们不傻。\n\n　　她们只是没有选择。\n\n　　林风看着她们，沉默了很长时间。\n\n　　不是林风要拒绝，他本来就不是什么好人，谁家好人在末日第一天就开始偷懒，混吃等死。\n\n　　看到漂亮的姑娘来主动靠近，当然不会拒绝，末日前是这样，末日后也是这样，甚至变本加厉，俗话说，身怀利器杀心自起，拥有实力，还不懂得享受，那不是纯纯给自己找不自在吗？\n\n　　但他除了见色起意外，还想到一件事情。\n\n　　小玄！\n\n　　这只乌龟越长越大了，现在已经超过一辆小货车了，照这个速度长下去，它最终会变得多大像游轮、航母那般，还是更大……\n\n　　小玄的背甲每大一圈，能利用的空间就多出不少，以后在上面盖房子囤物资，甚至是种菜，打造生态圈，林风一个人根本忙不过来。\n\n　　林风肯定得打造自己的班底，留下几个小美女在身边，既能赏心悦目，又能使唤她们干活，何乐而不为。\n\n　　从红姐把她们送来的那一刻起，林风的意思就很明显，我全都要。\n\n　　林风的目光在她们身上转了一圈，不得不承认，这几个女孩长得确实好看，小蕊可爱，小玉温柔，小晴利落。\n\n　　晓丽则是清清淡淡的，像一朵刚开的小白花，清纯淡雅，尤其是那极为纤细的腰肢，林风想到刚才还能看到微微起伏的进度条，一阵火热。\n\n　　到时候看着她们干活，应该是另外一幅风景吧。', 2407, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (30, 13, 28, '第28章 一次不忠，终身不用', '　　林风的沉默让这几个女孩的心一点一点的往下沉。\n\n　　她们的眼眶又红了，咬着嘴唇，就在她们以为没戏了，林风只是玩玩而已……\n\n　　“都留下吧……”\n\n　　四双眼睛同时亮了起来。\n\n　　“真的？”\n\n　　“真的，”林风又夹起一块那肉放进嘴里，“不过留下得守我的规矩。”\n\n　　“守，守！什么规矩都守！”\n\n　　小蕊猛地点头，其他女孩也跟着拼命点头，生怕林风反悔似的。\n\n　　“第一，听话，我说什么就是什么，有意见可以说，但决定权在我这，第二，我不养吃里扒外的人，谁要是背后搞小动作，别怪我不讲情面。”\n\n　　“目前就这两条，能做到就留下，做不到现在就走，我不强求。”\n\n　　林风说话的声音不大，但每个字都说得很清楚，末日里，什么女人找不到，背后搞小动作，内耗的女人，他是真心烦，提前给她们打好预防针。\n\n　　“能做到！”小蕊第一个举手。\n\n　　“我们也能做到！”X3\n\n　　“那就行了，吃饭。”\n\n　　几女这才重新拿起筷子，但这次她们的心情跟刚才完全不一样了。\n\n　　刚才吃饭，是吃了上顿不知道下一顿饭在哪里，前路迷茫。\n\n　　现在吃饭，是因为找到了一个安身的地方。\n\n　　同样一盘菜，吃出了两种不同的味道。\n\n　　小蕊扒了一口饭，腮帮子鼓鼓的，含糊不清的嘟囔：“大人你放心，以后我就是你的小丫鬟，你让我往东我绝不往西，你让我躺着我绝不趴着……”\n\n　　“咳咳……”\n\n　　“行了，吃饭……”\n\n　　…………\n\n　　肉香在营地里飘散，顺着风向，传得很远\n\n　　营地里的人早早就闻到了这股香味，不是煮野菜那种苦涩的味道，而是真正的肉香，勾得人的馋虫直往嗓子眼里爬。\n\n　　一双双眼睛看向林风的方向，看向那张桌子上那盆堆得冒尖的炒腊肉。\n\n　　有人咽了咽口水，手里的野菜团子捏了又捏，实在下不去嘴。\n\n　　有人蹲在车旁边，看着林风的方向，眼里有羡慕，有渴望，但没有人靠近。\n\n　　因为那只大乌龟就趴在那里，巨大的身躯就像一座小山，只要有人往那个方向多走几步，它就会抬头，用一种让人头皮发麻的目光看过来。\n\n　　那目光里，没有威胁，没有警告，就这样平淡的看着，那种看蝼蚁的目光比任何威胁都管用。\n\n　　没有人想试探一只像卡车一样巨大的凶兽的脾气和耐心。\n\n　　不过，此时依然有人从营地中往林风这边走过来，那是两个女人，穿着还算体面。\n\n　　林风的余光扫到这两个女人身上，手里的动作顿了一下。\n\n　　这两个女人，他认识。\n\n　　不仅认识，还陪他在大巴车上几度风流，一个叫小梅，一个叫小甜，当然这都是她们自己说的名字，至于是真的假的，林风从没过问。\n\n　　就是昨天林风被踢出核心队伍后，立刻收拾东西跑去找董雨的那两个女人。。\n\n　　走得那叫一个干脆利落，连一句多余的话都没有。\n\n　　她们走到近处，林风还注意到她们脸上和露在外面的手臂上，有一些青紫色的痕迹。\n\n　　“风哥……”\n\n　　两个女人还没有走近，就开始哭。\n\n　　不是小声的抽泣，而是嚎啕大哭，眼泪说掉就掉，哗哗的往下流……\n\n　　“风哥，我错了，我们真的错了。”走到前面的小梅哭喊道，声音凄惨。\n\n　　林风面无表情的吃饭，甚至都没有抬眼看她们。\n\n　　两个女人扑通一声跪在地上，她们爬过来，一人抱住林风一条腿，还试图用脸去蹭林风的裤腿。\n\n　　“风哥，你最喜欢我们了，我们当时鬼迷心窍，你原谅我们一次吧……让我们回来好不好，我们以后一定好好伺候你，保证比以前伺候的还要好……”\n\n　　可是她们的话丝毫没有引起林风的情绪波动，反而被他一人一脚踹开了。\n\n　　小梅和小甜被踢得往后倒去，手肘磕到碎石子上，疼得她们龇牙咧嘴，但不敢叫出声。\n\n　　“风哥……”见林风如此无情，她们哭得更凶了，“你看，你看我们……”\n\n　　小梅把手伸到衣领处，往下拉了拉，露出锁骨下面的皮肤，纵横交错的鞭痕，带着血痂，还有一个个圆形的淤青。\n\n　　小甜也掀开衣服，把后背露出来，背上全是同样的痕迹，触目惊心。\n\n　　“那个董雨……她不是人……”\n\n　　“她把我们绑起来，还用鞭子抽我们……用火烤我们……不给我们饭吃……风哥，我们真的错了，你让我们回来吧。”\n\n　　“风哥，求求你，我们保证听话，你让我干什么都行。”\n\n　　林风放下筷子，看着面前跪着的女人。\n\n　　他的目光很平静，没有愤怒，没有同情，更没有怜悯，没有任何情绪。\n\n　　自从她们离开的那一刻起，林风就做好了随时被女人背弃的准备，女人跟男人不一样，只要几个男人在一起，很快就能选出一个头，听从老大安排，分工协作。\n\n　　而女人？\n\n　　女人没有忠诚度可言，她们只会攀附强者，尤其是蓝星那经过思想大冲撞的女人，只要你够强，够有钱，有势，所以……跟谁都行……\n\n　　“一次不忠，终身不用！”\n\n　　林风的声音不大，却字字清晰。\n\n　　“滚……”\n\n　　两个女人愣住了，她们以为只要自己哭得够惨，就能引起男人的同情，她们是真的害怕董雨，董雨虽然是个女人，可是她变态啊。\n\n　　而且她们也听车队里其他人说了林风的御兽大变模样，实力强悍，而且还找了一堆物资回来。\n\n　　两人一合计，直接跑过来求情，以她们的姿色，迷倒一个20出头的小年轻不是手拿把掐的事吗？再者说，她们去的是董雨那里，她们自以为又没有失身，肯定能得到原谅。\n\n　　然后获得林风的庇护，吃上美美的饭菜，还有肉，只是没有想到林风这么绝情。\n\n　　“风哥……”\n\n　　“再过来，杀了你们！！！”\n\n　　小梅和小甜同时打了一个寒颤，止住了往前靠近的动作，她们看到了林风的眼神，那不是生气，而是冷漠，冷漠得像看蝼蚁一样的眼神。\n\n　　那眼神在告诉她们，再往前一步，他真的会杀了她们。\n\n　　小梅张了张嘴，想再说什么，但对上林风冰冷的眼神，把到嘴边的话全部咽了回去，她们挣扎着从地上爬起来，踉踉跄跄的往后退了几步。\n\n　　然后转身走了，走得很慢，一步三回头，希望林风能叫住她们，直到她们消失在林风的视线里，林风都一直无动于衷。', 2291, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (31, 13, 29, '第29章 收集物资回归', '　　刚才这一幕，晓丽她们同样看见了。\n\n　　此时她们四个坐在桌子边，手里的筷子都僵在了半空，大气都不敢喘一下。\n\n　　她们被林风的表情吓到了。\n\n　　尤其是小蕊，那张笑嘻嘻的小圆脸现在绷得紧紧的，整个人都往后缩了缩。\n\n　　她们从来没见过林风露出过那种表情，不是愤怒，不是凶狠，而是不带任何情绪的冷漠，完全的漠视比愤怒还可怕，因为它意味着，林风在做决定的时候，不会被任何感情干扰。\n\n　　如果她们犯了错，林风会不会这样对她们？\n\n　　“吃饭啊，愣着干嘛？”林风拿起筷子，夹了一块腊肉放进晓丽的碗里，又给小蕊她们一人夹了一块。\n\n　　“只要你们听话，我还是很好说话的……”\n\n　　“听话听话！”小蕊疯狂点头，“特别听话，全世界最听话。”\n\n　　晓丽她们也跟着点头。\n\n　　“那就对了，”林风又给她们一人夹了一块肉，“吃菜吃菜，别浪费。”\n\n　　在美食面前，气氛重新活络起来，小蕊又开始叽叽喳喳地说个不停，小玉在旁边附和，小晴偶尔插一句嘴，晓丽不怎么说话，把目光停留在林风身上，安静地笑着。\n\n　　如果这时候有好感度提示的话，林风觉得这几个女孩的好感度一定在飞快的+1、+1……\n\n　　这并非因为林风对她们有多好，而是在这个末日里，能找到一个有实力、不会打骂她们、能保护她们还能喂饱她们的人，已经是天大的幸运了。\n\n　　更何况，这人长得还不赖。\n\n　　小蕊偷偷地打量着林风的侧脸，心里嘀咕了一句……本姑娘赚大了。\n\n　　两大盆菜，一大盆米饭，硬生生被5人吃得干干净净，连盆底的汤汁都没有剩下，小蕊把盆底最后一点汤汁倒进碗里拌了拌，吃得津津有味，连最后一粒米饭都没有放过，还伸出小舌头把碗里的油脂都给舔得干干净净。\n\n　　林风靠在折叠椅的靠背上，有些感慨。\n\n　　这一顿，他至少吃了七八个人的量，不是他林风贪吃，而是觉醒者的消耗确实大，这具强大的身躯运转需要能量，这些普通的食物根本经不住他造。\n\n　　“这胃口，养猪都比我省粮食。”林风自嘲地笑了笑。\n\n　　晓丽跟小晴默默地收拾碗筷，小玉跟小蕊在旁边打下手，把东西归类放好。\n\n　　此时，小镇的方向传来一阵嘈杂声，林风抬起头，往那边看去，几十辆车在往这边靠近。\n\n　　“其他车队？”\n\n　　当车辆靠得更近时，我们才发现是王烈他们以及巡逻队和后勤成员，打头的是几辆皮卡车，后面跟着长长的一串，什么车都有，轿车，面包车，小型货车，车上还装满了各种各样的物资。\n\n　　车队后面跟着一大群人，男女老少都有，手里提着大包小包，脸上挂着笑容。\n\n　　有的人在小镇里找到了一袋面粉。\n\n　　有的怀里抱着大米袋子，肩上还扛着被子衣物。\n\n　　营地里留守的女人和孩子看到这一幕，纷纷从营地里跑出来，迎了上去。\n\n　　“回来了，他们回来了！”\n\n　　“好多车，好多物资。”\n\n　　“爸爸，爸爸！”一个小女孩冲了出去，抱住一个男人的腿，男人弯腰把孩子抱起来，从口袋里掏出一个饼干递给她。\n\n　　小女孩的眼睛瞬间亮了，“谢谢爸爸！”随后抱着饼干啃起来。\n\n　　林风从折叠椅上站起来，往那边走去。\n\n　　车队在营地的空地上停下，车门打开，巡逻队员一个接一个从车上跳下来，一个个灰头土脸的，但脸上都带着笑，那是物资大丰收的喜悦。\n\n　　后勤人员开始清点物资，拿着小本子记录，安排人把物资从车上搬下来，一袋袋大米、面粉、矿泉水、食用油、衣物……被分门别类地堆放。\n\n　　末日里，任何东西都有用，哪怕是一块布料，都不能随意舍弃。\n\n　　跟在后面的车队成员，乖乖地配合后勤人员统计物资，上交一半后，回到自己的车子里，跟家人分享喜悦。\n\n　　没有人心甘情愿地上交自己辛苦收集到的物资，可是不交，就要被赶出车队，离开车队中觉醒者的领航和庇护，只能死路一条，虽说大家都有怨言，但还是老老实实地配合。\n\n　　不过让林风意外的是，竟然开回来这么多车，实在是让人疑惑不解。\n\n　　据他所知，车队里应该很缺燃油才对，有的车辆燃油不足，还有电车，两三天前就抛弃了大半，目前骑自行车的那些人，大部分都是车辆没油导致的。\n\n　　现在开这么多回来干嘛，车队缺的从来不是车，而是油，车队前行的路途中随时可以看到一辆辆被抛弃的车辆，基本都是没电没油，才抛弃的。\n\n　　不然谁有车不坐，跑去骑车啊。\n\n　　林风在人群中扫了一圈，看到陈敏正靠在一辆皮卡车旁边，手里拿着一瓶矿泉水在喝水。\n\n　　林风走了过去。\n\n　　“敏姐。”\n\n　　陈敏转过头来，额头上全是汗，但精神头很好，看到林风现在这个样子，眼睛亮亮的。\n\n　　“哟，林风弟弟，洗白白了？”\n\n　　“敏姐说笑了，再不洗我都臭了。”林风笑了笑，指着那些开回来的车问道。\n\n　　“搞这么多车干嘛？咱们不是缺燃油吗？”\n\n　　陈敏放下手中的水，叹了一口气。\n\n　　“哎……还不是灰雾！”\n\n　　“灰雾？”\n\n　　“嗯！”陈敏压低声音说：“灰雾离我们越来越近，雨桐占卜过，最多还有5天，灰雾就会追上来。”\n\n　　林风的眉头皱了起来。\n\n　　灰雾，他在穿越第一天就见识过来，那东西所过之处，一切都会被吞噬，车辆，人，什么都没留下，车队之所以一直在赶路，就是因为灰雾在后面追。\n\n　　“所以呢？”\n\n　　“所以车队要提速。”陈敏朝那些开回来的车努了努嘴，这些车不是用来开的，是用来拆的，郭毅要把属于我们几人的车辆改装一下，提升速度和越野能力，能跑多快跑多快。\n\n　　她顿了顿，语气里有一丝无奈。\n\n　　“唉……估计这次又要有不少人要掉队。”\n\n　　林风没有说话，他知道掉队是什么意思。\n\n　　车队提速，那些骑自行车、三轮车的人肯定跟不上，在这世界里跟不上，跟送死没什么区别。', 2179, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (32, 13, 30, '第30章 改装车辆', '　　林风站在原地，看着那些车被开到指定的位置。\n\n　　郭毅站在一辆豪华房车旁边，那正是王烈他们的核心车辆，他身边围着一圈后勤人员，有的递工具，有的搬材料。\n\n　　“快快快，把所有车辆的燃油都抽出来，一滴也不要剩。”\n\n　　一根根橡胶管插进车子的油箱里，黑色的汽油被抽出来，灌进铁皮油桶，抽完油的车被推到一边，开始拆卸。\n\n　　几个男人围着一辆辆车，在郭毅的指挥下，把一个个零件全部卸下来。\n\n　　“把拆下来的轮胎和材料都搬过来，尤其是电瓶，全部搬过来，快点……”郭毅大声喊道。\n\n　　后勤队员的动作麻利，那些车子很快被拆得七零八落，然后他们把东西搬到房车边上。\n\n　　然后林风就看到郭毅双手按在车身上，一丝丝蓝色光芒从他手掌蔓延到车身和那堆材料之上。\n\n　　然后神奇的一幕发生了。\n\n　　材料就像融化了一样融入车身当中，首先是轮胎变了，原本的充气轮胎迅速膨胀，变形，重塑，最后变成一个实心的橡胶轮胎，那轮胎就像是用橡胶和钢板融合而成的，表面还泛着一层金属光泽，轮胎的体型足足翻了一倍，差不多有一人高。\n\n　　然后是车辆的底盘在延伸，整个车辆像被一只无形的手拉升，底盘的高度猛地拔升了一节，悬挂系统被改造强化，一眼看去就知道越野能力提升了好几个档次。\n\n　　然后是车身装甲，车身表面似乎有金属流动，从单薄的铁皮变成了厚实的装甲，车身周围还加装了防撞网。\n\n　　车顶的四周加装了一圈半人高的金属护栏。\n\n　　整个过程不超过一小时，这辆房车，蜕变成了一辆豪华装甲房车，就连体积都足足大了一圈。\n\n　　林风的嘴巴微微张开，半天没合拢。\n\n　　“牛逼啊……”\n\n　　“怎么样？”陈敏双手抱胸，一脸得意的看着林风，“郭毅的能力不错吧。”\n\n　　“岂止是不错，”林风绕着这辆装甲房车转了一圈，啧啧称奇，“这玩意开路上，一般的变异生物根本拿它没办法，就算是1级变异生物，也咬不动这铁疙瘩。”\n\n　　“是啊！”陈敏说，“郭毅在车队里的地位比你想的高得多，虽然他不参与战斗，但没有他，我们早就困死在路上了。”\n\n　　林风点点头，表示认同。\n\n　　这哪里是机械维修，这分明是人形改造工厂。\n\n　　这时候，郭毅满头虚汗，手里拿着一颗诡晶吸收，抓紧时间恢复能力，朝着王烈走过来。\n\n　　“队长，材料不够了，这辆车，我着重改造了动力系统，不仅强化了发动机的马力，还增加了油电双动力系统，行驶途中能给电瓶充电，但是改造太消耗材料了。”\n\n　　“我们还有7辆大巴车，2辆公交，4辆货车需要改造，现在开回来的这些小车，加上原本手里的轿车，就算全拆了，也不够。”\n\n　　王烈沉默了几秒，问道：“差多少？”\n\n　　“差很多，”郭毅指了指那几辆大巴车，“大巴车的装甲覆盖面积太大了，就算只改造车辆的轮胎、悬挂系统，防撞结构，都需要大量的材料，最多只够改装2辆，材料缺得厉害”\n\n　　“而且我有一个想法，如果我们能找到足够的材料，我可以在大巴车顶安装射击平台，等我晋升2级后，就可以融合诡异材料制作车载连弩，哪怕是普通人也能对付变异生物和诡异。”\n\n　　王烈思虑了一会，沉声说道\n\n　　“征用车队里的私人车辆，突破瓶颈的2级诡晶我来想办法……”\n\n　　“我，我去安排。”郭毅转身要走。\n\n　　“等等，”王烈喊住他，转头看向陈敏，“陈敏这件事你去办，问问车队里的人，有没有人愿意放弃自己的车辆，尽量争取自愿原则，愿意的，给他们安排一个车位，不愿意就算了，不强求。”\n\n　　陈敏点点头，转身朝营地走去。\n\n　　她当然知道王烈为什么强调自愿，在这种末日环境里，一辆车就是一条命，对于那些普通人来说，手里有一辆车，就意味着最后的一点自主权。\n\n　　拿走他们的车，就等于拿走他们的希望。\n\n　　“郭毅，你留在这里继续改造车辆，尽量多安排一些空位……”\n\n　　“好的，队长……”\n\n　　王烈又看向董雨、刘铁柱和方玲。\n\n　　“你们三个，挑一部分巡逻队的人跟我走。”\n\n　　“去哪？”刘铁柱问。\n\n　　“我刚才回来的时候，在镇子边上看到一个修车厂。”王烈指了指镇子的方向。\n\n　　“在镇子的东边，里面停着一辆大挂，那里应该有不少材料，够我们用的。”\n\n　　三人应了一声，各自去召集人手。\n\n　　王烈走了两步，忽然停了一下，转头看了林风一眼。\n\n　　“林风，你去不去？”\n\n　　林风愣了一下，没想到王烈会邀请他。\n\n　　说实话，林风不愿意去，刚洗了澡，换了一身干净衣服，还吃了顿饱饭，正想找个地方躺下休息呢，如果不是想看热闹，他才不会过来。\n\n　　林风这么想的，也是这么做的。\n\n　　“呃，队长，现在太阳这么烈，怨灵又不敢出来，既然没啥危险，我就不去了吧，我还要改造一下我那乌龟背上的房子呢，小玄又长大了，我得回去调整一下，下次一定……再见，队长……”\n\n　　林风头也不回地跑了，看得王烈嘴角抽抽……\n\n　　营地里，陈敏正安排人在一辆车一辆车地问。\n\n　　“张叔，你这面包车还能跑多远？车队里的大巴车正在改造，需要材料，如果你愿意贡献出来的话，车队可以给你安排一个空位。”\n\n　　“能上你们的车上吗？那我这面包车不要了。”\n\n　　陈敏在本子上记了一笔，转身走向下一辆。\n\n　　一个年轻的女人站在一辆红色马自达旁边，抱着一个两三岁的孩子。\n\n　　“你这车愿意贡献出来吗？”\n\n　　年轻女人点点头，“这车是我老公结婚时买给我的，他……他前两天……”她没有说下去，眼眶红了。\n\n　　陈敏沉默了两秒，在本子上记了一笔。\n\n　　“带着孩子去大巴车上找个座位吧，跟司机说是我安排的。”\n\n　　年轻女人点点头，收拾好车上的行李物资，抱着孩子走了。\n\n　　陈敏深吸一口气，继续走向下一辆。\n\n　　一辆接一辆地登记。\n\n　　有人愿意，有人不愿意。\n\n　　不愿意的也不强求，转身就走。', 2229, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (33, 13, 31, '第31章 布置移动家园', '　　林风回到小玄的身边的时候，它刨的土坑更大了。\n\n　　“别吃了，让我看看你长多大了。”\n\n　　小玄从土坑里站起来，林风围着它转了一圈，发现这家伙的体型确实又大了一圈，原本它背上的石头是紧贴着龟壳边缘放置的，现在龟壳向外扩展了一圈，大概半米宽。\n\n　　“正好，我还嫌房子有点小。”\n\n　　林风以意念沟通小玄，土黄色的光芒亮起，蔓延到石头房子上，墙壁开始迅速往外扩张。】\n\n　　地面上的泥土被牵引上来，化泥成石，填补到新的空缺当中。\n\n　　房子的宽度扩展到两米五，长度扩展到4米。\n\n　　内部空间一下子宽敞很多。\n\n　　“撑得住吗？”林风跟小玄沟通后，对方反馈的意思很简单，这点重量小意思。\n\n　　“既然如此，那就再高一点。”\n\n　　土黄色光芒继续涌动，墙壁开始往上延伸，一直拔高到4.5米。\n\n　　这还没停，林风又有了新的想法，那就是分层，下面留作储物室，上面做卧室。\n\n　　这样就算是赶路的时候，也能躺着睡觉了。\n\n　　林风把想法用意念传给小玄，然后墙壁内部开始流动，重塑，一分为二，一层石头楼板形成，一条旋转楼梯在房子外面形成，从一楼一直延伸到二楼。\n\n　　不到半小时，连楼梯的围栏，预留的窗户和门这些细节都改造完了。\n\n　　林风看着面前的杰作，满意地点点头。\n\n　　两层小楼，下面储物，上面住人，虽然面积不大，但在这末日世界里，已经算是非常豪华的庇护所了。\n\n　　“哇……”\n\n　　身后传来一阵惊呼，不用猜都知道是小蕊，她此刻站在林风身后，仰着头看着小玄背上那栋小房子，嘴巴长得能塞进去一颗鸡蛋，眼睛只冒星星。\n\n　　“好……好厉害。”\n\n　　小玉和小晴也走了过来，晓丽跟在后面，她此时走路的姿势还有点别扭。\n\n　　四个女孩仰头看着翻新改造好的石头房子，眼睛里全是不可思议。\n\n　　“有家了……”\n\n　　“我们有家了……”\n\n　　“林风大人，快带我们上去看看！”小蕊拉着林风的袖子，眼巴巴的看着。\n\n　　“行，我带你们上去……”\n\n　　林风让小玄往土坑边上靠了靠，这才带着几个女孩踏上小玄龟背上的楼梯平台，这里特意往外延伸了半米，一是方便打开门存取一楼的物资，二是方便人从这里的楼梯往上去2楼。\n\n　　几个女孩小心翼翼地跟着林风这走上龟背，发现这只大乌龟一动不动，温顺得很，这才放松心神，跟着林风一起上楼梯，来到2楼。\n\n　　然后她们就兴奋地开始打量起来。\n\n　　“靠墙这边可以放床，那边可以放个柜子，这里可以放个桌子……”小蕊用手比划着。\n\n　　“你到时会安排。”小晴在她脑袋上敲了一下。\n\n　　“本来就是嘛，这里就是我们以后的家，当然要布置得舒舒服服的，对吧，林风大人……”\n\n　　“嗯！”林风点头。\n\n　　“那行，布置房间的事情就交给你们了，楼下我带回来了一些床上用品，你们去看看，拿上来布置一下，如果不够的话，从里面拿一袋大米去车队里换。”\n\n　　“交给我交给我，保证完成任务。”小蕊举起手，满是兴奋地说道。\n\n　　很快几个女孩就走下楼翻找林风收集回来的物品，然后开始议论纷纷。\n\n　　“我们还需要地毯，床就不需要了，毕竟大人的御兽是移动的，我们可以在地毯上铺上乳胶床垫……”\n\n　　“还有窗帘呢，我看预留了窗户，这个肯定需要，还有玻璃和门。”\n\n　　“床垫再多换一个，拼在一起，这样我们都够睡了……”\n\n　　…………\n\n　　车队里的人们刚从小镇搬回大量物资，人们自发地组成了交易市场，把自己用不到的东西，跟别人换取自己想要的东西。\n\n　　没有货币，基本都是以物易物，比如用矿泉水换盐巴，罐头换汽油这类紧俏的物资。\n\n　　不到一小时，几个女孩就回来了。\n\n　　小蕊和小玉抬着一个乳胶床垫，小晴抱着被子和几个枕头，手里还提着一堆东西，晓丽抱着一卷地毯，她们后面还跟着两个后勤队的成员，听说是给林风换物资，于是主动前来帮忙，一个人扛着玻璃窗，一个扛着一扇防盗门。\n\n　　“我们把东西换回来了。”小蕊把床垫往地上一放，气喘吁吁的，脸上全是兴奋。\n\n　　“这么多？”\n\n　　林风有些意外。\n\n　　“那当然，大米在车队里可值钱了。”小晴擦了擦脸上的汗，“我们刚把东西拿出来，就好几个人围上来，抢着跟我们换，那扇门还是他们去小镇上先拆下来的。”\n\n　　林风点点头，没有多问。\n\n　　接过玻璃框和防盗门被搬上了楼，林风使用控土术的能力把房门和窗户严丝合缝地安装上去，还利用控土术修正了一下房屋的细节，比如把地面和墙壁打磨得光滑无比。\n\n　　几个女孩开始往楼上搬东西，毛毯最先搬上去，铺在光滑的石板地面上，然后是两张1.8乘2米乳胶床垫拼接好铺上床单，等被子枕头铺好，十平方的空间就已经被占据了大半。\n\n　　小玉还特意请林风在窗户两边开了两个卡槽，用铁丝挂上一个白色的窗帘，窗台面特意开了几个洞，被她放置了几个擦得干干净净的奶粉罐，说是以后种点绿植或者鲜花什么的。\n\n　　几个抱枕被小蕊堆在床头的位置，晓丽则把被子和毛毯叠得整整齐齐。\n\n　　十平方的小房间，被几个女孩布置得温馨极了。\n\n　　这哪里像是末日逃亡，这分明就是一间小公寓。\n\n　　“怎么样？林风大人，还满意吧。”\n\n　　小蕊站在床边，双手背在身后，笑盈盈的望着林风。\n\n　　林风的目光在房间里扫了一圈，最后落在那张铺得整整齐齐的大床上，似乎想到什么，嘴角不由自主地微微上翘。\n\n　　“不错，为了奖励你们，去洗个澡吧，别浪费水……”\n\n　　“真的吗？”\n\n　　“谢谢大人……”\n\n　　“谢谢风哥哥！”\n\n　　得到林风许可后，几个女孩迫不及待地跑出房间，去烧水洗澡，天知道她们想洗澡想得都要疯了。\n\n　　只有林风在期待，不洗白白，我也下不去嘴啊，再漂亮的女孩子，天天这么奔波，浑身污垢，也好看不到哪去，怎么会提得起兴趣呢？', 2213, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (34, 13, 32, '第32章 不想姐妹吃苦，结果姐妹开路虎', '　　帐篷那边很快传来哗啦哗啦的水声和女孩们的笑声。\n\n　　几个女孩挤在一起，拿着毛巾擦拭身体，她们可不敢像林风一样浪费那么多水，只烧了一桶热水，互相擦洗。\n\n　　“晓丽姐姐？你腰好细啊，给我摸摸……”\n\n　　“别闹……小蕊，你别挠我痒痒……”晓丽的声音软绵绵的，带着一丝慌乱。\n\n　　“我就摸摸嘛，又不干什么！”\n\n　　“那你别摸哪里……啊……小蕊！”\n\n　　帐篷里一阵骚动，水花溅起的声音夹杂着几个女孩的笑闹声，引得周围的人频频侧目。\n\n　　“小玉你帮帮我，按住她，这小妮子要上天了。”晓丽的声音难得的拔高了几个调，又羞又恼。\n\n　　“我可不敢，小蕊这丫头虎得很，回头肯定要报复我。”\n\n　　“我帮你，小蕊你别跑！”小晴的声音插了进来。\n\n　　“啊啊啊……不公平，你们两个欺负我一个！小玉你到时帮帮我啊……”\n\n　　“来了来了，我帮你按住！”\n\n　　“小玉你这个叛徒，你也欺负我……哈哈哈……我错了……呜呜呜……”小蕊被挠得哈哈大笑，又挣脱不开，连连求饶。\n\n　　过了一会，打闹声平息下来，取而代之的是更私密的交谈声。\n\n　　“说真的，小蕊，你胆子也太大了。”小晴的声音压得低低的，“你竟然敢叫大人哥哥？”\n\n　　“怎么了吗？”小蕊理直气壮地说，声音中带着小女孩的娇憨。“又不是叫老公，叫哥哥怎么了？反正……反正迟早都是他的人。”\n\n　　“小蕊你这话也敢说？”\n\n　　“有什么不敢的，你们没有发现吗？林风大人看起来冷冷的，但人其实很好，别看今天拿两个女人回来找他，他眼睛都没眨就赶走了，但是对我们……对我们挺好的，还给我们肉吃。”\n\n　　“那是我们听话！”\n\n　　“听话的人多了去了，车队里听话的人少吗？”小蕊的语气认真了几分。\n\n　　“红姐手下那些姑娘哪个不听话，可她们过的什么日子，车队里那几个觉醒者大人手下的成员哪个做事不认真，这几天死了多少了？”\n\n　　“林风大人不但给我们饭吃，还让我们住到那只大乌龟的房子里面，那可是他的家啊，你们想想，这可是末日，车队里谁会把车分享给别人住？那辆车又这么安全？”\n\n　　此话一出，几女都不说话了。\n\n　　“所以我觉得，跟着他是我们的福气，我就是要让他记住我，记住有个小蕊的丫头，特别乖，特别甜，叫哥哥的时候声音特别好听……这样她就舍不得赶我走了。”\n\n　　又是一阵短暂的沉默。\n\n　　“小蕊，你这个小机灵鬼，我还以为你就是嘴甜，没想到心里门清。”小晴的声音带着几分艳羡\n\n　　“那当然，我可聪明了，对了，你们说，林风大人喜欢什么样的女孩子啊？”\n\n　　“我怎么知道，你去问他啊。”\n\n　　“我不敢……”\n\n　　“你刚才不是挺大胆的吗？”\n\n　　“那不一样，当面问多不好意思。”\n\n　　又过了好一会，帐篷的帘子掀开了。\n\n　　四个女孩换上了干净的衣服，露出的肌肤就像剥了壳的鸡蛋一般，林风不得不承认，洗干净的她们，真的很漂亮。\n\n　　“大人，我们洗好了。”小蕊见林风坐在躺椅上休息，立刻蹦蹦跳跳地跑过来，“好舒服啊，我感觉自己轻了5斤。”\n\n　　“那是你身上的泥掉了。”小晴在她身后打趣地说着。\n\n　　“哪有那么夸张！”小蕊回头瞪了她一眼，蹲在林风身边，眼睛一眨不眨地看着林风。\n\n　　“看什么？”\n\n　　“看大人啊，林风哥哥真好看，比明星还帅。”小蕊笑嘻嘻的说。\n\n　　“油嘴滑舌。”林风在她小脑瓜上弹了一下，不重，但小蕊还是夸张的‘唉哟’一声，捂着脑袋往旁边躲。\n\n　　“大人？”小蕊声音轻轻的。\n\n　　“我可以叫你林风哥哥吗？”\n\n　　“随便……名字只是称呼而已，我没那么多讲究，其实相比你叫哥哥，我更喜欢你们叫别的……”\n\n　　“叫什么？”\n\n　　“叫主任……”\n\n　　“林风哥哥你好坏啊……”小蕊说这话的时候还故意往晓丽的方向看去。\n\n　　晓丽顿时脸就红了，从脖子红到耳朵尖，她想到今天在帐篷的时候，喊主人饶命的时候……\n\n　　小蕊抱着膝盖，下巴搁在林风的膝盖上，“林风哥哥，我们以后一直跟你吗？”\n\n　　林风抬头看了她一眼。\n\n　　“怎么，不想跟了？”\n\n　　“想！”小蕊猛地抬头，声音拔高了八度，“特别想，做梦都想，我就是怕……怕你以后不要我们了……”\n\n　　“只要你们听话，我说过，我很好说话的。”\n\n　　“我们听话，”小蕊声音特别认真，一点不像平时那个嘻嘻哈哈的丫头，“特别听话，全世界最听话。“\n\n　　“我们也一样！”晓丽她们同样拼命点头，表达自己的决心。\n\n　　…………\n\n　　就在这时候，红姐带了几个人过来。\n\n　　她是过来收帐篷的，车里的物资不多，帐篷是不可多得的好东西，车队修整的时候，有个帐篷就能好好休息，如果不是为了讨好林风这个觉醒者，她也舍不得送过来。\n\n　　见到是红姐过来了，林风直接对小晴说。\n\n　　“小晴，你跟小玉去仓库里拿一袋20斤的大米和一块腊肉过来。”\n\n　　“好的！”\n\n　　很快小晴手里提着一袋大米，就是那种10公斤装，20市斤的五常大米，小玉手里还提着一块腊肉。\n\n　　林风接过大米和腊肉，直接送到红姐手里。\n\n　　当红姐双手接过那袋米和腊肉的时候，手都在微微发抖，二十斤大米，一块腊肉，在这个末日里，这笔“谢礼”让她简直不敢相信。\n\n　　“林风大人，这……这也太贵重了。”红姐的声音有些发颤，可脸上的笑意怎么都藏不住，嘴角都快翘到天上了。\n\n　　“你太客气了。”\n\n　　这太超乎红姐的预期了，平时那些男人点一个姑娘，一袋方便面都抠抠搜搜的，她今天只是牵线搭桥而已，就获得了这么丰厚的一笔物资，这就是抱大腿的感觉吗？\n\n　　林风摆摆手，没多说什么。\n\n　　红姐手里抱着那袋米，目光不由自主地飘向了小玄背上的石头房子。', 2175, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (35, 13, 33, '第33章 灰雾？', '　　“红姐！”小蕊注意到了红姐的目光，连忙拉着红姐的胳膊。\n\n　　“你看，这是我们以后的家，林风哥哥御兽背上的移动家园。”\n\n　　红姐的嘴角抽了抽，她看了看小玄背上那坚实的石头房子，又看了看自己那辆公交车，心里不知道是什么滋味。\n\n　　既希望姑娘们过得好，又见她们开上了路虎，不，这可比路虎强多了。\n\n　　这简直就是顶级移动家园，既能在逃亡途中遮风挡雨，还能抵御变异生物的袭击，还无需担忧燃油不足，车辆半路抛锚。\n\n　　这不比坐车安全十倍？\n\n　　这怕是整个车队最安全的地方了。\n\n　　“好……真好……”红姐喃喃道，目光在那栋石头房子上舍不得移开。\n\n　　晓丽和小玉她们也走过来，围在红姐身边。\n\n　　“红姐，谢谢你，如果不是你，我们可能……”\n\n　　“别说了。”红姐摆摆手，脸上的表情有些复杂。“你们能过得好，我就放心了。”\n\n　　她看着这四个女孩，一个个容光焕发，跟来之前那副眼神空洞、一片迷茫的样子判若两人。\n\n　　她把目光落在晓丽身上。\n\n　　晓丽的脖子上还有几块红痕，但她脸色红润，眼神里有光，整个人像是被浇灌过的花朵，整个人都散发着一种生机。\n\n　　红姐的心里有些发酸。\n\n　　不是嫉妒，而是羡慕。\n\n　　她也想住上去啊。\n\n　　但她知道，她没有那个资格，再说她车里还有几个女人，没有她的护照，怕是很快就会被车队里的男人吃干抹净，哪天死在路上都无人知晓。\n\n　　“大人，东西我就先收下了。“红姐招呼手下的人开始拆帐篷。\n\n　　很快帐篷的骨架被拆下来，折叠好，捆成一捆。\n\n　　然后把折叠浴桶也收起来，折叠好，装进袋子里。\n\n　　然后她把浴桶和那些烧水做饭的工具全部留了下来。\n\n　　“大人，既然你都弄出移动房子， 这些东西我就送给你了，浴桶都是新的，没用过几次，锅碗瓢盆什么的，你留着用。”\n\n　　林风点点头，没有客气。\n\n　　临走的时候，红姐犹豫了一下，又开口了。\n\n　　“林风大人……那个……我就是想问，以后车队要是遇到什么危险，我能不能……来你这避一避？”\n\n　　她说这话的时候，目光有些闪躲，声音里带着一丝小心翼翼的试探。\n\n　　林风看着她。\n\n　　上下打量了一下，这个女人，三十来岁的年纪，哪怕在末日里，依旧保养得很好，皮肤白皙细腻，身材匀称丰满，腰肢纤细，整个人站在那里，就有一股风情万种的感觉。\n\n　　尤其是走路的时候，那腰肢扭得跟水蛇似的，要是搭配一件旗袍，（不知会有多迷人）。\n\n　　啧啧……\n\n　　末日之前，这样的女人走在街上，回头率绝对不低。\n\n　　林风心里转过一个念头，嘴角微微勾起。\n\n　　“行！”\n\n　　红姐愣了一下，随即笑意盈盈，脸上写满了欢喜。\n\n　　“谢谢林风大人，谢谢大人，那就不打扰了，你忙着，你忙着……”\n\n　　她转身走了几步，又回头看了一眼小玄背上那栋房子，目光里带着浓浓的羡慕。\n\n　　然后深吸一口气，扭着腰，消失在人群当中。\n\n　　林风站在小玄旁边，看着红姐的背影，嘴角微微翘了一下，这条美女蛇动心了……\n\n　　就在这时候。\n\n　　“滴滴滴——紧急情况，紧急情况！”\n\n　　车队的大喇叭猛地炸响，喇叭声尖锐刺耳，在整个营地上空回荡。\n\n　　“车队立刻出发，车队立刻，出发，重复，车队立刻出发……”\n\n　　林风猛地转身。\n\n　　刚才还一片和谐的营地瞬间炸了锅。\n\n　　有人在喊“怎么了？发生什么事了？”\n\n　　有人在尖叫，锅碗瓢盆摔地上的声音，孩子哭闹的声音，发动机启动的声音混在一起。\n\n　　人们从帐篷里冲出来，从各个方向涌向自己的车，有人抱着孩子。\n\n　　“别问了，赶紧走。”有人冲进驾驶位，立马就打火发动了车子。\n\n　　“快快快，上车，东西别拿了，来不及了……”有人在大喊。\n\n　　最前面的一辆豪华房车已经启动，大巴车一辆接着一辆跟在后面。\n\n　　“我的东西，我的东西还在帐篷里面。”\n\n　　“别要了，赶紧跑！”\n\n　　“大人怎么了？”小蕊的手里拿着红姐送的锅碗。\n\n　　“不知道。”林风皱着眉头，目光投向小镇的方向。\n\n　　然后他看到了……\n\n　　小镇东部，修车厂的方向。\n\n　　天变了。\n\n　　那边的天空彻底暗了下来，不是普通的那种天阴，而是一种诡异、让人毛骨悚然的天变，灰黑色的雾气从地下疯狂涌出来，像是有什么恐怖的东西即将苏醒，雾气翻涌着，升腾着。\n\n　　灰雾！\n\n　　不是蓝星的那种大雾，是这个世界特有的灰雾，那灰雾像有生命一样，以肉眼可见的速度向四周扩散。\n\n　　灰雾中还能听见恐怖的哀嚎与嘶吼声。\n\n　　怨灵，那些藏在小镇中的怨灵，此时在灰雾的掩护下，倾巢而出。\n\n　　林风的瞳孔猛地收缩。\n\n　　他看到了小镇的方向，几个人影正在快速的奔跑，最前面的是方玲，她的速度快的惊人，整个人像是一道残影，后面跟着王烈。\n\n　　王烈的双手之间不断有蓝白色的电弧跳跃，每一次电弧闪烁，就有一道雷电劈向身后的灰雾当中，将灰雾中的怨灵劈得飞灰湮灭。\n\n　　紧跟在王烈身后的是刘铁柱和董雨，两人的速度也不慢，但是没有前两个那么轻松。\n\n　　而他们身后的巡逻队员就没有那么幸运了，一个接一个的倒下。\n\n　　只要被雾气追上，就……\n\n　　就没有然后了。\n\n　　被灰雾笼罩的人，连惨叫都来不及发出，就消失了。\n\n　　林风从来没有见过灰雾推进速度这么快的，\n\n　　根本就不像是移动，而是爆发。\n\n　　“走，快走，全部上去！”林风回头冲几个女孩喊道。\n\n　　小蕊、小玉等四女手忙脚乱地往小玄背上的石头房子上爬，晓丽踩空了楼梯，膝盖磕在石头上，疼得眼泪都出来了，但她咬着牙没有喊出声，爬起来继续往上爬。\n\n　　“小玄！”\n\n　　林风纵身一跃，跳上石头房子的屋顶，稳稳地站在上面。\n\n　　小玄四条粗壮的腿，猛地撑起身体，整个背甲抬升了两米多，顺着林风手指的方向，开始狂奔。\n\n　　“追上最前面那辆房车。”', 2217, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (36, 13, 34, '第34章 灰雾是什么情况', '　　它的速度很快，每一步都跨出两米多的距离，背上的房子纹丝不动，二楼卧室里，几个女孩缩在角落里，抱在一起，但没有一个人发出声音。\n\n　　林风往车队的方向看去。\n\n　　灰雾已经蔓延到镇子外，冲到了车队后方的位置。\n\n　　方玲的速度最快，已经追上了车队末尾的一辆大货车，一个翻身就上了车。\n\n　　王烈最后放了一道雷电，头也不回地冲进车队，猛地一跃，被方玲拉上了车。\n\n　　刘铁柱的胳膊断了一只，仅剩的一只手还抓着董雨在跑，董雨脸色苍白，浑身都是伤口，几乎是刘铁柱带着她在往前跑。\n\n　　林风也没有想到，刘铁柱还有这么讲义气的一面，在灰雾追上他们的最后一刻，他猛地一发力，把董雨扔向车队的方向。\n\n　　董雨整个人像炮弹一样向方玲的方向砸来，然后被方玲稳稳地接住。\n\n　　把最后的求生机会，让给了队友，自己却被灰雾吞噬，然后被无数的怨灵包围……\n\n　　林风忽然觉得刘铁柱没那么讨厌了，这世界真有舍己为人的啊，这已经不是单纯的讲义气了。\n\n　　车队的速度猛的加速，所有人恨不得把油门焊死，所有能动的车辆都在疯狂的往前跑。\n\n　　那些骑自行车的人，双腿猛蹬，可是依然躲不过爆发的灰雾，连人带车被灰雾笼罩，消失不见。\n\n　　“等等我啊，让我上车，让我上车……”\n\n　　有人用力的拍打车门，试图登上汽车。\n\n　　没有人开门，没有人停下。\n\n　　那些跟不上车队的人注定只有一个结局。\n\n　　林风收回目光，看向前方，前面是无尽的荒野，灰蒙蒙的天空，看不清方向。\n\n　　但不重要，只要跟着车队走就行，车队里的领路人还在。\n\n　　重要的是他现在还活着，还有小玄，还有满满一屋子的物资\n\n　　嗯，还有4个听话的女孩。\n\n　　够了！\n\n　　林风深吸一口气，从屋顶上跳下来，落到楼下的楼梯口，然后沿着楼梯上了2楼。\n\n　　四个女孩挤在床边，脸色苍白，身体在发抖。\n\n　　看到林风进来，她们的眼睛齐刷刷的看过来。\n\n　　眼神里有恐惧，有不安，也有依赖。\n\n　　“没事了。”林风走过去，坐在床垫上。“灰雾已经追不上了。”\n\n　　小蕊的眼泪终于忍不住，啪嗒啪嗒地掉下来，她咬着嘴唇，拼命不让自己哭出声。\n\n　　“都休息吧，今天可能要跑一整夜。”\n\n　　没有人说话，只有小玄咚咚咚的奔跑声，还有车辆发动机的轰鸣声。\n\n　　林风把鞋子一脱，爬上床拉过一床毛毯盖在身上，从包里取出一枚诡晶开始吸收，已经给小玄下达跟随车队的命令，无需自己操心路线的问题。\n\n　　那还是提升实力比较重要，没有力量，一直都在逃亡，林风在心里发誓，总有一天，我要让灰雾看到我就绕道走。\n\n　　随着一颗接一颗的诡晶被吸收，1级跨向2级的进度越来越高。\n\n　　一路逃亡，车队几乎没有停过。\n\n　　车队在沈雨桐的指引下，不断转向、绕弯，有时候车队会突然减速，缓缓绕过一个巨大的黑影，看不清具体是什么东西的轮廓，就像一栋诡异的大楼耸立在荒野上\n\n　　有时候又会突然加速，像是逃离正在接近的诡异一般。\n\n　　好在这一夜几乎没有大规模的诡异袭击。\n\n　　零星的几只诡异从黑暗中扑出来，还没有靠近车队，就被一道雷电，或者一把飞刀给随手解决了，林风在后面把手里的诡晶吸收完后，想着去猎杀点诡异，才出手了一次。\n\n　　一只长得像蜥蜴一样的诡影从路边窜出来，直奔车队中段的一辆大巴车。\n\n　　林风坐在屋顶上，都没起身，只是伸手，意念一动，一道地刺从地面猛地刺出，那道诡影顿时消散不见。\n\n　　【猎杀0级诡蜥，获得进化点0.1】\n\n　　陈敏在另外一辆大巴车顶看到这一幕，朝着林风竖起大拇指。\n\n　　林风点点头，见没啥便宜可捡，干脆直接回到2楼，重新躺好。\n\n　　几个女孩子在窗户前看到这一幕，眼睛都看直了，心里的恐惧消散大半，普通人避之不及的诡异，被这样轻描淡写，如同捏死一只蚂蚁一般，实在太震撼了。\n\n　　“林风哥哥好厉害！”小蕊小声地说。\n\n　　“睡觉！”林风闭着眼睛说了一句。\n\n　　小蕊乖乖的闭上了嘴，但眼睛还是睁得大大的，偷偷看着林风的侧脸，过了好久才迷迷糊糊的睡过去。\n\n　　林风中途醒了几次，发现小玄依旧跟在车队里，便彻底放心地睡了过去。\n\n　　天亮的时候，车队的速度慢了下来，前面领队的车辆刚开始减速，后面的车辆跟着放缓速度。\n\n　　车队的喇叭响起来。\n\n　　“全体注意！全体注意！前方到达休整点，车队进行休整，重复……”\n\n　　一夜的狂奔让所有人都筋疲力尽，发动机慢慢熄火，车队停在一条小河边。\n\n　　河面大约七八米宽，水流不算急，河岸旁长着一些低矮的灌木和杂草。\n\n　　小玄的脚步也慢下来，最后趴在一处河滩旁边。\n\n　　人们从车上爬了下来，伸懒腰，活动筋骨，脸上全是劫后余生的表情。\n\n　　“活着……我们还活着……”\n\n　　“差一点，就差一点，我看到灰雾就在我后面，就差几米……”\n\n　　“老李呢？看到老李的车没？”\n\n　　没有人回答他。\n\n　　有人蹲在地上哭起来，肩膀一耸一耸的，昨天还在打招呼的熟人，今天就彻底倒在了后面的道路上……\n\n　　林风站在2楼的窗户边，看着下面这片劫后余生的景象，脸上没有什么表情。\n\n　　还能哭，说明还活着，没有到最绝望的时候。\n\n　　林风转身对几个女孩说了一句：“别离开房子，饿了就去楼下找吃的，在确定没有危险之前别乱跑！”\n\n　　“知道了，我们不会乱跑！”\n\n　　林风从小玄的背上跳下去，朝着领头的装甲房车走去。\n\n　　房车的车门敞开着，林风登上车时，几双眼睛齐刷刷地看过来。\n\n　　七个人。\n\n　　少了刘铁柱。\n\n　　林风的目光在车里扫了一圈，没有说什么，找了个空位坐下。\n\n　　王烈依旧坐在最里面的位置上，面前的桌子上摆放着一壶茶，茶汤金黄，他给林风倒了一杯，推过来。\n\n　　林风接过来，喝一口，茶叶的清香在口中弥漫，虽然林风不懂茶，可也觉得好喝。\n\n　　“这茶是昨天在镇子上找到的，我看着还不错，就泡了点，你要喜欢待会带点回去。”\n\n　　林风点点头，把茶杯放下，白来的好处，不要白不要。\n\n　　当然也没有忘记来这里的正事，当即开口问道：\n\n　　“昨天的灰雾！是什么情况？”', 2327, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (37, 13, 35, '第35章 花轿', '　　内安静了一瞬。\n\n　　几人互相看了看，最后把目光落在冬雨身上，\n\n　　董雨低着头，脸色惨白，身上缠满了绷带，绷带还往外渗着鲜血。\n\n　　她抬头看了一眼王烈，对方微微点头后，这才开口。\n\n　　“修理厂，我们在那个修理厂里面看到一顶花轿。”\n\n　　“花轿？”\n\n　　“对，”冬雨点点头，像是在回应什么让她不寒而栗的画面。\n\n　　“大红色的花轿，那种古代结婚用的花轿，轿子上面还绣着凤凰和祥云，做工很精致，就停在修理厂最里面的大厅里，周围什么都没有，干干净净的，跟外面车间里的那些破铜烂铁完全不一样。”\n\n　　“我当时就觉得这东西不一般，就喊队长他们过来看。”董雨说到这里的时候声音明显在发抖。\n\n　　“我们出于好奇过去查看了一下……发现那顶花轿散发的能量波动非常强烈，比我们见过的任何器物都要强，我们想着能不能把它搬回去，研究一下关于诡物的能力……”\n\n　　“然后……”\n\n　　“然后我掀开了轿帘……”\n\n　　董雨的声音开始颤抖，身体也在颤栗……\n\n　　“我只看见一抹红色的嫁衣，然后灰雾就从花轿里涌出来，不是一点点，而是像洪水一样往外喷……”\n\n　　“然后那些藏在房子里的怨灵，在灰雾中活了过来，紧接着地底的恐怖怨灵跟着爆发……”\n\n　　她没有说下去，\n\n　　车厢里的空气凝重得像凝固了一样。\n\n　　林风把董雨的话过滤了一遍。\n\n　　搬回来研究？\n\n　　怕是你们想贪图那件诡异器物是不知名的宝物，才把诡异引出来了，但这个念头只在脑子里转了一圈，始终没有说出口。\n\n　　事情都已经这样了，再追究没有任何意义。\n\n　　林风看向沈雨桐。\n\n　　沈雨桐坐在小桌的另一侧，勉强摊着一张手绘地图，手里拿着一支笔，在地图上画着什么，她的脸色比昨天更苍白了，眼睛上一圈黑眼圈，显然一整夜都没合眼，消耗了大量的精神，昨晚车队能安全跑出来，她功不可没。\n\n　　“雨桐姐！”林风开口问道。\n\n　　陈玉婷沉默了几秒，然后摇摇头。\n\n　　“不清楚，我们也才来这个世界八天，很多东西都不了解。”她手里的笔无意识地在纸面上点了点。\n\n　　“但据我猜测，灰雾可能来自一种……规则级的诡异。”\n\n　　“规则级？”林风不解。\n\n　　“那是什么等级？”\n\n　　沈雨桐摇摇头，声音里带着一丝恐惧与不安。\n\n　　“我不知道，我只知道……很强，强到我们无法面对。”\n\n　　车厢里彻底安静了\n\n　　过了好一会儿，王烈端起茶杯喝了一口，放下杯子的时候，手指在桌面轻轻的敲了两下，把所有人的注意力拉回来。\n\n　　“先不讨论这个问题了。”王烈的声音沉稳，带着一种安心的力量。\n\n　　“以我们现在的实力，讨论这个也没有意义，我们现在能做的，不是搞清楚灰雾到底是什么，而是想办法活下去。”\n\n　　他直起身，目光扫过所有人。\n\n　　“我们现在的问题是，车队损失惨重。”\n\n　　他看向方玲：“损失统计了吗？”\n\n　　方玲翻开手里的本子，上面写满了密密麻麻的数字。\n\n　　“人员减半了，天车队还有957人，现在……”她低头看了上面的数字。\n\n　　“不到五百。”\n\n　　957人一夜之间少了将近一半，不到五百人了，那些骑自行车的人，那些车辆跟不上车队的人，就这样被灰雾吞掉了。\n\n　　“物资呢？”王烈又问。\n\n　　“更惨！我们在小镇里找到的物资，大半都遗落在营地了，很多还在统计，来不及搬上车，灰雾就来了，现在车队里的食物储备，就算省着吃，最多还能撑两天。”\n\n　　两天？\n\n　　如果找不到新的物资，两天后，车队里的人饿急了，就得造反。\n\n　　然在饥饿下，什么事情都做得出来，就算有觉醒者武力镇压，一样没用，到时候车队还得继续减员。\n\n　　“雨桐，我们现在离那个加油站还有多远？”\n\n　　沈雨桐闭上眼睛，手指在地图上缓缓滑动，像是在感应什么。大约十几秒，她睁开眼睛。\n\n　　“经过昨晚放全速前进，现在距离加油站大约还有两百公里。”\n\n　　“两百公里！”王烈重复着这个数字，眉头皱成川字。\n\n　　“但灰雾追上来的时间，大约还剩十六小时。”\n\n　　“嘶！！！”车里的空气都仿佛被抽走了一层。\n\n　　在座的所有人心里都清楚，除非车辆全速前进，不然，他们可能跑不过灰雾了。\n\n　　“十六小时……”王烈重复呢喃着这个数字，然后深吸一口气。\n\n　　“先补充水源，刚好这里有条河，让大家去取水，一小时后出发。”\n\n　　“郭毅！”\n\n　　“我在，队长。”\n\n　　“你尽量改装我们的车辆，尤其是大巴车跟货车的动力，接下来我们要加速了……”\n\n　　“是，队长。”\n\n　　“方玲，你去通知后勤，组织人取水。”\n\n　　郭毅和方玲迅速下车，去组织人手，抓紧完成任务。\n\n　　“还有一件事，”王烈看着陈敏，“巡逻队昨天几乎全军覆没，除了留在营地里的十几人之外，其他的全没了，你去问一下有没有人愿意加入巡逻队。”\n\n　　陈敏点点头，跟着下车了。\n\n　　董雨默默站起来也下了车，江生见没他什么事，回自己的大巴车上培育土豆去了。\n\n　　车里只剩下王烈和林风，沈雨桐一如既往的研究着地图，充当背景板。\n\n　　王烈端起茶杯，把最后一口茶喝完，看着林风。\n\n　　“你要不要留下来，一起商量下一步的计划。”\n\n　　林风摇摇头。\n\n　　“不了，你们定就行，我这跟着走，有需要帮忙的知会一声。”\n\n　　说完林风站起来，朝着车门走去，走到车门的时候，停了下来。\n\n　　“刘铁柱这事，我敬他是个汉子，但我不欣赏这种人……”\n\n　　王烈看着林风消失的背影，沉默了很久。\n\n　　他明白林风的意思，这是末日……\n\n　　“全体成员注意，全体成员注意，车队只停留一小时，一小时后车队出发，重复……”', 2140, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (38, 13, 36, '第36章 变异利齿鱼', '　　喇叭里的声音播了一遍又一遍，本来瘫在地上的人群，像是被什么东西蛰了一下，猛地弹起来。\n\n　　“什么？只停一小时，才一个小时？”\n\n　　“快快快，打水去，别磨蹭！”\n\n　　人们手忙脚乱地从车里翻出矿泉水瓶、铁皮桶、塑料瓶等各种容器，抱着就往河边跑。\n\n　　“让一让，让我先打，懂不懂尊老爱幼。”\n\n　　“艹，老不死的，赶着去投胎啊？”\n\n　　人群密密麻麻的蹲在河岸边，把储水的容器按进水里，咕嘟咕嘟的灌水。\n\n　　“这水还挺清的，比上次停的那条小水沟强多了。”一个中年妇女蹲在河边，用手捧了一捧水浇在脸上，发出一声畅快的声音。\n\n　　“可不是嘛，前两天喝得都是带沙子的……”\n\n　　“哎，我说，”一个光膀子的男人往前走了几步，站在齐腰深的水里，朝岸上喊：“好几天没洗澡了，这水挺干净的，洗一个呗？”\n\n　　这话一出，人群纷纷附和。\n\n　　“是啊，我头发都打结了，梳都梳不开！”\n\n　　“身上都臭了，我自己都闻不下去 ！”\n\n　　几个男的二话不说，脱了上衣就直接跳进了河里，水花四溅。\n\n　　女人则要矜持一些，她们蹲在河边，挽起裤腿，把毛巾打湿，擦洗，有人从车上翻出洗发水，倒在手心里，抹在头发上，搓出灰色的泡沫。\n\n　　可见有多脏！\n\n　　“太舒服了……”一个女人闭着眼睛，手指插进头发里，慢慢的搓揉，表情享受。\n\n　　“好姐姐！洗发水给我用一点吧！”\n\n　　“用吧！不过我也不多了，就剩一点了！”\n\n　　旁边的女人接过瓶子往手心里磕了几下，也只挤出来一点点，不过也够她洗一次了。\n\n　　林风回到小玄身旁，远远的看着河滩上这一幕。\n\n　　“林风哥哥，我们不用去打水吗？”小蕊不知道什么时候从石头房子里跑出来，手里还提着一个铁桶。\n\n　　“别去，仓库里有水，还有十几箱，够用一阵子了。”\n\n　　“而且河里不知道有什么东西，老老实实带着。”\n\n　　小蕊“哦”了一声，又把铁桶放了回去。\n\n　　就在这时候，\n\n　　“啊……”\n\n　　一声惨叫声从河中央传来。\n\n　　林风猛的转头，就看见河中央，一个正在扑腾的男人突然就沉了下去，只留下一只手在拼命挥舞，然后那只手也被拖进水里。\n\n　　“怎么了?发生什么事了？”岸边的人还没反应过来，纷纷伸长了脖子往河里看。\n\n　　“有东西，河里有东西……”\n\n　　话音未落，一条巨大的黑影从水面窜了出来。\n\n　　那是一条鱼，但不是普通的鱼。\n\n　　它足足有一米多长，浑身覆盖着灰黑色的鳞片，最恐怖的是它的头，占据身体的近半体积，头骨畸形的凸起，嘴巴张开的时候，露出一圈圈密密麻麻的獠牙，最短的也有手指长。\n\n　　“咔嚓……”\n\n　　它跃出水面的瞬间，一口咬住一个正在往岸上跑的男人。\n\n　　腰部被整个贯穿，那个男人只来得及发出一阵短促的惨叫，就被那条鱼拖着往水里沉，水面迅速泛起一大片红色的血迹。\n\n　　“怪物，有怪物！”\n\n　　“救命啊……快跑，快上岸！”\n\n　　“觉醒者！觉醒者呢，为什么没有排查危险……”\n\n　　人群瞬间炸开了锅。\n\n　　男人们纷纷从水里连滚带爬的往岸上游，有些人吓得腿软，在水里扑腾了好几下才站起来，裤裆里湿漉漉的分不清是河水还是别的什么。\n\n　　女人们也顾不得头上的泡沫，尖叫着往远离河岸的方向跑，盆子，桶，水壶扔了一地，没有人回头去捡。\n\n　　但那变异怪鱼不止一条。\n\n　　水面像炸开锅一样，接二连三的炸开，一条、两条……至少五六条同样大小的怪鱼从水下窜出来，咬住还在水里挣扎的人。\n\n　　一个年轻人已经跑到了浅水区，水直到他的膝盖，马上就要跑上岸边，他回头看了一眼，就这一个回头，彻底断送了他的性命。\n\n　　一条怪鱼从水中跃起，张开的大嘴精准的咬住他的头颅。\n\n　　咔嚓……\n\n　　骨头碎裂的声音清晰的传到周围每一个人的耳朵里。\n\n　　那个年轻人的身体还在往岸上跑，头颅已经不见了，跑了两步才往前倒去，脖颈的断口还在往外喷血，把周围的河水和石头染成一片触目惊心的红。\n\n　　“啊…啊啊啊…”\n\n　　尖叫声此起彼伏。\n\n　　“救命啊，觉醒者为什么还不来，他们不是说会保护我们吗？”\n\n　　“快来人啊，死人了……”\n\n　　一个女人被一条怪鱼咬住小腿，整个人被拖入水中，她双手拼命的抓出河底的尸体，指甲都翻起来了，但还是在被一点一点的往深水里拖，她丈夫从岸上冲回来，一把抓住她的手，拼命往上拖……\n\n　　“啊……救我……”\n\n　　咔嚓……\n\n　　女人的小腿被整齐咬断，断口处白森森的骨头露在外面，血疯狂往外涌，她丈夫抱着她往岸上跑，两人身上全是血。\n\n　　“救命啊，有没有医生，有没有医生，救救我老婆……”\n\n　　林风看到变异鱼袭击人群，第一时间就往那边赶去。这时，一只变异鱼跃起，眼看就要咬中一个抱着孩子的女人。\n\n　　林风想也没想，调动灵气施展从小玄那里共享过来的控土术，一道锋利的土刺猛地从河底刺出，精准的贯穿那条还在空中的怪鱼身体。\n\n　　地刺尖端从鱼的背脊上穿出来，那条鱼剧烈的扭动着，但它挣脱不了，地刺又粗又硬，越挣扎死的越快。\n\n　　【击杀1级变异利齿鱼，获得进化点+1】\n\n　　1级？\n\n　　怪不得速度这么快，咬合力这么恐怖，一级的变异生物，对付这些毫无防备的普通人，和捏死一只蚂蚁没什么区别。\n\n　　与此同时，王烈的雷电也到了。\n\n　　一道蓝白色的闪电直接落在河面上，那条正要跃起攻击岸边人群的变异利齿鱼被劈了个正着。\n\n　　浑身抽搐着从半空掉下来，砸在河滩上，它的身体还在抽搐，鳞片被电得焦黑一片，发出淡淡的烤鱼香气。\n\n　　但更多的变异利齿鱼还在水里。\n\n　　王烈没有停，双手合拢，在掌心凝聚出一颗雷球，雷球越聚越大，从拳头大小变成篮球大小。\n\n　　“雷暴！”', 2176, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (39, 13, 37, '第37章 起哄', '　　他将雷球投向河面，雷球落入水中的瞬间，整个河面都炸开了。\n\n　　“轰！！！”\n\n　　水花飞起三米高，电弧在河面上织成一张电网，电蛇乱窜 ，水里的变异利齿鱼疯狂挣扎，有的跳出水面，落下去的时候已经不动了，有的在水里打滚。\n\n　　十几秒后，河面平静下来。\n\n　　七八条利齿鱼翻着鱼肚皮，漂浮在水面。\n\n　　陈敏站在岸边，精神力探测一番后，睁开眼睛。\n\n　　“没有了，河里的利齿鱼已经清完了，要么已经跑了。”\n\n　　王烈收回手，喘着粗气，刚才的大招消耗不低。\n\n　　“陈敏！能不能把那些鱼弄上岸？”\n\n　　陈敏点点头，伸出右手，对着河面轻轻一招，七八条利齿鱼像被一只无形的手抓着，缓缓飘向岸边。\n\n　　等飘到岸边的时候，林风跟方玲下去，一人提着一只，往岸上丢，包括林风杀死的那条，整整齐齐的码在岸边，一共九条。\n\n　　近距离看，这些变异鱼更加恐怖，每一条都有一米多长，它们的鳞片比指甲盖还厚，用手指敲上去能听到咚咚的声音，像铁板。\n\n　　“这玩意能吃吗？”方玲蹲在一条鱼旁边，用手里的匕首戳了戳鱼肚子。\n\n　　王烈蹲下来，仔细看了看鱼身上的肉质，又闻了闻，没有腐臭味。\n\n　　“应该能吃！”\n\n　　“1级变异生物的肉，觉醒者吃了能增强属性，普通人吃了也能增强实力。”\n\n　　林风心中一喜，这鱼分解后，去掉鱼头内脏啥的，最少也有五六十斤的鱼肉。\n\n　　“要是能多抓几条就好了！”\n\n　　王烈还没有开口，一群人就涌了过来，尤其是他们听见这鱼能吃，还能提升实力的时候，更是爆发出一阵嘈杂的议论声。\n\n　　大约三十四人，身上湿漉漉的，有的还光着膀子，脸上全是愤怒的神色。\n\n　　为首的是一个四十来岁的男人，他的头发还在往下滴水，眼睛红红的。\n\n　　“你们……你们觉醒者为什么没有排除危险？”\n\n　　“我弟弟刚才就死在水里！你们的职责就是保护我们，结果呢，河里有怪物你们不知道，我们这么多人下水，你们不管？你们干什么吃的？”\n\n　　他身后的人跟着附和，车队里每天都在死亡，不满的情绪早就压在心中，这次终于爆发出来。\n\n　　“对，排查危险本来就是你们觉醒者该做的事情！”\n\n　　“人死了，你们得给我交代！”\n\n　　“不交代清楚，今天这事没完！”\n\n　　越来越多的人围了过来，刚才那些从河里跑上来的人，目睹了这些亲人朋友被怪鱼拖走的人，还有那些被裹挟盲目从众的人纷纷聚拢过来。\n\n　　一个穿花衬衫的中年女人冲到王烈面前，她的手指戳向王烈，整个人的身体都在剧烈地颤抖，“我老公，我老公他就在我面前被咬死，你还我老公命来……”\n\n　　王烈站在那里一动不动，任由她的手指戳在他的胸口上。\n\n　　“我兄弟刚才也死了，死在河里，连个全尸都没有……”\n\n　　“对，要个说法，必须给个交代。”\n\n　　“觉醒者也不能光拿好处不办事吧？”\n\n　　“就是就是，凭什么我交一半的物资，连基本的安全都保证不了？”\n\n　　“这不公平！”\n\n　　“对，我们要公平……”\n\n　　林风抱着双手，站在一旁，看着面前这一幕，面无表情。\n\n　　甚至有点想笑。\n\n　　都什么时候了，还想要公平？\n\n　　这些人的愤怒，说实话他也能理解，亲人在面前惨死，换谁也不能无动于衷，再加上，这几天死的人实在太多了，每个人心中都绷紧了一根弦。\n\n　　只是位置不同，他也是觉醒者，代入的视角自然也不同，排查危险这种事情，在末日里本身就不现实，他们觉醒者才几个人，加上没有战斗能力的总的才9个人。\n\n　　不，现在只剩8个了。\n\n　　车队有多少人，从几千人，到现在的不足500人，几个人怎么可能保护得了近500人的车队，觉醒者又不是神。\n\n　　不可能提前预知每一处有没有危险，说白了，还是这些人看到河流，忘记了危险，以为靠着觉醒者就能万事大吉。\n\n　　别忘了，这是末日世界。\n\n　　人群还在嚷嚷，声音越来越大，仿佛在他们看来，喊得越大声就越有理。\n\n　　“你们想要什么交代？”王烈站在人群前，目光平静，面对几十张愤怒的面孔，没有任何慌张。\n\n　　为首那个男人咽了咽口水，王烈的气势让他有些犯怵，哪怕是刚才叫嚣的最凶的那个女人，此时也像被握住喉咙的鸭子，往后退去。\n\n　　“我弟弟死了，还有车队里死了这么多人，我们也不要多的。”他伸手指着岸上那对变异利齿鱼，“这些鱼，你们得赔给我们大家。”\n\n　　“对，赔给我们。”\n\n　　“还有，”他身后的一个人接话了，“既然你们连基本的安全都保证不了，那以后找到的物资，不能叫什么上交一半！”\n\n　　“对！”\n\n　　“有道理！”\n\n　　“凭什么好东西都是你们先挑？挑完了剩下的残渣剩饭还要我们上交一半吗？”\n\n　　“我们也在拼命，我们也在逃命，凭什么我们要上交一半物资！”\n\n　　“不公平！不公平！不公平！”\n\n　　人群里的声音又起来了，比刚才还大，有人挥舞拳头，有人扯着嗓子喊，这些人突然间找到了共同的敌人，不是那些变异生物，不是黑夜中的诡异，而是眼前这几个没有保护好他们的觉醒者。\n\n　　王烈没有说话。\n\n　　林风看着这一幕，心里猜测王烈接下来会怎么做，武力镇压？杀一儆百？\n\n　　在这个节骨眼上，普通人跟觉醒者起冲突，跟王烈叫板，跟能随手一道雷劈死1级变异生物的人叫板。\n\n　　胆子不小。\n\n　　这些人怕是不想活了。\n\n　　但王烈的做法让林风意外了！\n\n　　王烈没有发火，他抬起手，做了一个下压的动作。\n\n　　人群瞬间就安静下来。\n\n　　“你们不想上交一半物资的事，我同意了！”\n\n　　什么？\n\n　　林风愣了一下。\n\n　　人群也愣了一下。\n\n　　为首的那个男人张了张嘴，一时之间不知道怎么接话，他本以为王烈会拒绝，他都做好了一套说辞来争取，结果王烈直接同意了？\n\n　　“你……你同意了？”他的声音有些不确定。\n\n　　“同意了。”王烈说，“从今天起，车队不向任何人收取物资。”', 2227, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (40, 13, 38, '第38章 改造储物间', '　　那个男人得到了准确回复，下意识攥紧拳头，既然觉醒者这么容易松口，那是不是可以……要更多？他想到自己来的最终目的，那些能提升实力的变异鱼。\n\n　　“那些鱼呢？我们死了这么多人，这些鱼肉必须分给我们，不然……”\n\n　　“对，分给我们！”有人立刻附和道。\n\n　　“不然我们不同意！”\n\n　　“不同意，不同意！！！”\n\n　　气氛又起来了。\n\n　　林风的嘴角微微上翘了一下，不是笑这些人贪婪，是笑他们蠢，他们知不知道在跟谁说话，知不知道是谁带他们走到现在的。\n\n　　王烈的手终于动了。\n\n　　他抬起手，雷光在掌心跳动，然后，他猛地一挥手，一道雷电猛地劈向河面。\n\n　　轰……\n\n　　河水炸开，水花四起。\n\n　　人群齐齐后退了好几步。\n\n　　“想要鱼？自己去河里抓。”\n\n　　他的目光扫过在场所有人，像一把刀。\n\n　　“谁敢伸手，我看是你们的命硬，还是我的雷电快。”\n\n　　“滚！！！”\n\n　　没有人敢说话了。\n\n　　刚才那几个叫嚣得最厉害的人，一个个缩着脖子往后退，不敢看王烈的眼睛。\n\n　　人群很快散了。\n\n　　走得很快，他们收拾起散落在地上的水桶和盆子，低着头走回了各自的车辆。\n\n　　有人小声嘀咕两句，很快就被旁边的人拉住了。\n\n　　“别说了……不要命了？”\n\n　　“就是，人家一巴掌就能把你拍死……”\n\n　　“算了算了，至少以后不用上交物资了。”\n\n　　“我总感觉不对劲，心里不踏实……”\n\n　　声音渐渐远了。\n\n　　林风走到王烈面前，用肩膀碰了碰他。\n\n　　“队长，你怎么想的？”\n\n　　王烈看了林风一眼。\n\n　　“你觉得呢？”\n\n　　“我觉得你是嫌那群人太烦了，让他们自生自灭。”\n\n　　王烈没有否认，也没有承认。\n\n　　“灰雾还有十几个小时就追上来了，我们没有时间和他们耗。”\n\n　　他蹲下来，开始处理那些利齿鱼的尸体。\n\n　　“他们愿意跟着车队走，我不赶人，但想让我把精力浪费在跟他们吵架上不可能。”\n\n　　林风点点头。\n\n　　“这些鱼肉真能加属性吗？”\n\n　　“试试不就知道了。”\n\n　　“行，那这条我拿走了，再见，队长……”\n\n　　林风单手提起那条变异利齿鱼，朝着小玄走去。\n\n　　小玄又刨了一个土坑，连同泥沙里的鹅卵石一起咔嚓咔嚓的嚼碎，咽进肚子里。\n\n　　看到林风提着一条大鱼回来，它眼睛亮晶晶的，像是在说：“主人，你带什么好吃的回来了？给我拌拌……”\n\n　　“别看了，不是给你吃的。”\n\n　　林风把鱼往地上一扔，从石头房子里翻出仅剩的那只锹甲虫的巨颚，现在正是废物利用的时候。\n\n　　这东西他一直留着，边缘锋利无比，对付这种全身都是坚硬鳞片的大鱼，正适合。\n\n　　普通的菜刀估计一刀下去刀刃就卷了，还是这东西靠谱。\n\n　　林风蹲下去，把鱼翻了个身，用巨颚从最柔软的鱼腹开始处理，鳞片很硬，像一块块小铁片似的，好在巨颚也不是吃素的，鳞片被一片一片的刮下来。\n\n　　“这鳞片不错。”林风把刮下来的鳞片捡起来，堆在一起，这东西每一片都有硬币大小，而且硬度比一般的铁皮还高，先收起来，说不定以后有用。\n\n　　鳞片挂完，露出下面灰白色的鱼皮，林风直接用巨颚从鱼腹处切开，这下就轻松多了，刷的一下，鱼腹里的内脏哗啦一下全涌了出来，散发出一股浓烈的腥味，林风皱了皱眉头，把这些东西往旁边的河里扔去。\n\n　　鱼肚子里很干净，除了内脏什么都没有。\n\n　　鱼头最大，占了整个鱼的一半，林风用巨颚沿着鱼鳃的位置切下去，费了好大的劲才把鱼头剁下来，鱼头滚落在地上，嘴巴张得老大，那排獠牙在光线下泛着冷光，锋利得像一排小匕首。\n\n　　“这牙还不错。”林风打量了一下，把巨颚反过来，一颗一颗地把牙齿撬下来，獠牙很长，最短的都有手指长，最长的两根差不多有十厘米，尖端锋利无比，这要是做成箭头或者匕首啥的，绝对比普通的武器好使。\n\n　　灵找了一个布包，把这些东西收好，塞进仓库的角落里。\n\n　　剩下的就是鱼肉了，林风拿到河里清洗干净，找了块大石头，直接切成4大块，每一块都有十几斤重，鱼肉是淡红色的，纹理清晰，不用看就知道是顶级食材。\n\n　　等林风提着鱼肉回来的时候，那个鱼头已经消失不见了，看到旁边的土坑就知道是小玄拿去拌饭（土）了。\n\n　　林风朝二楼的卧室喊了一声。\n\n　　“出来一下。”\n\n　　4个女孩从二楼的楼梯口探出头来，小蕊最先跑下来，双马尾在身后荡来荡去的，小玉跟在她身后，手里还拿着一块抹布。\n\n　　“林风哥哥，做什么？”小蕊凑过来，眼睛一直盯着林风手里的鱼肉看。\n\n　　“做饭！”\n\n　　林风找了一个盆，把鱼肉放进去，又打量了一下被当做仓库的一楼，里面堆满了大米、面粉、罐头、矿泉水……锅碗瓢盆也塞在角落里，摆放得很乱，找什么都得翻半天。\n\n　　“给你们安排个活，把仓库整理一下，”林风指了指储物间里那些乱七八糟的物资。\n\n　　“待会我做几个石头货架，你们把东西分门别类地放好，吃的放一边，用的放一边，然后靠窗户的地方做个灶台，然后去车队里换个煤气罐和燃气灶。”\n\n　　“灶台?”小晴的眼睛亮了一下。\n\n　　“对，以后我们在龟背上做饭，不用下去生火了。”\n\n　　几个女孩对视一眼，眼睛里全是惊喜，在这末日里，能在自己的家里做饭，不用跟车队里其他人一样挤着共用火堆，吃野菜团子，这简直就是梦一样的生活。\n\n　　“还愣着干什么，干活啊，先把衣服这些全部抱上楼去，然后把东西往中间先挪一挪，我弄个货架出来。”\n\n　　几个女孩闻言，立马开始忙碌起来，见差不多了，\n\n　　林风双手按在墙壁上，控土术发动，墙面开始变形，一排排台面硬生生从墙壁上长出来，宽大约40公分，两米高的仓库被分成了3-4层空间。\n\n　　靠近窗户的那一面墙，直接做成一个光滑的石头橱柜，除了没有柜门外，跟普通厨房没什么两样，台面上还特意留了一个凹槽，用来安装燃气灶。\n\n　　这么一规划，看上去舒服多了。\n\n　　“完美！”林风拍了拍手上不存在的灰，满意地点点头。', 2271, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (41, 13, 39, '第39章 你故意的？', '　　小晴围着灶台转了一圈，伸手摸了摸光滑的台面，眼睛里全是小星星。\n\n　　“大人真厉害！”\n\n　　“行了，别拍马屁了，你们几个赶紧把东西整理好，然后把鱼肉和食材处理一下，我出去把燃气灶和煤气换回来，你别乱跑，等我回来。”\n\n　　几个女孩点点头，开始忙碌起来。\n\n　　林风从小玄的背上跳下来，朝着车队前方走去。\n\n　　一辆大巴车旁边，郭毅正指挥十几个人在拆卸一辆大货车，这辆大货车，已经被拆得七零八落了，车厢被卸下来，发动机被抬出来，正被小心翼翼地往地上放，货车的底盘暴露在外面，整个车被拆成一堆零件。\n\n　　“郭哥！这是干嘛呢？”\n\n　　郭毅回过头，看到是林风，他用袖子擦了一把汗，咧嘴笑道：“林风啊，你怎么跑过来了？”\n\n　　“闲着没事过来转转，顺便换点东西，你们这是干啥？拆得这么狠？”\n\n　　“材料不够改装了，”郭毅叹了一口气，指了指那辆大巴车。“7辆大巴车全部要改，没材料，只能拆这些现成的了。”\n\n　　“这些货车的发动机马力大，改装到大巴车上，动力能增强不少。”\n\n　　他又看了看林风的那只巨大的乌龟，苦笑了一下。\n\n　　“真羡慕你这御兽，现在连房子都住上了，我们这些人还在挤大巴车。”\n\n　　“嘿嘿……运气好……”林风笑了笑：“那你先忙着，我去找玲姐了。”\n\n　　林风转身朝那辆后勤物资车走去。\n\n　　方玲站在一辆大货车旁，手里拿着本子，正在核对物资，几个后勤队员在旁边搬运东西，把从河里打来的水，一桶一桶的装上车。\n\n　　“玲姐，”\n\n　　方玲抬起头，看到是林风，眉毛微微挑了一下。\n\n　　“哟，稀客啊，什么事?”\n\n　　“换点东西！“\n\n　　“换什么？”\n\n　　“燃气灶，要那种双灶台的，再来一罐煤气。”\n\n　　方玲上下打量了林风一眼，“你倒是会挑东西，燃气灶我们也就两套，煤气也没几罐了。”\n\n　　“我知道，所以我来找玲姐嘛。”\n\n　　方玲沉默了两秒，在盘算着什么，然后伸出两根手指：“20斤大米。”\n\n　　林风差点没站稳。\n\n　　“二十斤大米？玲姐，你这也太黑了嘛。”\n\n　　方玲笑了笑，没说话，一副吃定你的表情。\n\n　　林风咬了咬牙。\n\n　　说实话20斤大米确实不少，但他仓库里吞了几百斤粮食，挪20斤出来也不是不行，可是这是末日啊，大米可是硬通货中的硬通货。\n\n　　“行，换。”林风最后还是同意了，不换的话，想吃口热乎的都难。\n\n　　“东西先给我，我拿回去，待会我把米送过来。”\n\n　　方玲合上本子，朝着车斗里的人喊了一声。\n\n　　“小刘，把那个燃气灶拿出来，再搬一罐煤气，配件也拿一套，给林风。”\n\n　　车斗里的人应了一声，从物资堆里翻出一个包装完好的燃气灶，双灶头的，又提了一罐煤气下来。\n\n　　林风一手提着燃气灶，一手拎着煤气罐，走到小玄旁边的时候，四个女孩已经把储物间整理得差不多了。\n\n　　大米、面粉、腊肉、干货、调味品全部归类放好，整整齐齐的码放在架子上。\n\n　　林风把燃气灶的包装拆开，安放在预留的空位上，利用控土术微调，严丝合缝，然后拿出配件把煤气罐与燃气灶的管子接上，再把煤气罐往灶台下面的圆形凹槽里一塞，刚好卡在石壁之间，稳稳当当。\n\n　　林风试了一下，灶头上窜起一圈蓝色火苗。\n\n　　“完美。”林风关掉火，脸上带着满意的笑容。\n\n　　“大人，我们现在做饭吗？”\n\n　　“做，小晴，鱼肉清炖还是红烧。”\n\n　　“清炖！鱼肉新鲜，清炖最能吃出原味。”\n\n　　“行，你看着办。”林风从物资堆里提出一袋20斤的大米，拎在手里，“我去把账结了，希望我回来的时候能吃上一口热乎的。”\n\n　　“放心吧，大人！”\n\n　　林风拎着大米，走到物资处旁边，方玲还在核对清单。\n\n　　“这么快？”\n\n　　“答应的事，当然得快，我不喜欢欠别人的。”\n\n　　方玲接过来，满意地点点头，把米交给车斗里的小刘登记入库。\n\n　　“对了，玲姐，还有多久出发？”\n\n　　方玲抬头看了一眼郭毅的方向，郭毅正蹲在一辆大巴车旁边，双手按在车身上，蓝色的光芒在车身上蔓延，正在改装车辆的最后关头。\n\n　　“等那辆大巴车改装完毕，就出发，大约还有20分钟。”\n\n　　“行！”\n\n　　林风转身就走。\n\n　　20分钟应该都不够小晴把鱼炖熟了吧，看来只能在路上边走边吃了。\n\n　　林风回来的时候几个女孩还在忙碌，小晴站在灶台边，手里拿着菜刀在剁鱼肉，动作利落，小玉在一旁剥蒜，晓丽弯着腰在货架上找食材。\n\n　　林风往楼上走。\n\n　　“饭好了，叫我，车队快出发了，慢慢做，不着急，一会路上慢慢吃。”\n\n　　“知道了，大人。”\n\n　　林风上了二楼，把鞋子脱掉，往乳胶床垫上一躺，闭上眼睛准备眯一会。\n\n　　林风刚闭上眼睛，楼梯上传来轻微的脚步声。\n\n　　不是那种噔噔噔的上楼声，而是小心翼翼，脚尖点地，偷偷摸摸的声音。\n\n　　林风没有睁眼。\n\n　　脚步声在楼梯口停了一下，然后更轻快地走进了房间，床垫微微凹陷了一下，有人爬上来，膝盖和手掌压在乳胶床垫上的声音很轻，但林风的感觉很敏锐，每一丝震动都逃不过他的感知。\n\n　　“林风哥哥……”\n\n　　是小蕊的声音，软糯软糯的，舔得发腻。\n\n　　林风睁开一只眼睛，就看见小蕊跪坐在他腿边，还换了一身衣服。\n\n　　那件JK装重新穿上了，白色的衬衫下摆打了一个结，露出小肚子，领口松松垮垮敞着，露出白皙的锁骨，白兔快要蹦出来了。\n\n　　她今天把头发扎成双马尾，一左一右垂在肩膀上，随着她的动作轻轻晃动。\n\n　　“你怎么上来了？”\n\n　　“我……看林风哥哥累了，特意来给哥哥按按腿。”\n\n　　小蕊的脸颊浮起两团红晕，“我跟小玉姐姐学了两手，我来给哥哥按按，解解乏。”\n\n　　说完，她也不等林风答应，就往前挪了挪，双手搭在林风的小腿上，开始按。\n\n　　力道不算大，但位置找得不错，每一下都按在肌肉节点上。\n\n　　从脚踝开始，沿着小腿往上，慢慢的揉，然后又换了一个方向，身体前倾，按另外一只腿，就这一换。\n\n　　林风的视线就移不开了，裙底的风光一览无余。\n\n　　“小妖精……”\n\n　　她似乎注意到了林风的目光，反而把腰压得更低了，脸颊都要贴到林风的脚踝了。\n\n　　“林风哥哥……”她回头，眼睛水汪汪的。\n\n　　林风的喉结动了一下。\n\n　　“小蕊。”\n\n　　“你是不是故意的？”\n\n　　“什么故意的？”小蕊歪了歪头，咬着嘴唇。\n\n　　3分钟后。\n\n　　“我错了……不要抓我的马尾辫……”\n\n　　楼下！灶台上，锅里的油开始冒烟了。\n\n　　小晴把切好的鱼块倒进锅里\n\n　　“滋啦……”一声，浓烈的香味在房子里炸开，鱼肉在热油中翻滚。\n\n　　“火太大了，你要翻快点……”\n\n　　“我知道，小蕊呢，跑哪去了？”\n\n　　“好像上楼了……”小玉的声音顿了一下，“要拍点蒜蓉吗？”\n\n　　“要……”\n\n　　“啪啪……啪啪啪……”小玉拿起菜刀将剥好的大蒜一颗一颗的拍碎。\n\n　　“够了吗？”\n\n　　“不够！还要，再多点……”\n\n　　“啪啪啪啪……”\n\n　　锅里也传来大力翻炒的声音，“这鱼肉白嫩紧实，需要多翻炒一会，炒得焦香的时候，就可以放水了，等炖得差不多的时候，再调点小料汁浇上，绝对好吃到爆。”\n\n　　“全体注意！车队立刻出发，灰雾还有15小时抵达，所有人抓紧时间上车，车队即将全速前进……”', 2756, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (42, 13, 40, '第40章 这肉能提升实力', '　　“全体注意！车队立刻出发，灰雾还有15小时抵达，所有人抓紧时间上车，车队即将全速前进……”\n\n　　喇叭里的声音不像往常那样重复好几遍，而是急促的喊了一遍，话音还没落，最前方的装甲房车就发动了，车身猛地往前一窜，排气管喷出一股黑烟，眨眼间就冲出了营地。\n\n　　紧接着，几辆改装过的越野车一辆接一辆的启动，轮胎碾过碎石，头也不回地跟着跑了。\n\n　　反应慢的人被这突如其来的启动吓了一跳，愣了一下，才开始疯狂的往自己车上跑。\n\n　　“快快快！车队出发了！”\n\n　　“别拿了，快上车……”\n\n　　“等等我，我还没上车！”\n\n　　反应快的人早早就跳上了车，反应慢的还在收拾东西，锅碗瓢盆散了一地，他们顾不上捡起，扔在原地就立马跑了。\n\n　　有人舍不得东西，还在收拾，可是没有人等待。\n\n　　装甲房车已经开出去几百米了。\n\n　　林风在楼上也听到了车队喇叭的声音，动作没停，低头看去，小蕊整个人像化掉的奶油一般，软绵绵的趴在垫子上，嘴唇微张，正在大口大口的呼吸。\n\n　　“小玄，走！跟上最前面的车。”\n\n　　林风的意念传递到小玄脑海中，庞大的乌龟站起身，爬出土坑，四条粗壮的腿健步如飞，起步就瞬间超越了旁边那几辆还在打火的私家车。\n\n　　小玄的脚步飞快，背上的石头房子纹丝未动，很快便追上觉醒者所在的大巴车。\n\n　　紧跟的一辆越野车见到林风的乌龟忽然跑到他前面，摇下车窗探出头来就开始骂骂咧咧。\n\n　　还以为林风依然是以前在车队里那个对谁都笑呵呵的小年轻，骂了几句后，还朝着小玄竖了一根中指。\n\n　　小玄回头看了一眼，那根粗壮的尾巴还带着尖锐的骨刺，像一根巨型鞭子一样抽在越野车车头上。\n\n　　嘭……！！！\n\n　　越野车的车头当场凹陷，引擎盖飞了出去，整辆车像是被人踢了一脚的易拉罐一样，翻滚着飞出道路，在荒野上连续翻滚了十几圈，零件散落一地。\n\n　　【击杀人类X4，获得进化点+4】\n\n　　林风握住马尾的动作一顿。\n\n　　杀人给的进化点……这么多？\n\n　　杀一个1级鬼物才给1进化点，杀一个普通人就给1点？\n\n　　林风在心里算了一笔账，小玄下次进化需要1000点进化点，而他手里的进化点才个位数，还差得远，如果……\n\n　　林风想到车队里的那些普通人，一千点，似乎不难凑齐。\n\n　　一个可怕的念头在林风脑海深处冒出来，他只需要抬抬手，小玄一个大范围的控土术，就能……\n\n　　一个声音把他从这个可怕的念头拉了回来。\n\n　　“林风哥哥……饶了我吧……晓丽姐姐……救命啊……”\n\n　　算了，享受当下的快乐。\n\n　　车队里的普通人丝毫不知道，因为一个女人，他们躲过一劫。\n\n　　“晓丽！你有没有听见有人叫你！”\n\n　　晓丽手里拿着一个碗，在调酱汁，脸颊上浮起不自然的红晕。\n\n　　“晓丽，小蕊在叫你救命呢，你还不上去？”小玉打趣地说。\n\n　　“我看是你想去吧，这时候上去刚好……”\n\n　　“才没有……”小玉低下头，耳朵根红了一片。\n\n　　几女的心思都不在做饭上面了，听着断断续续、令人心跳加速的声音。\n\n　　“这小妮子，真不要脸。”\n\n　　“她本来就胆子大。”小玉取出木耳开始切，“趁我们做饭的时候上去送。”\n\n　　直到楼上的声音消失后，几人才松了一口气，扶着墙壁，听了差不多一个小时的墙根，腿有些发软……\n\n　　林风穿好衣服，拍了拍小蕊的翘臀。\n\n　　“小蕊，走了，下去吃饭。”\n\n　　“嗯~”小蕊的声音又软又哑，“走不动……”\n\n　　林风没有废话，给她理了理裙子，至于安全裤，这妮子压根没穿，准确的说是来的时候里面啥都没穿，再整理了一下凌乱的衣服，一把把她捞起来，一只手压住裙角，然后公主抱就抱着下了楼。\n\n　　小蕊窝在林风的胸口，脸上带着幸福的微笑。\n\n　　小晴在灶台上装菜，看到林风抱着小蕊下来，什么都没说，把一大盆鱼肉端到折叠桌子上。\n\n　　林风把小蕊放在自己平时坐的那张折叠椅上，然后坐在旁边的塑料凳子上。\n\n　　小蕊此时的头发散乱，衣服皱巴巴的，裙子下露出的小腿还在微微发抖，她嘴唇抿着，一副“我知道你们在看我，但打死我也不怕……”的样子\n\n　　“哎呀，你这是怎么了？”小玉的声音里带着明知故问的语调。“腿软了？”\n\n　　小蕊闭着眼睛不说话，耳朵尖都红了。\n\n　　“脸这么红，是不是发烧了？”小玉端着一盆凉拌木耳过来，忍住笑，一本正经的说：“要不要拿体温计给你量量。”\n\n　　“你们……你们别说了……”小蕊声音小得像蚊子叫，丝毫没有平时大大咧咧的样子。\n\n　　“林风哥哥还看着呢。”\n\n　　几个女孩同时看了林风一眼，该摆碗筷的摆碗筷，该盛饭的盛饭。\n\n　　一盆清炖水煮鱼放在桌子正中央，香味扑鼻，旁边摆着两个小菜，一个凉拌木耳，一个香菇炒火腿肠。\n\n　　“走坐下吃饭吧。”林风拿起筷子夹起一大块鱼肉，放进小蕊的碗里。\n\n　　“来，多吃点。”\n\n　　小蕊看着碗里那块白嫩嫩的鱼肉，又看了看林风，眼眶忽然有些红，她端起碗，小口小口的吃着。\n\n　　“来，你们也吃。”林风又给晓丽她们一人夹了一块鱼肉放进碗里。\n\n　　“这可是1级变异生物的肉，这肉能提升实力，你们多吃点。”\n\n　　林风给自己也夹了一块，咬了一口，鱼肉鲜嫩，带着一种天然的甜味，这怪鱼，看着丑，没想到味道这么好。\n\n　　几女听说能提升实力，对视了一眼，低头开始吃起来\n\n　　“好吃！”小蕊的眼睛弯成月牙。\n\n　　“那就多吃点。”林风又夹了一块鱼肉放进小蕊的碗里，又给其他三女各夹了一块，不偏不倚。\n\n　　很快，小玉停了筷子，眼睛瞪大了。\n\n　　“怎么了？”小晴问她。\n\n　　“我感觉……”小玉低头看了看自己的手，张开握拳，脸上的表情像是发现了什么不可思议的事情，\n\n　　“我感觉手上好像有劲了……不是心理作用，是真的有劲了。”', 2208, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (43, 13, 41, '第41章 全速前进', '　　小晴吃了几块后也感觉到了身体的变化，点点头：“确实有变化，身体暖暖的，像有一股热流在身体里游走。”\n\n　　晓丽吃得很慢，小口小口的咬着鱼肉，脸色比昨天好多了。\n\n　　小蕊又夹了一块，腮帮子鼓鼓的，“我好像没那么疼了。”\n\n　　几个女孩同时看向她。\n\n　　小蕊胆子大得很，完全没有注意到自己刚才说了什么，含糊不清的说：“晓丽姐姐你也吃，等你好了一定要帮我，我刚才差点要死了……”\n\n　　“行了行了，吃饭。”小晴在她脑袋上敲了一下。\n\n　　小蕊缩了一下脖子，终于闭上了嘴。\n\n　　鱼肉的能量很足。\n\n　　几个女孩才吃一小碗就吃不下了，一个个挺直了腰板，摸着肚子，脸上全是满足又带着痛苦的表情。\n\n　　“好撑……”小蕊瘫在椅子上，裙子皱成一团，走光了也懒得理，“肚子要炸了……”\n\n　　“我也是，”小玉用手揉着肚子，“吃不下去了，明明还想吃的，但肚子装不下来。”\n\n　　林风若有所思的看着她们。\n\n　　看来普通人对变异生物的肉吸收效率远远不如觉醒者，她们吃一小碗就饱了，不是胃装不下，而是身体的吸收上限到了，那些鱼肉里面的能量没有被完全吸收。\n\n　　简而言之，就是身体撑着了。\n\n　　林风却在想一个问题，很明显这鱼肉确实能提升普通人的实力，如果她们多吃几次变异生物的肉，身体素质会不会赶上觉醒者呢。\n\n　　哪怕没有觉醒相应的能力，只要身体素质够强，力量够大，反应够快，那么给她们配一把武器，教她们战斗，她们是不是就不再是花瓶了。\n\n　　这个念头在林风的脑海中转了一圈，林风默默的记了下来。\n\n　　现在不急，以后再说。\n\n　　林风把锅里的鱼倒进碗里，鱼肉少说还有两三斤，他一口气全部吃完了。\n\n　　【体质+3】\n\n　　一锅鱼肉下肚，林风的体质足足提升了3点，他看了一眼个人面板。\n\n　　等级：1级（92%）\n\n　　体质：75\n\n　　力量：56\n\n　　敏捷：46\n\n　　精神：58\n\n　　灵能：68\n\n　　这种提升速度，比吸收诡晶还快，每次吸收诡晶主要提升的是灵能，升级的时候提升最多的是精神力，顺带提升一点点力量和敏捷属性，不知道其他人的觉醒天赋，是什么样的，应该大差不差吧。\n\n　　林风心满意足的放下碗，长长的吐出一口气，锅里的鱼连汤带肉都干干净净的\n\n　　“吃好了，把东西收了吧。”林风站起来，活动了一下身体。\n\n　　几个开始收拾碗筷，小蕊虽然走路有些别扭，但还是帮忙把碗端到灶台上。\n\n　　“晓丽，你带小蕊上去休息。”\n\n　　晓丽点点头，伸手扶着小蕊的胳膊，小蕊乖乖跟着她上了楼。\n\n　　林风走出房间，顺着楼梯来到了房顶上，朝着车队的前方看去。\n\n　　白天赶路跟晚上赶路完全是两种不同的感觉，夜晚的车灯只能照亮前方几十米的路，再远就是一片漆黑，司机开得小心翼翼，车速慢的让人发慌，一晚上能走一百公里就算是烧高香了。\n\n　　白天完全不一样，车队全速前进，是真的把油门踩死的那种。\n\n　　最前方的装甲房车车速至少一百码，在荒野上狂飙，卷起一路烟尘，大巴车紧跟其后，一辆接着一辆，货车的速度稍微慢一些。\n\n　　那些跟随在后面的私人车辆也不敢落后，能跑多快跑多快，虽然不知道领头的车辆发什么疯跑那么快，一边骂骂咧咧，一边踩死油门紧紧跟上车队。\n\n　　谁也不敢在这个节骨眼上停下。\n\n　　时不时的有变异兽从道路两旁的荒野中窜出来。\n\n　　有的是变异鬣狗，有的是变异猫，或者是成群结队的巨大老鼠，身上带着变异生物特有的灰黑色斑块，猩红的眼睛盯着车队。\n\n　　这些变异怪物早已经失去原本的样子，一个个丑陋不堪，毫无理智，张着满口的獠牙朝着车队扑过来。\n\n　　轰……\n\n　　王烈站在装甲房车上，抬手就是一道雷电从天而降，精准地劈在那只变异兽的脑袋上。\n\n　　那畜生一声没吭就翻倒在地，四肢抽搐两下便不动了。\n\n　　另外一只狼形变异怪物从车队右边逼近，陈敏从一辆大巴车的天窗上探出半个身子，一把银白色的小刀在空中划出一道弧线，精准地贯穿那只变异狼的脑袋，小刀在空中转了一圈，又飞回她的手中。\n\n　　车辆连停都没停，车队从变异怪物尸体旁边呼啸而过，没有人下车去捡战利品，那些变异兽的尸体就这样被遗弃在路边，很快就被车队扬起的烟尘覆盖了。\n\n　　林风站在房顶上，看着那些尸体从视野中消失，有些肉疼，就这么扔了？\n\n　　但车队根本停不下来。\n\n　　灰雾在后面追，时间不等人，每一分钟都是生死时速，离灰雾越远越安全，\n\n　　道路依旧弯弯绕绕，忽左忽右，沈雨桐的占星能力发挥着重要的作用，装甲房车的司机按照她给出的线路行驶，每一次转向都在精准的绕开一个个高危区域。\n\n　　林风站在高处，看得清清楚楚，车队绕开的都是些什么东西。\n\n　　要么是一片残破的村庄，整个村子上空笼罩着一层淡淡的雾气，连阳光都透不进去，仅仅是看一眼那座村庄，林风就感觉到一股不寒而栗的气息从心底升起，像是有什么东西在那里沉睡，随时可能醒来。\n\n　　要么是一片倒塌的高楼，楼的表面覆盖着一层黑色的藤蔓，藤蔓的末端垂下来，在空中扭动、摇摆，让人望而生畏。\n\n　　或者就是一片诡异的高山，那山奇形怪状，呈现灰黑色，没有树，连草都没有一根，山上笼罩着一层厚重的黑云，不用看，就知道那里的东西不好惹。\n\n　　林风虽然没有觉醒精神力方面的能力，但隔那么远的距离都能感受到那些地方散发出不寒而栗的气息，像是身体在告诉你，离那里远点，越远越好。\n\n　　林风再次对沈雨桐的能力有了新的认知。\n\n　　这女人的能力，能在遍布死亡陷阱的末日世界里，找到一条相对安全的路线，在躲避灰雾的同时，还能绕开这些诡异的存在，这已经不是一般人能做到的了。\n\n　　换做是林风自己，可能连一半路都走不到，就一头扎进某个高级诡异的领地，被吞得连渣都不剩了。\n\n　　忽然，全速前进的车队，速度骤然降低了。', 2235, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (44, 13, 42, '第42章 遇到明星车队', '　　不是遇到了危险，而是前方出现了另外一支车队。\n\n　　林风朝前方看去。\n\n　　那支车队从一条岔路上开过来，正缓缓朝着主路靠近，打头的是一辆黑色的埃尔法。\n\n　　埃尔法后面跟着几辆越野车，都是那种皮实耐造的硬派越野，后面还有几辆灰扑扑的旅游大巴，车上还贴着某剧组的标语，紧跟其后的是几辆面包车。\n\n　　整个车队加起来大约十几辆车，规模不大，但车上塞满了人，跟林风所在这个哪怕经过重重危机，都还剩一百多辆的车队比起来，确实寒酸了一些。\n\n　　很快，两支车队汇合了，双方都没有太靠近，隔着几十米的距离停了下来。\n\n　　王烈从装甲房车上跳下来，方玲跟在他身后，目光警惕地看着对面的车队。陈敏从另外一辆大巴车上走出来，靠在车门上。\n\n　　对方车队的埃尔法车门打开了。\n\n　　一个女人从车里走下来。\n\n　　林风的眼睛瞪得老大了。\n\n　　那个女人的脸太有辨识度了，哪怕脸上没有化妆，依然醒目得让人移不开眼睛。\n\n　　是莫青峦！人如其名，如同山峦起伏\n\n　　林风虽然从来不追星，但那张出现在荧幕上无数次的脸，让无数人心动，尤其是男人，很少有不喜欢大的，当然林风也不能免俗，爱好美好的事物不分年龄这句话诠释得非常完美。\n\n　　银幕上终究隔着距离，此刻真人就站在几十米外，那种冲击力完全不是一个量级的。驾驶室的门也开了，另外一个女人也走下来。\n\n　　“那不是吗？”身后传来小蕊的声音，她从楼梯口探出头来，眼睛瞪得溜圆。\n\n　　“天啦，那是米雪吧，号称是西域双美之一。”小玉也从小蕊身后探出头来，声音里全是不可置信。“她们怎么在这里？”\n\n　　“穿越了呗，她们也穿越了呗。”小晴说话的语气平淡得就像说今天天气不错。“这不是很正常吗？全人类都穿越了，有几个明星不是很正常？”\n\n　　“可是……她们是青峦和米雪啊！”小蕊的声音拔高了八度，眼睛里的星星都快蹦出来了。\n\n　　林风没有理会几个女孩的叽叽喳喳，他的目光落在了那两个女人身上。\n\n　　大青峦。\n\n　　俏米雪。\n\n　　两个顶级美女，就站在几十米外的荒野上，头发被风吹得有些凌乱，但那张脸和那身材，就算末日也遮不住。\n\n　　林风的心思活络起来。\n\n　　从房顶上跳下来，落在小玄的龟壳上。\n\n　　“走，过去看看。”\n\n　　小玄迈开腿，朝前走去，它体型庞大，每一步都震得地面微微发颤，对面的车队很快就注意到了这只庞然大物。\n\n　　“那是什么东西？”\n\n　　“好大……好大的乌龟。”\n\n　　“快走，快走！”\n\n　　“别慌，别慌，先看看！”\n\n　　对面车队的人看到这一幕，骚动肉眼可见地扩散起来，大巴车上的人纷纷挤到窗户边往这边看，脸上的表情从好奇变成了震惊，震惊中还带着恐惧。\n\n　　几个从越野车下来的人，下意识地往后退了几步，甚至已经打开车门，准备随时启动车辆跑路了。\n\n　　莫青峦的脸色有些发白，但她没有后退，她站在原地，目光死死地盯着这只庞然大物。\n\n　　小玄距离埃尔法十几米的地方停下来。\n\n　　林风从龟背上跳下来，稳稳落在地上。\n\n　　“别怕！”王烈上前一步，声音沉稳，“这是我们车队的御兽师，这只乌龟是他的坐骑。”\n\n　　对面车队的人沉默了。\n\n　　坐骑？\n\n　　谁家坐骑这么大？\n\n　　谁家坐骑能在上面盖房子？\n\n　　“你好，”她开口了，声音里带着标志性的小奶音，和那张明艳的脸形成一种奇异的反差感，“你是这个车队的队长吗？”\n\n　　“是！”王烈点点头。\n\n　　“我是青峦，”她指了指身后的人，“这是我们的车队，我们想加入你们，一起走，路上太危险了，我们的车队有一半都留在了路上。”\n\n　　王烈沉默了两秒。\n\n　　“你们有觉醒者吗？”\n\n　　“我是觉醒者。”她伸出手，掌心亮起一层淡淡的光芒，那光芒很柔和，带着生命的气息。“我的能力是治疗，可以恢复伤势，轻伤几分钟就能愈合，重伤也能止血止痛。”\n\n　　她把光芒收了回去，指了指旁边的米雪。\n\n　　王烈的眉毛挑了挑。\n\n　　治疗系的觉醒者，在这末日里比战斗系的还要稀有，战斗系的觉醒者能杀变异怪物，能杀诡异，但受伤怎么办？车队里没有医生，没有药品，一个小小的伤口感染就能要了一个人的命。\n\n　　一个治疗系的觉醒者，其价值可想而知。\n\n　　米雪往前走了一步，站在莫青峦身边。\n\n　　“我的能力是危险感知，能提前感知到周围的危险源，包括诡异，变异生物，还有……灰雾的移动速度。”\n\n　　林风的耳朵竖起来，又一个感知类的觉醒者。\n\n　　林风把目光投向陈敏，陈敏靠在车门边，手里把玩着那把小刀，这个女人当时说她的能力是精神感知类，但实际能力远远不止那么简单，这女人藏得可深了，不知道热巴的能力会不会比她说的更强……\n\n　　陈敏似乎注意到了林风的目光，转过头来，冲他抛了一个媚眼。\n\n　　王烈点点头。\n\n　　“可以加入，不过有几个规则我要先说清楚。”\n\n　　莫青峦认真地听着。\n\n　　“第一，禁止抢夺他人财物，违者死。”\n\n　　“第二，禁止强迫，违者死。”\n\n　　这两条是车队的铁律。\n\n　　这话一出，莫青峦和米雪明显松了一口气，她们知道自己的价值，在这个末日里可没有律法，人最容易的就是释放心中的恶，她们虽然觉醒了，但都是辅助，对付一两个普通人没问题，面对一群大汉的围攻，也要躺下。\n\n　　王烈接着说。\n\n　　“除了这两条，目前跟随车队采取的是自愿原则，不强求，物资收集全靠自己，车队不会向任何人收取物资上缴，觉醒者也不会主动提供庇护，如果遇到危险，自己想办法。”\n\n　　“公平原则，各凭本事。”\n\n　　她们对视了一眼，没有说话，但林风能看出她们的犹豫，面前这支车队一看就比他们的车队安全不少，但是觉醒者不应该庇护普通人吗？\n\n　　他们的觉醒者只管自己的一亩三分地，其他跟随的成员被抛弃，是大概率的事，只是这种犹豫没有持续太久，热巴感受了一下灰雾的动向，比之前更近了，然后转过头，对杨密点点头。\n\n　　“我们加入。”\n\n　　王烈没有说多余的话，转身往回走，他不想浪费太多时间，车队必须立刻出发。\n\n　　林风站在小玄边上，近距离打量起面前的两个大明星，不得不说，这两个女人往那一站，确实比荧幕里好看好几倍，无论是颜值还是气质，尤其是她们觉醒后，脸上的皮肤跟二十岁的小姑娘似的。\n\n　　美得不像话。\n\n　　“这位小哥，你的队长走远了……”', 2414, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (45, 13, 43, '第43章 被调戏了', '　　等莫青峦和米雪上车后，车队重新启动，看着那辆埃尔法缓缓并入车队里，林风才回过神来。\n\n　　林风一个纵跃跳到屋顶上，让小玄跟上，忽然听见身后有脚步声。\n\n　　陈敏不知道什么时候爬上了小玄的背，沿着旋转楼梯走到屋顶上，双手抱胸，目光似笑非笑的看着他。\n\n　　“林风弟弟！”\n\n　　“嗯？”林风转过头，被她那副意味深长的表情看得心里有点发毛。\n\n　　“你这是什么表情？”\n\n　　“没什么？”陈敏收回目光，用矫健点了点脚下的石板，“我就是想说，你这乌龟，跑起来好稳啊，比我那辆大巴车平稳多了，那车颠得我腰都快要断了，你这上面跟平地一样。”\n\n　　林风不知道她葫芦里卖的什么药，只好应付道：“还行吧，小玄走路比较稳。”\n\n　　“带姐姐参观参观呗，你这小房子从外面看挺像一回事的，里面什么样子我还真没见过。“\n\n　　林风没有拒绝，本来就是少年心性，他也有点想在美女面前显摆一二，石头房子是他一手改造的，每一处细节都花了不少心思。\n\n　　“行，打你看看。”林风转身往楼梯口走，“小心台阶，有点陡。”\n\n　　两人一前一后走下旋转楼梯，来到二楼门口，林风推开门的时候，让陈敏的脚步顿了一下。\n\n　　乳胶床垫铺在地毯上，床单铺得平平整整，白色的窗帘用铁丝挂在窗户上，窗台上还放着几个奶粉罐，里面插着几根在小河边收集的野花。\n\n　　四个女孩子坐在床边，四张青春洋溢的脸。\n\n　　“这是敏姐！”林风介绍了一句。\n\n　　“敏姐好！”几个女孩齐刷刷地问好。\n\n　　陈敏的目光在她们身上扫了一圈，嘴角慢慢翘起来，然后转头看向林风，笑容变得意味深长。\n\n　　“臭弟弟~”\n\n　　她故意拖长了声音。\n\n　　“没想到你还真会金屋藏娇啊！”\n\n　　林风的嘴角抽了抽，坦然面对，只要我不尴尬，尴尬的就是别人。\n\n　　“从那儿找的这4朵娇花，真是艳福不浅，这一个个水灵灵的，比我大巴车上的姑娘强多了。”\n\n　　“敏姐说笑了。”\n\n　　陈敏往前走了两步，在那张乳胶床垫上坐了一下，感受了一下弹性，又看了看林风，眼睛弯成一道月牙。\n\n　　“我看你这床这么大，要不要收留姐姐，多我一个不多吧。”\n\n　　林风赶紧说道：“敏姐你大巴车上多宽敞，你在这不嫌挤吗？”\n\n　　“大巴车颠啊，哪有你这舒服。”陈敏眨了眨眼睛，“而且你这里还有热乎饭吃，刚才在车里我可是看见了，鱼肉的味道不错吧。”\n\n　　林风无语了，他是不想收留吗？他是有色心没色胆。\n\n　　陈敏看着他吃瘪的样子，笑得花枝乱颤，好一会才停下来，从床上起身，走到林风面前，伸出手指点了点林风的胸口。\n\n　　“好啦好啦，不逗你了，我知道你这住不下这么多人，跟你开玩笑的。”\n\n　　林风松了一口气，心里暗自下定决心，等我以后比你强了，一定要把你一百遍啊一百遍……\n\n　　“不过……”陈敏话锋一转，看向远处那辆埃尔法：“我看你看刚才那两位的眼神，眼睛都快放光了，口水都快流出来了吧！”\n\n　　“哪有！”林风矢口否认，但明显底气不足，“爱美之心人皆有之，我那是欣赏，欣赏而已……”\n\n　　陈敏翻了个白眼，懒得理他，转身下楼。\n\n　　“行了，不跟你闹了，我去看看你楼下的物资。”她一边走，一边回头看了林风一眼，“你刚才不是挺大方的嘛，下面的储物间也让我看看呗，我瞧瞧你藏了多少好东西。”\n\n　　林风跟在后面，嘴角抽了抽，这陈敏真不把他当外人。\n\n　　小蕊见林风走了，小声的说了一句：“敏姐好厉害，林风哥哥都不敢顶嘴。”\n\n　　小玉赶紧捂住了她的嘴。\n\n　　她走到楼下储物间，推开门，走了进去，然后整个人就像被定住了一样，站在那里一动不动，眼睛从左扫到右，从右扫到左，嘴巴慢慢张开。\n\n　　只见储物架上堆满了物资，那些大米袋子码放得整整齐齐，目测至少三四百斤，面粉也有好几袋。\n\n　　好几块腊肉挂在墙上，泛着油润的光泽，罐头堆放在架子上，肉罐头，水果罐头，火腿肠。\n\n　　干货装在塑料袋子里，木耳，香菇，粉丝，腐竹，都是耐存放的好东西，矿泉水码成小山，一箱挨着一箱，还有各种牌子的饮料，起码十几箱。\n\n　　调味品摆成了一排，盐、酱油、醋、料酒、蚝油、辣椒酱，旁边还有几包火锅底料。\n\n　　墙角的盆子里还放着处理好的鱼肉，另外靠窗的一边还真是一个现代化的灶台，虽然是用石头做的。\n\n　　可这……是末日吗？\n\n　　“臭弟弟，你竟然藏了这么好的东西。”\n\n　　她转过身看着林风，双手叉腰，脸上的表情全是惊讶。\n\n　　“几百斤大米，腊肉几十斤，罐头十几个，还有这么多干货和调味品，你这是把半个小卖铺的东西搬回来了吧？”\n\n　　“运气好，运气好。”\n\n　　“我不管，”陈敏的语气带着一种撒娇般的娇蛮“我要……”\n\n　　你要？\n\n　　你要什么？\n\n　　这是我家，是我辛辛苦苦从小镇上搬回来的物资！\n\n　　“我给你个棒槌你要不要？”\n\n　　这话一出口，林风就后悔了。\n\n　　陈敏愣了一下，然后盯着林风的某处，笑了，那笑容里带着一种说不清道不明的意味，像是一只狐狸看到了猎物。\n\n　　“棒槌？”陈敏靠近了几分，嘴里的气息喷到林风的脸上，“多长？多粗，什么材质的？”\n\n　　林风整个人彻底麻了，也不知道哪里来的胆子。\n\n　　心里暗想，死就死吧。\n\n　　一只手揽住对方的腰，一只手按住对方的后脑勺，低头，直接对着那张性感的红唇就亲了下去。\n\n　　动作快到陈敏都没有反应过来，就感觉到自己的唇被一个霸道的吻堵住了。', 2073, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (46, 13, 44, '第44章 你想听我的故事吗', '　　她的身体僵了一瞬，大概过了一秒，也许是两秒，陈敏的身体忽然放松了。\n\n　　然后她回应了，而且比林风更加热烈。\n\n　　她的双臂攀上他的肩膀，她的嘴唇才从被动变成主动，力道不轻不重，像是在挑逗。\n\n　　林风的后背撞上了储物间的货架。\n\n　　砰的一声，上面的矿泉水掉在了地上，没有人去捡。\n\n　　林风的手指从她的后颈滑落，陈敏今天穿的是一件灰色的针织开衫，扣子啪嗒一声掉在了地上，封印不住的夸张弧线暴露在眼前。\n\n　　“你疯了？”陈敏的声音有些沙哑，带着一丝颤音。\n\n　　“你不是要吗？”\n\n　　“臭弟弟！”\n\n　　林风没有给他说下去的机会，直接抱起来，储物间的空间并不大，林风把她放在灶台上。\n\n　　“你们有没有听见什么？”\n\n　　楼上，小蕊那软糯糯的声音响起。\n\n　　“没事，是大人在搬东西吧！”小玉故作淡定的说道。\n\n　　“我去看看……”\n\n　　晓丽拉住了小蕊的手，“别去打扰大人，他……他在跟敏姐谈事情。”\n\n　　楼上几女听见一声高亢的声音，顿时从脖颈红到耳朵尖。\n\n　　……\n\n　　而整个车队前进的速度丝毫未降下来，一辆接着一辆跟着头车风驰电掣，发动机的轰鸣声一浪高过一浪。\n\n　　车队在弯弯曲曲的道路上足足跑了几个小时，速度才缓缓降下来。\n\n　　“全体注意！车队减速，前方停车休整2小时，重复……”\n\n　　……\n\n　　储物间里，陈敏整理着身上的衣服，上衣的扣子被面前这个牲口扯掉了，怎么都扣不上。\n\n　　“臭弟弟，看够了没？”\n\n　　林风把她搂进怀里，理了理对方贴在脸颊上的头发，都被汗水打湿了。\n\n　　“怎么都看不够。”\n\n　　“贫嘴，以后姐姐可就是你的人了，你要是敢丢下我，我就把你……”她比了一个剪刀的手势。\n\n　　“咔嚓……”\n\n　　林风吓得往后一缩，“怎么会，敏姐你可是我的女神，从第一天在车队看到你的时候，我就喜欢你了。”\n\n　　“第一天？”陈敏抬起头，“第一天就敢喜欢我？不怕我把你扔诡异堆里？”\n\n　　“不怕，牡丹花下死，做鬼也风流。”\n\n　　“贫嘴，”陈敏此时温柔得像水一样，“我看呀，你就是一个渣男，见一个爱一个，那个雨桐，你看人家的眼神，恨不得把人家吃了，还有那个方玲，既干练又优雅，你不喜欢？还有今天那杨密和热巴，我看啊，她们才是你的女神，姐姐我呀，人老珠黄了……”\n\n　　“哪有，我发誓，我最喜欢敏姐了，你要不信，我现在就证明给你看……”\n\n　　陈敏感受到林风的变化，吓得她立刻离开林风的怀抱，“我不来了，我信，我信……”\n\n　　林风嘿嘿一笑，果然还是姐姐好，这不就被说服了嘛……\n\n　　陈敏白了他一眼，低头看了看自己那件扣不上的开衫，皱了皱眉：“你给我找件衣服换上，这样子怎么出去见人？”\n\n　　林风沿着楼梯上了二楼，四个女孩听到脚步声齐刷刷转过头来，目光落到林风身上，眼神复杂，有敬畏还有好奇，那么久，要是她们的话应该会坏掉吧……\n\n　　林风从衣服堆里翻出一件黑色的T恤，全新的，吊牌还在，比划了一下，觉得陈敏应该合身。\n\n　　转身要走的时候，小蕊突然从床上爬起来，把林风手里的T恤拿过去看了看，然后塞回林风手里，从另外一堆衣服里翻出来一件淡紫色的针织衫，面料柔软，领口还有一圈蕾丝边。\n\n　　“林风哥哥，用我这件吧，敏姐皮肤白，穿紫色好看。”\n\n　　林风看了看那件紫色的衣服，又看了看小蕊那傲人的身材，嗯，差不多，不对，敏姐的还要更加的E往无前。\n\n　　小蕊的眼睛亮晶晶的，脸上带着一种‘我是不是很懂事快夸我’的表情。\n\n　　林风伸手在她脑袋上拍了拍。\n\n　　“懂事！”\n\n　　林风转身下楼，身后小玉凑到小蕊耳朵边，压低声音说了一句什么，小蕊的耳朵尖一下子就红了，伸手去拧小玉的腰，两个人在床上滚成一团。\n\n　　楼下，陈敏接过那件淡紫色的针织衫，展开看了一眼，又看了看林风。\n\n　　“是那个小姑娘的？”\n\n　　“挺会挑的。”陈敏把开衫脱下来，换上那件针织衫，面料贴着她的身体，勾勒出一道动人心弦的夸张曲线。\n\n　　“走吧，该出去了。”\n\n　　林风拉着陈敏走上二楼，几个女孩看了看陈敏，又看了看林风，眼睛瞪得圆圆的，小蕊还偷偷朝林风竖了一个大拇指。\n\n　　林风没好气地瞪了她一眼。\n\n　　“你们几个，下去做饭，多做点。”\n\n　　小蕊吐了吐舌头，拉着小晴就往楼下跑，小玉和晓丽跟在后面，走到门口的时候还回头看了一眼林风，然后轻轻带上了门。\n\n　　房间里只剩林风和陈敏。\n\n　　陈敏在床垫上坐下来，摸了摸铺的平平整整的床单，和叠得整整齐齐的被子。\n\n　　“你这几个丫头，调教得不错。”\n\n　　“她们自己乖。”林风在她旁边坐下，伸手揽住她，陈敏没有躲，靠在他肩膀，闭上眼睛。\n\n　　“敏姐。”\n\n　　“嗯。”\n\n　　“以后跟我住吧。”\n\n　　陈敏睁开眼睛，看了一眼林风，她的眼睛里有光，是那种被温暖的感觉。\n\n　　“那你的丫头们住哪？”\n\n　　“这！”\n\n　　“那我住哪？”\n\n　　“诺！”\n\n　　陈敏顺着林风的目光看向床垫，她伸手在他胸口捶了一下，力道不重。\n\n　　“你想的美！”\n\n　　“嘿嘿，床这么大，多你一个不多。”\n\n　　“闭嘴！”\n\n　　陈敏从她的肩膀上直起身来，站在窗户边，外面的光线照在她的侧脸上，美不胜收。\n\n　　“林风。”她的声音突然变得很轻。\n\n　　“嗯。”\n\n　　“你刚才说的话，是真的吗？”\n\n　　“那句？”\n\n　　陈敏沉默了两秒。\n\n　　“从第一天在车队看到我的时候，就喜欢我。”\n\n　　林风站起来，走到她身边，伸手从后面环住她的腰，下巴搁在她肩膀上。\n\n　　“真的。”\n\n　　“骗人！你那时候根本不敢看我。”\n\n　　“那是因为你太好看了，我看了会紧张。”\n\n　　陈敏没有说话，但把手放在了林风的手上，两人就这样站着。\n\n　　“林风，你想听听我的故事吗？”\n\n　　林风没有说话，只是把她环得更紧了一下。\n\n　　陈敏沉默了很久，久到林风以为她不会开口了。\n\n　　“很久以前……', 2252, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (47, 13, 45, '第45章 明星？一个面包的事', '　　“很久以前，我隔壁有个小男孩，叫沈宇，他比你小，不，应该是比我小，他总是喜欢喊我敏姐，直到他上高中的时候，就不再叫我姐姐了，喊我敏敏，我叫他小屁孩。”\n\n　　“他高考完的那年，他爸妈请我吃饭，他说他报考了国外的大学，已经拿到了通知书，我愣了一下，然后笑了，他也笑了，笑得很勉强，他送我出门的时候，看了我一眼，像是有什么话想说，又没说出口。”\n\n　　“后来他走了，我送他去机场，他过安检的时候，突然跑回来抱了我一下，抱得很紧很紧，我能感觉得到他的心跳得很快，然后松开我的时候，从口袋里掏出一封信递给我，然后头也不回地跑了。”\n\n　　“信里写了什么？”林风轻声问，手不由自主地松了些。\n\n　　“不告诉你，等你什么时候不这么混蛋了，我再告诉你。”\n\n　　林风没有追问。\n\n　　“他走了后，我们一直有联系，电话，视频，他发过很多照片，国外的雪，国外的海，每次通话结束都说，等我回来，我说好。”\n\n　　“我们就这样过了四年，他回来的那天我去机场接他，他瘦了很多，也黑了很多，他从出口走出来看到我的第一眼，就把行李箱扔了，跑过来把我抱起来转了一圈，他说，敏敏，我做到了。”\n\n　　“然后呢？”\n\n　　“后来他又接着出国读研，一年！”\n\n　　“我说，你不怕我跑了。”\n\n　　“他说，你敢。”\n\n　　“走的那天，他说，我有很重要的事要跟你说。”\n\n　　“我问他什么事，他说等他回来再说。”\n\n　　“我在心里骂了他一百遍，但还是等了。”\n\n　　“三百六十五天，倒数第100天的时候，他说他买了下个月的机票，我问为什么提前了。”\n\n　　“他说想我了。”\n\n　　“结果第二天，我接到了他的电话，他说：“敏姐，我骗你了，我买了今天的机票，想给你一个惊喜，马上要登机了，等我回来有很重要的话跟你说。””\n\n　　“我问他，什么话，现在就说。”\n\n　　“他说，要当面说，然后电话挂了。”\n\n　　那天我的眼皮一直跳，心跳得很快，有种很不安的感觉。\n\n　　“我给他发了信息，落地了给我打电话。”\n\n　　没有回复\n\n　　“不管多晚都发。”\n\n　　没有回复\n\n　　“再发，臭弟弟，你别吓我。”\n\n　　还是没有回复\n\n　　第二天早上，我拨他电话，关机\n\n　　中午，关机\n\n　　下午，关机。\n\n　　“晚上，我接到一个电话，不是他的号码，而是一个陌生的座机号。”\n\n　　“请问是陈敏女士吗？”\n\n　　“我是”\n\n　　“我是星条国驻华大使馆的工作人员，很遗憾地通知你，沈宇先生搭乘的航班……”\n\n　　飞机失事，无人生还。\n\n　　“我等到了，一个装着遗物的纸箱，里面有一枚求婚戒指，还有一句再也等不到的话……”\n\n　　“后来的日子，我一个人过，就这样过了一年，两年，五年，八年，我把自己活成了一堵墙，谁也进不来，我也出不去。”\n\n　　“然后末日来了，世界崩塌的时候，我反而松了一口气，直到你第一次出现在车队的时候，我正在车顶上发呆，你从远处走过来，头发被吹得乱七八糟。”\n\n　　“我看到你的第一眼，我就想，怎么这么像！不，你比他高一点，你是那种……野的，倔的，让人想欺负的好看。”\n\n　　林风张了张嘴，想说点什么，却一个字也说不出口。\n\n　　陈敏在继续说，说沈宇在第一次跟她表白的时候，那个样子，笨拙，紧张，既想靠近，又害怕的样子。\n\n　　你见我眼神也是那个样子，明明眼神很色，想跟我搭讪，却害怕我。\n\n　　“你跟他一样笨。”\n\n　　“所以我开始逗你，故意在你面前晃，故意说那些让你脸红的话，我想看你手足无措的样子，我想看你被我撩得说不出话的样子。”\n\n　　她顿了一下。\n\n　　“我想看你，像他一样。”\n\n　　空气安静了很久。\n\n　　“敏姐。”林风终于开口了。\n\n　　“嗯~”\n\n　　“我不是他！”\n\n　　陈敏的身体微微僵了一下。\n\n　　“我知道。”她的声音很低，低得像是跟自己说。\n\n　　林风把她的身体转过来，让她面对自己。\n\n　　“你看着我。”\n\n　　陈敏看着他的眼睛。\n\n　　“我是林风。”\n\n　　“我知道。”\n\n　　陈敏没有立刻回答，她看着他的眼睛，看了很久。\n\n　　“臭弟弟，我喜欢的人是你，从你扯掉我扣子的时候，喜欢的就是你……”\n\n　　林风心里有些感慨，也有些无语，他非常清楚自己的性格，懒惰，贪念美色，喜欢享乐，不求上进，能躺平绝不坐着……种种缺点，不得不承认刚才有那么一瞬间的感动。\n\n　　但内心更多的想法是，‘姐姐，这是末日唉，我图你身子，你却跟我玩感情，你不知道我见一个爱一个吗？不管了，享受当下要紧，能不能活过明天都是未知数。’\n\n　　林风低头吻住陈敏的红唇，吻得很热烈。\n\n　　就在林风即将下一步动作的时候，车队的大喇叭响了\n\n　　“全体注意，全体注意，车队休整2小时，2小时后出发，车队成员自行收集物资，车队概不干涉，现招募狩猎队员，有意者到前方找队长王烈登记，重复……”\n\n　　一辆公交车还没停稳，车里五六个男人围坐一起。\n\n　　“你们看到了吗？”一个瘦子压低声音说道，“今天加入的那个车队，那是莫青峦和米雪啊！大明星！真人！那身材，那脸蛋，啧啧……”\n\n　　“比电视上的还要好看。”\n\n　　“你说……她们怎么活到现在的？”一个戴眼镜的年轻男人推了推鼻梁上的眼镜，“两个大明星，手无缚鸡之力，在末日里活到现在，指不定……”\n\n　　他没有说下去，但车里的男人都发出了心照不宣的笑声。\n\n　　“你可别小看她们。那个莫青峦，人家是觉醒者，能治伤的，你没听前面的人说吗？治疗系的觉醒者，比战斗系的还稀罕。”\n\n　　“治疗系又怎么样？”一个平头男嗤笑一声：“又不能打又不能杀，真遇到危险还不是得靠男人，再说了……”\n\n　　他朝埃尔法的方向努了努嘴，“觉醒者又怎么样，我可是听说了，她们那个车队可是连一个有战斗能力的觉醒者都没有，现在物资这么紧缺，等饿的不行了，也就一个面包的事，到时候我带兄弟们一起……”\n\n　　车里的笑声更大了。\n\n　　“大哥说得对，到时候带兄弟们一起去照顾照顾她的生意，咱们也享受享受大明星的待遇。”\n\n　　“对对对，大哥仗义！”\n\n　　“算我一个！”\n\n　　“我也去我也去！”', 2335, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (48, 13, 46, '第46章 看到漂亮姑娘就走不动路', '　　公交车的最后一排角落里，一个女人小声地嘀咕了一句：“这些男人，真不要脸，”\n\n　　“嘘……”她旁边的中年女人摇头，示意她别说话。\n\n　　车厢里的笑声还在继续，谈话之间也越来越放肆，黄腔不断。\n\n　　一个老头听不下去了，浑浊的眼睛瞪着那群男人：“你们够了啊，人家再怎么说也是觉醒者，得罪了她们，你们吃不了兜着走。”\n\n　　平头男斜了他一眼：“老头，关你什么事。”\n\n　　“我只是提醒你们，”老头没有退缩，“王烈队长说了，车队里禁止抢夺，禁止强迫，你们想做哪些龌龊事，先问问队长同不同意。”\n\n　　“王烈？”那男人冷笑一声。“王烈现在忙着跑路呢，哪里有空管我们？再说了，这不出发前才说了，各管各的，我们用自己的物资跟人家交换点‘服务’，不违反车队规定吧？”\n\n　　老头张了张嘴，没有说出话来。\n\n　　“行了行了。”瘦子摆摆手，“大哥，别跟那老头一般见识，咱们说咱们的……”\n\n　　笑声又起来了，老头长叹一声。\n\n　　一个抱着孩子的女人低声说了一句：“这世道，彻底变了。”\n\n　　车队终于在一片小树林外停了下来，树林边上还有一条已经干涸的河沟，河床里一滴水都没有。\n\n　　车辆一辆接一辆的熄火。\n\n　　车门一个接一个打开，人们从车里涌出来，有人试图去找水源，有人拿着袋子去挖野菜，准备做午饭。\n\n　　小玄在树林边缘停下，直接往地上一趴，开始刨土。\n\n　　“林风，队长喊你们过去开会。”江声的声音在外面传来。\n\n　　“知道了，马上。”\n\n　　陈敏从林风的怀里挣出来，理了一下有些褶皱的衣服，把头发重新扎起来，拉着门下了楼，林风跟在陈敏后面从小玄背上跳下来。\n\n　　江声站在小玄旁边，脸上带着一丝尴尬。\n\n　　“队长说有事商量，让你们赶紧过去。”\n\n　　装甲房车的门敞开着，林风上去的时候，里面已经坐了不少人，杨密和热巴也在。\n\n　　说起来这辆豪华房车其实还是属于沈雨桐的，林风对车队里的人和情况了解不多，只知道沈雨桐在穿越前就是富家千金，这辆豪华房车从穿越之初，她就在车里。\n\n　　至于后面为什么每次开会都在这辆车上，而不是在王烈车上，大概原因是这辆车空间最大，有桌子沙发，最舒服吧。\n\n　　当然林风曾经也分到了一辆大巴车，不过被收回去了。\n\n　　王烈手里端着茶杯，目光在林风和陈敏之间停留了一瞬，然后移开了。\n\n　　董雨身上的绷带已经拆了，只留下几道浅浅的伤痕。\n\n　　她正对着莫青峦说着话，声音温柔得让林风起了一层鸡皮疙瘩，尤其是董雨看莫青峦的眼神让林风的嘴角抽了抽。\n\n　　“青峦姐，你那个治疗能力太厉害了，我这胳膊本来以为要废了，你手一放上去，不到十分钟就好了……”\n\n　　董雨那眼神太熟悉了，跟林风看到漂亮女人的眼神一模一样。\n\n　　她喜欢女人的事，车队里的觉醒者都知道，她也从来不当众掩饰，之前她从林风身边抢走的那两个女人就是最好的证明。\n\n　　在这车队核心成员里董雨的能力最弱，她一个女人都惹不起，陈敏她惹不起，沈雨桐她惹不起，方玲她惹不起，这些女人要么实力比她强，要么地位比她高，要么两者兼备。\n\n　　所以她的目光一直停留在车队里那些没有自保能力的普通女人身上。\n\n　　但现在，车队迎来了两个新人。\n\n　　两个新人不仅都是觉醒者，还是两个大明星。\n\n　　两个都是能力不强的辅助型觉醒者，所以她觉得机会来了。\n\n　　董雨的目光黏在莫青峦身上，米雪感觉到了什么，她的危险感知能力本能地察觉到某种不对劲，但具体是什么，她也说不清楚。\n\n　　“人都到齐了，先说一下，我们车队新增了两名觉醒者，莫青峦，能力是治疗，米雪，能力是危险感知，欢迎加入。”\n\n　　林风从座位上站起来，绕过小桌，脸上挂着热情的笑容。\n\n　　“青峦姐，米雪姐，我是你们的粉丝，我可喜欢你们了，没想到末日里能见到真人，真是太荣幸了！”\n\n　　说着，林风张开双臂，作势就要去拥抱。\n\n　　“欢迎你们加入车队，以后大家就是一家人……”\n\n　　胳膊还没碰到莫青峦的肩膀，耳朵就被一只手捏住了。\n\n　　“疼疼疼疼疼……”林风歪着脑袋，往后退。\n\n　　陈敏站在他身后，两根手指捏着他耳朵，表情笑眯眯的，林风只感觉后背发凉。\n\n　　“给我老实坐好。”\n\n　　“敏姐，我这不是表达一下热情嘛。”\n\n　　“坐好！”\n\n　　林风揉着耳朵回到座位上，老老实实地坐下去，嘴里嘟囔着。\n\n　　沈雨桐在陈敏和林风之间来回转了一圈，嘴角微微翘了一下，却什么都没说。\n\n　　莫青峦和米雪对视一眼，杨密微微摇摇头，意思是，别问，不知道什么情况。\n\n　　米雪微微点头。\n\n　　“没吓到你们吧？”陈敏脸上的表情瞬间切换，露出一副和煦的笑容。\n\n　　“别理这个渣男，他看到漂亮姑娘就走不动路。”\n\n　　“敏姐，我哪有……”\n\n　　“闭嘴！”\n\n　　车厢里响起几声笑声，经过林风这一打岔，气氛比刚才融洽很多。\n\n　　王烈咳嗽一声，把所有人的注意力拉回来。\n\n　　“说正事。”\n\n　　“经过今天的全速行驶，我们现在距离目的地大约还有120公里直线距离，如果保持现在的速度前进，预计明天下午就能抵达。”\n\n　　120公里，如果放在蓝星高速上，也就一小时时间，但在末日里，那些弯弯绕绕的路线，诡异盘踞的区域，随时可能出现的变异生物，明天能到已经是天大的幸运了。\n\n　　“但目前的问题是，除了我们几名觉醒者的车辆外，车队里很多人的燃油即将耗尽，那些私人车辆，本来没什么油，跑了一上午，油箱已经见底了。”\n\n　　车里安静了下来。\n\n　　没有油的车，就是一堆废铁。', 2118, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (49, 13, 47, '第47章 圣母心泛滥了？', '　　“所以，”王烈看向所有人，“找你们来商议一下，我们几个觉醒者的大巴车，要不要贡献出来，让那些人挤一挤？”\n\n　　没有人说话。\n\n　　郭逸低着头，手指在桌面上画圈，他的车上还有自己一大家子，七八口人要养。\n\n　　江声也没有说话，他的大巴车除了司机外，其他地方都被改造成了培育土豆的地方。\n\n　　沈雨桐在地图上划着，像是没有听到这个问题，其他人也不会打她车辆的主意。\n\n　　林风更是直接靠在沙发上，翘着二郎腿，他又没有大巴车，现在他的交通工具是一只乌龟，就算是贡献大巴车，那也是他们的事，跟他有什么关系。\n\n　　“我没问题，”陈敏开口了，“我那辆大巴车空得很，腾出来能坐不少人，我搬林风那就行。”\n\n　　其他人齐刷刷地看向陈敏，然后目光落在林风身上，那意思就是，你小子能耐啊，这就拿下来？\n\n　　然后莫青峦开口了，“我们车队那边情况有些特殊，一部分是剧组的成员，再加上路上救了不少人，车已经塞满了，而且我们食物和水都已经耗尽了，我过来是寻求帮助的。”\n\n　　方玲的目光在莫青峦和米雪身上扫了一眼，董雨的表情从‘花痴’变成了担忧，嘴唇动了动，最终什么都没有说，不动声色的离莫青峦远了一点。\n\n　　“你们自己没有物资吗？”\n\n　　莫青峦摇摇头：“我们车队的物资都是收集上来后，再平均分配的，刚开始还好，后面越来越危险，愿意出去收集物资的人就变少了，所以……”\n\n　　林风心里明白了，车队里一百多人，一部分人冒着生命危险出去干活，最后还要分出去，其他人坐享其成，慢慢的就没人愿意了呗……\n\n　　“我们还有一些物资，”王烈说，“但不够养整个车队。”\n\n　　方玲合上手里的本子：“我们车队的食物储备只够2天，现在多出一百多人，如果分出去仅够一天。”\n\n　　“林风，你有多少？”\n\n　　车厢里所有人的目光都看向林风，他们都知道林风那只大乌龟的储物间里堆了不少好东西。\n\n　　莫青峦看着他，眼神里带着一丝期待。\n\n　　陈敏搂着林风胳膊的手紧了紧。\n\n　　林风在心里快速过了一遍自己的库存，大米大约三四百斤，面粉五六十斤，罐头几十罐，腊肉还有五六块，加上今天河里弄到的鱼，够他自己和几个女孩吃大半个月。\n\n　　但是养整个车队？不可能。\n\n　　“够我自己用的，匀不出来，再说今天上午，车队里的人逼宫的目的，不就是不愿意上交物资吗？队长你不是也因为物资损失大半，食物紧缺才顺水推舟答应的吗？”\n\n　　“怎么？圣母心泛滥了？”\n\n　　王烈咳嗽了两声，终于说出了自己的想法，“我的意思是，我们扩大巡逻队的数量，毕竟我们觉醒者的数量稀少，尤其是现在，根本顾不过来五六百人。”\n\n　　“啥意思？”\n\n　　王烈指着外面这片树林，“这片树林里经过雨桐的预测，有不少低级变异生物。”\n\n　　“什么？”\n\n　　米雪站起身，使用能力感受了一下，脸色微微变了一下。\n\n　　陈敏的眉心亮起微弱的光芒，精神力散开，朝着树林的方向延伸过去，几秒钟后，她睁开眼睛说道。\n\n　　“有东西，但不多，很集中，0级变异生物居多，1级大约十几只，没有2级。”\n\n　　王烈点点头，继续说自己的想法：“组建狩猎队，给他们发放武器，由觉醒者带领进入其中狩猎，获得的物资按贡献分配，保证公平，至于不愿意的……”\n\n　　王烈虽然没有说，但大家心里都明白，不愿意就等死。\n\n　　“我同意！”林风点头，他本来就是比较自私的人，根本不可能把自己的东西拿出去养陌生人，又不是漂亮的小姐姐。\n\n　　“不过，武器怎么解决，获得的猎物怎么分配？”\n\n　　“老规矩，其中5成归自己，其余5成上交，由我们觉醒者分配，现在加上莫青峦和米雪，刚好十人，由我们按贡献分配。”\n\n　　“至于武器的问题，郭逸能融合诡异掉落的物品打造一些简易武器。”\n\n　　郭逸从座位底下摸出一把泛着寒光的刀，刀身长约60厘米，刀背厚实，刀刃锋利无比，刀柄制作了防滑纹。\n\n　　“这是融合了诡异材料的精钢大刀，锋利程度比普通砍刀强数倍不止，砍0级变异生物跟切豆腐一样。”\n\n　　紧接着他又拿出一把弓，“反曲弓，用弹簧钢融合诡异材料打造，射程150米，箭头的材料我用了变异利齿鱼的牙齿，我试过了，五十米内能射穿3层钢板，对付0级变异生物不成问题。”\n\n　　林风拿起一支箭看了看，确实锋利无比。\n\n　　“只是……”郭逸的声音里带着一丝无奈，“我觉醒的能力是机械维修和改造方向的，做武器实在不是我的专长，这把刀和弓已经是我的极限了，融入了1级材料，却只能对付0级的变异生物，遇到1级的，刀砍上去会卷刃，弓箭根本射不穿，至于对付诡异……”\n\n　　他摇摇头：“完全没办法。”\n\n　　米雪忽然开口了。\n\n　　“我们车队里有一个人，养了一条黑狗。”\n\n　　“黑狗？”\n\n　　“对，纯黑的狗，从穿越第一天就跟我们了，有一次遇到诡异的时候，我们发现黑狗的血能逼退它们。”\n\n　　“黑狗血？”郭逸有些激动：“你是说，民间传说的黑狗血。”\n\n　　“对，我们车队能走到现在，就是靠放那条黑狗的血，涂抹在武器上，能伤害到诡异，好几次诡异袭击的时候，围着我们转了很久都不敢靠近，就是因为那车里有黑狗血。”\n\n　　“对啊，我怎么没有想到！”郭逸一拍大腿。\n\n　　“黑狗血辟邪，老祖宗传下来的东西，肯定有道理！”\n\n　　“民间传说不一定全是空穴来风，这个世界的诡异和我们蓝星传说的鬼魂有一些相似之处，黑狗血能辟邪，在这个世界一样有效。”\n\n　　林风靠在沙发上，听着几人的议论，脑子已经在转了。\n\n　　黑狗！\n\n　　御兽。', 2131, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (50, 13, 48, '第48章 买下黑狗', '　　林风升到1级后，多出来了一个御兽空位，小玄是他的第一只御兽，第二只现在还没有着落。\n\n　　黑狗血能辟邪，能逼退诡异，如果把那条黑狗契约了，再升级一下，它的血会不会更强，或者它能不能直接击杀诡异。\n\n　　如果能对付诡异，以后的夜晚谁还担心诡异袭击。\n\n　　林风直起身，看向米雪。\n\n　　“那条黑狗，卖不卖？”\n\n　　米雪愣了一下，“你买黑狗干什么？”\n\n　　“我是御兽师，我的御兽就是那只乌龟，你们应该看到了，我还有第二个御兽空位，一直没有找到合适的契约对象。”\n\n　　林风这话一出，车里的人顿时明白了，一想到如果林风能契约那条黑狗，再培养成小玄那种，那岂不是能在诡异中横着走。\n\n　　“我可以帮你问问，”莫青峦的声音响起，带着她那特有的小奶音，只是下一句话就让林风心里咯噔一下。\n\n　　“不过那条黑狗在我们车队很重要，便宜了可不行。”\n\n　　林风心里暗骂，这女人要宰自己。\n\n　　但一想到黑狗契约后升级的潜力，咬咬牙，认了。\n\n　　“行，你先帮我问问。”\n\n　　几人继续讨论招募狩猎队的事情，王烈的目的很明确，那就是从车队里招募愿意加入狩猎队的人，发放郭逸制作的武器，由觉醒者带队进入树林狩猎，获得的猎物，五成归狩猎队，五成上交，由他们几个觉醒者按贡献分配。\n\n　　“加入狩猎队的人，能带一个家属上大巴车，不愿意的自己找活路，坐享其成的人，等死！”\n\n　　王烈定下基调后，没有人反对。\n\n　　林风听得心不在焉，脑子里全是那条黑狗，会议一结束，他就站起来。\n\n　　“青峦姐，快，带我去看看那条狗。”\n\n　　莫青峦的车队停在大部队的尾部，十几辆车排成一排。\n\n　　此时一辆旅游大巴车前面围了一圈人。\n\n　　大约十几个，男女都有。\n\n　　一个老人靠在轮胎边，怀里死死的抱着一条黑狗，那老人看起来六十多岁，头发花白，身体干瘦，此刻手臂上的青筋都暴起来了，整个人弓着背，把狗护在怀里。\n\n　　那条狗很小，看起来才几个月大，浑身漆黑，一根杂毛都没有，此刻它蔫哒哒的，脑袋靠在老人的胳膊上，它的腿上还缠着绷带，绷带上渗出来的血迹变成了黑褐色。\n\n　　“不行，你们不能吃它。”\n\n　　老人的声音沙哑，整个人都在发抖。\n\n　　“你们忘了？这一路都是靠放它的血才救活你们的，你们怎么能忘恩负义？”\n\n　　老人面前站着3个男人，领头的三十多岁，穿着一件皱巴巴的西装。\n\n　　“那是以前，现在是现在，现在有车队里强大的觉醒者庇护，能一样吗？”\n\n　　“就是，”他身边一个跟班往前凑了一步，“我们都饿一天了，吃条狗怎么了？”\n\n　　“就是就是，车里的东西都是大家的，拿出来！”\n\n　　周围的人开始起哄。\n\n　　“拿出来吧，老头。”\n\n　　“一条狗而已，又不是人。”\n\n　　“我们可都是明星，吃你一条狗是看得起你！”\n\n　　周围的人一起哄，为首那个男人顿时底气十足，伸手就去拽老人怀里的狗。\n\n　　“放开！”\n\n　　老人死死的抱着狗，身体往后缩，忽然他被踹了一脚，身体往一边倒去，摔在地上，但怀里还是死死的抱着那条黑狗，不肯松手。\n\n　　“怎么回事？”\n\n　　莫青峦的声音不大，但围着的人群听到她的声音，一下子就安静了。\n\n　　那个男人看到是杨密，立刻换上了一副笑脸。\n\n　　“青峦姐，大家都饿一天了，这不是寻思搞点吃的嘛，这老头养了一条狗，我们想着把它炖了，到时候分你一点，这老头不识抬举，正教训他呢。”\n\n　　“放手，把狗还回去！”\n\n　　那男人的笑容僵了一下。\n\n　　“青峦姐，大家一天都没吃东西了，再不吃东西，我们都要饿死了，一条狗而已，我给钱就是……”\n\n　　他从口袋里抽出一沓钞票，在老人面前晃了晃。\n\n　　“看到没，真钱，够不够！”\n\n　　老人看都没有看那沓钞票，只是死死地抱着狗。\n\n　　“行了，老头，别不识抬举。”\n\n　　他拽了一下，老人没松手，他又拽了一下，老人的身体被拖着往前划了半米，膝盖在碎石上擦出一道血痕，但他的手没有松开。\n\n　　“你他妈……”\n\n　　林风走过去，没有给他说话的机会，抬起脚，一脚踹在那男人的肚子上。\n\n　　那男人被林风踹得直接往后飞去，撞在了大巴车上，发出嘭的一声，整个车身都晃了晃，然后滑落在地，捂着肚子缩成一团，嘴巴张着发不出任何声音，脸上全是痛苦和恐惧。\n\n　　其他人见到这一幕，同时往后退了一步，一句话都不敢说。\n\n　　林风蹲下来，老人身体抖了一下，看着他，眼里全是警惕和恐惧。\n\n　　“老人家，别怕，我是御兽师，那狗能不能让我看看？”\n\n　　老人抱着黑狗的手下意识地紧了一下，过了好几秒，老人才松开手。\n\n　　林风把黑狗接过来。\n\n　　很轻，这狗才几个月大，加上这几天没怎么吃东西，抱在手里轻飘飘的，林风仔细打量了一番，果然是五黑犬，民间传说能辟邪，看透阴阳，驱散鬼魅，以前只当是迷信。\n\n　　但穿越到这个末日世界后，见识了诡兽，怨灵这些真实的诡异玩意后，再看这条狗，他的想法完全不一样了。\n\n　　老祖宗严选的，能是普通货色吗？\n\n　　“老人家，这狗我要了，给你十斤米，换不换？”\n\n　　老人的嘴唇哆嗦了两下，十斤大米，在这个末日里够他吃半个月的。\n\n　　莫青峦的声音从身后传来。\n\n　　“林风弟弟，你这就不厚道了。”她走过来双手抱胸，“这狗可是能辟邪驱逐诡异的好宝贝，你十斤大米就想换？”\n\n　　她伸出一根纤细白嫩的手指，在林风面前晃了晃。\n\n　　“最少一百斤。”\n\n　　林风翻了个白眼。\n\n　　果然，漂亮的女人，心都是黑的。\n\n　　林风不理会莫青峦，低头看着老人。\n\n　　“老人家，十斤大米，另外我给你安排到车队前方的大巴车上，比这安全，灰雾来了也跑得快。”\n\n　　林风想了想，反正陈敏的大巴车空着也是空着，她的不就是自己的吗？安排一个座位而已，多大点事。\n\n　　“我是御兽师，我不会吃它，反而会想办法让它变强。”林风看着老人的眼睛，说着自己最后的筹码，再不换我就换个方式要了。\n\n　　“真的……不吃？”\n\n　　“不吃。”', 2284, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (51, 13, 49, '第49章 第二只御兽', '　　老人看了一眼林风手里的狗，伸手在狗背上慢慢抚摸，从头顶摸到尾巴，满眼不舍。\n\n　　“换，只要你不吃它，这就换，它叫小黑，是我老伴在世的时候买给我作伴的，没想到这世道……”\n\n　　莫清峦在旁边皱眉，车队这么多人，这么点东西还不够塞牙呢，于是说道：“这不合规矩！”\n\n　　“交易而已，你情我愿，有什么不合规矩的？别忘了这是我们的车队，得守我们的规矩，大锅饭那一套，在这，行不通。”\n\n　　林风的目光扫过周围的人，嘴角微微往上翘了一下。\n\n　　“就算她……”林风的手指指着一个高挑的身影，那是一个二十多岁的女人。\n\n　　“唉，那个美女，”林风朝她招招手。\n\n　　那个女人愣了一下，左右看了看，确定林风是在叫自己。“就是你，过来。”\n\n　　那个女人犹豫了一下，从人群中挤过来。走近了看，林风发现她的身材确实很好，高挑修长，该凸的凸该凹的凹，五官精致，鼻梁高挺，一眼就能看出她曾经的职业，模特，还是走过国际大秀的高级模特。\n\n　　“叫什么名字？”\n\n　　“苏婉。”女人的声音有些沙哑，嘴唇有些干裂，看上去很久都没吃过饱饭了。\n\n　　“苏婉，好名字，”林风上下打量了一下，暗自点头，“跟着我怎么样，每天都能让你吃饱。”\n\n　　周围的人一下子炸了锅，顿时响起一阵窃窃私语声。\n\n　　苏婉的脸微微红了一下，但没有低头，也没有躲开林风的目光，她已经一天没吃东西了，胃里空空的，像是有什么东西在啃噬她，她之前是模特，公司给她争取了一个角色。\n\n　　为了保持身材，饿过无数次，但从没有像现在这样，饿得想啃桌子，沉默了一会，然后开口道：“你说的是真的。”\n\n　　“不骗你！车队里那只大乌龟是我的坐骑。”\n\n　　“别答应他！”\n\n　　米雪从外面挤进来，一把拉住苏婉的手。\n\n　　“苏婉，别答应这个人渣！”\n\n　　米雪瞪了林风一眼，那眼神里有愤怒，有警惕，还有一丝‘早知道就不该让你跟过来’的后悔。\n\n　　林风耸耸肩，抱着黑狗，扶着老人就走。\n\n　　“没意思，走了。”\n\n　　林风走了几步，忽然停下来。\n\n　　“我那句话一直有效，跟着我有饭吃，当然……只要美女哦。”\n\n　　说完没有等任何人回答，抱着狗，走了。\n\n　　那条黑狗被林风抱在怀里，睁开一双深褐色，清澈的，圆溜溜的眼睛看着林风，然后伸出舌头，舔了一下林风的手背。\n\n　　“呵呵，小家伙……”\n\n　　林风揉了揉小黑的脑袋，带着老人一前一后的来到小玄身边，小玄趴在树林边缘，用爪子刨出了一个大坑。\n\n　　还真是一停下来，就不停地刨土、啃土块，林风摇摇头，随它去吧。\n\n　　“敏姐。”\n\n　　陈敏放下矿泉水瓶，看了看林风，又看了看他身后的老人，最后把目光落在他怀里那条黑狗身上。\n\n　　“这就是那条狗？”陈敏伸手摸了摸狗的脑袋，黑狗的尾巴轻轻摇晃着。\n\n　　“老人家，你跟她走。”林风指了指陈敏，对着老人说道：“她帮你安排座位，米我一会儿送过去，十斤，不会少你的。”\n\n　　老人点点头，没说什么。\n\n　　“狗借我玩会。”陈敏从林风手里接过黑狗，带着老人走向自己的大巴车。\n\n　　陈敏回到大巴车上，翻出一根火腿肠，剥开皮，掰成小块，喂到黑狗的嘴边，黑狗闻了一下，就开始吃，吃得狼吞虎咽，显然已经饿急了。\n\n　　“你们几个，我的东西收好了没。”\n\n　　“敏姐，收好了。”\n\n　　几个女人从车上下来，年纪都不大，二十多岁的样子，穿着T恤和牛仔裤，素面朝天，不过样子都还不错，放在人群里，也算小有姿色。\n\n　　她们此刻一个个手里扛着包，拎着袋子，大包小包的往车下搬。\n\n　　“你就这些东西？”\n\n　　林风不知道何时来到大巴车前，见陈敏堂堂一个核心队员的觉醒者，竟然只有这点东西。\n\n　　食物只有一小袋，也就是一些方便面、面包，米面啥的，加起来也不到十斤，甚至还有小半袋野菜，最好的也就半条鱼肉，看样子还是早上分的那条，这也太寒酸了吧。\n\n　　“就这些。”陈敏把最后一块火腿肠喂给黑狗。\n\n　　“我的东西本来就不多，车队物资紧缺，大部分我也看不上。”\n\n　　林风把手里的一袋米，递给老人，顺便把那袋野菜也给老人。\n\n　　“来，你的东西，以后你就坐这车上，这袋野菜也给你。”\n\n　　“谢谢，谢谢……”老人老泪纵横，一个劲地感谢。\n\n　　林风摆摆手，过去搂着陈敏。\n\n　　“敏姐，跟我了，还吃什么野菜，保证给你养得白白胖胖的。”\n\n　　“你才白白胖胖的。”陈敏娇嗔地拍了林风胸口一下，不过在末日里这么一句话，不亚于最好的情话。\n\n　　末日里感情本就奢侈，朝不保夕，随时可能丧命，车队里很多失去丈夫的女人，很快身边就会有新的男人出现，不仅是为了获得食物和生存资源，或许还有心理寄托。\n\n　　只要不是强迫的，基本上都睁一只眼闭一只眼，这也是底层的物资流通方式之一，毕竟都是为了活下去。\n\n　　“走吧……”\n\n　　回程的速度很快，林风指着小玄背上的房子。\n\n　　“搬上去吧，衣物放楼上，食物和水放一楼储物间里。“\n\n　　陈敏身后的几个女人应了一声，搬着东西上了楼梯，她们站在储物间门口，目光在堆满物资的货架上扫了一圈，眼里全是震惊，这房间里的东西，够她们吃好几个月了。\n\n　　怪不得敏姐不坐大巴车也要搬过来，换她们也要跟过来啊，不过她们知道这不是自己能奢望的，她们懂事的把东西放下，什么都没说，转身就下了楼，一步三回头的往回走。\n\n　　“林风哥哥，敏姐，来吃饭了。”\n\n　　“来了。”\n\n　　林风伸手把黑狗从陈敏的怀里接过来，拍了拍它的脑袋。\n\n　　“走，吃饭。”', 2115, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (52, 13, 50, '第50章 御兽升级', '　　小小的储物间桌子已经支起来了，一大盆鱼肉放在桌子中央，乳白色鱼汤还冒着热气，旁边还有两个小菜，素炒土豆丝，以及一份凉拌木耳。\n\n　　一大盆蒸米饭摆在旁边的石台上，米香扑鼻。\n\n　　四个女孩站在桌子旁边，手规矩地放在身前，像是在等待老师发号施令的小学生。\n\n　　“都坐下吃饭吧。”陈敏开口了，语气温和自然，就像是女主人一样。\n\n　　四个女孩看了林风一眼，才慢慢坐下，她们坐在塑料凳子的边缘，身体挺得笔直，眼睛看着桌子上的菜，直咽口水，但谁也没有动筷子。\n\n　　林风见状，一人夹了一块鱼肉放她们碗里。\n\n　　“吃饭，放松点，敏姐又不吃人。”\n\n　　林风把黑狗放地上，从盆里夹了一块鱼肉，黑狗尾巴摇得飞快，流着口水，眼睛死死地盯着林风筷子上的鱼肉，就是没有上前。\n\n　　直到林风把鱼肉放地上，小黑狗这才上前闻了闻，然后才开始吃。\n\n　　小蕊的眼睛直了。\n\n　　“狗狗！”\n\n　　她放下筷子，蹲在小黑狗的旁边，伸手去摸它的背。\n\n　　“好黑啊，好可爱，它叫什么名字。”\n\n　　“小黑！”\n\n　　“小黑，小黑，你饿坏了吧。”小蕊从碗里拿起一块鱼肉，撕成小条，放在手心里，递到小黑嘴边。\n\n　　小黑闻了闻，然后小心地开始吃，舌头舔过小蕊的掌心，痒得她咯咯直笑。\n\n　　小玉也蹲下来，抚摸小黑的脑袋。\n\n　　小晴和晓丽跑去角落里找了两个稍微旧一些的不锈钢盆，洗干净，倒了小半瓶清水，小晴添了点米饭，又舀了几勺鱼汤，拌均匀后，放在小黑的面前。\n\n　　四个女孩围着小黑，脸上带着开心的笑容。\n\n　　“好了好了，先吃饭，你们自己都没吃呢。”\n\n　　几个女孩这才重新坐回凳子上。\n\n　　陈敏吃饭的姿态很优雅，可是吃的速度一点也不慢，觉醒者的饭量本来就大，一碗米饭几口没了，林风的速度更快，吃鱼肉随便嚼两下就咽了下去。\n\n　　伴随着“体质+1，+1”的提示，一大盆鱼肉很快就被几个人消灭得一干二净。\n\n　　“饱了，你们收拾一下……”\n\n　　林风把碗往桌子上一放，低头看了一眼桌下，小黑已经吃完那碗鱼汤泡饭，正趴在他的脚边，脑袋搁在他脚背上，眼睛半闭，打着呼噜。\n\n　　林风弯腰，把小黑狗抱起来，起身就往楼顶走。\n\n　　到了楼顶，把小黑放下来，从指尖逼出一滴鲜血按在小黑的脑门上。\n\n　　契约！！！\n\n　　契约没有什么特效，只是感觉与自己的精神之间多了一股连接而已，能感应到对方的情绪，能通过精神连接下达指令。\n\n　　【本命御兽2/2】\n\n　　御兽1：玄龟\n\n　　御兽2：辟邪犬\n\n　　等级：0级（进化需消耗10点进化点。）\n\n　　能力1：辟邪之力（注：你的御兽血液具有驱散诡异的效果，等级越高效果越强，对1级及以下诡异造成额外伤害，对1级以上诡异造成震慑效果，诡异等级越高效果越弱。）\n\n　　能力2：未解锁\n\n　　“好家伙，怪不得杨密她们的车队能走到现在，小黑的功劳不可忽视啊。”\n\n　　林风看了一眼自己的进化点数量。\n\n　　11.2\n\n　　小黑从0级升到1级，需要的进化点够了。\n\n　　林风没有丝毫犹豫，在心里默念一声，进化。\n\n　　淡淡的进化之光覆盖了小黑的全身，然后它的体型以肉眼可见的速度开始生长，原本几个月大的小狗，身体开始慢慢变大，四肢变得粗壮有力，爪子从脚垫里伸出来，锋利无比。\n\n　　整个进化过程在短短几分钟内就完成。\n\n　　整个狗从幼犬的圆润憨态变成了成年犬的流线型体型，不，比成年犬体型还要大一些，肩高已经超过林风的小腿了，伸手摸去，能感受到它浑身都充满爆发性的力量。\n\n　　【进化反馈，体质+3，力量+4，敏捷+6，精神+6，可选一项本命御兽能力作为自身天赋。】\n\n　　面板上的信息变了。\n\n　　辟邪犬：小黑\n\n　　能力1：辟邪之力（注：你的御兽具备辟邪之力，能对2级及以下诡异造成大额伤害，对2级以上诡异造成震慑效果，诡异等级越高效果越弱。）\n\n　　能力2：守护领域（注：狗狗是人类的守护者，可释放半径100米的守护领域，震慑诡异，能驱散2级及以下诡异，在领域内，诡异隐匿效果失效，降低诡异50%能力，对诡异的伤害翻倍，诡异等级越高效果越弱。）\n\n　　林风看到面板上新出现的能力说明，嘴角彻底收不住了，然后嘿嘿嘿地笑出声来。\n\n　　百米的守护领域，诡异能力直接降低一半，伤害翻倍，而且还能驱散诡异，这简直就是神级能力。\n\n　　这意味着什么？意味着晚上终于能睡个好觉了，从穿越到这个末日世界的第一天起，车队就没有安稳睡过一晚，车队要不停地往前行驶。\n\n　　最早还在顶上安排了巡逻队员，试图防备随时随地可能出现的诡异，可巡逻队员也只是普通人，没有觉醒能力，对付普通人还行，面对诡异也毫无办法。\n\n　　后面只能几名觉醒者轮流守夜，就算是这样，每天夜晚同样要死不少人。\n\n　　现在好了，小黑的守护领域一开，半径百米内就相当于一个小型的安全区，就算有诡异来了，诡异能力降低一半且伤害翻倍，只要不遇到高级诡异，他们也能对付。\n\n　　“林风？”\n\n　　陈敏的声音从楼梯口传来，带着一丝担忧。\n\n　　“你在笑什么？笑得跟傻子似的。”\n\n　　“敏姐，你过来！”\n\n　　陈敏走过来，理了理林风被风吹乱的头发：“怎么了？”\n\n　　“敏姐，你看小黑！”\n\n　　陈敏的目光落在小黑身上，眼神里满是惊讶。\n\n　　“这……？”\n\n　　她伸手摸了摸小黑的头，小黑没有躲，反而把脑袋在她手心里拱了拱，尾巴摇得飞起。\n\n　　“这有这么大了吧，刚才还是一团，现在就长这么大了？”\n\n　　“刚进化的，而且小黑有两个能力。”\n\n　　“什么能力？”\n\n　　林风没有隐瞒，把小黑的能力统统都告诉给了陈敏，尤其是能制造临时安全领域的事。\n\n　　陈敏听着听着，脸上的表情从惊讶变成了认真，然后变成了凝重，那双勾人的眼睛盯着林风，像是在确认他有没有开玩笑。\n\n　　“你说的是真的？”\n\n　　“我什么时候骗过你？”\n\n　　“走，去找队长。”陈敏转身就走，走了两步见林风还没动静，“愣着干嘛？走啊！”', 2284, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (53, 13, 51, '第51章 吃不得半点亏', '　　林风拍了拍小黑的脑袋，示意它跟上。\n\n　　林风和陈敏来到装甲房车前的时候，这里黑压压一片人头，大部分都是男人，各个年龄段的都有，其中以年轻力壮的年轻人为主，人群里还有几个女人。\n\n　　郭逸站在人群前面，地上堆着一地的钢刀，他一把一把地往外递，每递出去一把，都会说一句，“刀是借的，回来要还的。”\n\n　　王烈站在旁边，目光扫视人群，自带一股压迫感。\n\n　　其他队员也在，林风还看到了莫请峦和米雪，她们腰间多了两把短刀，手里提着一把弓，正在测试弓弦的力度。\n\n　　王烈看到林风和陈敏走过来。\n\n　　“你们来得正好，人挑好了，60个，你，我，方玲，董雨，陈敏一人一队，清峦和米雪一队，各带领10名狩猎队员，进树林。”\n\n　　林风看了一眼那60个人，站得松松垮垮，队形不整，每个人握着武器，眼神里带着殊死一搏的狠劲，那是食物耗尽，对生存的渴望。\n\n　　“我这队不要人，我跟敏姐两个就够了，人你们带吧，我一会带着小玄直接趟过去。”\n\n　　林风对带队没什么兴趣，还得费心保护他们，麻烦。\n\n　　直接走到郭逸身边，从地上捡起仅剩的几把反曲弓，然后把一整捆箭矢全部抱走了。\n\n　　“这几把弓给我，箭矢我全拿走了，咦，这刀也不错。”又拿起一把长刀。\n\n　　郭逸看着林风把弓和箭矢往怀里揽，嘴角抽了抽。“这反曲弓不好做，材料有限，数量不多，你这一个人全拿走了……”\n\n　　“怎么不舍得？”林风头也没抬，反而又捡起一把长刀。\n\n　　王烈在身后咳了一声。\n\n　　“林风，先把东西放下……”\n\n　　林风没有理他，反而把东西抱得更紧了，转过身看着王烈，脸上一副我全拿走了你能把我怎么样的表情。\n\n　　“我本来还有个好消息告诉你的，你这么小气，我就不跟你说了……”\n\n　　王烈：“……”\n\n　　陈敏拍了林风一下，笑着打圆场说：“队长，他就这德行，吃不得半点亏。”\n\n　　“不过确实是好消息，是关于整个车队的。”\n\n　　陈敏朝身后招招手，小黑从林风脚边走出来。\n\n　　王烈看着这条狗，目光在狗身上停留了好几秒，表情没有太大的变化。\n\n　　“1级，这狗……确实比普通狗强很多，这就是好消息？”\n\n　　陈敏没有卖关子，把小黑的能力一五一十地告诉王烈，辟邪之力，守护领域等等。\n\n　　王烈听完，神色变了，不仅仅是他，其他几名觉醒者的脸上的表情也是各不相同。\n\n　　“半径一百米的安全领域？”\n\n　　王烈沉默了几秒，然后深吸了一口气，肩膀微微松了一下。\n\n　　从穿越第一天起，灰雾在后面追，诡异天天夜袭，物资越来越少，人员越来越少，每一天都有人死，他作为队长，不能慌，不能怕，不能倒，必须撑着，让所有人觉得他有办法带领大家活下去。\n\n　　此刻听到小黑的守护领域后，那根一直绷紧的弦，终于松开了。\n\n　　“确实是个好消息。”\n\n　　王烈的声音恢复了平静，看着小黑，在它身上停留了很久，然后看向林风的眼神都顺眼了一些。\n\n　　“好，以后的收获，多分你一成。”\n\n　　“成交。”林风的嘴角翘了一下。\n\n　　“好狗，我以后的好日子全靠你了。”\n\n　　商议完毕后，几个觉醒者重新分配好自己的队员后，已经整装待发，十人排成一列，沿着树林边缘小心翼翼往里进发。\n\n　　莫清峦和米雪带着最后一队人，站在树林入口，十几个人握着刀，手在发抖，他们这一队的觉醒者战力最低，不得不害怕，米雪闭着眼睛，感知着树林里的危险。\n\n　　林风抱着武器回到小玄背上的时候，四个女孩正趴在2楼窗户往外看，显然是发现了觉醒者带人进入树林了。\n\n　　“小蕊，小玉，小晴，晓丽，都上来！”\n\n　　“大人怎么了？”\n\n　　“你们会射箭吗？”\n\n　　四个女孩齐刷刷地摇头。\n\n　　“不会没事，你们先试试。”林风把反曲弓一人一把递过去。\n\n　　几个女孩接过弓，握在手里掂了掂，小蕊试着拉了一下弓弦，脸憋得通红，但弓弦竟然被她拉开了。\n\n　　她松开手，看着自己的手指，眼睛里全是不可置信。\n\n　　“我……我能拉开？”\n\n　　“你们吃了两顿1级变异鱼的肉，现在的体质和力量不比普通男人差，能拉开正常。”\n\n　　林风从地上捡起一只箭，搭在弓上，拉满，松手，箭矢‘嗖’的一下射出去，钉在30米外的一棵枯树上。\n\n　　“这弓不错……”\n\n　　几个女孩对视一眼，小玉也试了一下，同样也拉开了，晓丽和小晴也跟着试了一下，尤其是晓丽，拉得最慢，弓弦拉得最满，那眼神、那姿势，像是天生就该拿弓的人。\n\n　　林风点点头，看来还是有点战斗天赋的，只要稍微培养一下，能成为不错的帮手。\n\n　　“等会进来树林，你们就站在这房顶上，看到变异生物就射。”\n\n　　林风说话期间使用控土术在房顶的边缘又加高了一圈石墙，刚好可以当护栏用，然站在后面，身体被挡住大半，只有上半身露在外面。\n\n　　“好了，这是护栏，站在这后面射箭，免得你们掉下去，别探出身子，瞄准了再射，射不中没关系，谁都是从射不中开始的，但千万别把箭射人身上。”\n\n　　见几个女孩，拿着弓箭在那唧唧喳喳的说着话，练习拉弓的样子。\n\n　　陈敏忍不住开口“你认真的？”\n\n　　“当然？我们这可是在逃亡，末日里哪有花瓶的存在，每个人都要为生存努力，她们这不是玩得挺开心的嘛！”\n\n　　“出发！”\n\n　　收到指令的小玄从土坑里站起来，啃了一肚子土的它体型又大了一圈，估计用不了多久又要调整房子的大小了。\n\n　　唉，真是幸福的烦恼。\n\n　　小玄迈开步子，踏入小树林，周围寻找野菜的人纷纷为这头庞然大物让开道路，小玄的体型太大，两边的树枝从龟壳两侧划过，发出刷刷的声音。\n\n　　越往里走，树木越密，好在小玄的控土术发挥了作用，泥土把树根拱起来，自动往两侧分开，一条宽敞的道路自动产生。\n\n　　其他队伍不像林风这样仗着有小玄在横冲直闯，反而走得很小心。', 2217, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (54, 13, 52, '第52章 暧昧的教学', '　　莫清峦和米雪带着她那队人，猫着腰，小心翼翼地往前探索，热巴用她的能力感知着周围动静。\n\n　　“停，前面有东西。”忽然米雪抬起手，身后的人齐刷刷停下脚步，眉头冒汗，握着刀柄的手都有些颤抖，现在面对的可是变异生物，由不得他们不害怕。\n\n　　在前方20米的位置，一棵合抱粗的大树下，有一堆泥土被翻开，堆成了一个小土包，土包下是一个黑漆漆的洞口。\n\n　　莫清峦示意大家跟上，从两侧绕过去，形成一个包围圈。\n\n　　一只地鼠从洞口探出头来，它的体型不比成年犬小多少，见到人群后，不仅没躲，毛发如同钢针般一根根竖起来，露出两颗长的门牙，朝着最近的一个人扑来。\n\n　　“小心！”莫清峦身边一个四十来岁的女人，手持长刀，当头劈下。\n\n　　地鼠感觉到头顶的风声，那只又长又尖的爪子猛地一缩，放弃攻击，对着头顶的长刀抓去。\n\n　　“当”的一声，刀锋和爪子碰撞，发出金铁交加的火花声。\n\n　　“张姐，小心。”\n\n　　莫清峦喊道，这个张姐穿越前就是她的保镖，当时还有6个人，经过这几天的逃亡，她的保镖只剩张姐和另外一人，由于她和米雪都觉醒了能力，所以一直跟着她们，如果不是还有保镖的护卫，她们两个早就被车队里的人吃干抹净了。\n\n　　地鼠的反应极快，落地就往张姐的小腿扑去。\n\n　　旁边一个男人健步上前，一刀砍在地鼠的的背上，刀锋切开地鼠粗糙的皮毛，一道深可见骨的伤口处顿时冒出鲜血，地鼠吃痛，猛地转身，朝着那男人扑去。\n\n　　就在这时候，一道箭矢传出破空声，精准地插在地鼠身上。\n\n　　这一箭是莫清峦射出的，只见她又取一支箭矢搭在弓上。\n\n　　“快！快帮忙，你们看着干嘛？”\n\n　　周围提着刀的人，唯唯诺诺不敢上前，被张姐大声呵斥。\n\n　　“还不动手，一会没你们的份。”\n\n　　其他人咬咬牙，眼神发狠，一拥而上，十几个人围着那只地鼠，乱刀劈下，没有任何章法。\n\n　　地鼠在人群中左冲右突，撞倒好几个人，每次想要逃跑，都被张姐和另外一个叫阿勇的保镖给挡回去。\n\n　　最后张姐看准时机，一刀砍在地鼠的脖子上，这一刀直接切开对方的脖子，血液喷涌而出，地鼠在地上抽搐了几下，然后不动了。\n\n　　周围的人大口地喘着气，几乎所有人身上都有伤，尤其是两个倒霉蛋，伤得最重，此刻正在惨叫，一个被地鼠咬断半个手掌，一个小腿被抓出几道长长的口子，每一道都深可见骨。\n\n　　“给他们包扎一下，其他人带上猎物，继续前进。”张姐看了一眼那两个人，说道。\n\n　　人群里出来两个人，把衣服撕成布条简易包扎了一下，然后扛起地上的地鼠，继续前进，至于地上那两个伤员，只能互相搀扶着往营地走，其他人丝毫没有停留。\n\n　　这就是末日，获取资源比救治伤员更重要。\n\n　　米雪想说什么，被身边的莫清峦拉了一下，继续往前走。\n\n　　其他队伍明显要轻松很多，尤其是王烈那一队。\n\n　　王烈走在最前方，步子不紧不慢，像是在逛自家后院一样，他身后同样跟着15个人，手里握着刀，东张西望。\n\n　　“队长，那边有动静！”一个人指着前方的一处灌木丛。\n\n　　王烈顺着他手指的方向看了一眼，然后他抬起手，只见他随手一挥。\n\n　　“轰……”\n\n　　一道雷电劈在灌木丛上，灌木丛瞬间炸开，一只地鼠从里面飞出来，落在地上，浑身冒着青烟。\n\n　　他身后的十几人大眼瞪小眼，一个个张大了嘴巴，一秒钟不到，地鼠就死了。\n\n　　“愣着干什么？去捡回来。”\n\n　　有个机灵的跑出去，把地鼠的尸体扛回来，王烈看了一眼地鼠，又看了看那十几个人一眼。\n\n　　“想吃肉的，自己动手，没有贡献的人什么都分不到。”\n\n　　他说完，转身就往前继续走，以他目前的实力，对付这种0级变异生物就像捏死一只蚂蚁一样轻松，只是他要的不是当保姆，而是要一批敢打敢杀，能面对怪物的战士，而不是一群等待喂食的猪猡。\n\n　　那些人对视一眼，握紧了手里的刀，跟上王烈的脚步。\n\n　　而林风这边的画风就完全不一样了。\n\n　　房顶上，四个女孩趴在石墙后面，箭矢搭在弓弦上，一个个跃跃欲试。\n\n　　“小玉，你的手太紧了，来，放松点，对，就是这样，瞄准……”\n\n　　“放……”\n\n　　咻……\n\n　　“中了中了，我射中了。”小晴的声音十分兴奋。\n\n　　“不错，射中了，还没死，继续练习……”\n\n　　小蕊在另外一边急得跳脚。\n\n　　“林风哥哥，我也要我也要，教教我嘛。”\n\n　　她从另外一边蹦到林风面前，直接钻进林风怀里，把小晴挤出去，小晴被挤出林风的怀抱，不满地瞪了小蕊一眼。\n\n　　“教教我嘛，你都教小晴好久了。”\n\n　　林风无奈地叹了口气，站在她身后，胸膛贴着她的后背，右手握住她拉弓弦的手，左手托住她握弓的手。\n\n　　“手要稳，对，就这样。”林风在她耳边说话，呼出的气流拂过她的耳朵，小蕊的耳朵一下就红了。\n\n　　“专注点，别急，等瞄准后再松手。”\n\n　　“咻……”\n\n　　箭矢飞出去，扎中地鼠的腹部。\n\n　　“我中了，我也中了！”小蕊从林风的怀里跳出来，蹦得老高。\n\n　　“林风哥哥，你看到了吗，我射中了……”\n\n　　“看到了。”林风把弓还给她，伸手在她脑袋上拍了一下，“继续。”\n\n　　“得意什么？又不是你一个人射的。”小玉看着小蕊那张得意的表情，不屑地‘切’了一声。\n\n　　“我就是射中了嘛，你还没射中呢。”小蕊那小得意的模样看得小玉牙痒痒。\n\n　　陈敏靠在墙上，双手抱胸，看到这一幕，翻了个白眼。\n\n　　“你就宠着她们吧。”\n\n　　“敏姐，你吃醋了？”林风走过去伸手要搂陈敏的腰，“来，我也教你，手把手的，包教包会，一射一个准。”\n\n　　陈敏侧身躲过他，银白色的小刀在指尖转了一圈，刀尖对着林风。\n\n　　“死开，别打扰我。”\n\n　　林风把手缩了回去，嘿嘿笑了一下。\n\n　　“敏姐，你这刀太快了，万一划一下，我可就破相了。”\n\n　　“破相了好，省得你出去还祸害小姑娘。”\n\n　　小蕊突然喊起来，声音里带着掩饰不住的兴奋，“林风哥哥，快来看，我射中了它的头！”\n\n　　林风走过去，顺着小蕊手指的方向看过去，地鼠头上插着一支箭，除了这一支外，它身上还歪七竖八地插着好几支箭矢。\n\n　　“好，干得漂亮。”\n\n　　“小黑，下去把猎物带回来，顺便把箭矢也叼回来。”\n\n　　蹲在一旁的小黑，顺着楼梯一阵风地跑下去，跳下龟背，眨眼的功夫就把猎物给我带回来，然后又把射偏的箭矢一根根的找出来，全部叼回来。\n\n　　“好狗！”林风拍了拍对方的脑袋。\n\n　　“林风哥哥，快点让大乌龟继续找地鼠，太好玩了，哦对了，还要让大乌龟把地鼠控制起来，不准它动，不然我射不中。”小蕊抱着林风的胳膊撒娇道。\n\n　　林风的嘴角抽了抽。\n\n　　“行！”', 2544, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (55, 13, 53, '第53章 原来变异生物也会害怕', '　　小玄继续往前走，随着一只只地鼠被小玄用控土术翻出来，地鼠见到小玄如此恐怖的体型，吓得惊慌失措的想往土里钻。\n\n　　但土壤在小玄的控制下，变得像钢板一样硬，它们不仅钻不回去，还被土壤死死地束缚在原地，变成一个不会移动的固定耙子。\n\n　　然后4个女孩兴奋地一根接着一根的放箭，箭矢飞出去，要么落在地鼠身边，要么扎在地鼠身上，地鼠不知道是被吓得，还是疼的，一个个吱吱乱叫，拼命挣扎，却怎么也挣脱不了。\n\n　　地鼠的叫声越来越尖，到最后变成委屈的嘶鸣，像是在说，没这么欺负鼠鼠的，你放开我，咱们单挑啊。\n\n　　见她们练的差不多后，林风射穿地鼠的头颅，终结了鼠鼠的凄惨鼠生。\n\n　　【击杀0级地鼠，获得进化点0.1】\n\n　　给她们练箭归练箭，该抢的人头还是要抢的，不能让她们全杀了，0.1也好，毕竟蚊子腿也是肉嘛。\n\n　　小玄继续开路，控土术翻出一只又一只地鼠，几个女孩射箭的准头越来越准，手也不抖了，尤其是晓丽，成长的速度最快，3箭就能射中一次固定靶。\n\n　　猎杀的效率比任何一只狩猎队都要高，其他队员在树林里小心翼翼地搜索，寻找目标，偶尔发现一只地鼠，还要围追堵截半天，防止地鼠一溜烟的功夫就钻土跑了，时不时的还要防备狂暴的地鼠临死反扑，付出伤亡的代价才能杀死。\n\n　　林风这边从进入树林开始，死在他们箭下的地鼠已经超过十只了。\n\n　　“林风哥哥，地鼠是不是变少了。”已经好大一会没遇到新的地鼠了，小蕊开口问道。\n\n　　“不是变少了。”陈敏的精神力延伸，感知着周围的动静。\n\n　　“前面有一个地下洞穴，大部分地鼠都在那里，不仅有0级的，还有几只1级的。”\n\n　　“小玄，走，去看看。”\n\n　　小玄朝着树林深处走去，大约走了200米，眼前豁然开朗，一大片空地出现在树林中央。\n\n　　空地中央，足足几十个黑漆漆的洞口，有些洞口大的能钻进去一头熊。\n\n　　空地周围已经站了不少人，王烈和几名觉醒者站在最前面，后面站着四五十个拿着长刀的人，一个个身上都带着大大小小的伤口。\n\n　　王烈看到林风的御兽小玄踏着沉重的步伐从树林里挤出来，对着他们说道：“陈敏，感应到没？”\n\n　　陈敏点头：“就是这里！”\n\n　　王烈：“动手？”\n\n　　林风：“动手！”\n\n　　林风起手就是控土术，土黄色的光芒从掌心亮起，他的控土术虽然没有小玄那么强，但掀起一片地面还是足够了。\n\n　　泥土就像被一只无形的巨手托起，整个地面猛地往上拱了一下，然后裂开，大片的泥土往两边翻滚。\n\n　　轰！\n\n　　地面塌了，不，准确地来说，是整块地面被掀开了一层，十几只地鼠暴露出来，它们愣了一下，不明白为什么家没了，但看看到这么多人虎视眈眈的盯着它们，开始四处逃窜。\n\n　　有的往树林里跑，有的朝着人群冲过来，惊慌失措，连方向都分不清。\n\n　　王烈的雷电最先出手，电弧从他掌心射出，在空中分成数道，精准地劈在3只地鼠身上，地鼠的身体顿时被电得抽搐起来，然后彻底不动了。\n\n　　陈敏地操控的飞刀紧随其后，在空中划出一道弧线，穿透了一只地鼠的头颅，然后转过弯又穿透了第二只。\n\n　　董雨手持长刀冲进地鼠群中，刀刃划过空气，一只地鼠的脑袋被砍下来，这女人的实力虽然不咋地，力量不如刘铁柱，也就是身体防御还行，不过对付这些0级地鼠还是没问题的。\n\n　　方玲同样抽出一把短刀，身影在地鼠群中飞快穿梭，速度极快，每闪一次，就有一只地鼠毙命，伤口精准地切在喉咙上。\n\n　　不到两分钟，十几只地鼠全部毙命，林风连动手的机会都没有，这些地鼠就全部被杀死了。\n\n　　狩猎队的成员站在空地外，目瞪口呆，他们刚才十几个人为杀一只地鼠都要费半天劲，还有人伤亡，如果不是觉醒者偶尔搭把手，起码得死伤过半。\n\n　　而现在，短短两分钟就杀了十几只，而且毫发无损，这就是普通人和觉醒者之间的差距吗？他们想要变强的心思更强了，甚至痛恨为什么自己没有觉醒。\n\n　　“地下的还没出来，三只，1级的，体型很大。”陈敏感知到地下还有几个大家伙，立刻出声提醒。\n\n　　“小玄，把地下的大家伙赶出来。”\n\n　　小玄的控土术比林风强太多了，土黄色的光芒在亮起，地面开始剧烈地震动，不是像林风那样掀开一层土，而是面前整个大地像波浪一样翻滚，石头泥土疯狂地往上涌，几百米外很快就被掀翻的泥土堆成了一座小山。\n\n　　吱吱吱……\n\n　　尖利的叫声从地下传来，三只巨大的地鼠从翻涌的泥土中冲出来，它们的体型比普通地鼠大好多倍，每一只都有牛犊那么大，背脊上长着一排倒刺，从脖子一直延伸到尾巴上，前爪更大，指甲更是锋利无比，闪着寒光。\n\n　　它们此刻愤怒无比，眼睛通红，在洞里睡得好好的，突然间家被毁了，晕头转向地爬出来，不管不顾的朝着毁了他们家园的敌人扑过来。\n\n　　然后……\n\n　　然后他们停了，冲锋的姿势还未靠近人群就猛的刹车，前爪在地上犁出两道深深的沟壑，只因他们看到一只体型是它们无数倍的凶兽……小玄，就站在它们前面，那双铜铃大的眼睛死死盯着它们，\n\n　　似乎在说，你再靠近试试。\n\n　　地鼠冲锋的姿势变成了滑稽的急刹车，然后掉头就跑，爪子疯狂地刨土，身体拼命地想往地下钻。\n\n　　“哈哈，好搞笑啊，原来变异生物也会害怕！”小蕊指着滑稽的地鼠笑道。\n\n　　王烈几人可没给它们机会，雷电从掌心射出，劈在最后面那只地鼠背上，地鼠发出一声惨叫，陈敏的飞刀也从侧面飞来。\n\n　　林风急忙喊道：“小玄。”\n\n　　三道地刺从地面冒出来，瞬间穿透3只地鼠的身躯，将它们瞬间毙命。\n\n　　【击杀1级变异地鼠，获得进化点+3，当前进化点5.2】\n\n　　“还好，人头抢到了。”林风拍拍胸口，要是没抢到人头，得后悔3天。', 2200, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (56, 13, 54, '第54章 分战利品', '　　王烈：“都愣着干什么，把战利品带回去。”\n\n　　狩猎队员们这才回过神来，纷纷走上去，拖得拖，抬得抬，带着满满的战利品返回营地。\n\n　　返回营地后，等林风把楼顶上最后一只地鼠丢下去的时候，地上的地鼠已经堆成了小山，方玲正在做着记录，狩猎队的队员围在周围，虽然他们身上带着伤，有的手臂缠着布条，有的腿上缠着纱布，但脸上的表情却是无比兴奋。\n\n　　周围同样围满了车队的人群，看着这么多地鼠，狂咽口水。\n\n　　“队长他们太厉害了，这么多地鼠……”\n\n　　“是啊，就是不知道会不会分给我们一点，我好几天没吃肉了，野菜都快吃吐了。”\n\n　　“别想了，想吃肉，加入狩猎队啊……”\n\n　　“我觉得面糊糊煮野菜就挺好的，我跟你说，你没看到吗？今天带回来那些尸体和伤员，怕你有命去，没命回来，那些怪物是那么好杀的吗？”\n\n　　“我要是觉醒者就好了……”\n\n　　围观的议论纷纷。\n\n　　王烈接过方玲手里的本子，看了一眼，然后开口了。\n\n　　“这次狩猎一共猎杀了1级地鼠3只，0级地鼠32只，其中林风那队猎杀的数量最多，占全队三分之一。”\n\n　　“按此次贡献，加上许诺你多分你一成，一共……”\n\n　　“0 级的地鼠我就不要了，分两只1级的给我。”林风直接打断王烈的话，自己储物室里的粮食还有几百斤，0级的地鼠哪里能跟1级的比较，这么大两头地鼠的肉，起码能把他的体质往上再提升不少，尤其是晓丽她们几个，提升会更显著。\n\n　　“你确定？”\n\n　　“确定！”\n\n　　王烈点点头，在本子上做好记录。\n\n　　“林风这一队分两只1级地鼠。”\n\n　　周围的人倒吸一口凉气，那么多地鼠这就放弃了，只要了两只1级的。\n\n　　有人小声说：“那个林风大人是不是这里有病，明明0级地鼠分得更多。”他指了指脑袋\n\n　　旁边那人瞟了他一眼：“你懂个锤子，这东西的肉能提升实力，1级的别看分的肉少，效果肯定比普通地鼠的肉好，人家这是赚了。”\n\n　　王烈继续说：“我只要1只1级地鼠，你们同意不？”\n\n　　几个觉醒者都示意没有问题，王烈见大家没有意见后，继续开口。\n\n　　“狩猎队成员总共狩猎8只地鼠，按规矩上交一半，虎子，去拿4只，跟队员们分一分！”\n\n　　一个壮硕的汉子，从人群里走出来，从地鼠堆里，拖出4只地鼠，递给几名狩猎队员，说：“兄弟们，跟我走，分肉。”\n\n　　“好嘞……”\n\n　　狩猎队剩余的52人，迫不及待地跟着虎子的脚步往一边走去，4只，每只都有三四十斤肉，够他们每个人吃两顿饱的了，至于死去的8名队员，只能怪他们命不好了。\n\n　　“清峦和米雪。”王烈看向这两个往日里的大明星，一周多的末日求生，她们已经不复往日的那般艳丽，此刻脸色有些不好看。\n\n　　“你们这一队贡献最低，分2只地鼠。”\n\n　　“江声，看在你今天培育催生出第一批500斤的土豆，分3只地鼠给你。”\n\n　　江声连连道谢：“谢谢队长，谢谢队长，我一定努力，让大家都有吃的。”\n\n　　林风诧异地看着江声，满打满算才穿越8天，去掉改造大巴车的时间，也就是说他短短7天时间就能催生出出500斤土豆，这简直就是末日天选之子啊，末日世界最缺的是什么，不是别的，是食物啊，这意味车队里有了他，就不会缺少食物。\n\n　　这才1级，7天就产出500斤，要是等级高了呢，1000斤，还是5000斤，完全可以供养整个车队啊。\n\n　　林风心里暗想，这小子是个人才啊，有机会得多接触接触。\n\n　　“郭逸。”王烈喊道：“整个车队的维修和改造都靠你，所以你的贡献能分6只。”\n\n　　“嘿嘿，谢谢队长，我别的不会，修个车还是没问题的。”他开心地拿走6只地鼠。\n\n　　“车队的路线规划都靠雨桐，所以雨桐也分8只。”\n\n　　“方玲，分5只。”\n\n　　“董雨，分4只。”\n\n　　战利品分完后，各自带着自己的战利品回去处理，营地里很快生起了火堆。\n\n　　狩猎队的人抱着分到的肉一个个笑得合不拢嘴，每一个人连骨带肉差不多分了2斤多，哪怕是腥臭的内脏都没有人嫌弃，这可是变异生物的肉，每多吃一口，说不定就能多变强一点。\n\n　　很快肉香在营地里弥漫开来。\n\n　　“这肉真的能提升实力！”不知道谁喊了一声。\n\n　　这下子气氛更热烈了，有的队员自己舍不得吃，把肉带回车上，和家人孩子一起吃。\n\n　　另外一边，莫清峦和米雪站在埃尔法旁边，面前百来号人围得水泄不通。\n\n　　“清峦姐，我们吃什么？”一个穿着古装戏服的年轻女人声音带着哭腔问道。\n\n　　“对啊，清峦姐，大家一天没吃东西了。”\n\n　　“清峦姐，分点吃的吧，孩子都饿哭了。”一个中年女人抱着孩子挤过来，孩子在她怀里哭。\n\n　　“清峦姐，你们不是分到肉了吗？分一点吧，就一点。”另外一个男的也开口了。\n\n　　莫清峦手里提着那两只鼹鼠，看似不少，加起来七八十斤还是有的，可是一百多个人，分到每个人手里根本没有多少，而且也仅仅只够吃这一顿，下一顿呢？\n\n　　她们车队里的物资都是统一分配，可是来到王烈的车队后，这里的规矩可跟他们那种大锅饭不一样。\n\n　　每一个人的物资都是自己的，现在大家手里都缺物资，根本没有人愿意分给他们。\n\n　　王烈他们的车队，唯一能吃上大锅饭的只有失去车辆加入巡逻队的人，或者加入后勤队的成员，但那也就比车队里其他人稍微好一点，最多就是野菜里加了点油，放了点盐巴，偶尔能放点米面，一起乱炖，做成野菜团子。\n\n　　而且每个人的份额还有严格的限制，饿不死，但也吃不饱。\n\n　　在自己都吃不饱的情况下，更不可能分给这些半路加入车队的人食物。\n\n　　莫清峦车队的人除了少数人或许有私藏的，大部分都已经断粮了，现在大家饿得没有办法，最先想到的人自然是她们车队的队长杨密。\n\n　　莫青峦和米雪都感受到人群中的情绪，那种饥饿，焦躁，几乎就要一触即发的失控和混乱。\n\n　　她们不知道王烈他们这些觉醒者对混乱的人群是什么态度，是安抚，还是直接大清洗。从今天去猎杀地鼠时，他们车队的觉醒者看到队员死亡都无动于衷的情况来看，大清洗的概率更高。\n\n　　大清洗的概率更高，她不敢去赌，尤其这一张张面孔，好多都是她熟悉的人。\n\n　　“大家静一静，听我说。”', 2372, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (57, 13, 55, '第55章 最重要的是跟对人', '　　“大家静一静，听我说。”莫清峦的声音很大，只是她那特有的声音一点威慑力也没有。\n\n　　好在她身边站着两个保镖，眼神冷冽地注视着众人，让周围的嘈杂声低了下去。\n\n　　“车队还没有出发，大家跟我去树林里挖野菜，树林里没有危险，车队里的觉醒者已经清理过了。”\n\n　　她指着树林的方向，“挖野菜，煮野菜汤，加上这地鼠肉，大家都能分到！”\n\n　　人群沉默了片刻，然后响起稀稀拉拉的声音，有人说“好”“我跟你去”。\n\n　　当然也有坐享其成的人，提出反对意见。“树林那么大，会不会有危险。”\n\n　　“张姐，你在这里处理地鼠，我和米雪带他们去找野菜。”\n\n　　“要我跟着你吗？”张姐不放心地说道。\n\n　　“不用，米雪跟我一起就可以了，而且我也不弱。”她手臂弓起，做了一个有力气的动作。\n\n　　“行吧，你们小心点，注意安全，快去快回，车队还有1小时就出发了。”\n\n　　最终，一百多人只有十多个人愿意跟着杨密去寻找野菜。\n\n　　但更多的人没有动，他们站在原地，眼巴巴地看着张姐她们在那里处理地鼠的肉，他们宁愿坐等，留着口水，也不愿意自己动手去寻找吃的。\n\n　　前面车队里传来的烤肉香味，勾得人胃里翻江倒海。一个年轻的女人站在人群边缘，看着前面营地里架在火上煮的肉汤，看了很久，然后移开了目光。\n\n　　几个男人朝着她走过来，为首的是那个公交车里的平头男，他走到女人面前，嘴里挂着一个猥琐的笑容，伸手从口袋里掏出半包饼干，在女人面前晃了晃。\n\n　　“想吃吗？陪我睡一晚，这半包饼干就是你的。”\n\n　　这女人脸色白了一下，手指紧了紧裙摆，她想拒绝，可是好饿。\n\n　　平头男人往前凑了一下，饼干在她面前晃得更近了，饼干的香味从袋子里飘出来，直往她鼻子里钻，女人的喉咙上下滚动了一下。\n\n　　“滚！”一个中年女人看到这一幕，一把推开平头男人，把女人拉到身后。\n\n　　“你当这里是什么地方，想欺负人，找别人去，就你这种人，也配高攀我家丫头。”\n\n　　平头被推了一个踉跄，他站稳后，想上前理论，结果看到巡逻队的人往这边看来，瞬间阴沉个脸，停下脚步，啐了一口唾沫，转身走了。\n\n　　那个中年女人拉着年轻女人的手，走到一处没人的地方蹲下来，四处张望了一下，从身上小心翼翼地摸出一块士力架，掰成两半，把其中一块递给年轻女人。\n\n　　“瑶，先吃点垫垫肚子，等会清峦姐就回来了。”\n\n　　“谢谢李姐！”被叫做瑶瑶的女人接过士力架，咬了一口，眼泪从眼眶里滑落。\n\n　　“谢我干啥，瑶瑶，别轻贱自己，在这个圈子里混，最重要的是要有眼光，跟对人，眼光放长远点，你这模样，不比那苏婉差，真到哪一步了，为什么不选择最强的。“\n\n　　“李姐，我……”\n\n　　“行了，我知道你想说什么，我们这个圈子没有你想的那么干净，用自己换资源的比比皆是，更何况现在可是末日，我不会害你的，把东西吃完，别让别人发现，后面的事情听我的……”\n\n　　……\n\n　　车队就是一个小社会，为了活下去，各自施展手段，其他男的没有平头男那么笨，一来就盯着莫清峦车队里最漂亮的几个女人下手。\n\n　　他们拿着手里的食物，很快谈妥，有一些受不了饥饿的女人，跟着他们就钻进了车里，或者帐篷里。\n\n　　这种你情我愿的事情，巡逻队的人都是睁一只眼闭一只眼，只要不发生混乱就行。\n\n　　营地的另外一处地方，一个老太太站在一辆SUV面前，伸手去拽一个女人手里的袋子，袋子里装着一块拳头大小的肉，是那个年轻女人用一袋盐换的，老太太拽着袋子不松手，嘴里念叨着。\n\n　　“你们年轻人吃不了那么多，分我一点怎么了？尊老爱幼知道不？我这么大岁数了，你好意思让我饿着，就算是大明星的车队里，都不敢让我饿着，你凭什么不给……”\n\n　　年轻女人拽着袋子的另一头，不肯松手：“这是我的东西，我用自己的盐换的。”\n\n　　老太太见周围围拢的人群多了，嗓门更大了：“你这孩子怎么这么不懂事，我吃你一点肉怎么了？你爹妈没教过你要尊重老人？”\n\n　　她拽了一下袋子，年轻女人没有松手，她又拽了一下，袋子被撕开了，那块肉掉在了地上，老太太伸手要去抢，手还没碰到肉，就被一个身影挡住了。\n\n　　老太太抬起头，看到一个手里提着刀的巡逻队员站在她面前，面无表情地看着她。\n\n　　“车队里禁止抢夺他人物品，违者处死，这条规矩，你们队长没告诉你们吗？”\n\n　　那老人撒泼道：“我不管什么破规矩，我是老人，你们就应该给我们吃的，你们车队里那么多吃的，为什么不分出来给我们？”\n\n　　“退后，再次警告，如果不听劝，我有权把你当场斩杀！”那名巡逻队员，双手持刀，眼神凶狠地盯着她，似乎再说一句就要动手了。\n\n　　那名老太太到嘴边的话立刻被吓得咽了回去，连连后退，嘴里小声嘟囔着难听的话语，转身就走，比年轻人还跑得快。\n\n　　巡逻队员弯腰把肉捡起来，在裤腿上擦了擦灰，递给那个年轻女人，她接过肉，小声地说了一声谢谢。\n\n　　没过去多久，莫清峦带着十多个人从树林回来了，收获没有她想象的那么多，车队里的人听说，觉醒者带队进入树林猎杀变异生物后，原本只有少数胆子大的人在寻找野菜，这一下子听说没有危险后，更多人也加入了寻找野菜的队伍。\n\n　　数百人一窝蜂地冲进去，把能吃的东西都给翻了一个底朝天，他们可没有莫清峦车队里的人那么娇气，尤其是现在找到的都是自己的，不用上交，更是一个个干劲十足。\n\n　　他们十几个人总共才找到两三袋野菜，怕是连十斤都没有。', 2114, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (58, 13, 56, '第56章 暴雨', '　　莫清峦把带回来的野菜倒出来，让人简单清洗一下，吩咐张姐把处理好的两只地鼠肉拿出一只切成小块，放进锅里。\n\n　　一百多，这点肉，十斤不到的野菜，每个人只能分到一点点。\n\n　　“张姐，多加水，野菜和肉一起煮。”\n\n　　肉汤的味道让所有人的唾沫疯狂分泌，等差不多后，她把野菜一把一把丢进去。\n\n　　人群端着碗围了过来，碗各式各样，有不锈钢的、陶瓷的、塑料的，只要能盛东西就行。\n\n　　张姐见人群有些混乱，厉声呵斥道：“都排队，不排队的没有！”\n\n　　一百多人，排成歪歪扭扭的队伍，张姐拿着大铁勺，给每个人碗里都舀了一碗汤、一小块肉和一小勺野菜，确保每个人的份量都差不多。\n\n　　很快，锅里的汤见底，肉分完，野菜也吃完了。\n\n　　“这就没了？”一个男人把碗往地上一摔，“这点东西够谁吃的，还不够塞牙缝，这菜又苦又涩，给狗，狗都不吃。”\n\n　　“就是就是！”另外一人跟着附和，“不是还有一只地鼠吗？为什么不一起煮了。”\n\n　　“对，一起煮了，这点东西够谁吃。”\n\n　　“清峦姐，你不能这样啊，我们可都是跟着你从剧组一路跑出来的，你现在有吃的就不管我们了？”\n\n　　莫清峦站在一旁，手里端着一碗汤，才喝了一口，就感觉到一股苦涩的味道充斥口腔，直皱眉头，养尊处优多年，何时吃过这种苦。\n\n　　米雪把碗往地上一放，站起来，对着身边的人喊道：“你们够了！”\n\n　　“这是我们最后的食物，全煮了，明天吃什么？后天吃什么？你们想过没？”\n\n　　“明天的事明天再说！”那个摔碗的男人梗着脖子说道，他在蓝星的时候作威作福惯了，两个女明星还不放在眼里。“先吃饱了再说！”\n\n　　“吃饱？”米雪冷笑。\n\n　　“一百多人，两只地鼠，怎么吃饱，你们自己心里没数吗？人家车队的人，要么去狩猎，要么去挖野菜，自己养活自己，你们呢？坐在这里等着别人把饭送到嘴边？”\n\n　　“我们是演员！我们不会打猎！”一个女演员从人群里挤出来。\n\n　　“我们怎么去杀那些怪物，你是觉醒者，你们有本事，你们就应该保护我们！”\n\n　　“就是就是！”有人附和道。\n\n　　“你们不是觉醒者吗？觉醒者就该保护普通人，这是你们的责任！”\n\n　　“责任？”米雪往前走了两步，目光在那些人脸上一一扫过。\n\n　　“谁告诉你们觉醒者就有责任保护你们？我们现在加入的车队，人家王烈队长说了，跟随车队是自愿原则，路上各凭本事，人家觉醒者不欠你们的，我们也不欠你们的！”\n\n　　她指着营地前方那些正在烤肉的狩猎队员，“你们看看人家，个个带伤，甚至死在树林里，人家有肉吃，那是拿命换来的，你们呢？让你们去挖个野菜怕这怕那，一百多人，只有十几个愿意去，剩下的就在这里等着？”\n\n　　米雪看着一个个低下头、不敢说话的人。\n\n　　“怎么，都哑巴了，说话啊，想吃肉，去狩猎队报名啊，想挖野菜，树林就在那边，你们想跟着车队走，就老老实实跟着，不想跟的，现在就走，没有人拦你们！”\n\n　　她说完，端起自己那碗汤，转身走到那辆埃尔法旁边，一口一口地喝起来，汤已经凉了，野菜的苦涩味更重了，她皱着眉头喝完了。\n\n　　张姐和另外一名保镖自始至终都默默站在她和莫清峦旁边，手按在刀柄上。\n\n　　“全体注意！全体注意，车队即将出发，所有人上车，不要掉队，重复……”\n\n　　车队的喇叭响起，最前面那辆装甲房车已经启动，随后改装的大巴车一辆接一辆启动。\n\n　　营地里的人纷纷收起东西，跑向自己的车。\n\n　　“等等我，我的车没油了，让我上车……”\n\n　　“大哥，求你了，让我老婆孩子上车，我这里还有几包泡面，买两个位置。”一个中年男人敲打着一辆大巴车的车门，连忙喊道。\n\n　　开车的人见状，打开车门，“快点上车，自己找座位，没有就自己找空位，小李，把东西收好。”\n\n　　“谢谢大哥，老婆，快上来！”那个中年男人感激地说道，把手里东西交给车门后的一个年轻人，拉着自己的老婆孩子上车，车里已经坐满了人，过道也坐满了人，这些人都是车辆没油了，不得不交物资在大巴车上买一个上车的机会。\n\n　　那男人四处看看，最终在车上找到一个空位，拉着老婆孩子直接坐下。\n\n　　“全体注意，车队加速，跟紧车队，保持车距，别掉队……”\n\n　　小玄跟头车保持着距离，速度不紧不慢地跟着。林风在房顶上处理那两只1级地鼠，将其脊背上的倒刺一根根拔下来，鼠皮剥下，两个大门牙敲下，满嘴的利齿也一颗不少地收集起来放好。\n\n　　这些都是上好的材料，等改天找郭逸融入武器里面。\n\n　　内脏和鼠头直接剁下来，往外一丢，这玩意看着就倒胃口，不要……\n\n　　“兹……”\n\n　　一声声刹车声响起，后面的车看到后，连忙停车，下来几个人捡起地上的鼠头和内脏就往车上放，林风看不上的东西，在他们眼里，这可都是肉啊，处理干净起码一二十斤呢。\n\n　　为此他们还差点打起来，在一声声喇叭声的催促下，这才继续跟上车队。\n\n　　“林风哥哥，下雨了！”\n\n　　林风抬起头，一滴雨落在额头上，然后是第二滴，第三滴，雨点越来越密，越来越急，天空瞬间就灰蒙蒙的，然后越来越暗，雨越下越大。\n\n　　眨眼间就变成了倾盆大雨，林风就着雨水把地鼠肉处理干净后，连忙跑下楼梯，把地鼠挂在墙上，然后冲进二楼石屋里。\n\n　　顺手把门关起来，身上的衣服已经全部湿透了，整个人就像是从水里捞出来的一样。\n\n　　“林风哥哥，毛巾，先把衣服换了……”小蕊拿出一条干毛巾递到林风手里。\n\n　　接过毛巾后，林风擦了把脸，然后把头发擦干，自顾自地把湿衣服脱掉，然后若无其事的拿起一块浴巾围上。\n\n　　“呀……”\n\n　　几女的反应各不相同，小蕊几个女孩，用手蒙着眼睛，只是那手指缝大得跟没挡没啥区别，陈敏则完全不同，抱着熊，大大方方的打量，还点评道：\n\n　　“身材不错……”\n\n　　“那当然，今天敏姐不是体验过吗？再来一次……”\n\n　　“你给我松开，她们还在，唔……”', 2271, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (59, 13, 57, '第57章 守护领域', '　　暴雨倾盆，天色一片黑暗。\n\n　　而小玄背上的石头屋里，因为没有灯光，房间漆黑一片，林风最终还是没能得逞，陈敏被吻得差点迷失，但在最后关头一脚把林风踹到另外一边，抓起被子捂住自己。\n\n　　房间太黑，最后也不知道抓到谁，只感觉如同陷入了水中，一浪接着一浪在冲刷着他。\n\n　　轰隆隆……\n\n　　一道闪电划过，光线从窗户照进房间，映入眼帘的是小玉那张沾满汗水的俏脸。\n\n　　“小玉啊？你真叫这个名字？”\n\n　　“嗯~我全名叫苏雪玉，她们都叫我小玉。”\n\n　　林风笑着说：“我觉得你应该叫小水，你看，这被子，没法用了……”\n\n　　“讨厌~……呜……”\n\n　　唯有美人不可辜负，继续……\n\n　　外面的雨越来越大，打在车上，发出噼啪噼啪的响声。\n\n　　雨刮器开到最大都无济于事，挡风玻璃上全是水，视野一片模糊，全靠双闪辨别车队的方向，车队的速度一下子就慢了下来。\n\n　　车轮在泥泞的道路上打滑，车身左摇右晃。\n\n　　最前面那些经过郭毅改装后的大巴车还好，底盘高，轮胎大，但后面的那些小轿车就麻烦了，轮子陷入泥坑里，油门就算踩到底，就是出不来。\n\n　　有好几辆车陷在半路上，车上的人冒着倾盆大雨下来推车，衣服全湿透了，摔得满身是泥，但依旧只能爬起来继续推。\n\n　　有些车陷得太深了，根本推不出来，发动机都踩冒烟了依旧无济于事。\n\n　　“我们完了，车没了，什么都没了！”这个车主崩溃地喊道\n\n　　前面的车队不会停下等他，一辆又一辆车从侧边开过去，没有人停车，没有人帮忙，在这个末日每个人都在为自己活着。\n\n　　陆陆续续有人放弃自己的车辆，把能带上的东西都背在身上，跑去敲大巴车的门，用手里的物资求一个位置。\n\n　　有的人掏不出任何东西，在外面拍打车门，大声哀求，车门始终没开。\n\n　　车队在暴雨中艰难前行，慢得像是在爬行。\n\n　　头车内，王烈找到沈雨彤。\n\n　　“雨桐，这么大雨，车队走不了，你看看附近哪里能停车修整，等雨停了再走。”\n\n　　沈雨彤没有说话，只是点点头，面前摊开那张手绘地图，她眉头微微皱着，几分钟后。\n\n　　她抬起头，指着地图上一个位置，\n\n　　“这里有一个断崖，断崖往内倾斜，下面有一片空旷的位置，那里能避雨。”\n\n　　“多远？”\n\n　　“三公里！”\n\n　　“全体注意，头车转向，右前方三公里有断崖，车队到岩壁下避雨，各车跟紧，不要掉队。”\n\n　　车队在暴雨中转向，朝着断崖的方向驶去，后面的车一辆接一辆的跟上，3公里的路，走了半个多小时。\n\n　　岩壁下确实有一块空地，而且面积还不小，装甲房车停稳后，后面的车一辆接一辆地拐进来，车灯把崖壁下整个空地照得明晃晃的。人们从车上跳下来，站在干燥的地面上，仰头看那高耸的岩壁，长长的吐了一口气。\n\n　　王烈从房车上下来，方玲几人也从车上下来。\n\n　　王烈的目光在车队里扫了一圈，看向方玲：“统计一下，还剩多少车，多少人。”\n\n　　很快方玲带着十几名后勤人员把人员和车辆统计完毕。\n\n　　“队长，现在加上莫清峦她们车队的，总人数只有567人，路上丢了小型车辆37辆。”\n\n　　王烈沉默了几秒，从最初的几千人，到现在的567人，每一次停下来，都会少一批人，每一次出发，都会有车永远留在路上，这就是末日。\n\n　　“安排所有人休整，巡逻队注意警戒，有情况随时汇报。”\n\n　　巡逻队的人开始行动起来，有的人指挥车辆重新排列。\n\n　　林风已经穿好衣服，神清气爽的站在小玄旁边，小黑安静地蹲在一旁，耳朵高高竖起，聆听着是否有危险靠近。\n\n　　王烈来到林风身前看着他身边的黑狗说道：“林风，试一试你御兽的能力，今晚要在这里过夜了。“\n\n　　“小黑！”\n\n　　小黑听到林风的命令，一道淡金色的光芒从它身上展开，往四周开始扩散，如同一个碗倒扣在空地上，很大一部分还深入岩壁内。\n\n　　然后淡金色的光芒缓缓隐没消失，所有在范围内的人都感受到了一种安心的气息，像是被人守护一般，让黑暗中游荡的东西不敢靠近。\n\n　　“队长可以了，持续时间大概12小时，就是这个守护领域一旦释放就无法移动。”林风把小黑的技能效果说了出来。\n\n　　王烈点点头，然后沉声喊道，声音清晰地传入车队所有人耳中。\n\n　　“所有人注意，以此为中心，所有人不得离开方圆百米范围！”\n\n　　“是！！！”\n\n　　所有人连忙下车来到百米范围内，尤其是听到雨夜中那些诡异的声音后，更是加快了动作。\n\n　　不想死，就听话照做。\n\n　　大雨一点停的意思都没有，空气里的温度在下降，尤其是风吹过来的时候带走人身上的热量，有人忍不住打了个喷嚏。\n\n　　“虎子，生火！让大家烤一烤”王烈对旁边的壮汉说道。\n\n　　“队长，货车上的木头都湿了，点不着。”\n\n　　被叫做虎子的壮汉，本名王虎，听说跟王烈有点沾亲带故的关系，最开始帮王烈管着百来号巡逻队的人，现在还是狩猎队的小队长之一，在车队中可谓是觉醒者之下第一人。\n\n　　“用汽油，车上有汽油桶，倒一点，烧着了就不怕湿了。”\n\n　　虎子应了一声，转身跑开了。\n\n　　篝火在汽油浇过的木头上腾的一下窜起来，火光照亮了几十米的范围。\n\n　　人群围了上来，在火堆旁找了个位置坐下，有帐篷的已经在找位置搭帐篷了，有食物的，围着篝火小口小口的吃着。\n\n　　“今晚能在这过夜了？”有人问道。\n\n　　“王队说了，在这休整12小时，再走。”\n\n　　有孩子问：“妈妈，是不是安全了？”\n\n　　孩子的母亲声音有些沙哑：“安全了，觉醒者大人说安全了，睡吧。”\n\n　　一个戴眼镜的男人语气里的兴奋怎么都压不住，对着旁边的人说道：“你们看到了吗？那只黑狗，金光一闪，一个护盾就凭空产生了，我现在，怎么说呢，整个人都感觉舒坦了……”\n\n　　“那不是一般的狗，那是林风大人的御兽，听我巡逻队的兄弟说，那是林风大人的御兽，能驱散诡异。”\n\n　　“真的吗？那岂不是我们终于可以睡个好觉了！”\n\n　　“啧啧，不止这狗，你们看那边，那只乌龟，现在比一辆卡车还大，背上还驮着一个房子，那也是他的御兽。”\n\n　　几人同时转头看向小玄的方向。\n\n　　那个眼镜男咂了咂嘴，“这能力，在这世道里，活的比谁都滋润。”\n\n　　“可不是吗？听说那房子里好几个校花级美女，啧啧……”\n\n　　人群另外一侧，一座小火堆旁，莫清峦和米雪并肩坐着，两人的外套都湿了，脱下来放在一旁靠着，身上只穿着贴身的打底衫。\n\n　　米雪用树枝挑了一下木头，让火苗烧得更旺。她的目光落在那只巨龟上，停了很久，忽然开口道。', 2492, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (60, 13, 58, '第58章 小玄沉睡', '　　“清峦姐，那条狗到他之前，没那么厉害吧”\n\n　　莫清峦没有接话，但目光却落到了林风那边，那只黑狗寸步不离的跟着那个男人，如今已经模样大变，体型高大，神俊异常。\n\n　　“那狗在她们车队一个星期，就是一只普通黑狗，结果他一带走，就觉醒了能力，这金光一罩，诡异都不敢靠近，这什么运气？”\n\n　　“真是人比人，气死人，早知道就不能让他那么轻易的得到。”\n\n　　“还有，清峦姐，你看那只大乌龟，那么大一只，能跑，能扛，能打，能住人，这简直就是移动堡垒。”\n\n　　莫清峦继续沉默，只是目光停在一楼储物间里，那里火苗攒动，几个人影在那里忙碌，看轮廓，都是女人。\n\n　　显然，米雪也看到了。\n\n　　她盯着看了几秒，然后呸了一声。\n\n　　“这个渣男？”\n\n　　莫清峦看了她一眼：“你骂谁？”\n\n　　“还能是谁？”米雪朝那龟背上的石头房子抬了抬下巴：“你没看见那几个女人，我之前就注意到了，4个小姑娘，一个个水灵灵的，刚才剧组里的那几个女的还在那议论呢，应该是听到中午他说的话了，说啥“只要漂亮的……”我看啊，她们估计是想往他跟前凑？”\n\n　　莫清峦嘴角微微弯了一下，想笑但是忍住了。\n\n　　“你笑什么？”米雪瞪她。\n\n　　莫清峦的语气慢悠悠的：“我在想，你骂他渣男，是因为他真的渣，还是因为……他身边的女人，不是你呢？”\n\n　　米雪脸一下子红了，也不知道是火烤的，还是被说中了什么，抄起手里的树枝就朝莫清峦扔过去，莫清峦侧身躲过去。\n\n　　“你瞎说什么？”\n\n　　“我什么都没说，你急了？”\n\n　　米雪看着莫清峦脸上那似笑非笑的表情，想反驳，最后哼了一声，扭头看向别处，不说话了。\n\n　　但眼角的余光还是瞟向那个石头房子，她们是在做饭吧，肚子好饿……\n\n　　剧组那边，篝火旁围着一群年轻女孩。\n\n　　都是二十出头的小演员，有几个在蓝星的时候，还演过几个小角色，模样都不差，她们挤在一起。\n\n　　“你们看到了吗？那个觉醒者，好像是叫林风。”一个短发女孩压低声音说道，眼睛里亮晶晶的。\n\n　　旁边一个长卷发的女孩接话：“看到了，他刚才从那个大乌龟身上下来，身边还带着一只黑狗，个子挺高，长得不错，不比那些流量明星长得差。”\n\n　　“何止不错，”另外一个女孩凑过来，“你们没有注意到吗？他身上干干净净的，跟咱们这些落汤鸡比起来，简直像两个世界的人……”\n\n　　“你们闻到什么味道没？”\n\n　　几个女孩同时吸了吸鼻子。\n\n　　空气中有一股淡淡的肉香，从那只乌龟背上的房子里飘出来。\n\n　　“他有吃的！还有房子住，还有能力保护自己……跟了这样的人，至少不用饿肚子吧……”其中一个身材高挑的女孩小声地说：\n\n　　“我去一趟洗手间。”\n\n　　“苏婉，这荒郊野岭的，哪来的洗手间？”那个短发女孩明知故问地说道。\n\n　　“那边，岩壁后面。”她胡乱地指了一个方向。\n\n　　但她走的方向，明明是那只巨龟的位置。\n\n　　另外几个女人看着她走远的背影，又低头看了看自己，衣服湿了大半，还散发着一股难闻的味道，犹豫了几秒，最终还是没有站起来。\n\n　　“我们先看看……”\n\n　　林风对此一无所知，他此刻站在小玄身后，看着它用那锋利的前爪，对着崖壁挖掘，它那利爪切入岩石，像是切豆腐一样，大块大块的红褐色石头被扒拉下来。\n\n　　然后它咔嚓咔嚓地把矿石嚼碎吞下去。\n\n　　林风见它今天没有刨土，反而对这石头这么感兴趣，感到有些奇怪。\n\n　　林风捡起一块碎石，石头表面是红褐色的，另外一面完全不一样，是深黑色的，反射着金属一样的质感。\n\n　　“这……这是矿？”\n\n　　林风想到小玄的食土能力，能吞噬矿物成长！\n\n　　小玄没有理林风，还在埋头猛吃，爪子如同两台挖掘机，岩壁露出越来越大的缺口，那种黑色的矿石越来越多。\n\n　　林风用意念跟小玄沟通。\n\n　　“你在吃什么？”\n\n　　“矿……好吃……长大……”\n\n　　这还真是矿？林风的眼睛一下子亮了。\n\n　　林风拍了拍小玄的龟壳。\n\n　　“你这吃货，随便找个地方停车，都能找到矿！你这运气真是无敌了。”\n\n　　林风注意到了小玄的体型，随着它吞下矿石越来越多，它的四肢变得更加粗壮了一些，上面细密的鳞片泛着一层金属般的光泽，而且体型也在慢慢变大。\n\n　　这一点从龟甲边缘就能看出来，原来是石头房子的外墙面，现在龟甲已经凸出来一小圈了。\n\n　　“哈哈，吃，多吃点，能吃多少吃多少。”\n\n　　小玄都不用林风催，完全沉浸在进食的快乐中，前爪刨得更快，缺口越来越大，此刻洞口已经能开进去一辆货车了。\n\n　　也不知道它怎么能吃这么多东西的，就像胃里有个次元空间似的，就在林风期待小玄能长多大的时候，\n\n　　小玄的动作忽然慢下来，它吞下最后一块矿石，那双大眼睛缓缓眨了一下。\n\n　　然后它趴下了，四肢收拢，脑袋缩回龟壳里，沉沉的压在地面上。\n\n　　林风的笑容凝固在脸上。\n\n　　“喂？”林风连忙上前拍了拍小玄，“你怎么了？”\n\n　　没有反应。\n\n　　林风又拍了两下：“小玄？你别吓我！”\n\n　　林风有些慌乱，忽然想到什么，连忙打开个人面板。\n\n　　面板上，小玄那一栏的状态变了。\n\n　　【御兽1：玄龟】\n\n　　（当前状态：沉睡中，沉睡能加速‘食土’能力转化效果，促进御兽快速成长，本次沉睡持续时间——8小时。）\n\n　　（注：可强制唤醒，强制唤醒将导致御兽出现虚弱状态，持续24小时。）\n\n　　林风盯着这行字看了足足十秒钟，然后长长的吐了一口气。\n\n　　“你跟我说说，”林风对着小玄自言自语，“现在是逃亡路上，外面还不知道有多少诡异在晃荡，你倒好，吃饱了就睡，也不告诉我一声，担心死我了……”\n\n　　说完还踹了小玄一脚。\n\n　　小玄纹丝不动，反而震得脚疼，龟壳里还传来一声极低的呼噜声。\n\n　　林风“……”', 2208, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (61, 13, 59, '第59章 你急了', '　　林风无奈地摇摇头，靠在小玄身边坐下来，区区8小时而已，要是小玄能长大一圈，那就太值了。\n\n　　到时候再多加两个房间，多收两个小美女，岂不美滋滋。\n\n　　就在这想着，就见到一个身影往这边走过来。\n\n　　脚步有些犹豫，像是在反复做心理建设，她的衣服被雨水打湿，那件T恤紧紧地贴在皮肤上，勾勒出一道流畅的曲线。\n\n　　这……\n\n　　林风被这极具冲击力的一幕看花了眼。\n\n　　他认出来了，白天那个高挑的女孩，模特身材，站在人群中特别扎眼，叫什么来着？苏……婉？对，苏婉。\n\n　　她走到林风面前停下来，手指绞着衣角，一副含羞带怯的模样，这是她惯用的伎俩，男人很吃这一套。\n\n　　当然林风也不例外。\n\n　　只是林风没有说话，就这样大大方方的看着她，从修长的大腿，到极具视觉冲击的腰臀比，再到那副惹人怜爱的脸。\n\n　　“林风大人，我……”\n\n　　她特意顿了一下。\n\n　　就在这时候，\n\n　　咕噜噜……\n\n　　她的脸一下子从脖子红到了耳朵尖尖，恨不得找个地缝钻进去。\n\n　　林风嘴角不由自主地弯起。\n\n　　肚子里的饥饿迫使她下定了决心，“我想跟着你……”\n\n　　“你能让我吃饱饭吗？”\n\n　　林风打量了她好一会，确实是一副好皮囊，放在蓝星，这种级别的身材长相，起码也是某种级别的人才能把玩，但在末日里，漂亮不能当饭吃。\n\n　　不过，漂亮的人确实更容易找到饭吃。\n\n　　“可以，来我这里得守我的规矩。”\n\n　　“什么规矩！”\n\n　　“听话。”\n\n　　苏婉一愣，没想到就这个？她张了张嘴，听话？这算什么规矩，但她一秒钟都没有犹豫，直接点头。\n\n　　很干脆。\n\n　　“我听话！”\n\n　　林风从小玄身边站起来，拍了拍裤子上的灰，一个翻身跳上龟背，然后站在龟背边缘上，弯下腰，朝苏婉伸出手。\n\n　　“上来吧，刚好吃饭。”\n\n　　苏婉看着那只伸向她的手，愣了一瞬，然后伸手握住林风的手，一股力气从手掌传来，她整个人被轻飘飘的拉上龟背。\n\n　　她站在龟背上，低头看了一眼地面，并不高，也就2米左右，但此时的视野完全不一样了，她忽然意识到，从这里往人群看去，那些嘈杂，饥饿，迷茫还有恐惧，忽然变得很远很远。\n\n　　林风已经走到储物间门口的平台上，回头看了她一眼：“愣着干嘛，进来。”\n\n　　苏婉连忙跟上。\n\n　　这一幕被很多人看到了。\n\n　　米雪手里的树枝‘啪’的一声折断了。\n\n　　“你看！”\n\n　　她的声音很低，但那种咬牙切齿的劲隔着老远都能感觉到。\n\n　　“清峦姐你看！那个苏婉，中午才被那个渣男调戏，我好心把她拉回来，晚上就主动送上门去了！”\n\n　　莫清峦看了一眼龟背上那个高挑的身影消失在楼梯口，又看了看米雪那张快要冒火的脸。\n\n　　“你急什么？”\n\n　　“我没……”\n\n　　“你手里的树枝断了。”\n\n　　米雪低头看了一眼，手里的树枝果然被她掰成了两节，她把树枝往火里一扔。\n\n　　“我就是看不惯，她苏婉好歹在蓝星也是公众人物，现在倒好，自己送上门去了，这跟……这跟……”\n\n　　“这跟什么？”\n\n　　米雪噎住了，半天没憋出来一个合适的词。\n\n　　“你看不惯她送上门去，还是看不惯送上门的那个人不是你？”\n\n　　米雪张了张嘴，发现确实没有什么可反驳的，每个人都有自己的选择，这在她们这个圈子里算什么？有的女演员睡遍整个剧组，只为一个角色的大有人在。\n\n　　她同样也有自己的小心思。\n\n　　“我……我只是觉得他太渣了，你看见没，他房子里已经有好几个女人了，再加上这个苏婉，五个了，不对，还有陈敏那个觉醒者，也跟他搅在一起，他当自己是什么？皇帝选妃吗？”\n\n　　莫清峦没有接话，但嘴角那抹笑意怎么都压不住。\n\n　　米雪的话音刚落，篝火那边又有动静了。\n\n　　剧组那边，那几个女人对视一眼。\n\n　　“她上去了，”短发女孩压低声音跟身边几个同伴说道，眼睛里闪着兴奋的光。\n\n　　“看到了。”\n\n　　“她成功了。”\n\n　　“嗯。”\n\n　　几人同时沉默了，然后短发女孩霍地站起来，把湿漉漉的头发往后拢了一下，露出光洁的额头，她看了一眼身边另外几个人。\n\n　　“去不去？”\n\n　　卷发的那个女人咬了咬嘴唇，站起来，声音中带着豁出去的语气：“去！”\n\n　　另外两个对视一眼，也跟着站起来，最后那个穿着古装戏服的女孩，见到同伴都去，犹豫了一下，也站了起来。\n\n　　五个人，整整齐齐的朝着那只巨龟的方向走过去。\n\n　　走近了，她们才真正感受到这只乌龟有多大，趴在地上像一座小山，龟壳的边缘比她们头顶还高。\n\n　　五个人站在小玄面前，仰着头。\n\n　　“真的好大……”卷发女人喃喃道\n\n　　“许昭，别发骚，叫人。”短发女孩推了她一把。\n\n　　叫许昭的卷发女人清了清嗓子，仰着头，喊了一声“林风哥哥~”\n\n　　林风刚把苏婉领进房间，还没有来得及跟陈敏她们介绍，就听到外面有人喊他。\n\n　　林风从锅里舀了一碗热汤，递给苏婉：“趁热喝，暖暖身子，我去看看。”\n\n　　林风走出门，看到下面站着的几个女人，问道“什么事？”\n\n　　“林风哥哥，你有吃的吗？”\n\n　　林风挑了挑眉：“有是有，但你们能付出什么代价？”\n\n　　短发女孩胆子确实不小，她仰着脸，直直地看着林风。\n\n　　“我叫徐冉，是影视学院大三学生，这次刚好在竖店城拍戏，她们是我们在剧组认识的好朋友，这个长发大波浪的女人叫许昭，这个穿古装的小美女是安歌，她们是崔爽、项蓉蓉、王珂。”\n\n　　“我们什么代价都可以，只要能让我吃饱，哪怕是你要我好朋友当陪床丫头都可以……”\n\n　　旁边几个女人纷纷点头，似乎没有听清她话里的陷阱。\n\n　　林风看了一眼面前的几人，只能说不得不感叹，娱乐圈的美女真心不少，哪怕经过几天的末日生存，还能保持不错的风采，这几人，每一个放在校园里都是校花级别，放在外面也是万里挑一的存在。\n\n　　“上来吧。”林风说：“只是房间的位置不够了，你们去楼顶。”\n\n　　短发女孩徐冉愣了一下，她原本以为能用身体换一顿饱饭就不错了，没想到，林风竟然让她们上去。', 2284, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (62, 13, 60, '第60章 招黑奴挖矿', '　　这毕竟是巨龟的背上啊，多少人想靠近都没有机会，更别说能上去，哪怕只是站一站，也算半个自己人了吧。\n\n　　“好……”她连忙点头，伸出手，生怕林风反悔。\n\n　　林风把她们全部拉上来，“你们先上去，一会我让苏婉给你们带饭。”\n\n　　徐冉她们顺着楼梯爬上楼顶，这里还摆放着一些弓箭，屋顶并不大，只有10平方，从这里能看到整个营地的全貌，篝火，车辆，人群，全部尽收眼底。\n\n　　“我们……真的上来了？”许昭小声地说道。\n\n　　“上来了。”\n\n　　几个人同时安静下来，彼此看了一眼，她们同时笑出了声，那种从心底升起的安全感油然而生，这几天死的人实在太多了。\n\n　　现在终于有了着落的安心感，比任何语言都真实。\n\n　　篝火旁，米雪已经把树枝戳成灰了。\n\n　　“你看见没？五个，又上去5个，他那屋顶上都站着5个，加上之前的苏婉，十一个了。”\n\n　　莫清峦不急不缓地说道：“米雪！”\n\n　　“干嘛？”\n\n　　“你急了！”\n\n　　米雪“……”\n\n　　米雪直接破防了，“清峦姐，你再这样我就不跟你坐一起了！”\n\n　　“那你坐哪？”\n\n　　米雪环视四周，四周全是陌生的，疲惫的幸存者，没有第二个像莫清峦这样跟她熟到吵闹的人，她最终哼了一声，给莫清峦留了一个后脑勺。\n\n　　…………\n\n　　另外一边，苏婉端着一盆饭菜上楼顶的时候，5个女演员并排坐在石墙后面，听到脚步声，短发女孩徐冉第一个转过头来，看到苏婉手里端着的盆，眼睛一下子亮了。\n\n　　“是吃的吗？”\n\n　　“嗯。”\n\n　　苏婉从小臂上挂着的袋子里取出一块塑料布铺在地上，然后才把盆放在塑料布上，盆里放着几只填满米饭的瓷碗，还有满满一大碗肉汤，碗里6块婴儿拳头大小肉块，不多不少。\n\n　　“这是……肉？”徐冉声音有些颤抖，有些不可思议。\n\n　　“地鼠肉，1级的。”苏婉蹲下来，开始给每个人分肉。\n\n　　“林风大人说，每人一块，这肉能提升我们的体质。”\n\n　　徐冉一个动了，夹起碗里的肉，咬了一口，然后眼睛睁得大大的，咀嚼的速度更快了。\n\n　　长发波浪卷的女孩许昭也动了，小口小口的吃着，动作一点也不慢。\n\n　　“这肉……吃下去后，好暖和，我好像没那么冷了，就像从肚子里往外涌热流一样。”\n\n　　“我也是……”\n\n　　“1级变异生物的肉，吃下去能增强我们体质，力气也会变得比普通人大。”\n\n　　几个女人对视一眼，加快了吃饭的速度，肉汤倒进碗里，很快见了底。\n\n　　“隔~，好饱……”\n\n　　“林风哥哥对我们太好了，还给我们1级变异生物的肉吃……”还穿着古装戏服的女孩安歌抱着膝盖，下巴搁在膝盖上，声音弱弱的，她年纪最小，这几天吃了不少苦头。\n\n　　“不仅收留我们，还给我肉吃……”\n\n　　“别说了，再说我也要哭了，你们是不知道，车队里那些猥琐男，竟然想用一个破野菜团长让我跟他睡觉，我去他……&￥……￥￥#%&****……”\n\n　　许昭说着说着，就直接骂出声来，可以想象得到她当时有多恼火。\n\n　　几人沉默了一会，然后同时笑了，现在再看到营地里那些人，一种优越感升起，剧组里的其他人还在挨饿，她们已经吃上米饭了，车队里吃野菜都要省着，她们已经吃上1级变异生物的肉了。\n\n　　她们忽然觉得，选择为什么比努力更重要了，很明显，她们的选择是末日里做的最对的一次。\n\n　　楼下，林风已经把碗里的饭扒完了，把碗往桌子上一放，站起来，陈敏和4个女孩同时抬头看向他：“怎么了？”\n\n　　“你们吃，我出去一趟，心里有事，坐不住。”\n\n　　小蕊站起来：“林风哥哥，天这么黑……”\n\n　　“没事，我就在营地内，我去找方玲说点事，”林风已经走到了门口，顿了一下，说道：\n\n　　“小蕊，一会去找红姐借个帐篷，叫楼顶那几个去洗个澡换身干净衣服……”\n\n　　小蕊点点头：“好，包在我身上。”\n\n　　等林风走远后，几女才叽叽喳喳小声说起话来，\n\n　　“林风哥哥肯定是嫌弃她们都臭了……”\n\n　　“换你一星期不洗澡，也臭了……”\n\n　　……\n\n　　林风找到方玲的时候，她正在一辆货车面前安排人从车上搬运木材下来。\n\n　　“玲姐！”\n\n　　方玲抬起头看着林风，后面还跟着那条黑狗：“你怎么来了？”\n\n　　“有个事，想麻烦你帮个忙。”\n\n　　“说吧，什么事。”\n\n　　林风指了指断崖的方向，“我的御兽发现这座断崖是一个矿山，里面有不少矿石，我想着车队里不是有很多人饿着肚子吗？我这个人心善，看不得别人受苦，想雇人挖矿，你帮我安排安排？”\n\n　　“心善？”方玲打断他，就这铁公鸡一毛不发，见死不救，别人骂他一句，都连车带人一起抽飞的样子，心善？\n\n　　“你什么时候心善了？”\n\n　　“我一直心善，就是你没有发现。”林风面不改色，继续说：“挖一百公斤矿石，换一碗稀粥，怎么样？公平吧，现在食物多珍贵啊……”\n\n　　方玲的嘴角抽了抽，上下打量林风一眼：“挖一百公斤矿石，换一碗稀粥？你这叫心善，周扒皮都没你抠门，黑，真黑……”\n\n　　林风也不尴尬，“玲姐，你就说，帮不帮我吧。”\n\n　　“帮，怎么不帮，这些人饿疯了，别说一百公斤一碗粥，两百公斤一碗他们也干，我这就让人去问。”\n\n　　她走了两步，又停下来，回头看着林风，“不过你那碗粥，得多加点水，别太稠，不然这么多人要干活的，你供不起。”\n\n　　“呃……好吧！”林风点了点头，眼神异样的看着方玲，没有想到你是这样的玲姐。\n\n　　方玲的效率确实快，不到二十分钟，消息就传遍了整个营地。\n\n　　忽然，林风想到什么，一拍脑门，怎么把这事情给忘了。', 2116, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (63, 13, 61, '第61章 一事不烦二主', '　　人有了，现在还缺挖矿的工具啊，自己真是一着急，啥都想不起来。\n\n　　林风这么急吼吼的主要原因是，他想着明天车队肯定得出发，灰雾可不会等人，小玄吞噬矿石的成长速度明显比吃土强很多倍。\n\n　　现在小玄已经沉睡，矿石就明晃晃地摆在那里，既然如此，挖了带走，在路上边走边喂小玄，岂不两全其美。\n\n　　林风找到郭逸的时候，他正蹲在自己那辆大巴车上，双手按在车身上，掌心泛着蓝色光芒，正在改造车身，他的几个兄弟姐妹，在旁边打着手电筒，搬运零件，忙得脚不沾地。\n\n　　“郭哥！”\n\n　　郭逸忙着手里的动作，头也没回：“什么事？”\n\n　　“我那御兽，发现这是一座矿山，就在断崖地下，我想雇人挖矿，但缺工具，想请你帮忙搞一批镐头和铁锹。”\n\n　　“矿山？带我去看看。”郭逸听到这话，立马停下手里的动作。\n\n　　两人一前一后地来到崖壁处，小玄还趴在那里沉睡，它旁边还散落着大大小小的矿石。\n\n　　郭逸蹲下来，捡起其上一块碎石，翻来覆去地看了看，越看越欣喜，掌心泛起一抹蓝光，几秒钟后，一小团金属从矿石中抽离出来，矿石本身失去金属成分后，变成一滩细沙。\n\n　　郭逸盯着这块金属，眼里放光：“铁矿石，纯度不低，含铁量最少在7成左右。”\n\n　　“林风，这矿石，挖出来，我要三成，你先别急着拒绝，你绝对不吃亏，我免费帮你制作工具，不是简单的工具，而是利用变异材料制作的工具。”\n\n　　“而且我改造车辆也需要材料。”\n\n　　林风心里飞快地算了一笔账，郭逸出技术，拿三成还算合理，而且利用变异生物材料制造的工具肯定比普通矿镐挖矿的效率要高。\n\n　　“行，三成就三成，成交。”\n\n　　“好，工具我帮你做，金属倒是有现成的，你去弄点地鼠利爪过来，这东西硬度极高，融合进铁里，又耐磨又锋利。”\n\n　　林风也不磨叽，转身就去找方玲，付出了10公斤大米的代价，把这次狩猎的地鼠利爪都给换了过来。\n\n　　有了材料，郭逸很快把第一批矿镐给弄了出来，林风拿起一把，刃口闪着深寒的冷光，锋利无比，铁柄结实，确实是一把趁手的好工具。\n\n　　“郭哥，谢了。”\n\n　　郭逸摆摆手，“去去去……别谢我……赶紧干活去，我还没做完呢，你小子，让你换一点，你给我全换过来，你就拿我一个人羊毛使劲薅嘛……”\n\n　　林风扛着十几把铁镐走到崖壁的时候，已经有30多个人等在那里了，稀稀拉拉的站着。\n\n　　“工具来了。”\n\n　　“这铁镐看着不错……”\n\n　　林风喊道：“过来领工具，没有领到的去郭逸那边取，拿到后赶紧过来挖矿。”\n\n　　“一人一把，用完了还回来，一百公斤换一碗粥，多挖多换，没有上限。”\n\n　　“所有人跟我来！”林风带着人来到小玄挖的那个坑洞面前。\n\n　　“就是这，挖吧。”\n\n　　一个中年男人第一个走进去，握紧了手里的矿镐，抡圆胳膊，镐头轻松凿进岩壁，崩下来一大块矿石，断口乌黑发亮。\n\n　　其他人见状各自找到自己的位置。\n\n　　咣\n\n　　咣\n\n　　咣\n\n　　林风听着矿镐凿击岩壁的声音此起彼伏的响起，心里踏实多了，明天小玄路上吃的口粮有了。\n\n　　四处看了一下，见到小蕊正蹲在一顶帐篷外面，旁边小晴她们正在烧热水。\n\n　　“小晴，小蕊，苏婉，你们几个，过来！”\n\n　　几个女孩同时抬头，小蕊开口说：“林风哥哥，什么事，我正在排队等洗澡呢，趁下雨有水……”\n\n　　“洗什么澡，过来干活！”\n\n　　“去那边煮粥，待会挖矿的人出来，要吃饭。”\n\n　　“煮粥？好的，我现在来？”小蕊一脸疑惑，但还是起身就要跟着林风走。\n\n　　“林风大人，这点小事何必麻烦她们？小蕊妹妹，你们继续……”\n\n　　只见是红姐从她那辆公交车那走过来，身后还跟着十几个姑娘，这么冷的夜晚，穿的依旧清凉。\n\n　　“我带姑娘们去帮忙，煮粥，打饭，这活我们熟，你让那几个丫头干别的去。”\n\n　　林风看了她一眼，红姐这个人，永远知道自己该出现在什么地方，于是点点头，“行，跟我来。”\n\n　　红姐朝身后一招手，十几个姑娘便跟了上来，脚步轻快，路过的人看着这一群姑娘，眼睛里全是不解。\n\n　　不知道林风把车队里的女菩萨叫过去干什么？难道是要犒劳那群挖矿的泥腿子？\n\n　　来到崖壁边上，林风选了一个相对平坦的位置，一跺脚，控土术发动，泥土在意念的控制下涌动，变形，一座灶台在几分钟内就形成。\n\n　　“郭哥，正好你来了，一事不烦二主，赶紧帮我做两个大铁锅。”\n\n　　郭逸的脚步一个踉跄，差点没站稳：“你就带着我薅是吧，我才帮你做了一百多把铁镐，你又让我做锅。”\n\n　　“顺手嘛。”林风面不改色。\n\n　　“再说挖出来的矿你是不是有三成？锅也是挖矿的配套设备嘛，你说是不是？皇帝还不差饿兵呢。”\n\n　　“哦，对了，记得再做个地秤，一会称矿石要用……”\n\n　　郭逸：“……”\n\n　　郭逸盯着林风看了好几秒，最终叹了一口气。“行行行，我做……你真是我这辈子见过最会蹬鼻子上脸的人。”\n\n　　他叫身边那几个兄弟把铁镐放地上，“都在这了，一共140把，其中有12把用的是1级地鼠的利爪，锋利度比普通的高出一大截，你可得收好了。”\n\n　　他一边说，一边利用材料把铁锅做好，跟灶台严丝合缝，最后做了一座地秤。\n\n　　“好了……”\n\n　　林风看着郭逸那张累得发白的脸，心口一热：“谢谢郭哥，放心，矿石少不了你的。”\n\n　　郭逸摆摆手，转身走了，边走边嘟囔：“真是上辈子欠你的……”\n\n　　红姐已经带姑娘们忙活起来了，也不知道她从哪里找来的木头，把火升起来，接了雨水倒进锅里。\n\n　　林风爬上小玄背上，从储物间里提出来一包50斤的大米，足够煮好几锅。\n\n　　白粥的味道很快就飘出来了，红姐握着大铁勺在锅里搅动。\n\n　　“好香……”\n\n　　“快点挖，挖够了就能喝，谁要是攒够了物资，还能挑一个姑娘解解乏。”红姐的声音在挖矿的人群中响起。\n\n　　“红姐，这可是你说的，我眼馋你家的小玫好久了……”\n\n　　“可去你的吧，小玫是我的……”\n\n　　听到男人们在那议论纷纷，引得红姐手下的姑娘一个个娇笑不已，甚至有姑娘调笑：“小玫姐姐可不便宜，没两斤大米可是连味道都闻不着，要不看看妹妹……”\n\n　　这让他们挖矿的速度更快上三分。\n\n　　在白粥和女人的诱惑下，比任何动员和鸡汤都管用。', 2393, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (64, 13, 62, '第62章 第62章 杀人威慑', '　　很快，第一个人扛着矿石出来了，是个中年人，脸上全是汗水和矿灰，他搬了几趟，放在地秤上。\n\n　　“一百零一斤，你叫什么名字？”\n\n　　“赵大勇！”\n\n　　晓丽不知道什么时候跑来了，手里拿着一个本子和一支笔：“好的，赵大勇，一百零一斤，去那边领粥吧。”\n\n　　赵大勇走到灶台前面，接过红姐递过来的碗，碗不大，但里面的粥很稠，里面还放了盐。\n\n　　林风没有听方玲的，往粥里多放了水，甚至还加了盐，都是为了让他们更有力气干活。\n\n　　营地里彻底炸锅了。\n\n　　刚才还有一些人说林风心太黑，挖一百斤才给一碗粥，觉得不如省点力气，现在闻到这股味道也坐不住了。\n\n　　“真的能换？真的给粥，不是掺水跟野菜的稀粥，是实打实的米粥！”\n\n　　“快去，领矿镐，再不去没位置了。”\n\n　　那些原本躺在车里睡觉，或者躺在篝火边打盹的人，哪怕还是莫清峦原先剧组那些好吃懒做的人，此刻纷纷站起来，往矿洞这边涌来。\n\n　　“别急别急，排队……”\n\n　　很快140把矿镐被领完了，领到工具的人，兴高采烈地冲进了矿洞，没有领到工具的，站在旁边不肯走。\n\n　　而且人群还在涌来，一个看起来大概五六十岁的人往里挤。\n\n　　“小伙子，我也能挖矿，不就是一百斤吗？我年轻的时候在矿上干过，有把子力气。”\n\n　　林风看了看地上已经分发完毕的矿镐，说：“矿镐没了，你们自己想办法，自己有工具去挖也可以，或者去找郭逸买也行，只要凑够100公斤，我就给你换粥。”\n\n　　老人点点头，挤出人群，其他人看到，也跟着去找郭逸了，林风看到这一幕笑了。\n\n　　“郭哥，别说我不仗义，这买卖不就来了嘛！”\n\n　　矿洞里的镐头声更密集了，林风看着堆积的矿石越来越多，脸上笑开了花。\n\n　　忽然看到一个矮胖的女人，一身沾满污渍的名牌，身上还挂着一根大金链子，走过来就说：“你有这么多粥，为什么不分给我们一点，大家都是幸存者，我们不应该互相帮助吗？”\n\n　　林风一愣，哪里来的煞笔。\n\n　　旁边正在称重的人，反驳了一句：“你去挖矿啊，挖一百公斤就能换一碗粥。”\n\n　　谁知道那女人听到这话，声音都拔高了八度：“凭什么啊？凭什么要我们女人去挖矿，这是男人干的活，分我们女人一点怎么了，我们就不能吃一口热乎的了？”\n\n　　周围安静了一瞬，好久都没有听到这么奇葩的言论了，莫清峦车队里还真是啥人都有。\n\n　　“莫清峦，你的人，管不管，不管我直接剁了喂诡异！”\n\n　　莫清峦原本正在火堆旁闭目养神，忽然就听到林风在喊她，睁开眼睛看向林风的方向，站起来，不紧不慢地朝这边走过来。\n\n　　米雪跟在她身后，看向林风的眼神有些不善。\n\n　　莫清峦来到林风面前，笑盈盈地，那双漂亮的眼睛仿佛会说话：“林风弟弟，你这可冤枉我了，这可不是我车队的人，连我们都是你们车队的人，你说对不对？”\n\n　　她偏头看向身边的米雪。\n\n　　米雪“哼”了一声，把脸转向别处，懒得接这个话题。\n\n　　莫清峦耸耸肩，朝林风摊摊手，“所以啊，你看着办吧，我不管。”\n\n　　林风也没想到莫清峦这么干脆，直接就放弃管这事了。\n\n　　那女人显然也没有料到莫清峦会是这个态度，脸上闪过一丝慌乱，随即强撑起一个色厉内荏的狠劲。\n\n　　“你算什么东西，你敢动我一下试试，你知道我是谁吗？……”\n\n　　“滚，给你十秒钟，滚出我的视线。”林风直接打断她的话。\n\n　　那女人愣了一秒，然后炸了。\n\n　　“你个小瘪三，你以为你是谁，要不是末日来了，你能混到今天，你这种人在蓝星连跟我提鞋都不配，你知道我老公是谁吗？一句话就能让你在圈子里混不下去……”\n\n　　女人的话越说越难听。\n\n　　林风的脸直接黑了。\n\n　　“小黑！”\n\n　　蹲在林风身边的小黑听到林风的命令后，瞬间动了。\n\n　　像一阵风一样瞬间窜到那女人面前，一张嘴，锋利的牙齿咬中她的小腿，没有任何犹豫，拖着她就往守护领域的边缘跑。\n\n　　“啊啊啊……放开我，放开，救命，杀人啦，觉醒者杀人啦……”\n\n　　她的身体被小黑拖在地上，碎石和泥浆糊了一身，双手徒劳地抠着地面，手指抓得血肉模糊也没能停下半分。\n\n　　“我错了，饶了我……饶命……”\n\n　　最后变成了绝望的哭嚎。\n\n　　小黑拖着她径直冲出领域范围，外面下着倾盆大雨，雨幕中发出让人头皮发麻的声音，没有人看清黑暗中发生了什么，尖叫的声音戛然而止。\n\n　　【进化点+1】\n\n　　林风的嘴角微微勾起。\n\n　　整个营地安静了数秒，就这样看着那只黑狗抖了抖身上的水滴，然后安安静静地重新坐回林风身边。\n\n　　原本那些有说有笑的人，此刻看向林风的眼神彻底变了，除了之前的羡慕和巴结，现在又多了几分畏惧和忌惮。\n\n　　车队里其他觉醒者虽然冷漠，但不会因为一点小事主动杀人，甚至像莫清峦和米雪这种还会主动庇护普通人，王烈他们也会接纳路上遇到的幸存者，不管出于什么目的，但表面上至少是温和的。\n\n　　营地里开始小声议论起来。\n\n　　“他……真把那个女人丢出去喂诡异了？”\n\n　　“虽然那女人讨厌，但罪不至死啊……”\n\n　　“以后离他远点。”\n\n　　林风对这些充耳不闻，转身看向红姐，语气恢复了正常。\n\n　　“红姐，锅里的粥，你跟手下的姑娘随便吃，不能让你们白忙活，把事情给我安排好，别出乱子。”\n\n　　红姐目睹了全过程，那双狐媚的眼睛在林风脸上停了两秒，然后笑了，末日里就要这样的男人才能镇得住场子，她觉得自己的选择没有错。\n\n　　“你放心，我带姑娘们谢谢你。”她转头招呼手下，声音恢复了干练：“都听见了，粥管够，抓紧干活。”\n\n　　林风转身要走，后面传来莫清峦的声音：\n\n　　“林风，等等！”', 2160, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (65, 13, 63, '第63章 小玄苏醒', '　　林风停下脚步，回头看着她：“干嘛，我要睡觉去了，你要跟我一起去？”\n\n　　莫清峦还没开口，旁边的米雪先炸了，“你想得美，你个渣男。”\n\n　　林风无语地看了米雪一眼，这妮子吃炸药了？\n\n　　懒得理她，直接问莫清峦：“什么事？”\n\n　　莫清峦沉默了两秒，还是开口说道：“我想用剩下那只地鼠肉跟你换一些米熬粥，跟我来的那一百多人，食物已经耗尽了，总不能看着他们饿死？”\n\n　　林风看了看她，又看了看她身后那些围在火堆边烤火的那些人，对比矿洞里那些忙得热火朝天的人，她身后的，不是在聊天，就是在理直气壮地躺着，等着分配食物。\n\n　　“你管得过来吗？你看着他们？”林风指着正在卖力挖矿，过秤，换取白粥，自己舍不得吃，把粥给身边的妻儿。\n\n　　“你再看看跟着你的那些人？全是在抱怨雨什么时候停，抱怨肚子饿，有几个人站起来了？我的粥就摆在这里，只会眼巴巴的望着，等着？”\n\n　　莫清峦的目光在那群人身上停了几秒，嘴角的笑意淡了几分。\n\n　　“那些都给各个剧组的演员，导演……”米雪在旁边冷笑一声：“还有某总，某投资人，某大佬的太太，一堆养尊处优的主，你让他们挖矿，比杀了他们还难受。”\n\n　　“你想跟我换米，我只能说，没有，我的物资就算喂狗，也不会给他们吃，你手底下的那些人，什么样子的，你心里没数？”\n\n　　“不过！”林风话锋一转，目光在莫清峦那热火的身上和米雪那充满异域风情的脸上停留了一下：“我对你和米雪挺感兴趣的。”\n\n　　莫清峦：“……”\n\n　　米雪的耳朵尖红了。\n\n　　“活不下去了，可以来找我，别的不说，喂饱你们两个还是没问题的。”\n\n　　林风说完这句话，转身就走，连反驳的机会都没有留给她们，迈步走向小玄，一个翻身跃上了龟背上，朝着下面喊了一声。\n\n　　“小晴，跟我上来！”\n\n　　小晴正在帮着称重记录，听到这一嗓子，手里的笔差点掉地上，她看了看旁边的小玉和晓丽，脸刷的一下红了。\n\n　　小玉推了她一把：大人叫你，快去呀！\n\n　　“我……我这还在记账……”\n\n　　“我来记！”小玉一把抢过她手里的笔和本子：“快去，快去，别让大人等。”\n\n　　小晴低着头往楼梯那边走，她的心扑通扑通跳个不停。\n\n　　米雪看着这一幕，撇了撇嘴。\n\n　　“这个渣男，想得美，还想养我们两个，做梦，我就是饿死，也不会出卖自己。”\n\n　　莫清峦在她旁边站着，没有说话，目光在那个巨龟背上的石头房子上停留了几秒，然后收了回来。\n\n　　又把视线转移到篝火旁边那群无所事事的人身上，她沉默了好一会，仿佛下定了某种决心\n\n　　“米雪！”\n\n　　“干嘛？”\n\n　　“去跟王姐说一下，让她通知我们原车队那些人，从明天开始我们不管了……”\n\n　　米雪愣了一下：“你是说……？”\n\n　　“让他们以后自力更生，我已经不是车队队长了，我也管够了……”\n\n　　米雪看着莫清峦的脸，那双眼睛里有一种很久没有见过的光芒，点头应了一声：\n\n　　“早就该这样了，我们凭什么养一群蛀虫！”\n\n　　她走向王姐的方向，脚步都轻快了几分。\n\n　　二楼房间里，小晴低着头，手指绞着衣角，“大……大人，叫我上来什么事？”\n\n　　“过来……”\n\n　　卸甲\n\n　　小晴确实是4个女孩中最高的，而且骨架纤细，腰胯的弧线惊人，尤其是那一双笔直的大长腿，真应了那句话，胸以下全是腿，而且韧性极强。\n\n　　一字马对她而言轻而易举，林风一时没忍住，翻来覆去……\n\n　　wan了个遍\n\n　　……\n\n　　矿洞叮叮当当的声音不绝于耳，干了一整夜的人开始休息，营地内安静了许多。\n\n　　林风半睡半醒间，感觉房门被打开了，床垫往下陷了一些，然后有人靠在林风身边。\n\n　　林风下意识地把对方揽进怀里。\n\n　　“还没睡呢？”陈敏的声音在黑暗中响起。\n\n　　“嗯，怎么了？”林风感觉到对方身上的凉意，把被子往对方身上扯了扯。\n\n　　“我刚才去了雨桐的车里，她说雨最近两天不会停。”\n\n　　林风紧了紧双手，感受着惊人的弹性：“所以呢？”\n\n　　“所以队长决定，安排所有人挖矿，要彻底改造大巴车。”\n\n　　“那些小车也好，面包车也罢，在这样的路上根本走不了，这个世界连条像样的路都没有，底盘太低，一下雨，就彻底陷进去，根本出不来，队长说与其在路上抛锚，不如现在废物利用，直接拆了改装成装甲大巴车。”\n\n　　“那就拆呗。”林风打了一个哈欠：“难道有什么问题？”\n\n　　陈敏把头靠在林风的臂弯上，吐气如兰。\n\n　　“这意味着要多停一天，灰雾不等人，补给也在消耗，车队里的人没东西吃，哪有力气挖矿。”\n\n　　林风困得不行，反正自己的食物够用：“明天的事明天再说，睡觉。”\n\n　　陈敏见林风无精打采的样子，“嗯”了一声，给林风整了整被子，同样也闭上了眼睛。\n\n　　房间里彻底安静下来，只能听见几人的呼吸声，还有崖壁矿洞那边偶尔传来的矿镐声。\n\n　　……\n\n　　不知过了多久，林风被一阵沉闷的震动声惊醒，一下子睁开了眼睛。\n\n　　林风把陈敏的手挪开，坐起来。\n\n　　“嗯~”陈敏迷糊地哼了一声：“几点了？”\n\n　　“不知道，小玄醒了，我下去看看。”\n\n　　陈敏眼睛还没睁开，但身体已经跟着坐起来，被子从肩膀滑落……\n\n　　“我也去。”\n\n　　“你睡你的，又不急。”\n\n　　“不，我也要去……”陈敏打了个哈欠，揉了揉眼睛，语气里带着一丝刚睡醒的慵懒和娇憨。\n\n　　林风也没有想到陈敏还有这么娇憨的一面，真是御姐卖萌，谁也顶不住。\n\n　　两人穿好衣服，推开门，刚走到楼梯口，就听见外面传来小蕊的惊呼声。\n\n　　“天啦……林风哥哥，你快下来看，大乌龟变得好大啊！”\n\n　　林风发现原来10平方的房子矗立在龟背中间，现在龟背的面积足足翻了一倍有余。\n\n　　小蕊站在龟壳下面仰着头，她现在整个人还没有一只龟掌大，她跳着脚往上面挥手。\n\n　　“林风哥哥，大乌龟好高啊！我都上不去了！”', 2243, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (66, 13, 64, '第64章 体型翻倍', '　　林风低头看了一眼地面，确实高了不少，现在目测至少3米。\n\n　　他翻身一跃，从龟背上跳下来，陈敏也跟着跳下来。\n\n　　周围的空地上围了不少人。\n\n　　包括还在矿洞里干活的人听到动静，纷纷放下手里的矿镐跑出来看，一个个仰着头看着小玄，嘴巴张得能塞进一个鸡蛋。\n\n　　“这……这比昨晚大了一倍啊？”\n\n　　“何止一倍，这还是没站起来，一晚上就长大这么多，再长下去还得了。”\n\n　　人群议论纷纷，站在最前面那几个人，林风一眼就看到了。\n\n　　王烈站在最前面，仰头看着小玄的体型，方玲在旁边，手里还拿着个本子，在那里记录着什么？\n\n　　就连从不下车的沈雨桐此刻都来了，她的目光落在小玄身上，难得的露出好奇的目光，嘴巴微微动了一下，像是在自言自语。\n\n　　王烈看到林风后，连忙上前问道：“你这御兽，还能长多大？”\n\n　　林风摊了摊手：“我也不知道啊。”\n\n　　你问我，我问谁去？\n\n　　“它吃矿石就能长，我倒是希望它越大越好，这样我的房子就能盖大一点了，然后种点花草。”\n\n　　王烈：“越大越好？”\n\n　　“当然，”林风带着理直气壮的语气继续说道：“我这个人心善，现在是末日，全民都穿越过来了，朝不保夕的了，我见不得美好的事物陨落，当然是越大越好，到时候方便我收集美女……”\n\n　　“……”\n\n　　王烈的嘴角抽了抽，看到林风那副理直气壮的样子，又看了看他身边的陈敏，意思是，你不管管。\n\n　　陈敏却是一副“他就是这样子的人，我能有什么办法？”的表情。\n\n　　王烈那叫一个无语，在心里过了一遍车队觉醒者的情况，越想嘴角越抽抽。\n\n　　董雨是个拉拉，还有施虐倾向，看看她车里的女人，都被她折磨得不成样子了。\n\n　　江声？江声更离谱，他对女人完全没兴趣，他那车里堆了一堆成年人用品，明明车队里女人不少，偏偏是一个恋物癖。\n\n　　郭逸？郭逸就不说了，车里十几个人，基本都是猛男，干活倒是利索，一个女人没有，反正他对外说都是亲戚，是“堂兄弟”“表兄弟”，好吧，他兄弟真多。\n\n　　陈敏……陈敏以前是最让王烈头疼的，琢磨不透的性子，加上神秘的精神能力，招惹到她的人死状极惨，车队里没人敢招惹她，现在倒是好了，被林风收了后，安安静静的，眼神柔和平静，像一头终于被抚顺了毛的猫。\n\n　　沈雨桐？越来越不爱说话算不算。\n\n　　王烈又想到自己。\n\n　　他咳嗽了一声，把这些乱七八糟的念头压下去，把话题拉回正事上。\n\n　　“林风，你这乌龟继续成长下去，体型只会越来越大，是不是可以带上一部分幸存者？”\n\n　　林风听到这话，当即脸色变了：“不行？”\n\n　　王烈愣了，不解地问道：“为什么不行”\n\n　　“我的御兽，除了女人，谁也不许上，除非是太监！”林风一副这事没得商量的样子。\n\n　　王烈“……”\n\n　　方玲忍不住开口：“林风，你这也太……”\n\n　　“玲姐你别劝我，我的御兽我做主，你要是想上来，随时欢迎，至于说这事，免谈……”\n\n　　王烈揉了揉太阳穴，深深地叹了一口气。\n\n　　“行吧，今天的安排是这样的，雨桐说这雨一时半会停不了，我打算利用这一天的时间，让所有人参与挖矿，配合郭逸改造车辆，小型车辆根本无法通行，昨天丢了三十多辆，不能再这样下去了。”\n\n　　林风点点头：“挖矿没问题，我还能吩咐小玄帮忙，一个能抵百人。”\n\n　　王烈看了一眼小玄的体型，点了点头。\n\n　　“行，那就这样安排，争取今天多挖一些出来，我和方玲去跟那些车主商议。”\n\n　　王烈带着方玲和郭逸他们，在营地里走了一圈。\n\n　　“各位，听说我两句？”王烈的声音清晰传遍整个营地。\n\n　　“这雨一时半会停不了，今天我们要多停一天，趁这个时间，我打算改造一批大型车辆，把能用的材料都集中起来，提升越野能力，接下来的路程中，小型车辆已经撑不住了，如果你们愿意拆解车辆提供零件，可以优先安排乘坐改装后的车。”\n\n　　人群里议论纷纷。\n\n　　“要拆我们的车？”\n\n　　大部分车主思考了一会，都同意了，没有人是傻子，昨天路上抛锚了几十辆，那些困在泥坑里的轿车就是一堆废铁，与其等着自己的车变成那样，不如现在拆了换一个上车的资格。\n\n　　但也有一些人抱着侥幸心理。\n\n　　“我再等等，我这车底盘高，能走，再说了，跟几十号人挤一块？熏也熏死了。”一个身上带着金链子的男人不愿意放弃现在的生活，他这车是一辆悍马，车上还有两个小美伺候他，自然不太愿意。\n\n　　王烈也没管他，这事全凭自愿。\n\n　　莫清峦那边的情况更棘手。\n\n　　莫清峦站在他们面前，劝说道。\n\n　　“这三辆旅游大巴需要改装，需要矿石，大家都去帮忙挖矿和搬运，干活的人能分到一碗野菜粥。”\n\n　　“清峦姐。”一个打扮精致的女人缩在火堆旁，声音矫揉造作。\n\n　　“我们怎么能去干那种粗活，你看那些挖矿的人，满身都是灰，又脏又累，我们好歹是明星，在蓝星的时候……”\n\n　　“蓝星已经没了。”莫清峦打断她。\n\n　　那女人眼眶开始泛红，眼泪说掉就掉，不愧是专业的，周围的人七嘴八舌地议论着。\n\n　　“青峦姐你变了。”\n\n　　“你以前不这样……”\n\n　　当然也不全是这样的人，有一些不是剧组的人，站起身，脸上的表情跟那些或躺或坐的演员不一样，那是认清了现实，知道现在这个车队不会白白养他们的觉悟。\n\n　　“清峦姐，我们去挖矿。”\n\n　　莫清峦点点头：“去吧，去找郭逸领工具，队长他们已经组织人在煮野菜粥了。”\n\n　　莫清峦看着大部分还是没有丝毫动作，再次开口：“大家听我说……”\n\n　　她话还没说完，就被人打断。\n\n　　“清峦姐，你又不是不知道，我们这些人哪里干过这种活，要不你去跟那个林风说说，分我们一碗粥啊，哪怕半碗也行。”\n\n　　“是啊，青峦姐，你可是大明星，看在你的面子上他肯定愿意给的。”他们说话的语气仿佛理所应当一样。\n\n　　“你看那个谁，苏婉，以前跟我们一个剧组的，现在不是在他那好吃好喝的，她也没去挖矿啊，她凭什么有吃的，我们要饿肚子？”\n\n　　“人家漂亮呗，长得好看就是本事，你长那样也想吃上！”\n\n　　“我要是长那样，我也去他床上躺着，还挖什么矿？”\n\n　　“哈哈哈……”笑声从人群中响起。', 2361, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (67, 13, 65, '第65章 你现在变傻了', '　　莫清峦看着面前这一群人，想说什么，最后什么也没说，她的保镖王姐脸色已经很难看了，恨不得冲上去给这群人光晃两拳……\n\n　　米雪忍不住了，她扒开人群，挤到最前面，快步跑到莫清峦身边，一把拉着她手腕。\n\n　　“你在这干什么？你跟他们说有什么用，他们根本不会动的，你看看他们那样子，是能商量的人吗？”\n\n　　米雪把莫清峦从人群中拽走，走了十几米远后，用恨铁不成钢的语气说：“清峦姐，你以前谈合同的时候可不是这个样子的，那时候谁敢跟你讨价还价？你往那桌子上一拍，人家大气都不敢喘一下，剧组里的那些人哪个敢这样跟你说话。”\n\n　　“清峦姐，你的精明能干呢？我发现你现在变傻了！”\n\n　　莫清峦愣了一下。\n\n　　“我只是觉得……末日了，能救一个是一个。”\n\n　　米雪看着她，眼神软了一下，拉着她继续走，边走边说：“你先别管了，让王姐去说吧，你越说话，他们觉得你越好说话，这些人不是能说得动的，得让他们自己活出道理来，人教人教不会……”\n\n　　“你管不了所有人，他们自己不想活，你拉不动，就别拉了，别把自己搭进去。”\n\n　　“知道了……”\n\n　　黎明到来。\n\n　　车队里动员了所有能动员的人，挖矿的挖矿，搬运的开始搬运，后勤的大妈们，把车上的野菜一袋袋搬下来。\n\n　　林风和郭逸两人还被叫去做了几个灶台和大铁锅，野菜混合着米面煮粥一锅锅稀粥，分发给所有干活的人。\n\n　　虽然难吃，但也能填饱肚子。\n\n　　轰……\n\n　　一声巨响从崖壁传来，小玄醒了后，被林风指挥着开始挖矿，它的前爪比昨晚更大了，每一爪下去都能刨开一大片岩壁，把整块的铁矿山扒拉下来。\n\n　　效率比昨晚一百多人干一整夜的效率还要高。\n\n　　短短一个小时，就堆起小山般的矿堆。\n\n　　林风站在一旁，看着那堆矿石，又看了看远离小玄挖矿的那些人，还有那些凑够了100公斤正在领粥的人，心里的算盘打得劈啪作响。\n\n　　“我是不是亏了？”\n\n　　“什么亏了？”一个声音从身后传来，吓了林风一跳。\n\n　　林风猛地转身，看到一个身影就在自己半米开外，莫清峦不知道什么时候来到了他身前，近到能闻到她身上的香水味：“你走路没声音的吗？”\n\n　　“你刚才在说什么亏了？”\n\n　　“我在算账。”林风指了指地上的小玄挖的那堆矿石，又指了指另外一堆，“你看，他们一百多人，挖了一整晚，挖出这么一点……”\n\n　　林风用手比划了一下。\n\n　　“他们挖那么一点，我那米粥换出去不少吧，结果我家小玄干一小时，抵他们一晚上，你说……我是不是亏了？”\n\n　　莫清峦看着那堆矿石，又看了看在崖壁挖矿的那些人，只能幽幽地说一句：“末日里，都是蓝星人类，能救一个是一个吧。”\n\n　　林风转过头，用一种奇异的目光，在她身上上下打量，最后停在她胸前。\n\n　　“啧啧啧……没有想到，你这奶妈，还挺圣母。”\n\n　　莫清峦顺着他目光低头，看不到脚尖，忽然想到什么，然后腾的一下脸红了。\n\n　　她也玩游戏，自然知道“奶妈”是什么意思，只是林风这个语气，这表情，“奶妈”两个字从他嘴里说出来那个微妙的重音，让她有些抓狂，同时还伴随着久违的害羞情绪。\n\n　　“你……”\n\n　　林风摆摆手，不继续调戏她，换了个话题：“你跑过来干什么?不在那边盯着那群大爷小姐了？”\n\n　　“我把自己那辆埃尔法交给队长了，拆了拿去改装大巴车。”\n\n　　林风的眼睛亮了。\n\n　　“那你不是没有载具了？”林风咧嘴一笑。“来我这怎么样？小玄背上大得很，多你一个不多。”\n\n　　“你想得美！”\n\n　　莫清峦还没说话，米雪的声音就传来，她快步走到莫清峦身前，挡住林风的视线，双手叉腰，瞪着眼睛看着林风：“队长说了，改装完，给我们一辆改装大巴车，谁稀罕去你那？”\n\n　　林风看着她那副护犊子的架势，又看了一眼她身后的莫清峦，莫清峦似乎想说什么，但米雪挡在面前，她张了张嘴，又闭上了，表情有些复杂。\n\n　　林风本来就是随口一提，但热巴这小妮子天天跟他作对。\n\n　　“米雪，你这小妮子，天天跟我作对，小心我给你吊起来打，屁股都打肿，你信不信？”\n\n　　米雪的脸一下子红了，下意识地伸手捂住后面，往后跳了一步，瞪着他：“你敢？”\n\n　　“你看我敢不敢！”\n\n　　“清峦姐你看她！”\n\n　　莫清峦看着米雪那副炸毛的样子，又看了看林风那副“你能拿我怎样”的表情，嘴角终于忍不住弯了一下。\n\n　　她上前一步把米雪拉到身后，朝林风笑了笑。\n\n　　“林风弟弟，你别逗她了，她不经逗。”\n\n　　林风看了米雪那副气鼓鼓的样子，得意地哼了一声：“行，看在你的面子上。”\n\n　　米雪：“……”\n\n　　林风没有再理她，转身对小玄喊了一声：“小玄，继续挖，今天能吃多少吃多少，就是别睡着了。”\n\n　　小玄发出一声低沉的声音，像是在回应林风。\n\n　　轰隆一声，又一片矿石滚落下来，小玄低头叼起最大的几块，咔嚓咔嚓嚼碎吞下去，然后继续挖。\n\n　　每一抓都能刨开大块矿石，林风慢慢地注意到，小玄的速度变慢了。\n\n　　起初还没在意，但在十分钟后，小玄的动作明显慢了一大截，到后面干脆不挖了，就趴在那堆矿石边慢吞吞地叼起一块矿石，嚼半天，才咽下去。\n\n　　林风站在不远处，看着小玄那副昏昏欲睡的模样，皱了皱眉。\n\n　　用意念沟通小玄，结果传来的情绪很清晰：“饱了……不想动……消化……”\n\n　　林风明白了，它吃了太多矿石，身体需要消化吸收。\n\n　　莫清峦走到林风旁边说：“你看，你的御兽虽然厉害，但还是需要人来挖矿的……”\n\n　　林风偏过头看了她一眼：“你想说什么？”', 2129, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (68, 13, 66, '第66章 原来你是这样的清峦', '　　莫清峦没有急着回答，看了看矿洞里那些挥汗如雨的人，慢悠悠地说道：“你的御兽体型在不停地变大，以后它越长越大，等它的龟壳成长到能建起城堡的时候，让它自己去挖矿明显不合适，你看看它现在这个体型，还能往矿洞里钻吗？”\n\n　　林风顺着她的话想了想，确实，小玄现在的体型比昨晚大了一倍，等它再长大几圈，到时候挖矿这活，还真得靠人。\n\n　　莫清峦看他没有反驳，继续说：“你想啊，你的御兽吃矿石长得快，但矿石总得有人挖出来摆在它嘴边才行，你养一支矿工队，他们挖矿，你的御兽吃，两不耽误，你该干嘛干嘛。”\n\n　　“还有，”莫清峦越说越顺，“而且如果矿工队的人越多，效率越高，你把那些闲散的人组织起来，给他们一口饭吃，他们帮你干活，御兽成长的速度更快，还能保护车队，大家的生存几率都高了，一举多得。”\n\n　　莫清峦开始从多个方面给林风说着各种好处，画大饼，林风听得直点头。\n\n　　莫清峦越说越兴奋，“你看，这样一来，车队安全了，你的御兽也长大了，它的背上能搭载更多人，这样大家……”\n\n　　“不行！”\n\n　　林风猛地惊醒，手从下巴上放下来，整个人像从美梦中被人泼了一盆冷水，瞬间清醒了。\n\n　　莫清峦愣住了：“为什么不行？”\n\n　　“前面你说的，我觉得有道理，但是最后一句，想都别想。你想上来我随时欢迎，别人免谈。我这御兽，除了女人，谁也不能上……”\n\n　　“可是如果车队需要……”\n\n　　“车队需要是车队的事，我这御兽是我的事。”林风斩钉截铁地打断她的话。\n\n　　“不过你说的确实有道理，不能让小玄事事亲为，找一群人专门给他挖矿喂养，确实是个好主意。”\n\n　　莫清峦看着他，眼神复杂，似乎想再劝林风两句，但是看到林风那副“你再提这事我跟你翻脸”的表情，最后还是没有把话说出口。\n\n　　“那矿工队的事，你想怎么弄？”\n\n　　林风摸着下巴想了想：“人肯定不缺，不说车队里就有四五百人，而且目前穿越还没多少天，随时会遇到其他车队的人，愿意下力气换口吃的的人大有人在，毕竟不是人人都是你们车队里的那些蠢货。”\n\n　　莫清峦：“……”\n\n　　林风想了想，说出自己心里的看法：“我只是觉得矿石这东西不是每次都能遇到，我组建挖矿队后，要是没矿可挖，总不能白白养着他们吧，还有怎么防止人偷奸耍滑。”\n\n　　林风从不怀疑人的劣根性，一旦他们以为傍上觉醒者的大腿后，那就是另外一个样子了。\n\n　　“这有什么难的？”旁边的米雪突然插嘴了，语气里带着一副很懂的傲娇。\n\n　　“分组就行啊，几个人一组，完成了有饭吃，完不成全组受罚，扣口粮就行，挖得多的，多给点奖励，我以前拍综艺的时候，看节目组就是这么管群演的，好用的很。”\n\n　　林风和莫清峦同时转头看着她。\n\n　　米雪被两个人盯着，“你们看着我干嘛？我说的不对吗？”\n\n　　“说的对，”林风难得地夸奖了她一句，“你总算说对了一句人话。”\n\n　　“你……”米雪又想炸毛，但林风已经转过头不理她了。\n\n　　“还有，队长分给我的车，可以搭载愿意加入矿工队的人，平时让他们自己去找物资，如果他们真的没有口粮了，我们只需要一天提供一顿基础食物，保证饿不死就行……”\n\n　　莫清峦说完这话发现林风和米雪都一眨不眨的盯着她。\n\n　　“没有想到你是这样的清峦，我还以为你是圣母呢！”\n\n　　“哪有，我只是觉得，每个人少吃点，节省下来的食物，就能让更多人活下去……”莫清峦越说越小声。\n\n　　“哈哈，好，就按你说的办……”林风忽然觉得不愧是清峦老板，甚合他心意，只要没饿死，关键时刻就是一个劳动力。\n\n　　不提林风与莫清峦之间商量接下来组建矿工队的事。\n\n　　从黎明到中午，从中午到夜晚，整个断崖下变成了一座热火朝天的矿场。\n\n　　为了提升大家的积极性，车队里的觉醒者也是大放血，把储备的食物混合野菜煮出一锅又一锅粥，只要来干活的，都可以去找郭逸领工具。\n\n　　然后来吃上一碗不算好吃，但是能饱腹的野菜粥。\n\n　　后勤的那几个大妈根本忙不过来，红姐带着姑娘们也不营业了，忙得脚不沾地的为大家分粥。\n\n　　无论男的女的几乎都在忙碌，要么挖矿，要么搬运矿石。\n\n　　最忙的还是郭逸那边，他那十几个兄弟，把那些小型车的汽油抽出来，然后就开始拆卸，把能用的轮胎、电瓶、零件全部一样一样的拆下来。\n\n　　郭逸本人则蹲在送来的矿石边把金属成分抽离出来，然后在他的操控下，这些金属和材料，开始塑形，焊接，改造。\n\n　　原本只是普通的大巴车，就像是变魔法一样，一点一点变样。从轮胎开始，金属混合橡胶制成的轮胎首先成型，每一个都足有一人多高。\n\n　　然后是车身的底盘结构，加粗加厚，紧接着是发动机改造，为了配上这么庞大的车体，发动机被郭逸重点改造，还加装了油电混合动力。\n\n　　最后就是车体，车体就随便多了，里面的座位更是五花八门，从其他车上拆下来的座位，就这样硬生生地焊接上去，也不管美观不美观，主打一个性价比，能载人就行。\n\n　　最后一辆车车身变成3米多宽、15米长，俨然一个庞然大物彻底成型。\n\n　　“行了。”郭逸拍了拍身上的灰尘，“完工。”\n\n　　他跳上驾驶座，拧动钥匙，发动机发出一阵低沉的轰鸣声，挂挡，踩油门，这辆钢铁巨兽缓缓启动，灵活转弯，冲进雨幕后，很快返回。\n\n　　“好！”旁边围观的人忍不住叫了一声好，有这车，安全性大大提升啊，再也不怕掉队了。\n\n　　郭逸熄火下车，在车身上拍了拍。“争取在天亮前多改装几辆。”\n\n　　消息传开后，那些原本还在观望的车主彻底坐不住了，这大家伙可比他们身下的小破车安全多了。\n\n　　纷纷说愿意把自己的车拆了，只求改装后能分到一个位置，郭逸来则不惧，反正材料越多，改装得越结实，他回头去找王烈要诡晶的时候也理直气壮。\n\n　　下次跟他要3级诡晶突破3级的时候，也更好开口，不用像这次一样，火烧眉毛了，他才抠抠搜搜地给1颗2级诡晶让自己突破等级。\n\n　　林风这边也没有闲着。', 2301, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (69, 13, 67, '第67章 改造房间', '　　小玄的背甲已经成长到四十多平，原先的石头房子只占了中心的一小块，周围多出一大片空旷的位置。\n\n　　林风通过意念沟通小玄，让它开始干活，\n\n　　把10平方的小屋子，直接扩建成40平，一楼的储物间和厨房分开，比原先宽敞很多，上楼梯的平台那边制作了一个软梯放下去，免得又出现小蕊她们有家不能回的尴尬情况。\n\n　　二楼，林风犹豫了片刻，还是没有分成两个，直接扩大成40平的卧室，里面隔出来一个10平方的卫生间，浴缸、马桶、洗漱台、热水器一应俱全。\n\n　　还特意从车队里找人换了一块镜子安装在洗漱台上，虽然都是石头做的，但林风利用控土术制作得光滑无比，不知道还以为是贴的瓷砖。\n\n　　当然一张超级大床是免不了的，睡个七八人还有余，大被同眠的小心思不言而喻。\n\n　　小玄头部位置有一个推拉型的大型落地窗，从这里走出去，是一个两米宽的环形走廊，栏杆也制作得精美无比，一下子就让整个2楼的使用面积扩大不少。\n\n　　至于楼顶正中央，花了小半天时间做了一个大型蓄水池，在墙壁里开出一根根管道，连接上卫生间和一楼的厨房。\n\n　　为此林风还找到郭逸，用一块腊肉和一袋20斤大米的高价让他制作了一些配件，全套的金属洗浴配件，水龙头、花洒啥的，还有厨房里的金属柜门，大落地窗。\n\n　　当然这些肯定不值一块腊肉和大米的价值。\n\n　　林风可是不占便宜就算吃亏的主，主要是要来一套灯具系统，一个汽车电瓶改造的大型储电池，电线，灯泡，还有一块太阳能充电板。\n\n　　本来林风想多要两块太阳能板的，郭逸就是不给，说没有材料，造不出来，现在的要用在改装车上，最后软磨硬泡，答应后面找到材料后，免费帮林风多制造几块才罢休。\n\n　　这些都被林风利用控土术巧妙地安装在房子上，从此进入了电力时代，不用晚上黑灯瞎火的，摸错人都不知道，只能将错就错。\n\n　　“哇……好大啊！”\n\n　　小蕊不知道什么时候顺着软梯爬上来，一来到卧室里就看到焕然一新的房间。\n\n　　“这么大个衣柜，我能放好多漂亮的衣服了！哇！还有卫生间啊，这下再也不用出去找地方上厕所了。”\n\n　　“林风哥哥，你真厉害。”小蕊蹦蹦跳跳地来到林风身前。\n\n　　林风揉了揉对方的小脑袋，试了一下开关，卧室的灯光如他期望的那样亮起，“嗯，没有问题。”\n\n　　“正好，你叫小晴她们回来整理一下屋子，顺便做一下饭。”\n\n　　晚上8点，天彻底黑透，小黑再次释放了守护领域。\n\n　　营地里的晚饭也做好了，还是米面混合着野菜煮的粥，闻着虽不诱人，反而飘着一股淡淡的苦涩味。\n\n　　但对于干了一整天重活的人来说，这一碗热粥，比什么都要实在。\n\n　　挖矿的人群纷纷放下手中的工具，拿出自己的锅碗，排着不算整齐的队伍，眼巴巴地望着大锅里的粥。\n\n　　“赵大勇，你的，下一个。”打饭的大妈手没抖，满满的一大勺野菜粥舀到赵大勇碗里。\n\n　　赵大勇端着碗，来到老婆孩子身边，把碗递过去，让她们先吃，他老婆接过碗，先给孩子喂了小半碗。\n\n　　“爸爸，你也吃！”\n\n　　赵大勇嗯了一声，两夫妻才分着吃完。\n\n　　赵大勇看着满是血泡的双手，嘴角却带着笑容，那是一家人又活了一天，对未来有了希望的笑容。\n\n　　挖矿的矿工们，三三两两的端着碗，坐在火堆旁喝着粥，低着头说话，话题从今天挖了多少矿，聊到明天车队什么时候出发，再聊到那些没有干活的人今晚吃什么。\n\n　　“吃什么？吃个屁！”有人冷笑。\n\n　　“刚才我路过那边的时候，一个个饿得肚子咕咕叫呢，一个女的在那里哭，说两天没吃饭了。”\n\n　　“活该，”一个人往嘴里塞了一口粥说道：“白天我们干活的时候，他们一个个在那里装死，这会知道饿了？”\n\n　　营地边缘，原先莫清峦车队里那些演员，经纪人，导演……还有一些沾亲带故的人员，白天动员的时候，没有参加，搬运的时候装死，在观望，觉得车队总会给他们吃的。\n\n　　但晚饭时间一到，他们发现没有人管饭了。\n\n　　有人找上王姐，声音带着哭腔：“王姐，清峦姐呢，她去哪里？我们……我们一整天没东西吃了，能不能给我们一碗粥？就一碗！”\n\n　　王姐看了她一眼，声音平淡：“想喝粥？去矿洞那边报到，挖一百公斤矿石换一碗粥。”\n\n　　“可……可我们都是女人啊，饿一天了哪有力气挖矿……”\n\n　　“哦，忘了提醒你了，清峦在替林风招募长期矿工，现在是500公斤换一碗粥，过时不候……”说完，王姐不再理她，转身走了。\n\n　　“500公斤……”那女人一下子坐在地上，埋着头哭泣。\n\n　　林风那边。\n\n　　“清峦，你定挖500公斤矿石就换一碗这种粥，你确定吗？”林风用勺子舀起一勺，稀粥，里面全是米汤，米饭只有浅浅的一层。\n\n　　眼神诧异的盯着她看，心里想的全是，清峦啊清峦，你才是真正的周扒皮吧。\n\n　　莫清峦脸不红气不喘：“你就说这是不是粥吧，你是不当家不知道柴米贵，我前几天管一百多人的时候，找不到食物的时候，一天吃的比这还少……”\n\n　　“你看看人家王烈队长，今天一个人何止才挖500斤，那粥里，啧啧……全是野菜，里面的米还没这碗多呢……”\n\n　　“再说了，你提供的那个矿镐，那锋利度，你是真不懂还是假不懂，我一个弱女子，你猜猜我今天挖了多少？”\n\n　　莫清峦竖起一根手指：“1吨！”\n\n　　“呃……”\n\n　　好吧，你是弱女子，也就力气比成年壮汉大两倍罢了，林风也没有想到自己提供的那个矿镐效率那么高，也小看了杨密竟然能吃得苦跑去挖矿。\n\n　　“行，你觉得就好，反正被骂的又不是我！”\n\n　　“哼，到时候被骂，我就说是大老板吩咐的，你说呢，林风弟弟……”\n\n　　“说不过你，走吧，我的大明星，我请你吃饭！”林风揭过这个话题，顺势邀请道，反正占便宜的是他。\n\n　　“哼，渣男，我也要去……”米雪像个跟屁虫一般跟在两人身后。', 2235, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (70, 13, 68, '第68章 这里的门永远为你们敞开', '　　莫清峦和米雪跟着林风从软梯爬上去，当她们踩在小玄背上的地面时，\n\n　　眼前的景象让她们一时有些回不过神，脚下的地面如同水磨石一样平整，里面的灯光从敞开的大门投射出来。\n\n　　林风率先走进去，莫清峦和米雪犹豫了一下，也跟着进了屋。\n\n　　一楼的格局，右边靠近小玄头颅的那间空荡荡的，堆着一小堆矿石，左边是厨房，橱柜和货架上堆着大米，面粉，腊肉，各种罐头调料，摆放得整整齐齐。\n\n　　她们见到这么多食物也狠狠地震惊了一下，她们还在饿肚子，林风就已经囤积了能吃几个月的食物，中间两张折叠桌拼凑在一起，桌子上已经摆放好了饭菜。\n\n　　两大盆肉，一盆土豆炖地鼠肉，一盆水煮鱼，还冒着热气。\n\n　　鱼肉的鲜香，和炖肉的浓香混在一起，两人的肚子不争气地叫了一声，在这安静的房间里格外清晰，她们两人的耳朵一下子红了，目光在那两盆肉上停住，小心地咽口水。\n\n　　林风看到两人的样子，心里一乐，大明星饿肚子的样子跟普通人也没什么区别嘛。\n\n　　“两位妹妹，过来坐。”陈敏语气随和，像是招待客人的女主人。\n\n　　林风正准备往两女中间的位置坐下，手刚搭在凳子上，就被陈敏在他手腕上轻轻拍了一下。\n\n　　“你坐那边去，别挡着我和两位妹妹说话。”\n\n　　林风看了看陈敏，又看了看掩嘴偷笑的莫清峦和米雪，委屈巴巴的“哦”了一声，绕到桌子的另外一边坐下，小蕊她们还在灶台边站着，不敢过来。\n\n　　“站着干嘛，过来坐！”林风拍了拍两侧的凳子，招呼道。\n\n　　小蕊看了陈敏她们一眼，犹豫了一下，拉着晓丽她们在林风两边坐下来。\n\n　　陈敏坐在莫清峦旁边，给她和米雪一人夹了一块肉：“别客气，吃菜，就当自己家一样，清峦妹妹，我听说你今天跑去挖矿了，一下午挖了两吨？”\n\n　　莫清峦愣了一下：“没了那么多，只有一吨多点，敏姐，你怎么知道的？”\n\n　　“整个营地都在传，”陈敏笑了笑，“那些挖矿的人都看傻了，说你两小时挖的比他们一天都多。”\n\n　　“没有啦……主要是那个工具好用。”\n\n　　“那也够厉害的。”陈敏又给她夹了一块鱼肉，“先吃东西，边吃边聊。”\n\n　　鱼肉入口的瞬间，莫清峦只感觉这是她末日里吃过最好的东西，这一刻才感觉到原来能吃饱是多么幸福的一件事。\n\n　　莫清峦好歹吃得克制一点，米雪的动作就豪迈很多，嘴里还在嚼着，筷子已经伸向那盆土豆炖肉。\n\n　　“慢点吃，别噎着。”陈敏把盆往她那边推了推。\n\n　　莫清峦吃得差不多的时候，问道：“你这厨房……怎么弄的？”\n\n　　“他弄得，”陈敏朝林风扬了扬下巴，“控土术，房子都能做出来，想做个灶台还不是轻轻松松。”\n\n　　吃饱饭后，陈敏站起来，招呼两人上楼：“走，带你们上去看看。”\n\n　　莫清峦本来想说，不去了，但看到米雪正仰头看着二楼的楼梯，一副好奇的样子，莫清峦只好跟着陈敏上了楼。\n\n　　走上二楼先经过一个环形阳台，栏杆的高度刚好到腰，从这里能看到整个营地。\n\n　　“这边。”陈敏推开房门，带着两人进入房间。\n\n　　房间并不大，靠墙的地方是一张宽大的石床，上面铺着干净的床单，被子叠得整整齐齐，角落的位置还有石制的沙发，上面铺了一层垫子和几个靠枕，房顶的灯光散发着柔和的光芒。\n\n　　陈敏在床边坐下，顺手拍了拍旁边的位置，“两位妹妹，想留下来吗？”\n\n　　米雪她看着那张大床，目光又扫到卫生间。\n\n　　“清峦姐……”她声音有些发干，她好想说，留下来留下来。\n\n　　她们多豪华的酒店都住过，像这种房间，她们平时根本看不上，可是末日里能住在这种房间，那是想也不敢想的事情。\n\n　　莫清峦看了米雪一眼，目光在那张大床上停了好几秒，然后移开了\n\n　　她拉住米雪的手腕，往外拖了一步：“不了，我们还有事，多谢款待。”\n\n　　陈敏没有挽留，只是笑着点点头：“想来了随时来，这里的大门永远向你们敞开……”\n\n　　莫清峦没有回头，拉着米雪走下楼梯，路过厨房的时候，目光在里面停留了好一会，然后抓住软梯，一阶一阶地往下爬。\n\n　　等她们踩在地面那一刻，两人站定了好一会，回头看向那扇亮着灯光的窗户，对视了一眼，沉默了好一会，才朝着改装车的方向走去。\n\n　　张姐依靠在车门边，她看到莫清峦和米雪回来：“你们回来的比我想的早。”\n\n　　莫清峦点点头。\n\n　　这辆改装车大得像一辆火车车厢似的，车头的位置是留给觉醒者的私人空间，空间挺大，占据了整辆车的三分之一体积。\n\n　　她们从车头的车门上了车，车内比她想象的宽敞很多，比她们原先的埃尔法也要更加舒适，而且还有床，从她们车上拆下来的小冰箱、液晶显示屏、卫生间等一应俱全。\n\n　　郭逸对车辆的改装能力极强，完全是照着沈雨桐的装甲房车的模式改造的。\n\n　　有一道门通向后面车厢，这里就杂乱多了，上下两层，个子高的还得弯腰，各种乱七八糟的座位焊在车上。\n\n　　下面那一层甚至连座位都没有，就一层光秃秃的铁皮，让幸存者自由发挥，爱坐地上坐地上，爱躺着自己躺着，郭逸对于普通人，连安装一个铁皮座椅的想法都有。\n\n　　门一关，车头和车厢完全就是两种不同的待遇。\n\n　　米雪见莫清峦一上车，就坐在那个冰冷的铁皮床上很久没有说话：“清峦姐，你是不是后悔了？”\n\n　　莫清峦看了米雪一眼：“后悔什么？这里的环境还不错，虽然确实比不上林风那座龟背上的小房子，比绝大多数幸存者强太多了，再说了，你不是说他是渣男了？怎么？你想留下了？”\n\n　　“哪有……”\n\n　　“收拾一下吧，今晚好好睡一觉……”', 2115, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (71, 13, 69, '第69章 东西放下…', '　　郭逸那边干得热火朝天，每个人手里都拎着工具，搬运零部件和矿石，他正在改第7辆，车队里的一百多辆车几乎消失殆尽，都成为了材料融入了这7辆改装车当中。\n\n　　剧组那边开旅游大巴的司机壮着胆子去问郭逸：“郭师傅，我们那3辆大巴车，您能不能帮我们也改造一下。”\n\n　　“材料呢？”郭逸头也没抬，继续手里的动作。\n\n　　“材料……材料还没挖……”\n\n　　“没有材料，拿什么改？”郭逸抬起头看了面前几人一眼。\n\n　　“而且就算有材料，我也不免费改，要么拿物资来换，要么……算了，看你们的样子，啥也没有吧？”\n\n　　来人哑口无言，最后无奈地退了回去。\n\n　　剧组那边看向正在分粥的灶台，眼睛里全是渴望，还有人不死心，追着王姐，祈求能给点吃的，最后被王姐一个眼神瞪了回去。\n\n　　车内，莫清峦和米雪正在整理床铺，热巴小声地说：“清峦姐，你说他们能撑过去吗？”\n\n　　“能撑过去的就撑过去了，撑不过去的，明天也该想明白了，我跟王姐打过招呼了，不会饿死人的。”\n\n　　有帖子曾说过，人不吃东西能活七天。\n\n　　昨天只吃了一顿，加上今天饿了整整一天的众人，发现莫清峦真的不管他们了，肚子发出一阵又一阵的咕噜声，眼睛盯着灶台那边，全是血丝。\n\n　　众人想不顾一切地冲上去，可是见到巡逻队和狩猎队的人个个手持长刀在营地巡逻，内心的那点想法早就不翼而飞了。\n\n　　“我受不了！”一个女人忽然站起来，身上裹着一件脏兮兮的羽绒服，她是其中一个剧组里的场记，白天她跟着其他人一起躺着，那时候她觉得杨密肯定不会不管她们。\n\n　　但现在发现，莫清峦她好像真的不管了。\n\n　　“你去哪？”旁边一个头发乱得像鸡窝的男人拉着她，这个男人在圈子里知名度不算低，凭着小鲜肉的流量名气拍过不少剧。\n\n　　“我去看看？”\n\n　　那人眼睛一亮，“你要去找那个觉醒者换吃的吗？那个，你待会回来的时候，能不能，给我带一点。”\n\n　　小姑娘甩开他的手：“你能不能不要那么龌龊，我去看看挖矿那边，还收不收人。”\n\n　　她走了一圈，发现原先还在给大家分粥的红姐已经不见了，反倒是她的那辆公交车上，响起一阵让人面红耳赤的声音。\n\n　　心底暗骂一声，这些臭男人，才吃饱饭一天，就想着这事。\n\n　　最后找到王姐那边，“王姐，我想挖矿。”\n\n　　王姐看了她一眼：“可以，青峦正在帮林风组建挖矿队，成为矿队的人，如果没有车，可以上清峦这辆车，平时的主要任务就是收集物资，挖掘矿产，当然，收集的物资需要上交一半，没有工作的时候一天只提供一顿饭，有任务的时候，有额外奖励，现在是挖500公斤铁矿换一碗粥，你要干吗？”\n\n　　“干，我干，谢谢王姐，谢谢蜜姐！”那女孩连连点头，饥饿几乎要烧穿她的理智，此刻她最后悔的是林风开出挖100公斤矿石就能领到一碗粥时，自己为什么要听旁人的话，现在却需要付出更多。\n\n　　可再后悔也要咬着牙齿干。\n\n　　“去林风大人的御兽那边找李晓丽，让她给你一把矿镐，去干活吧。”\n\n　　她壮着胆子来到那只庞大的乌龟下面，那里搭着一个帐篷。\n\n　　“晓丽姐姐，晓丽姐姐……我是王姐叫过来的，说……说是找你领一柄矿镐……”她小声地朝着帐篷里喊道。\n\n　　晓丽走出帐篷，睡眼惺忪地说：“名字！”\n\n　　“我叫何琪！”\n\n　　“嗯，去那边拿一把矿镐，自己找，用完了必须还回来。”晓丽在本子上记录上对方的名字，然后指着旁边那堆矿镐说道。\n\n　　“谢谢，晓丽姐！”\n\n　　“嗯，给你，吃完了有力气挖矿，吃吧。”晓丽见对方嘴唇干裂的样子，不忍心，走到灶台前舀起一碗粥递到对方手里。\n\n　　何琪连连道谢，手里接过那碗已经凉掉的粥，眼泪顺着脸颊滑落到碗里，只有饿过肚子的人才知道，此刻她的心情有多么复杂。\n\n　　这一幕，很多人都看到了，莫清峦原本车队里那些人，陆陆续续有人站起来。\n\n　　“小周总，你也要去？”\n\n　　“我……我去问问？”被叫做小周总的人戴着一副眼镜，此刻给人一种瘦弱、风一吹就要倒的感觉，作为星二代的他自然有一股傲气，此刻他也屈服了，“再饿一天，我扛不住！”\n\n　　随着他的离开，其他人也撑不住了\n\n　　一个人，两个人，到后半夜的时候，矿洞里又响起来稀稀拉拉的叮咚声，原本已经熄灭的灶台，重新升起热腾腾的米香味，这香味勾得在崖壁挖矿的人多了几分力气。\n\n　　何琪不知道是运气好还是什么，从众多矿镐中挑中了一把由1级地鼠爪子制作的矿镐，每一次挥下，都能深深地切入矿石当中，三两下就能挖下一大块，每挖一小堆，就搬运出去称重，\n\n　　“还差100斤，加油……”\n\n　　为了给这些人记录挖矿的数据，晓丽又把沈梦晴（小晴）她们几人喊起来，加上新来的安歌五女，一起忙碌。\n\n　　至于跟安歌她们一起来的苏婉嘛，此刻正在和林风探讨人生。\n\n　　只能说苏婉不愧是模特出身的，不仅仅身材完美，最主要的是放得开啊，让林风体验了一把什么叫人间极乐。\n\n　　林风凭借觉醒者的强悍体质，加上自身天赋异禀、恢复能力强，才制服了这个小妖精。\n\n　　早上八点，小黑的守护领域消散，车队重新响起大喇叭的声音。\n\n　　“所有人请注意，车队即将出发，重复……”\n\n　　人群纷纷行动起来，一个个收拾好手中的东西登上车。\n\n　　还在挖矿的人也停下了手中的动作，林风也从睡梦中醒来，从温香软玉中起身，穿好衣服，走出屋外，就看到地上堆积的矿石，控土术发动，地面土浪翻滚，一道斜坡从地面延伸到龟背上的储物间门口。\n\n　　“晓丽，赶紧上来，叫他们把矿石全部给我搬运到仓库里，剩下的半锅粥，分给他们！然后把东西收好。”\n\n　　“好的。”\n\n　　有了半锅粥作为奖励，挖矿的人群纷纷行动起来。\n\n　　忽然一道声音在人群中炸响。\n\n　　“你在干什么，东西放下……”', 2221, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (72, 13, 70, '第70章 雨中迁徙', '　　“你在干什么，东西放下……”\n\n　　所有人同时转过头，就看到那个短发女孩徐冉正站在那堆矿镐面前，叉着腰，瞪着一个老头，那老头怀里抱着一把矿镐，而且还是品质最好的那12把矿镐之一。\n\n　　镐头泛着冷光，哪怕是普通人也能一眼看出这是一把好货色。\n\n　　“你拿它干什么？这是林风大人的东西。”\n\n　　旁边的人围了过来，目光都落在那老头身上。\n\n　　那老头被周围的人围着，非但没有松手，反而把矿镐搂得更紧了，理直气壮地说：\n\n　　“我年纪大了，拿一把防身怎么了？而且昨天我也挖矿了，这把我喜欢得紧，以后我干活也用得上。”\n\n　　周围响起低低的议论声。\n\n　　“昨天他干了多久？两小时就歇了吧？”\n\n　　“就是，昨天王烈队长组织人挖矿的时候，偷奸耍滑，分粥的时候倒是积极得很……”\n\n　　“哪也不能偷东西啊！”\n\n　　“偷？”老头的声音拔高了八度，“我老头子活这么大岁数，什么东西没见过，不就是一把矿镐吗？你们能把我怎么着，我挖了一天矿，拿把工具是天经地义的！”\n\n　　“天经地义你个大头鬼！”小蕊从人群中挤出来。\n\n　　她刚才正好和晓丽收拾东西，听到这边吵吵嚷嚷，跑过来看，一眼就发现了老头手里的矿镐。\n\n　　小蕊几步走到老头面前，伸手就要去夺矿镐。\n\n　　“这是林风大人的东西，不准拿，还给我！”\n\n　　老头一把攥紧，往后退了半步，小蕊拽了两下硬是没有拽动。\n\n　　“你个小丫头片子！”老头瞪着眼睛叫嚣道：“你就是昨天管发粥那个吧？我昨天干那么多活，才换一碗粥，你个黑心肝的……”\n\n　　“放手！”\n\n　　“我就不放！”\n\n　　两人僵持在原地，周围的议论声越来越大，有人说“这老头为人太不像话了。”\n\n　　也有人嘀咕：“一把镐子而已，至于吗？”\n\n　　还有人说：“那镐子确实好用，比普通镐子锋利数倍不止，我也想弄一把，可是不敢……”\n\n　　“我去你丫的！”人群中窜出一个人影，一脚踹在老头屁股上，老头整个人被踹得扑倒在地，矿镐当场脱手，疼得龇牙咧嘴。\n\n　　是赵大勇，他看到有人闹事，想也不想直接站在林风这边，他小跑着上前，捡起地上的矿镐，在裤腿上擦了擦灰，转身递给小蕊。\n\n　　“小蕊姑娘，矿镐我拿回来了！”\n\n　　小蕊接过矿镐，“谢谢赵大叔。”\n\n　　那老头从地上爬起来，灰头土脸地说：“你们……你们欺负老人，我要去告你们……”\n\n　　“去，你去！”赵大勇抱着手臂杵在那里，目光冷冷的扫了他一眼。\n\n　　“你去跟王队说，你偷东西被抓了个现行，看看他是帮你还是把你扔出车队。”\n\n　　“你……你……”老头嘴唇哆嗦了两下，最终还是没敢去，骂骂咧咧的钻入人群中。\n\n　　小蕊把矿镐放回物资堆里，清点了一下数量，140把，不多不少，才终于放下心来。\n\n　　“赵大叔，”小蕊喊道，“你能帮我把这些东西搬上去行吗？”\n\n　　赵大勇看了一眼小玄的龟背，比昨晚又大了一圈，就像看到一座小山。\n\n　　“行，没问题，我去喊几个人一起。”\n\n　　他朝身边招了招手：“老李，小李……过来搭把手。”\n\n　　很快，来了几个壮实的男人，几人把矿镐捆成一捆，一趟一趟地往小玄背上搬。\n\n　　其中赵大勇最卖力，搬完矿镐，还帮着其他人把堆积的矿石全部搬进小玄背上的仓库里，大家齐心协力，很快就把东西全部搬完了。\n\n　　小蕊正在分最后半锅粥。\n\n　　“赵大叔，多给你一点。”\n\n　　赵大勇看着手里的碗比旁人多出两勺，他露出憨厚的笑容，“谢谢小蕊姑娘。”\n\n　　他拿着自己那碗装得满满当当的粥，找到自己的老婆孩子，登上改装大巴车。\n\n　　“林风哥哥，都收拾完了！”小蕊把最后一样东西抱上龟背后，来到林风身边说道。\n\n　　林风点点头，对小玄下令。\n\n　　“出发！”小玄慢吞吞地抬起头，用控土术从背上的仓库里挪走一块铁矿石，飞进嘴里，咽进肚子里，这才慢悠悠地撑起身体，巨大的龟甲从地面抬起，龟背上的房子跟着轻微晃了一下。\n\n　　随着小玄迈开步子，又变得如同平地一般。\n\n　　此时沈雨桐那辆装甲房车，率先冲进了雨幕当中，随后已经坐满人的7辆改装超级大巴车紧跟其后，巨大的轮胎碾过泥泞的道路如履平地，其他车辆纷纷跟上。\n\n　　于雨没有丝毫停止的意思。\n\n　　小玄冲进雨幕的瞬间，狂暴的雨点打在房子上，林风站在落地窗前，哪怕是白天，也只能看到车灯闪烁的光芒，视线严重受阻。\n\n　　小玄的体型巨大，走在了车队最后面，每一步落下，都感觉地面在震动。\n\n　　陈敏与林风并肩站着，房间里小蕊等十个女人或坐、或躺着，房间里灯光调成微弱的暖光，照在她们身上，充满了别样的美感与诱惑。\n\n　　林风暗叹，果然，女人的美丽是得靠养了，前两天一个个还脏兮兮，嘴唇干裂，臭哄哄的样子，现在换上了干净的衣服，吃了几顿变异生物的肉，一个个重新恢复美貌。\n\n　　看着就养眼。\n\n　　感受到了林风投来的目光，一个个下意识地展示出自己最美或最诱人的一面。\n\n　　她们算是车队里最早明白末日真谛的女人，早早就凭借自身美貌搭上林风的大船，现在不仅一日三餐有着落，还有安全的庇护所。\n\n　　她们互相对视了一眼，下意识地暗暗下定决心，要使出浑身解数让林风离不开她们。\n\n　　“楼上的蓄水池满了，想洗澡的可以去卫生间那边，我加装了一个热水器，注意别感冒。”\n\n　　“太好了……”\n\n　　几个女孩惊呼一声，就连躺在床上休息的苏婉都坐起来了，她们拿着换洗的衣服就往里面跑。\n\n　　那种能洗个热水澡的期待在她们脸上表现得明明白白。\n\n　　车队在弯弯曲曲的荒野中前行，道路几乎看不清，全靠前方的尾灯领路，大约走了一个多小时，陈敏的身体微微绷紧一瞬。\n\n　　“怎么了？”林风感受到怀里女人的紧张连忙问道。\n\n　　“有东西靠近，在那个方位，距离车队不到两百米！”', 2206, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (73, 13, 71, '第71章 诡异来袭', '　　林风松开陈敏香软的身躯，站起来，几步就来到窗前，顺着陈敏指的方向看去。\n\n　　雨幕太密，什么也看不清。\n\n　　但林风能感觉到一道道阴冷、腐败的气息在靠近。\n\n　　“我出去看看。”\n\n　　林风推开房门，来到阳台上，大雨顷刻间就打湿了林风的衣服，雨水顺着头发往脖子里灌，林风摸了一把脸上的水，把头发往后捋了捋。\n\n　　他眯起眼睛看向前方和车队左右两侧。\n\n　　车队里的改装大巴车上，车顶的探照灯同时亮起来，巨大的光柱穿透雨幕，扫向车队两侧的荒野，也照亮了那些试图靠近车队的黑影。\n\n　　是诡异。\n\n　　十几个，不对，最少二十几个，在探照灯下快速朝着车队靠近，它们贴着地面，速度极快。\n\n　　“有诡异！数量不少！”车队里负责瞭望的巡逻队员扯着嗓子喊道。\n\n　　王烈的反应速度极快，一道电光从他所在的位置劈向车队左侧扑向大巴车的诡异身影，被雷电命中的诡异在雷光中炸开，化作一道道灰黑色气体消失不见，原地留下一颗诡晶。\n\n　　与此同时，林风也施展着自己的能力。\n\n　　共享自小玄的天赋——控土术。\n\n　　前方泥地里一根尖锐的地刺从地面猛然升起，正好出现在扑向一辆越野车的诡异下方，紧接着，接二连三的地刺噗呲噗呲的扎向诡异。\n\n　　那头诡异就像被刺破的气球一般爆裂开来。\n\n　　【获得进化点+1】\n\n　　更多的诡异借着雨幕袭击车队，林风的攻击也是毫不停歇。\n\n　　一连串的提示出现在林风脑海里，但此刻也顾不上那么多了，他不明白为什么诡异能白天出没，或许是暴雨的原因，不过此刻也顾不上这么多了，连续施展能力击杀诡异，\n\n　　车队的速度猛地增加。\n\n　　他能拦住的区域始终有限，有黑影扑向车队中部一辆越野车的侧窗，锋利的爪子划破铁皮，车里的人发出惊恐的惊叫。\n\n　　诡异的利爪猛地一抓，车身猛地一歪，车门被整个拽下来，甩进泥水里，诡异趁机钻了进去，然后整辆越野不受控制地侧翻，在泥泞中翻滚了好几圈，侧面着地，轮子在空中旋转。\n\n　　惨叫声在雨声中断断续续地传来。\n\n　　其他觉醒者也出手了，方玲手持两把断刃，如同一阵风一般 掠过一头诡异，下一秒诡异就尸首分离，而且她还有空捡起地上的诡晶。\n\n　　陈敏的飞刀不知何时也出现在场中，轻易地洞穿一头头诡异的身躯，顺便用精神力将林风击杀的诡晶一同带了回来。\n\n　　林风心中大定，终于不是白杀了，战利品保住了。\n\n　　有一辆越野车被一只如同豹子一般大小的山猫诡异掀翻，车队里其他车辆为了躲避来袭的诡异，猛打方向盘，在泥泞中打滑，车头猛地和其他车辆撞在了一起。\n\n　　“你他妈的找死啊……”\n\n　　被撞车辆的司机猛踩油门，也无济于事，眼看诡异就要扑上来了，他抄起武器就跳下了车，朝着前面的车队跑去，后车门打开，跑下来两个惊慌失措的女人，看着前面的男人头也不回的跑了，赶紧追上去。\n\n　　“强哥，等等我……”\n\n　　这时候也顾不上那么多了，连滚带爬地往前跑，眨眼就被一头诡异扑中身体，咬下头颅，血液洒在泥水里，被大雨冲走。\n\n　　其他车主骂骂咧咧的绕开撞在一起的车辆，猛踩油门，朝前狂奔。\n\n　　小玄跨过一辆侧翻的越野车，车身侧躺在泥水里，车窗完全碎了，里面没有人影，只有混合着血液的泥水浸满了整个车厢。\n\n　　它没有低头，也没有减速，跨过车顶的时候，车身被直接踩扁。\n\n　　小玄也跟着车队加速了。\n\n　　前面有一辆悍马直接陷进深坑里，有人朝着车队挥手。\n\n　　“救我，求求你们……”\n\n　　没有车停下，直接绕开，现在谁都恨不得把油门直接焊死，生怕自己走得不够快，被诡异追上。\n\n　　林风站在阳台上，控土术一次接一次发动，他整个人完全湿透，就像泡在水里一般，手死死地握着栏杆，微微喘气，太阳穴一阵一阵的疼，身体也感觉被抽空，那是精神力和灵能双重严重耗空带来的后遗症。\n\n　　小黑蹲在林风脚边，一步不离地守护着他，耳朵竖着。\n\n　　“不好！有个大家伙来了。”\n\n　　不知道什么时候陈敏来到林风面前，伸手扶着有些虚脱的林风。\n\n　　林风都来不及问大家伙在哪，就感觉到一股恐怖的气息在车队前方爆发，探照灯全部打了过去。\n\n　　所有人的目光都盯着那个方向。\n\n　　一道黑影裹挟着四五米高的泥石洪流朝着车队前方直冲而来，洪流中似乎还有数不清恐怖的诡异在咆哮，在嘶吼。\n\n　　“迎敌！”\n\n　　王烈不知道何时已经窜上了车顶，大喊道。\n\n　　车队猛地转向，最前面的7辆改装大巴车试图拉开队形，但雨太大，地太滑，车队还未完全散开。\n\n　　一只巨大的蛇形身影从泥石流中抬起半个身子。\n\n　　有多大？\n\n　　林风哪怕在车队最后面，仰头望去感觉那蛇粗的就像一根烟囱，鳞片散发黑色的光芒，每一片鳞片上的黑气都勾连着一个诡异的身影，从鳞片中探出半截身影，在痛苦的哀嚎，仿佛有无数的怨灵缠绕一般。\n\n　　仅仅只是看一眼，就亡魂直冒。\n\n　　还没等林风看清它的全貌，这条巨蛇裹挟的泥石流直接冲撞在车队正中央，一辆15米的改装大巴车避让不及，当场被撞翻，庞大的车身就像被踢翻的积木一般，连续滚了几十米才停下来，紧跟在后面的两辆货车和数辆越野车被泥石流淹没。\n\n　　车身直接变形，车厢里装的物资散落一地，整个车队被拦腰截断。\n\n　　有人从翻倒的车里爬出来，浑身是血，在泥地里爬行。\n\n　　“快跑……”有人大喊，连忙往后面跑。\n\n　　但那头巨蛇已经转过头来。\n\n　　它的竖瞳，扫过车队，盯着慌乱的人群。\n\n　　然后它动了。\n\n　　它的身体从泥石流中显现出来，林风才来看清它的全貌，那是一条足有50多米的巨蛇，周身怨灵缠绕，恐怖至极，它的速度极快，眨眼间就窜到了一辆载满人旅游大巴面前。', 2169, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (74, 13, 72, '第72章 救人', '　　“拦住它！”\n\n　　王烈此刻已经站在那辆旅游大巴车顶大喊道，双手往前一推，一个篮球大小雷球砸在巨蛇的头部。\n\n　　雷电猛地炸开，巨蛇的头颅被打偏了一瞬，鳞片上的诡异被雷电打散，可仔细看去，鳞片本身只留下了一些焦黑的痕迹，丝毫没有受损。\n\n　　不破防！\n\n　　它发出一道愤怒的嘶鸣声，极速窜出，蛇尾横扫，抽在那辆旅游大巴车身上，那辆车，就像是被用棍子抽中的瓶子一般，直接飞出去几十米，车身扭曲成一堆废铁，大片血水顺着扭曲的铁皮流出。\n\n　　林风驱使小玄，快步跑向战场。\n\n　　就看到王烈狼狈的趴在泥水里，方玲的身影极速掠过巨蛇的身躯，手里的短刃在蛇身上划出一长串火星子。\n\n　　董雨手持长刀，还没靠近蛇身，就被巨蛇身上的怨灵死死的缠住，疲于应付，怨灵的利爪把她抓得浑身是血，如果不是方玲火速救援，已经丧命于蛇口中了。\n\n　　一柄飞刀猛地刺向巨蛇的眼睛。\n\n　　“叮！”\n\n　　飞刀直接被崩飞出去，哪怕是陈敏攻击巨蛇的眼睛，同样也不破防。\n\n　　“这玩意打不动！快走。”它皮太厚了，方玲大声喊道。\n\n　　方玲没有再犹豫，一只手拎着已经昏过去的董雨，另外一只手抓住王烈的胳膊，速度天赋在这一刻被她发挥到极致，飞速掠过那些翻倒的车辆。\n\n　　方玲朝着前方的车辆追去。\n\n　　车队开始绕行，其他车辆，纷纷远离那条巨蛇的区域，朝着前方领头的车辆追过去。\n\n　　没有人停车，没有人回头，所有人都在逃，有些车辆被毁，幸运存活下来的人，不顾一切地往前跑，趁着巨蛇还在吞噬翻到车辆里的人的时候，朝着唯一的生路涌去。\n\n　　“走！”林风给小玄下达命令，跟着转身，这时候再凑上去，简直就跟找死没什么区别。\n\n　　忽然，林风看到一辆熟悉的车辆，是红姐的那辆公交车，它此刻正歪倒在泥石流边缘，整个车陷入泥里，车辆被淤泥堵死，车窗的玻璃也碎了大半。\n\n　　红姐此刻正带着她的那十几个姑娘，站在泥水里，浑身湿透，朝着过往的车辆挥手，只是没有一辆车停下，她此刻有些绝望。\n\n　　他们这一群女人，失去车辆后，绝对跑不过诡异，尤其是下这么大雨的情况下。\n\n　　当她感受到地面的震动，抬起眼眸看到林风那只体型庞大的乌龟御兽正朝她这边赶来时，求生的希望一下子涌上心头。\n\n　　“快，姑娘们，跟我走，上林风大人的御兽上面。”\n\n　　她们绝望的表情立刻消失，纷纷跟在红姐身后，往林风的御兽那边跑。\n\n　　“快，从软梯爬上来。”林风放下软梯，朝下面喊道。\n\n　　小玄停下脚步。\n\n　　“快，上去！“红姐抬起头，看着落下来的软梯，连忙大声朝身后喊道，把最前面的一个姑娘往软梯的方向推了一把。\n\n　　那姑娘抓住软梯，手脚并用地往上爬，雨水淋在身上，带走身上的体温，爬到一半，整个人滑了下去，被后面跟上来的姑娘从下面托了一把。\n\n　　“抓紧了，都抓紧了！”\n\n　　有人在软梯上哭出声来，但没有停下来，还在往上面爬，红姐站在下面，把每一个爬的人扶稳了才松手，看着她们一个个都爬上龟背后，她才最后一个爬上软梯。\n\n　　林风看到红姐已经爬上软梯后，立刻大声喊道：\n\n　　“小玄，快跑。”\n\n　　他已经看到那条巨蛇在那辆旅游大巴的残骸边，重新直立起上半身。\n\n　　那双竖瞳在雨幕中精准地锁定了小玄，林风仅仅只是对视了半秒，就感觉一阵凉意从脖子一路窜到了尾椎骨。\n\n　　巨蛇动了，50多米的躯体猛地朝这边窜过来，它的身体在泥地里划出数米宽的沟壑，眼看就要冲进50米距离了，林风已经感觉到一股死亡气息笼罩全身\n\n　　小玄感应到了林风的焦急，四条腿同时发力，猛地窜出去，软梯往后一甩，红姐整个人跟着软梯腾空而起，差点被突如其来的加速甩下去，整个人死死地抱住软梯。\n\n　　巨蛇的头颅猛地张开巨口朝红姐咬来，一股腥臭的气味直扑而来，一股热流从大腿根传来，红姐此刻又羞又恐惧。\n\n　　眼看就要咬中她，这时候一股强大的拖拽力道传来，她整个人连同软梯，被林风一把给拉了上来。\n\n　　巨蛇一口咬空，顺着惯性栽进泥水里，反倒灌了满嘴的泥水。\n\n　　她整个人摔在平台上，胸口剧烈地起伏，头发湿漉漉的贴在脸上，狼狈无比，嘴里大口大口的喘着气，似乎要把刚才的恐惧全部呼出来。\n\n　　就差一点，就差一点她就被吃了。\n\n　　“嘶……”巨蛇发出愤怒的嘶吼。\n\n　　小玄的脚步更快了，速度几乎是贴在地面飞掠一般。\n\n　　巨蛇紧追不舍。\n\n　　“都站起来，别瘫着，龟背上风大，全都给我进屋，会掉下去的。”\n\n　　林风对着那些还在发抖的姑娘们喊道。\n\n　　红姐忍住颤抖的腿，爬了起来，小心地看了一眼林风，脸色有些羞红，希望刚才那羞人的一幕，他没有看见吧。\n\n　　“快，都跟我走，上楼去。”\n\n　　她招呼着那些姑娘，立刻往楼上卧室里跑。\n\n　　林风跟着上了2楼阳台，看着紧追不舍的巨蛇。\n\n　　忍着头昏脑涨，再次发动控土术，一道土墙升起，被巨蛇一头撞碎。\n\n　　一根地刺刺出，刚碰到鳞片就被碾压成碎石。\n\n　　没用，完全没用。\n\n　　实力的差距太大了，林风感觉到自己的精神力被极速消耗，灵能也消耗得一干二净。\n\n　　林风从口袋里掏出仅剩的诡晶，快速吸收，这些0级诡晶恢复的灵能只能说聊胜于无。\n\n　　继续。\n\n　　压榨了所有灵力和精神力，构建了一个地陷术，巨蛇的身躯猛地掉进坑底，眨眼功夫就爬起来了，巨蛇更加狂暴了。\n\n　　“完了……”\n\n　　前面就是车队，林风咬咬牙就要让小玄转向引开这条巨蛇。\n\n　　“你要引开它？”陈敏的声音带着难以置信，她以为林风会直接冲进车队，祸水东引。\n\n　　“小玄，往那边……”林风就要下令往车队相反的方向跑。\n\n　　“你是不是忘了什么？”', 2166, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (75, 13, 73, '第73章 击杀巨蛇', '　　林风的话才说了一半，陈敏的声音就从她身边传来。\n\n　　“什么？”林风转过头看着陈敏，她的眼神里只有平静，没有慌乱，只有一种让你仔细想想的笃定。\n\n　　林风只顾得上逃命，哪还有时间想那些。\n\n　　“小黑！”陈敏无奈地说，“小黑的能力克制诡异。”\n\n　　“是啊！”林风猛地清醒。\n\n　　小黑，这条一直跟在他脚边，寸步不离的黑狗，安安静静的，没有什么存在感，但它的能力是辟邪，是专门克制诡异的，那些缠绕在巨蛇身上的怨灵，本质上跟诡异没什么区别。\n\n　　只是它们的数量太多了，这些数量庞大的诡异与巨蛇共生，让它们拥有难以想象的恐怖力量。\n\n　　“我真是……”林风恨不得抽自己一巴掌，“被吓傻了。”\n\n　　谁知道诡异白天也能出现啊，还是遇到的危险太少了，都不知道怎么利用身边的战斗伙伴。\n\n　　“小黑，守护领域，给我覆盖那条蛇，最大范围。”林风大喊道，“小玄准备停下战斗。”\n\n　　“汪呜……”\n\n　　小黑发出一声吼叫，金色的光芒从它身上炸开。\n\n　　金色的光芒瞬间覆盖了半径百米的范围，将紧追不舍的巨蛇整个包裹了进去。\n\n　　巨蛇的身体猛的一顿。\n\n　　它身上那浓密的诡异雾气，在接触到金色光芒的瞬间，就像被浇了开水的积雪一般，发出滋滋的灼烧声，开始大片大片的消散，那些缠绕在它身上，如同从鳞片中生长出来的诡异怨灵发出尖锐刺耳的痛苦哀嚎声。\n\n　　成千上万道惨叫声同时响起，\n\n　　那些怨灵的面孔在金光中显现出来，无数扭曲的，痛苦的，狰狞的怨灵，在疯狂的挣扎，试图从巨蛇身上剥离出来，最后只能在金色的辟邪之力下化作一缕缕青烟。\n\n　　击杀1级怨灵，获得进化点+1\n\n　　击杀1级怨灵，获得进化点+1\n\n　　+1\n\n　　……\n\n　　林风的脑海里响起一大片密集的提示声，那个数字在疯狂的跳动，从个位数，眨眼间就跳到了十位数，然后突破50，朝着100直奔而去。\n\n　　巨蛇的身躯剧烈地抽搐起来，它身上的怨灵被大面积地杀死，那些与它共生的怨灵死亡后，露出成片成片的白色鳞甲，像死了很久的那种灰白色。\n\n　　但这也彻底激怒了它。\n\n　　它的竖瞳骤然变成了血红色，黑色的雾气从眼眶中冒出，它的身体猛地弓起，蛇尾疯狂抽打地面，泥浆四溅，它张开巨口，朝着小玄猛地扑了过来。\n\n　　“小玄，土墙，拦住它！”\n\n　　小玄早已灵活地转身，前爪猛地拍地，一道比之前林风控制的任何土墙都要厚实数倍的岩石巨墙从地面升起，如同一个屏障一般挡在巨蛇面前。\n\n　　巨蛇猛地一头撞上去。\n\n　　轰……\n\n　　一声沉闷的撞击声响起，石墙裂了一大半，巨蛇的头颅在撞击中歪向一边，头上的鳞甲碎裂，酷酷往外冒黑气，\n\n　　它摇晃着脑袋，显然被撞得有些发蒙。\n\n　　小玄没等它反应过来，一道土黄色光芒涌入地面，泥土像活物一样从泥地里升起，包裹住巨蛇的尾巴，蛇身，颈部，巨蛇拼命挣扎。\n\n　　可它身上的怨灵被消灭大半，加上小黑守护领域对诡异的压制，此时它的力量比刚才弱了不止一个档次。\n\n　　“地刺！”林风喊道。\n\n　　小玄施展出一排排锋利的地刺，精准地刺中那些失去怨灵加持的灰白色鳞片。\n\n　　噗呲\n\n　　噗呲\n\n　　噗嗤……\n\n　　这一次地刺没有被崩碎，而是实打实的刺穿了巨蛇的鳞甲，扎进肉里，墨绿色的诡异血液从伤口涌出来，然后被金光灼烧成青烟。\n\n　　巨蛇发出痛苦的嘶鸣，身体猛地一挣，狂霸的力量把缠在它身上的泥土崩裂，碎石和泥块飞溅得到处都是，它的头抬起来，血红的目光死死地盯着小玄。\n\n　　“有效果，小黑，进化……”\n\n　　林风看了一眼现在的进化点，已经积攒了200多点，意味着共生在巨蛇身上的1级诡异被消灭了大半，现在正是时候进化小黑，消灭更多的共生怨灵，继续削弱巨蛇的力量。\n\n　　优势在我。\n\n　　这波能打。\n\n　　眨眼间，小黑在进化之力的作用下，产生了巨大的变化。\n\n　　它的体型猛的变大，它原本到林风膝盖的高度，如今拔高了一截，肩高到了林风的腰部，皮毛深处流动着金色的纹路，那双眼睛更是神俊异常。\n\n　　【御兽辟邪犬进化成功，当前等级2，下一次进化需消耗1000点进化点。】\n\n　　【获得属性反馈：体质+12，力量+7……】\n\n　　打开小黑的属性面板\n\n　　辟邪犬：小黑\n\n　　能力1：辟邪之力（注：你的御兽具备辟邪之力，能对3级及以下诡异造成大额伤害，诡异等级越高效果越弱。）\n\n　　能力2：守护领域（注：可释放半径200米的守护领域，震慑诡异，对3级及以下诡异造成强烈的灼烧伤害以及震慑效果，在领域内，诡异隐匿效果失效，全属性降低50%，对诡异的伤害翻倍，诡异等级越高效果越弱。）\n\n　　【叮！击杀2级怨灵，获得进化点+10】\n\n　　……\n\n　　提示音再次响起，巨蛇身上残存的怨灵在更加猛烈的辟邪金光照耀下，像雪花一样片片瓦解，消散。\n\n　　那些还在张牙舞爪的怨灵此刻疯狂的往蛇皮里钻，想要躲避这致命的辟邪金光，但辟邪之力无孔不入，将它们从每一片鳞甲，每一寸血肉中生生剥离出来。\n\n　　随着大量怨灵的消亡，巨蛇的挣扎越来越弱，它的鳞片大片大片的剥落，露出下面灰白的血肉。\n\n　　巨蛇发出最后的哀鸣，朝着小玄扑来，然后小玄动了，前爪高高扬起，朝着巨蛇的头颅猛的拍下去。\n\n　　砰……\n\n　　巨蛇的头颅被拍进泥地里，陷进去半丈深，它抽搐了两下，尾部最后一次甩动，再次被一爪子拍飞，扬起一片泥浆，然后彻底不动了。\n\n　　巨大的蛇身开始风化，碎裂，成片成片地崩塌、消散，被小黑的辟邪金光笼罩，最终化为乌有。\n\n　　这头卷起泥石流、掀翻了车队十几辆车的恐怖巨蛇，就这样憋屈地死在这里。\n\n　　【击杀3级怨众尸蛇，获得进化点100！】\n\n　　林风瘫坐在阳台上，背靠着墙壁，手指还在微微发抖，小黑蹲在旁边，默默的守护着他，看到林风的目光望过来，它摇了摇尾巴，趴在林风身边，把头靠在他腿上。\n\n　　林风揉了揉对方湿漉漉的狗头。\n\n　　“哈哈……好狗……”', 2275, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (76, 13, 74, '第74章 结束了', '　　“结束了？”\n\n　　“嗯，结束了！没想到这巨蛇看着恐怖，其实一点也不经打。”林风点点头。\n\n　　陈敏给林风解释道：“这巨蛇实力恐怖的原因，是成百上千的怨灵为它提供力量，它本体的实力并不强，而且刚好遇到克制它的力量，只能说我们运气好。”\n\n　　林风：“嗯！”\n\n　　陈敏的手轻轻一招，那只巨蛇死后掉落的物品，被无形的精神力抓着，快速朝她飞来，落入她掌心中，是一块暗红色鳞片，还有一颗3级诡晶。\n\n　　陈敏把这东西递给林风，林风接过看了一眼，鳞片只有巴掌大小，不仅没有阴冷的气息，反而泛着温润的光泽。\n\n　　林风翻来覆去的看了几眼，最后用手指敲了敲，发出金铁般的声音，发现没啥特别的，顺手就还给了陈敏。\n\n　　“敏姐，你收着吧，万一以后有用呢，还有这颗3级诡晶也给你。”\n\n　　陈敏愣了一下：“你不自己留着用？”\n\n　　“留什么留，我才1级，用不上这玩意，你拿回去突破三级，正好，等你战力上去了，我才好躺平。”\n\n　　陈敏看了他两秒，嘴角微微往上弯了一下，没有推辞，把诡晶和鳞片都收起来。\n\n　　然后她弯下腰，一只手穿过林风的腋下把他架起来。\n\n　　“走，跟我进屋，我们得赶紧跟进车队，别掉队了。”\n\n　　林风勉强打起精神，喊了一声：“小玄，跟上车队，别跟丢了。”\n\n　　小玄发出一声低吟作为答复，迈开脚步朝着早已连车尾灯都看不见的车队追去。\n\n　　林风实在太累了，尤其是太阳穴一阵一阵的疼，浑身就像是被抽空了一般，疲惫无力，半个身体靠在陈敏身上，几乎是被陈敏半拖半拽的弄进了门。\n\n　　房间里挤满了人，红姐和她那十几个姑娘全部缩在墙角，浑身湿透，头发一缕一缕的贴在脸上，嘴唇冻得发紫，缩成一团，水滴从她们衣服上滴下来，在地面形成一小滩水洼。\n\n　　小蕊她们还好，在屋里躲了那么久，只是从窗户边看到那么恐怖的一幕，几人都吓得不轻，生怕林风挡不住那条恐怖的巨蛇，好在最后有惊无险。\n\n　　看到林风和陈敏进来，小晴连忙抱着毛巾迎了上去：“大人，敏姐，毛巾。”\n\n　　林风接过毛巾，就往浴室走去，把湿透的衣服随手一脱，扔洗漱台上，快速地冲了一个热水澡，扯下一块浴巾裹上。\n\n　　整个过程不超过三分钟。\n\n　　好在当初跟郭逸要来一个大容量的改造电池，这才能有热水用。\n\n　　从卫生间出来，看到红姐她们现在狼狈的样子后：“小蕊，给她们找一些干爽的衣服，去换一换，里面还有热水，去洗一洗，别生病了，这末日里生病了连药都找不到。”\n\n　　“谢谢……”红姐冻得牙齿打颤，还是连忙道谢。\n\n　　小蕊应了一声，跑去翻柜子，很快拿了几块毛巾过来，递给离她最近的几个人，又跑去衣柜里翻衣服。\n\n　　林风没有再停留，径直走到那张大石床边上，整个人往床上一倒，眼睛一闭，然后就什么都不知道了。\n\n　　留下屋内二十多个女人面面相觑。\n\n　　陈敏看着林风趴在床垫上一动不动，摇了摇头，脸上带着一抹心疼，走上前，给林风调整了一下睡姿，不小心把浴巾扯掉，脸一红，嘴里暗骂一声。\n\n　　“呸……”\n\n　　还是扯过被子给他好好盖上。\n\n　　陈敏见一双双眼睛朝这边看过来。\n\n　　“都别愣着了，都把湿衣服换了，毛巾不够互相匀一匀，生病了可没有药给你们吃。”陈敏没好气地说。\n\n　　红姐最先反应过来，连忙推了推身边的姑娘们：“听见了没，都动起来，你，换好衣服去那边坐着歇会，腿都在发抖，还有你，别哭了，还活着，哭什么？”\n\n　　那些姑娘们被红姐这么一催，陆续动起来，有人直接解开湿透的衣服，接过毛巾擦拭身体，把头发裹起来，有人互相搀扶着去卫生间洗个热水澡。\n\n　　好一幅活色生香图，可惜林风已经睡着了，看不到这么让人流鼻血的一幕。\n\n　　大半个小时后，屋里的人大致都换上了一套干衣服，虽然尺码不太合身，但至少不再冷得发抖了。\n\n　　湿透的衣服被洗干净，一条条的拧干，挂在细绳上。\n\n　　见大家都收拾得差不多了，陈敏的眼神打量起面前这群人，开口说道：\n\n　　“小蕊，你带她们下楼去煮一点姜汤。”\n\n　　“好的！”\n\n　　一众人顺着楼梯来到厨房。\n\n　　“你叫红姐是吧，你等一会，我有话给你说。”其他人见到陈敏单独叫住红姐，不知道陈敏要跟她说什么，但还是听话照做。\n\n　　红姐小心翼翼地站在陈敏身前，她不知道叫住她是什么意思，她不怕面对男人，她自能周旋一二，可是面对同为女人的陈敏，她不知道为何。\n\n　　心里直打鼓。\n\n　　“你叫什么名字？”\n\n　　“陆……陆红缨。”\n\n　　“多大？”\n\n　　“29！”她终于说出了自己的真实年龄，比对外宣称的小上不少。\n\n　　陈敏围着她转了两圈，连连点头：“不错，不错……”\n\n　　陆红缨被她那双仿佛能看透人心的眼睛看得心里直发毛，她心里想是不是陈敏不欢迎她上来，难道是要把她丢下去，就在这么想的时候。\n\n　　忽然一句话把她问愣了。\n\n　　“你想不想成为林风的女人！”\n\n　　“啊？”\n\n　　“你不想吗？嗯？”\n\n　　“想！”陆红缨连连点头，这是什么情况，主动给自己男人找女人，这女人怕不是有什么大病，可她心里可不敢这么说，她怕说了被直接丢下去喂了诡异。\n\n　　车队里谁不怕她几分。\n\n　　“可是，那些女孩不都是林风大人的女人吗？”陆红缨不解的问道。\n\n　　“呵呵，她们？还不配！”\n\n　　“啊？”轮到陆红缨疑惑了。\n\n　　陈敏继续开口：“说说，你怎么保持完璧之身的？”\n\n　　“啊？”被说破了心里最大的秘密，陆红缨脸刷地一红，然后在陈敏的精神压迫下娓娓道来。\n\n　　“我在蓝星是大哥的……”', 2118, '2026-07-11 13:12:38');
INSERT INTO `t_book_chapter` VALUES (77, 13, 75, '第75章 觉醒的代价', '　　“我父亲曾经是……”\n\n　　经过陆红缨的诉说，陈敏知道这个女人为什么能在末日里左右逢源了。\n\n　　她爸年轻的时候叱咤风云，算一个不小的人物，后面洗白后做着正经生意，她妈是大哥的女人之一，而且老来得女，给了很多的资源和关爱。\n\n　　而且还有不少小弟、保镖啥的明里暗里保护她，别说小黄毛了，就算是正经的男人靠近她，都会有人把上下三代都给查得一清二楚。\n\n　　就为了给她一个安全的成长环境，生怕自己的小棉袄被偷了。\n\n　　偏偏她自己还不省心，从小带小太妹玩，长大带小台妹玩，还喜欢搞几家酒吧会所啥的玩玩，可谓是操碎了老头子的心。\n\n　　自从不少黄毛或者某些社会精英，某总啥的，只要带着目的靠近他这个小棉袄，出门不是摔断腿啊，就是不看路掉下水道，或者走路摔断几根肋骨啥的，再也没有男人靠近她了。\n\n　　下面的人不敢靠近，上面的人给的面子，这不，一晃，就变老姑娘了。\n\n　　这不末日一来，立马就操起了老本行。\n\n　　“哦，大哥的女儿啊，嗯……不错，你待会这般这般……”陈敏点点头，凑在路红缨耳边小声嘀咕。\n\n　　哪怕是路红缨也听得面红耳赤，不敢置信地看着陈敏，最后在她的眼神威胁下，勉强点头同意。\n\n　　车队前行了不知道多久，林风迷迷糊糊的被人旱醒，眼睛睁开一条缝。\n\n　　就看见一个妖娆的女人，见到林风醒了，风情万种的瞄了林风一眼，把头发挽在脑后。\n\n　　是红姐，怎么是她？\n\n　　“嘶……”\n\n　　外面的暴雨下个不停，车辆在泥泞的道路上行驶得歪歪扭扭，车队面对未知的道路。\n\n　　车队一路走走停停，忽快忽慢，陷入深深的泥沼里，费老劲了，中途停了七八次，又继续行驶，期间车队里又来了一队人，队伍再次壮大。\n\n　　不知过去多长时间。\n\n　　雨小了，车队开始减速，最终彻底停下。\n\n　　同样停下的还有陈敏这个疯批婆娘。\n\n　　“陈敏，你怕不是有什么大病，我都要散架了……”林风感觉自己好不容易睡一觉，恢复的精力再次被这两个人榨干，连敏姐都不喊了。\n\n　　鬼知道陈敏啥时候还有这种嗜好了，一开始红姐那水蛇腰扭得，那叫妖媚入骨。\n\n　　&%……*&%……\n\n　　……林风愣了好半晌，这女人，不对劲啊，跟车队里的传言不太一样。\n\n　　传言她穿越前就是大哥的情人，手下一群姑娘，谁家情人还能保留得这么干净，就算是那些看似青春靓丽的大学生，有人谈过不知道多次了。\n\n　　现在不是感慨这个的时候，只是林风发现陈敏真的有点不对劲，她的状态太兴奋了。\n\n　　陈敏力气耗尽瘫倒在林风怀里，他才趁机翻身下床，腿一软，差点没站稳。\n\n　　“我……”\n\n　　看着陈敏微微泛红的娇躯和痴恋的表情，林风想骂出声的话语始终没有说出口。\n\n　　林风翻出一套衣服给自己穿上，然后才重新坐在床边，将她脸颊被汗水打湿的头发往后捋了捋，露出光洁的额头。此时她整个人都懒洋洋的，林风顺手扯过一条被子盖住那极具视觉冲击的娇躯。\n\n　　他也怕自己忍不住。\n\n　　“敏姐，你的状态不对劲。”林风的话语中带着几分关切。\n\n　　“弟弟，我3级了，我用那颗诡晶顺利地升三级了。”\n\n　　“等级提升了？“\n\n　　“嗯！”陈敏翻了一个身，往上挪了挪，把头靠在林风的腿上，那双好看的美眸盯着林风看了好半晌，似乎要把他印在心底。\n\n　　“我用你给我的那颗3级诡晶突破境界，很顺利的就提升了，然后就……”\n\n　　“然后心里就生出一股强烈的渴望……紧接着就不受控制了，怎么都压不住，你别得了便宜还卖乖啊……臭弟弟！”\n\n　　她抬起脸，眼尾还带着水光：“怎么，姐姐想感谢你，你还不乐意了？”\n\n　　林风摸了摸了鼻子，这种事，说不乐意是假的，只好岔开话题。\n\n　　“哪有，我说的是你的精神状态。”\n\n　　陈敏撑着身体坐起来，被子从肩上滑落，她没有急着拉被子，而是闭上眼睛，眉心亮起一点淡淡的光晕，似乎在使用精神力反复探查自身的状态。\n\n　　片刻后，她睁开眼睛，幽幽地说道。\n\n　　“可能是觉醒者的副作用！”\n\n　　“副作用？”林风皱眉，“觉醒者还有副作用？我怎么没有感觉到？”\n\n　　陈敏靠在林风怀里，偏着头看他：“不，你已经感觉到了，你仔细想想，从穿越到现在，你对女人的态度，和你曾经在蓝星的时候一样吗？”\n\n　　林风刚好开口，突然停住了，他回忆起自己的觉醒前后的经历。\n\n　　陈敏没有等他回答，继续说下去：“你现在见到漂亮的女人就想拥有，你自己想想，你以前在蓝星的时候，你看到好看的姑娘会不再像现在这样，第一反应不是挺好看的，而且怎么把她弄到手？”\n\n　　林风没有说话，他确实想到一些事情，从最初的那几个女人，到现在的晓丽、小晴，再到苏婉她们。甚至看到杨密和热巴时那种占有欲。\n\n　　那不是欣赏，而是第一时间跳到了，能不能弄过来的念头。\n\n　　虽然目前拥有的女人，都是因为种种原因主动来到他身边的，没有强迫任何人，但不可否认，他确实变了。\n\n　　“那个……好像是哈。”林风有些尴尬地挠了挠后脑勺。\n\n　　“董雨喜欢玩文字游戏也是副作用？”林风想到当时来向他求助的那两个女人，身上全是伤痕，已经超出了正常的亲密范畴。\n\n　　“百分之百是！”陈敏的语气十分笃定。\n\n　　“她穿越前就是个拉拉，但没有这么极端，你现在再看，上她车的那些女人身上的伤？”\n\n　　陈敏接着说：“还有沈雨桐不爱说话，不是因为内向，她在蓝星的时候是个很活泼的人，现在呢，一天说不了十句话。”\n\n　　“那你呢？”林风低着头看着她：“你觉醒后的副作用是什么？”\n\n　　陈敏眼神有些飘忽，沉默了很久，久到林风以为她睡着了，她才慢慢开口。\n\n　　“以前，我以为是喜欢折腾人，用精神力操控折磨别人，看着他们痛苦，我就能忘掉自己的痛苦，所以整个车队的人都害怕我，方玲躲着我走，王烈看着我就皱眉，就连郭逸那种人都绕着我走……”\n\n　　林风没有说话。\n\n　　“后来……”', 2256, '2026-07-11 13:12:38');

-- ----------------------------
-- Table structure for t_check_in
-- ----------------------------
DROP TABLE IF EXISTS `t_check_in`;
CREATE TABLE `t_check_in`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `check_date` date NOT NULL COMMENT '打卡日期',
  `streak_days` int NULL DEFAULT 1 COMMENT '连续天数',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_date`(`user_id` ASC, `check_date` ASC) USING BTREE,
  INDEX `idx_user`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '连续打卡记录表' ROW_FORMAT = Dynamic;

