-- Records of t_collection_tag
-- ----------------------------

-- ----------------------------
-- Table structure for t_daily_statistics
-- ----------------------------
DROP TABLE IF EXISTS `t_daily_statistics`;
CREATE TABLE `t_daily_statistics`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `stat_date` date NOT NULL COMMENT '统计日期',
  `practice_count` int NULL DEFAULT 0 COMMENT '练习次数',
  `total_chars` int NULL DEFAULT 0 COMMENT '总练习字数',
  `total_duration` int NULL DEFAULT 0 COMMENT '总耗时(秒)',
