-- ----------------------------
-- Table structure for t_practice_session
-- ----------------------------
DROP TABLE IF EXISTS `t_practice_session`;
CREATE TABLE `t_practice_session`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `book_id` bigint NOT NULL COMMENT '素材ID',
  `chapter_index` int NULL DEFAULT NULL COMMENT '章节索引(null=整本练习)',
  `chapter_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '章节标题',
  `mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'copy' COMMENT '练习模式',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'active' COMMENT '状态',
  `typed_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '已输入内容(断点续练)',
  `current_position` int NULL DEFAULT 0 COMMENT '当前抄写位置(字符索引)',
  `total_chars` int NULL DEFAULT 0 COMMENT '总字数',
  `typed_chars` int NULL DEFAULT 0 COMMENT '已输入字数',
  `error_count` int NULL DEFAULT 0 COMMENT '错误次数',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '结束时间',
  `duration` int NULL DEFAULT 0 COMMENT '耗时(秒)',
  `accuracy` decimal(5, 2) NULL DEFAULT 0.00 COMMENT '正确率(%)',
  `speed` decimal(7, 2) NULL DEFAULT 0.00 COMMENT '速度(字/分)',
  `score` int NULL DEFAULT 0 COMMENT '综合评分',
  `summary_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '摘要内容',
  `self_written_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '自写内容',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user`(`user_id` ASC) USING BTREE,
  INDEX `idx_user_status`(`user_id` ASC, `status` ASC) USING BTREE,
  INDEX `idx_book`(`book_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 23 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '练习会话表' ROW_FORMAT = Dynamic;

