INSERT INTO `t_practice_session` VALUES (20, 1, 13, 0, '前言/引子', 'completed', '书名：全民穿越！我在末日世界养城兽\n作者：三水华光\nbook_id=7525419385083661337\n状态：连载\n评分：6.1\n字数：159173\n章节：75\n分类：科幻末世\n标签：穿越|末世|宠物|多女主\n在读：18.4万人在读\n简介：\n【末日+多女主+城兽】\n林风发现自己穿越了，幸存者组成一个个逃亡队伍向着未知方向逃亡。\n好消息是，自己是一个觉醒者，在队伍里处于核心地位，身边美女不断。\n坏消息是，自己觉醒的是一个垃圾御兽能力，本命契约是一只毫无战斗能力的小乌龟。\n现在自己被踢出了核心圈子，平日里攀附在自己身边的女人也相继离开。\n更糟糕的是断水断粮了，眼看就要活不下去了。\n恭喜你觉醒觉\n醒天赋……\n林风……？\n双天赋？\n事情似乎变得有趣起来', 0, 327, 328, 0, '2026-07-12 13:39:26', '2026-07-12 13:39:35', 8, 92.00, 2460.00, 96, '2026-07-12 13:39:26', '2026-07-12 13:39:35');
