INSERT INTO `t_practice_session` VALUES (22, 1, 13, 7, '第7章 这就是现实', 'completed', '  五个人腰里别着对讲机，提着一根根自制的武器，负责外围警戒巡逻，同时也负责在车队停留期间外出收集物资时排查危险，并顺便保护收集物资的人。', 69, 2363, 69, 206, '2026-07-12 23:20:26', '2026-07-12 23:36:39', 158, 100.00, 26.00, 57, '2026-07-12 23:20:26', '2026-07-12 23:36:39');

-- ----------------------------
-- Table structure for t_ranking_snapshot
-- ----------------------------
DROP TABLE IF EXISTS `t_ranking_snapshot`;
CREATE TABLE `t_ranking_snapshot`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `platform` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '平台: qidian/fanqie/jinjiang/zhihu',
  `rank_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '榜单: month_ticket/recommend/collect/hot_search/new_book',
  `rank_no` int NOT NULL COMMENT '排名',
  `book_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '书名',
  `author` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '作者',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '分类标签',
  `word_count` bigint NULL DEFAULT 0 COMMENT '字数',
  `hot_value` bigint NULL DEFAULT 0 COMMENT '热度值(月票/推荐票/收藏数)',
  `intro` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '简介摘要',
  `cover_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '封面URL',
  `book_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '原书链接',
  `snap_date` date NOT NULL COMMENT '快照日期',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_platform_date`(`platform` ASC, `snap_date` ASC, `rank_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 75 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '网文榜单快照' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_ranking_snapshot
-- ----------------------------
