INSERT INTO `t_ranking_snapshot` VALUES (4, 'qidian', 'recommend', 2, '首次使用？点我注册', '', '', 0, 0, '', '', 'https://passport.qidian.com/reg.html?appid=10&areaid=1&target=iframe&ticket=1&auto=1&autotime=30&returnUrl=https%3A%2F%2Fwww.qidian.com', '2026-07-13', '2026-07-13 20:19:19');
INSERT INTO `t_ranking_snapshot` VALUES (5, 'qidian', 'collect', 1, '剑烛大荒', '爱潜水的乌贼', '玄幻·东方玄幻', 0, 29, '“烛龙，食之开浑沌、照九阴、掌昼夜、更替四时、呼风唤雨。“相柳，食之蚀大地、吞山岳、毒百世、九头各行。“肥遗，食之克虫豸、御精神、百病不入。“蜮虫，食之擅伏擅藏、含沙射人。“……“这个世界的秘传《山海经》怎么和我上辈子看得不太一样？”丁松言默念之中，侧头望向旁边的人：“你是说，这些东西早已绝迹，只有先吃者根据身体变化开创的武功遗留下来，可以修炼？”', '', 'https://www.qidian.com/book/1048862481/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (6, 'qidian', 'collect', 2, '我正经学生，每天只吃九种魔药', '鬼谷道长', '轻小说·原生幻想', 0, 76, '伊文穿越成卖血试药的学生，获得天赋面板。【九龙之力：你可以同时将九种药物的副作用反转】贤者大学：最新安眠药，来能熬夜的学生。你服用【未完成的冬眠魔药】：认知受损，五天睡不醒。反转效果：五天内可以入梦学习。红国王实验室：实验型生长药剂，后果自负。你服用【二阶段D病毒】：肌肉增生，血液凝固。反转效果：体质+0.3，增加肉体延展性。治愈教会：来耐药性强的孤儿。你服用【？？？】：皮肤溃烂，内脏融化，精神突', '', 'https://www.qidian.com/book/1048827563/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (7, 'qidian', 'collect', 3, '青山', '会说话的肘子', '玄幻·东方玄幻', 0, 244, '当今名利已斩天下九分侠气，诸位，这是天下最后一分侠气的故事。', '', 'https://www.qidian.com/book/1033014772/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (8, 'qidian', 'collect', 4, '我能活化技能', '四诗风雅颂', '玄幻·东方玄幻', 0, 29, '“灵气复苏是世界的回光返照。”“异界降临里我们是异界，要降临到对面世界。““敌对的天命之子个个人中龙凤，不是横压一世就是举世无双。”“给我的身份要么是炮灰要么是龙套。”作为武馆里被抛砖引玉的三师兄、异能民国里家业败落的纨绔子弟、修炼骑士呼吸法的乡下贵族长子等等身份的魏乐府庆幸自己也不是什么省油的灯。', '', 'https://www.qidian.com/book/1049458319/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (9, 'qidian', 'collect', 5, '临圣', '卖报小郎君', '仙侠·修真文明', 0, 31, '这天下谁在执棋，谁在局里？刀笔写忠义，转身成谋逆。金銮殿上舞未停，江山半壁已凋零。谁在封王拜相，谁在易子而食？满朝朱紫谈社稷，无人肯听百姓音。', '', 'https://www.qidian.com/book/1048640442/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (10, 'qidian', 'collect', 6, '足球：从逐出拉玛西亚开始登神', '鲨鱼藤椒', '体育·足球运动', 0, 63, '“Leo简直就是这个星球最完美的球星！”“是啊是啊，拉玛西亚天才，巴萨王储，10号球衣，简直就是马拉多纳的最佳继承人...”“嗯，看看他那凶暴的球风和伟岸的身姿！大开大合的推进、暴力长传、炮弹远射、推土机一样的野兽身体、魔鬼铲断、舍我其谁的霸气庆祝...还有天生的领袖气质！他简直无所不能！”“......等等，你说的他妈的是哪个Leo？！”......2011年的那个冬天！当梦三王朝的余晖依然还在', '', 'https://www.qidian.com/book/1048676538/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (11, 'qidian', 'collect', 7, '姐姐，我也要一起当女仆吗？', '电子熊猫', '轻小说·恋爱日常', 0, 71, '【双胞胎】【恋爱日常】高定两万，均订过万，请放心观看~江渝白第一次收租，就撞见了因为没钱交租而对房东苦苦哀求的双胞胎姐妹林见夏：事先说好，还完欠租我们就两清了！林见夏：只是打扫卫生做做饭而已，我才不要穿女仆装！毕业后。林见夏：....喂，江小白，你不会要等着女孩子主动吧？江渝白：哦，其实我喜欢的是你妹妹。林见夏：？------------------------------------------', '', 'https://www.qidian.com/book/1045463939/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (12, 'qidian', 'collect', 8, '让仙门再次伟大', '鹤守月满池', '玄幻·东方玄幻', 0, 53, '“承认吧，你根本无法忍受那些高高在上的修行者。”“他们与我们不同，我们的情感无法共通，我们的逻辑大不相同，共存绝无可能。”王平话音落下，一方巍峨书册徐徐翻开。任你洞天福地，红尘世俗，王侯将相，漫天仙佛，都不过是书中的一道道经卷，是他这位书主的修行资粮。“所以现在是时候了，我们将战斗！”“在人间战斗，在梵国战斗，在清虚天战斗，在每一个矢志抗争的地方战斗！”“哪怕要燃烧大地，焚灭天空。”人群中央，王平', '', 'https://www.qidian.com/book/1049107474/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (13, 'qidian', 'collect', 9, '玄鉴仙族', '季越人', '仙侠·修真文明', 0, 600, '陆江仙熬夜猝死，残魂却附在了一面满是裂痕的青灰色铜镜上，飘落到了浩瀚无垠的修仙世界。凶险难测的大黎山，眉尺河旁小小的村落，一个小家族拾到了这枚镜子，于是传仙道授仙法，开启波澜壮阔的新时代。(家族修仙，不圣母，种田，无系统，群像文)', '', 'https://www.qidian.com/book/1035420986/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (14, 'qidian', 'collect', 10, '以神通之名', '猪心虾仁', '都市·都市异能', 0, 236, '农历3230年大灾变爆发，人类从世界霸主位置跌落，神州成为人类最后的自留地。3255年，武侯陆昭正在接受调查。“按理说，你这个级别的超凡者，还无权调查我。”', '', 'https://www.qidian.com/book/1044896207/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (15, 'qidian', 'collect', 11, '诡秘之主', '爱潜水的乌贼', '玄幻·异世大陆', 0, 446, '诡秘之主动画特别篇已在腾讯视频上播出，欢迎大家前去观看！蒸汽与机械的浪潮中，谁能触及非凡？历史和黑暗的迷雾里，又是谁在耳语？我从诡秘中醒来，睁眼看见这个世界：枪械，大炮，巨舰，飞空艇，差分机；魔药，占卜，诅咒，倒吊人，封印物……光明依旧照耀，神秘从未远离，这是一段“愚者”的传说。', '', 'https://www.qidian.com/book/1010868264/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (16, 'qidian', 'collect', 12, '星河之主', '烽仙', '玄幻·高武世界', 0, 101, '旧历1986年，大战后的人类首次登陆月星，成为新历开端。新历8年，月星人口超过千万，人类诞生第一位星空武者，同年，月星人类开始探索‘原初星’，并建立起第一座星空基地。这是新月和旧土争锋、生命进化不止的未来世界。……新历60年，蓝星旧土，一所武道大专。“月星大开发计划，武道生三不限安保岗，报考比2622:1……。”即将大四的武道生方羽，眉头紧锁，看着屏幕上每天不断刷新的人数：“我可是学校十大优秀大专', '', 'https://www.qidian.com/book/1047654482/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (17, 'qidian', 'collect', 13, '天才只是我的门槛！', '碳烤竹笋', '都市·都市生活', 0, 53, '【无系统+天才+日常+科研+科技+大国腾飞】林东重生回到幼儿时期。一个强大的灵魂，住进一具幼小的身体，会带来什么？答案是：意识突破肉身的桎梏，思维超越身体的极限。从自动识别的激光武器，突破热障可变冲压的无人战机，到一飞冲天直入星空的太空战机……凭借灵魂的视觉，林东一步步打破科技的极限，解放生命的枷锁，突破宇宙的大过滤器。“林东是谁？”“他是人类史上最伟大的天才，是人类星空文明的总设计师，是人类族群', '', 'https://www.qidian.com/book/1048960312/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (18, 'qidian', 'collect', 14, '御兽仙朝：我能设计进化形态', '爱穿女仆装', '仙侠·修真文明', 0, 33, '“在大乾仙朝，一切伟力归于神兽，神兽归于仙朝。官职掌【神兽】，神兽掌【天地权柄】。有的【兽】，先天就仅适合劳作陪伴，再怎么【进化】，也是底层。有的【兽】，生来就注定司掌日月轮转，周天星斗，地府轮回，操控天地权柄，被誉为【神兽】！想获得【神兽】？你只需考上官职，便可鲤鱼跃龙门，掌控那高高在上的神明！”教习如此说道，眸光炯炯有神。罗影望着脑海中的【万兽衍策】，陷入了沉思。“什么叫掌万兽轮回衍道，定众生', '', 'https://www.qidian.com/book/1049348807/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (19, 'qidian', 'collect', 15, '首富从AI浪潮开始', '路大头', '都市·商战职场', 0, 100, '【创业+商战+互联网+人工智能+智商在线】被裁当天，他的眼睛变了。所有人头上都浮着数据面板。HR的补偿方案有两处计算错误——他当场多拿了四万七。前领导身上挂着三个鲜红的WARNING：严重Bug，等级不足未解锁。代码里的bug一眼看穿，合同里的漏洞无处遁形，商业对手的底牌一清二楚。别人创业靠赌，他创业靠开全图。从软件到硬件，从AI到芯片，从孤身一人到商业帝国。AI风口将至。他决定用程序员的方式，把', '', 'https://www.qidian.com/book/1047996831/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (20, 'qidian', 'collect', 16, '夺嫡在嘉靖朝', '夜星月语', '历史·两宋元明', 0, 52, '大明嘉靖二十八年，太子薨，储位空缺，裕景之争，牵扯着无数人的生死荣辱。一边是裕王朱载坖，占长幼之序，拥清流满朝，以祖制为名，被士林奉为理所当然的储君。而另一边的景王朱载圳，有首辅严嵩支持，其门生故吏都在推动其正位东宫，以延续严党的权势。此时张居正、高拱尚在翰林院，胡宗宪、俞大猷、戚继光、赵贞吉、海瑞未登高位，天下大势未定，名臣风骨未显。而一心长生不老的嘉靖皇帝，只是垂下眼帘，在西苑的丹炉青烟中，投', '', 'https://www.qidian.com/book/1039931006/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (21, 'qidian', 'collect', 17, '钢铁，病菌与奥法医生', '李斯特菌', '轻小说·原生幻想', 0, 31, '这是最好的时代，这是最坏的时代。但要莱昂来说，这是最臭的时代。前急诊医生莱昂，现奥法医学唯一毕业生，来到了这个奥法与蒸汽并存的世界。他本打算凭着超前的医学知识和奥法的生产力，顺手客串一回“现代医学之父”。防护学派的护盾术？刚好用来罩出无尘结界。元能学派的燃烧之手？刚好用来消毒手术器械。嬗变学派的物质变换？刚好用来手搓生理盐水。他还遇到了被称作“死眠圣女”的女孩，其双手所触，任何活物都会安然睡去，再', '', 'https://www.qidian.com/book/1049210540/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (22, 'qidian', 'collect', 18, '真实历史游戏：只有我知道剧情', '余弦公式', '游戏·游戏异界', 0, 120, '【高订87000，均订31000的万订作品！品质保证，放心阅读！】“那个叫马谡的思路很清晰嘛，街亭之战胜负手就在山上！连山都不敢占的，都是庸才，根本不足为虑！”“别去斯大林格勒卷了，我刚从西线副本出来，德军的闪电战就是无敌的，苏联那嘎达撑不过三个月！”“滑铁卢？拿破仑的指挥能力肯定是满级的，会输只有一个可能，就是他手下的元帅全是内鬼！”“土木堡决战！五十万对两万，优势在我！大明皇帝可是御驾亲征，一', '', 'https://www.qidian.com/book/1046770618/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (23, 'qidian', 'collect', 19, '夜无疆', '辰东', '玄幻·东方玄幻', 0, 369, '那一天太阳落下再也没有升起…………………', '', 'https://www.qidian.com/book/1040765595/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (24, 'qidian', 'collect', 20, '我的魔法没有上限！', '瑟瑟发抖梨花猫', '奇幻·剑与魔法', 0, 129, '转生成异世界魔法师的泽利尔，获得了可以解锁神级天赋技能的外挂。升到二级，即可从以下天赋技能之中二选一：其一：【法术汹涌】提升魔力上限，提升回蓝速度，提升法术强度，让你的魔法基础如磐石般牢固。“火力！即正义！”其二：【术式天演】能够解析看见的任何魔法术式结构，并将其复现出来化为己用。“你的魔法很不错，不过下一秒就是我的了。”稍加思索，果断选二！从此泽利尔化身偷学狂魔，任何魔法只要一眼，瞬间就能变成自', '', 'https://www.qidian.com/book/1040840487/', '2026-07-13', '2026-07-13 20:27:14');
INSERT INTO `t_ranking_snapshot` VALUES (25, 'fanqie', 'hot_search', 1, '苍陆纪元', '泽宇剑锋', '', 948288, 7, '古“星祇”“灵”爆“灵争”，灵爆封印星，导致则破碎、灵枯竭，残留“寂灭瘴”，崩塌废土，陆裂漂浮块巢穴', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/43085f275f0987d726d8ac06101378a1~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=PQX3StIwRmMqopPkLx4hu58coS8%3D', 'https://fanqienovel.com/page/7587343301011835966', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (26, 'fanqie', 'hot_search', 2, '谁产品？', '二肖戌狗', '', 353424, 2, '互联网厂级产品，精“福”，深谙画饼，毕绝“管”“优级排序”。\n连续班趴憩，醒穿越。穿越反惊慌，识找卡，“故旷”扣资阵肉痛。\n互联网思维（、、敏捷、复盘） 社畜验（糊弄、管），强魔。', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o74330516dcac1859d3dd59ecc0bbe074~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=7G0P5qq7Z2h3vDpYhUJbwziyFNk%3D', 'https://fanqienovel.com/page/7643690295216852030', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (27, 'fanqie', 'hot_search', 3, '圣痕', '迁鸟', '', 530879, 2, '源极北“亡灵灾”席卷陆，团，凋零。\n帝倾尽运，牺牲九官，终灾厄封印“冰冠冰”。\n胜价帝终。\n皇权崩落，式微，陆王林“破碎”。\n，，姆陆际突巨爆炸，诡异空，异侵。\n狱魔皇领七魔王及麾颗魔星，及清狱类', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o7c47c833bd05c928755ec0e4c074c3ff~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=0Z4MMn1B9vGh%2BclwN6j3g3PNfH8%3D', 'https://fanqienovel.com/page/7561045711651867672', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (28, 'fanqie', 'hot_search', 4, '晨曦龙血', '退休农', '', 795552, 1, '品炉，欢迎番茄阅读品，希够喜欢，注，努讲故！', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2od009f73a77da97327ddec8a5c63be33f~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=xldEqcIszF4%2BcfKSLbK86SVsycE%3D', 'https://fanqienovel.com/page/7617799865220729881', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (29, 'fanqie', 'hot_search', 5, '黑科技魔', '枯木松', '', 3320251, 56742, '【枪炮甲+空魔++贵族+】\n（系统，非爽，慢节奏）\n穿越伯爵默·林，醒强空赋，静贵，准备享校园，族派追求冷丽爵继承，。\n保护，改赘运，魔改识，创造独属魔科技，制造魔枪炮，魔甲，虚空飞船……魔科技，仅改运，改整', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o431e1ea3120c93ed82ebbaf62b4b9264~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=7wRLEmbE88nKEbRnj%2BPxEwcdwwY%3D', 'https://fanqienovel.com/page/7400747900034108440', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (30, 'fanqie', 'hot_search', 6, '恶龙典，', '阿姌', '', 541241, 51, '濒恶龙博，《典》底层规则，恶龙制秩序。', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o393a17003a430a0348b47c42b1240428~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=ZsxJqLQfFH2x2zvHLO4%2BNCJ2G50%3D', 'https://fanqienovel.com/page/7624059942441323582', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (31, 'fanqie', 'hot_search', 7, '摸鱼？！', '青阳', '', 1570538, 292, '【幻+慢热+魂穿+单+权谋+争+田】\n（刚评）\n王宇普班族治症早早束。靠谱排，剑魔奇幻异。\n\n完辈梦，稳幸福。令始料未及，算极避免各势扯系，麻烦灾找。\n\n，冰冷残酷梦', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o56872c95eec0228b74042d84f5c51ac0~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=TXi%2B%2Bf4MqyFAk5ViPh3I238xT%2Bw%3D', 'https://fanqienovel.com/page/7403886871463349272', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (32, 'fanqie', 'hot_search', 8, '村，钦救', '落榜术', '', 2815251, 31018, '        【魔幻+系统+慢热+】\n         异，刚刚穿越。\n　　【末逆袭系统载功，推演宿轨迹……】\n　　【六，背井离乡，誓言，莫欺穷。】\n　　【八，尽，誓言，莫欺穷。】\n　　【六五，清剿哥布林，誓言，莫欺穷。】\n　　【七五，衰哥布林。详，末黑潮降临。】\n　　【棺材板震', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o3c4a8bbb380b7438b72ee8a7411a4ea5~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=ZrgtAT1qEBbFqWhwkhwAp8hzqHU%3D', 'https://fanqienovel.com/page/7526841565671590936', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (33, 'fanqie', 'hot_search', 9, '局仙跳，魔导王', '云歌渺渺', '', 4999506, 24538, '罗宁穿越异，徒。\n似乎？\n施需吟唱杖，罗宁需...\n磷火球术、绝零封印术、覆盖岩炮弹、魔改飞剑术、超距投送、超阶禁咒震爆、空坠落、裂术。\n魔导傀儡，型侦查傀儡、空轰炸飞器、基武器攻击台、浮空争堡垒\n魔创造奇迹，识改运。', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o9d02ddc5cdf665a518e85b2ae9ead2c2~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=nCBgDJad3ZKdJhPzJNjtfIXdZBY%3D', 'https://fanqienovel.com/page/7215022633027374120', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (34, 'fanqie', 'hot_search', 10, '骑始巫旅', '喜欢漆柿琦', '', 2611299, 45604, '超越类，纪陈，冒险某疯狂科，量芯片植验。\n验，官突闯，引验室爆炸。\n陈华丽丽穿越异，爵领卫兵收养孤。\n存超凡量异，追求超越类陈，毫犹豫选择追逐量识。\n载：掌握切血脉王，伟阳，微末断崛，终超越切存。', 'https://p3-reading-sign.fqnovelpic.com/novel-pic/p2o540fef5887673941bd402efaf3b82b1e~tplv-resize:225:0.image?lk3s=5b7047ff&x-expires=1784557034&x-signature=Cj%2BUjFSJ2yjM9tYS0cyk5npZ6Xs%3D', 'https://fanqienovel.com/page/7512466263801613374', '2026-07-13', '2026-07-13 22:17:14');
INSERT INTO `t_ranking_snapshot` VALUES (35, 'fanqie', 'new_book', 1, '苍陆纪元', '泽宇世界的重剑无锋', '西方奇幻·玄幻·奇幻仙侠·异世大陆·架空·末日求生·废土', 948288, 7, '远古“星界神祇”与“大地之灵”爆发“灵能战争”，大地之灵自爆封印星界通道，导致世界法则破碎、灵能枯竭，残留“寂灭瘴气”，文明崩塌为废土，大陆分裂为无数漂浮地块与地下巢穴', 'https://p3-novel-sign.byteimg.com/novel-pic/43085f275f0987d726d8ac06101378a1~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=iixTn2Nd8rJBd%2FDs%2Bly89PDgSEM%3D', 'https://fanqienovel.com/page/7587343301011835966', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (36, 'fanqie', 'new_book', 2, '谁说法师不能是个产品经理？', '十二生肖戌狗', '西方奇幻·玄幻·奇幻仙侠·异世大陆·穿越·架空', 353424, 2, '前互联网大厂高级产品经理，精通“996福报”，深谙PPT画饼之道，毕生绝学是“向上管理”和“优先级排序”。\n连续加班72小时后趴在工位小憩，醒来发现穿越了。穿越后的第一反应不是惊慌，而是下意识找打卡机，并因“无故旷工”会扣工资而感到一阵肉痛。\n最后把互联网思维（KPI、OKR、敏捷开发、复盘） 和社畜经验（糊弄学、向上管理），强行应用于魔法世界。', 'https://p3-novel-sign.byteimg.com/novel-pic/p2o74330516dcac1859d3dd59ecc0bbe074~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=YCfB59iaVQEcJmNccfImhQ94s5M%3D', 'https://fanqienovel.com/page/7643690295216852030', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (37, 'fanqie', 'new_book', 3, '光之圣痕', '迁候鸟', '西方奇幻·玄幻·奇幻仙侠·异世大陆·国运·诸天万界·空间', 530879, 2, '一场源自极北之地的“亡灵天灾”席卷大陆，不死军团所过之处，万物凋零。\n帝国倾尽国运，光明教会牺牲了九成神官，才终将灾厄封印于“冰冠冰原”。\n胜利的代价是帝国的终结。\n皇权崩落，教会式微，大陆进入了王国林立的“破碎时代”。\n不过，7000多年后，姆大陆的西方天际突然发生了巨大的爆炸，诡异的空间之门打开，来自异位面的入侵者到来。\n地狱的魔皇带领的七大魔王及其麾下108颗魔星，以及数不清的地狱大军向人类', 'https://p9-novel-sign.byteimg.com/novel-pic/p2o7c47c833bd05c928755ec0e4c074c3ff~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039752&x-signature=EFunsUaGgmSSkmmFOyuAwBnec8I%3D', 'https://fanqienovel.com/page/7561045711651867672', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (38, 'fanqie', 'new_book', 4, '晨曦之龙血战神', '退休的老农民', '西方奇幻·玄幻·奇幻仙侠·重生', 795552, 1, '新作品出炉，欢迎大家前往番茄小说阅读我的作品，希望大家能够喜欢，你们的关注是我写作的动力，我会努力讲好每个故事！', 'https://p6-novel-sign.byteimg.com/novel-pic/p2od009f73a77da97327ddec8a5c63be33f~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=yg9lDF4ZR0f4leUf2i9szt%2BmkPI%3D', 'https://fanqienovel.com/page/7617799865220729881', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (39, 'fanqie', 'new_book', 5, '黑科技魔法师', '枯木松', '西方奇幻·玄幻·穿越·天才·多女主·奇幻仙侠·异世大陆', 3320251, 56742, '【枪炮机甲+空间魔法+天才+贵族+多女】\n（无系统，非爽文，慢节奏）\n穿越成伯爵次子的默里·格林，觉醒了强大的空间天赋，本想做个安静贵公子的他，正准备享受天才学员的校园生活，结果却被家族派去追求高冷美丽的公爵继承人，还被其看中。\n为了保护自己，改变入赘命运，他魔改前世知识，创造出独属于自己的魔法科技，制造出的魔法枪炮，魔法机甲，虚空飞船……这种种魔法科技，不仅改变了自己的命运，还改变了整个世界的命', 'https://p9-novel-sign.byteimg.com/novel-pic/p2o431e1ea3120c93ed82ebbaf62b4b9264~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039752&x-signature=syUg9F6%2BOwdX3c8ZuIyfWvhWFxc%3D', 'https://fanqienovel.com/page/7400747900034108440', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (40, 'fanqie', 'new_book', 6, '恶龙法典，法理', '阿姌', '西方奇幻·玄幻·奇幻仙侠·穿越·重生', 541241, 51, '重生为濒死恶龙的法学博士，用一部《法典》重写世界的底层规则，从恶龙变为制定秩序的法理之神。', 'https://p9-novel-sign.byteimg.com/novel-pic/p2o393a17003a430a0348b47c42b1240428~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=nr52swr9lUh7mzl0CgbNcCNAAjc%3D', 'https://fanqienovel.com/page/7624059942441323582', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (41, 'fanqie', 'new_book', 7, '不让我摸鱼？那你们就都别活了！', '青阳d', '西方奇幻·奇幻仙侠·奇幻·玄幻·架空·异世大陆·穿越·单女主', 1570538, 292, '【西幻+慢热+魂穿+单女主+权谋+战争+种田】\n（刚出评分所以不高）\n一个名叫王宇的普通上班族由于不治之症早早结束了自己的生命。但在一个看着就不太靠谱的神明的安排下，他意外重生到了一个有着剑与魔法的奇幻异世界。\n\n他本想在这个世界完成上辈子的梦想，安稳幸福的度过一生。令人始料未及的是，就算他极力避免和各种势力扯上关系，麻烦和灾难还是一个接一个的找上门来。\n\n然而，这个冰冷而残酷的世界没有他实现梦想', 'https://p6-novel-sign.byteimg.com/novel-pic/p2o56872c95eec0228b74042d84f5c51ac0~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=RplZaPigicpjohKIfXDy6o9Eix4%3D', 'https://fanqienovel.com/page/7403886871463349272', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (42, 'fanqie', 'new_book', 8, '人在新手村，被钦定救世主', '落榜美术生', '西方奇幻·奇幻·玄幻·系统·穿越·奇幻仙侠', 2815251, 31018, '        【西方魔幻+系统+慢热+多女主】\n         人在异界，刚刚穿越。\n　　【末日逆袭系统加载成功，正在推演宿主的人生轨迹……】\n　　【十六岁，你背井离乡，发下誓言，莫欺少年穷。】\n　　【三十八岁，你受尽白眼，发下誓言，莫欺中年穷。】\n　　【六十五岁，你在清剿哥布林，发下誓言，莫欺老年穷。】\n　　【七十五岁，年老体衰的你死于哥布林之手。死后不详，末日黑潮降临。】\n　　【棺材板震动', 'https://p6-novel-sign.byteimg.com/novel-pic/p2o3c4a8bbb380b7438b72ee8a7411a4ea5~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=j6RB0Yj1AWyrzRN4AIso04L1V%2FY%3D', 'https://fanqienovel.com/page/7526841565671590936', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (43, 'fanqie', 'new_book', 9, '开局仙人跳，成为魔导王', '云中歌渺渺', '西方奇幻·奇幻仙侠·奇幻·玄幻·异世大陆·架空·开局·穿越', 4999506, 24538, '罗宁穿越到异世界，成为了一名法师学徒。\n这个世界的法师似乎和自己想的不太一样？\n这里法师施法需要吟唱与法杖，而罗宁却不需要...\n白磷火球术、绝对零度封印术、全覆盖岩炮弹、魔改飞剑术、超远距投送、超阶禁咒日光震爆、天空坠落、大裂解术。\n魔导傀儡，小型无人侦查傀儡、高空轰炸飞行器、天基武器对地攻击平台、浮空战争堡垒\n魔法创造奇迹，知识改变命运。', 'https://p3-novel-sign.byteimg.com/novel-pic/p2o9d02ddc5cdf665a518e85b2ae9ead2c2~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=f2Qr0movtqo8gVaxv%2F%2F9fVwEmk0%3D', 'https://fanqienovel.com/page/7215022633027374120', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (44, 'fanqie', 'new_book', 10, '从骑士开始的巫师之旅', '喜欢漆柿的何琦', '西方奇幻·奇幻·玄幻·穿越·奇幻仙侠·升级流', 2611299, 45604, '为了超越人类，23世纪的陈天，冒险接受了来自某个疯狂科学家的，量子芯片植入实验。\n在实验的最后关头，官方的突然闯入，引发了实验室的大爆炸。\n陈天就这样华丽丽的穿越到异界，成为了一个男爵领地卫兵收养的孤儿。\n在这个存在着超凡力量的异世界，追求超越人类的陈天，毫不犹豫的选择追逐力量与知识。\n在后世的记载中：掌握世间一切真理的血脉之王，伟大的太阳之子，从一个微末的地方不断崛起，最终成为超越一切的存在。', 'https://p3-novel-sign.byteimg.com/novel-pic/p2o540fef5887673941bd402efaf3b82b1e~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784039753&x-signature=dTBhrTG1DswIKvnEAfpy1kzJ5o4%3D', 'https://fanqienovel.com/page/7512466263801613374', '2026-07-13', '2026-07-13 22:35:54');
INSERT INTO `t_ranking_snapshot` VALUES (45, 'qidian', 'pubnewbook', 1, '从火枪手肝成骑士之王', '月下狂风', '奇幻·史诗奇幻', 0, 2, '路西斯穿越类似17世纪的奇幻世界，觉醒爆肝面板。他本想靠火绳枪打猎搞钱，再买个骑士爵位，当个普通富商。但可惜命运弄人，教廷横征暴敛，帝国陷入内战，帮派欺压。深渊魔物重现，灭世风暴来临。为活命，他加入骑士团，成为火枪手。从【剑术（入门)】爆肝到【圣剑，风暴神罚。】从【火铳（入门)】爆肝到【魔铳，地狱业火。】从【枪术（入门)】爆肝到【天枪，圣域辉光。】多年后，率领人类大军驱除末日，成为永世英雄的路西斯', '', 'https://www.qidian.com/book/1049615982/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (46, 'qidian', 'pubnewbook', 2, '星穹实验：人权觉醒第3部', '丁从容', '科幻·星际文明', 0, 2, '这部书，记录的是人类从蒙昧到觉醒、从奴役到自主、从尘埃到星辰的抗争之路；铭记的是无数先烈以生命守护希望、以热血浇灌自由、以灵魂点亮星河的不朽传奇；传递的是无论身处何种绝境，无论面对何等强权，自主意志永不磨灭、自由之火永不熄灭的坚定信念。翻开此书，便是踏入那场横跨银河系的终极抗争，感受灵魂觉醒的震撼，见证文明重生的辉煌。愿每一位读者，都能在星穹之下，守住心中的自由之火，坚守生而为人的尊严与主权，明白', '', 'https://www.qidian.com/book/1049979551/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (47, 'qidian', 'pubnewbook', 3, '如果是这样的相遇', '梦中走出来的人', '轻小说·衍生同人', 0, 3, '（已经准备了70章存稿才开始发，慢热治愈向。有没有人看，其实也没有自信，不过如果都要看下简介再不看的话，是不是简介写多点会好些……如果能写出温暖的故事就好了。）醒来的时候还以为是梦，明明不是名侦探但身体却变得年轻。路上遇见的人的头发和眉眼都是奇异的色彩，网上查到的历史总是有很多的神迹和莫名的天谴。不知道算不算穿越给的能力，除了可以和这里的人无障碍沟通以外，我还可以听懂一些动物的话语，不过和石头就对', '', 'https://www.qidian.com/book/1049981315/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (48, 'qidian', 'pubnewbook', 4, '半岛：黄金之路', 'QWER一套秒', '都市·娱乐明星', 0, 9, '英雄联盟+hy，hyLOL比例73开。后宫，金手指（至臻蝙蝠侠版），无敌流，不喜勿入。女主五六代（炽吒芙爻礼心）。本文另含以下内容，请谨慎观看:张元英柳智敏谁是五女一？金秋天迟到的叛逆期。世纪名曲《O.O》诞生之迷。小爱豆为何总想找我开一局？当太阳升起后，就把前任忘掉吧！（做得到吗？）又名：《被五女一抛弃后我成了世界第一上单》', '', 'https://www.qidian.com/book/1022467032/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (49, 'qidian', 'pubnewbook', 5, '我在宗门当祸害的那些年', '失约笔记', '仙侠·修真文明', 0, 18, '怕死怕到背着一口黑锅修仙的魏平安，进宗门只有一个梦想：长生不老。可混着混着，他发现自己成了全宗最头疼的祸害。对此魏平安很委屈：我真的只想安稳活着，是他们先动手的。', '', 'https://www.qidian.com/book/1049728180/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (50, 'qidian', 'pubnewbook', 6, '开局鸿蒙紫气，我是大宋帝姬', '鸣潮今汐', '仙侠·古典仙侠', 0, 5, '北宋盛世浮华之中，劫数早已暗伏。朝堂六贼当道，粉饰太平；江湖地煞应劫，梁山啸聚；东南方腊借邪法起事，生灵涂炭；北境金国厉兵秣马，凶兽妖氛直逼中原。更有武学世家行走江湖，暗布棋局；修真门派封山闭门，袖手旁观；水府龙族蛰于深泽，静观世变。她本可潜修道法，逍遥世外，却偏选了最险的一条路。抗金兵，守河山，收人杰，以鸿蒙紫气镇万军凶锋，挽天倾于既倒。待到靖康烽烟卷过黄河，金戈铁马兵临城下。世人方才知晓：大宋', '', 'https://www.qidian.com/book/1049885215/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (51, 'qidian', 'pubnewbook', 7, '凡人：开局修炼吞天魔功', '随风飘散的烟', '玄幻·东方玄幻', 0, 8, '穿越凡人修仙传世界，林渊携吞天魔功而来。三灵根资质平平？无妨——吞噬修士精元，修为暴涨；吞噬妖兽本源，肉体增强；吞噬法则碎片，领悟大道，演化混沌体！成就混沌道祖！从青石村凡人起步，拜黄枫谷，入乱星海，偷渡灵界，飞升仙界……一路低调发育，杀伐果断，走出一条吞噬天地的逆天之路。你修时间法则，我吞万物本源。吞天魔功——天地万物，皆为我食！', '', 'https://www.qidian.com/book/1049705859/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (52, 'qidian', 'pubnewbook', 8, '有天赋就能成为球王吗', '呼呼的梨', '体育·足球运动', 0, 2, '2013年，19岁的中甲球员姜云在球队保级关键战中献上助攻，次日，他常年携带的黑色笔记本幻化成FM系统，揭示残酷真相：他的潜力值(PA)被锁死在85。系统只提供潜力提升路径和分析建议，绝不直接加能力。姜云从绝望中奋起，以魔鬼般的努力兑现每一分潜力。他坚守母队江城联，用系统分析队友和对手，率队从中甲杀入中超，入选国家队，踏上世预赛征程。凭借努力和智慧，他一步一步登上更高的舞台。', '', 'https://www.qidian.com/book/1049772357/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (53, 'qidian', 'pubnewbook', 9, '吞噬星空：开局系统绑错人', '舍芯遗魂', '科幻·时空穿梭', 0, 11, '陈阳被狗系统带到吞噬星空世界，却发现绑错了宿主。为了偿还因果，狗系统把陈阳改造成原始宇宙的特殊生命。还扔下五件宝物就自个溜了。', '', 'https://www.qidian.com/book/1049704502/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (54, 'qidian', 'pubnewbook', 10, '无职转生：魔眼是写轮眼', '源林林', '轻小说·衍生同人', 0, 7, '看过《无职转生》的我转生到了这个世界。成了希露菲叶特的义兄，意外带了一双能看穿魔力流动的写轮眼。四岁那年，我第一次牵着绿头发的妹妹走出院子。提前三天去村里空地把自己打成孩子王，然后对那些孩子说——&quot;这是我妹妹。你们不能欺负她。&quot;原作里她没有这样的哥哥。这一次她有。', '', 'https://www.qidian.com/book/1049805596/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (55, 'qidian', 'pubnewbook', 11, '凡人修仙之万道雷尊', '玄衣难渡', '仙侠·幻想修仙', 0, 4, '穿越成《凡人修仙传》落云宗的炮灰冯坤（以动漫中的人物设定为准），却无系统无外挂，唯有凭借原著记忆与现代思维立足修仙界，借先知优势整合宗门资源，自创修行功法，悄然崛起，暗中布局。待韩立现身，结下善缘，顺势拿下各路机缘，踏上独属于自己的仙道巅峰。', '', 'https://www.qidian.com/book/1049928526/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (56, 'qidian', 'pubnewbook', 12, '异世召唤：孤城召群雄星汉铸帝朝', '白沙问道', '历史·架空历史', 0, 6, '星汉帝朝崩塌七百年后，七大皇朝并立，四方外族窥伺，天下再无共主。大汉北疆，靖北王战死，二十二万靖北军崩散。东夷压境，完颜南下，朝廷猜忌，宗室暗害，十四岁的靖北王世子姬昭，被困榆关孤城。城外是敌军铁骑，城内有叛臣内应，辽西粮道断绝，父王旧部四散。危局之中，姬昭觉醒召唤系统。蒙恬整军，萧何定粮，贾诩查暗，赵云破阵，陈到立营，王猛肃政，后羿弯弓镇北疆。从一座将破孤城开始，收残军，复平辽，夺辽西，整北疆，', '', 'https://www.qidian.com/book/1049848147/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (57, 'qidian', 'pubnewbook', 13, '全职法师，莫凡的任务系统', '不喜欢起名', '轻小说·衍生同人', 0, 9, '当本来就天赋逆天的莫凡获得了一个完成任务就能得到奖励的系统，那么会发生什么呢？莫凡：你先别整那么多，这他妈都是什么任务？你让我对着觉醒石喊以太阳之子的身份命令你给我觉醒一个牛逼哄哄的魔法系！系统：你就说你要不要奖励吧？莫凡：你……以太阳之子……', '', 'https://www.qidian.com/book/1046416480/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (58, 'qidian', 'pubnewbook', 14, '诡秘：巫师之旅', '七月的鸦', '轻小说·衍生同人', 0, 8, '刚穿越来的梅林发现自己竟然身处一场奇诡命案现场，甚至还有被恶灵盯上的风险。好不容易获得官方保护的他发现自己被卷入了一系列巧合又危险的事件中。这让梅林不禁感叹道：身为穿越者的我真倒霉啊！！！但当心累的梅林看了眼身前的豪华庄园，想到前不久去过的同事家中，他突然觉得自己好像也不算太倒霉。……这是最好的时代，也是最坏的时代！伟大的梅林阁下，将踏上成为“魔法之神”的道路！PS：《诡秘之主》同人，知识双途径，', '', 'https://www.qidian.com/book/1049864271/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (59, 'qidian', 'pubnewbook', 15, '天物遗命', '七十五代孔', '历史·架空历史', 0, 11, '一个高材生，一支青翠竹。你是来要饭的吧？看我持竹棒打尽天下恶犬，还人间一个清明！！！', '', 'https://www.qidian.com/book/1049735430/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (60, 'qidian', 'pubnewbook', 16, '1936：谍战浦江', '西语东言', '军事·谍战特工', 0, 5, '国安特工高骏，意外穿越到九十年前的烽火年代，正值国土沦丧、民族危亡之际。国家有难，匹夫有责，操戈披甲，众士争先！利用前世的特工技能，高骏寻找地下组织、追查日本间谍，为抗战事业贡献了自己的力量。', '', 'https://www.qidian.com/book/1049922816/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (61, 'qidian', 'pubnewbook', 17, '斗罗绝世：霍雨浩拜师萧炎药尘', '乌月屋', '轻小说·衍生同人', 0, 3, '霍雨浩在与萧炎药尘建立通话面板时，命运已经变成不可预测之舞台。萧炎：居然是个低等位面看完唐三的为人药尘：我药尘从未见过有如此厚颜无耻之人。萧炎：有这么当爹吗？啊？不管了，你先食我一发焰分噬浪尺，你要不死，我再给你一发佛怒火莲。', '', 'https://www.qidian.com/book/1049739196/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (62, 'qidian', 'pubnewbook', 18, '半岛：我不是渣，只是有多重人格', '且疾行', '都市·娱乐明星', 0, 9, '【女主：少女时代、Twice】方宇有一个秘密。他的身体里住着好几个人。上一秒他是江南区谈判桌上的投资人，西装革履，挥金如土。下一秒他就撕掉衬衫骑着摩托冲进贫民窟，对着电话吼&quot;再催我把你头拧下来&quot;。再下一秒，他又站在东国大学讲台上，把少女时代批得体无完肤。重生七年，手握资本，预知未来，他要把韩娱的遗憾一个个改写。结果身体不配合，动不动就切换人格，每次醒来都不知道另外那个&quot', '', 'https://www.qidian.com/book/1049754410/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (63, 'qidian', 'pubnewbook', 19, '冒姓太原王', '阿基米德没有米', '历史·两宋元明', 0, 7182, '宣和六年。所有人都相信，大宋迎来了最好的时代。只有王平知道，他们迎来的是亡国。寒门学子人微言轻？那老子便冒姓太原王氏又如何？世人骂我欺世盗名也好，后世骂我乱臣贼子也罢。我不在乎，我救的从来不是赵宋，而是这天下百姓。如果历史注定是一场悲剧。总该有人替那些无名之人改一个结局。【王平只想事情是它本来该有的样子。】', '', 'https://www.qidian.com/book/1050034876/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (64, 'qidian', 'pubnewbook', 20, '万古债主', '琼徒', '玄幻·东方玄幻', 0, 3, '陆沉只是归墟城里一个小账房。沈家逼他签下一笔假账时，他手里那册破旧账簿忽然多出了一个名字。沈玉楼，欠期二百一十七年。从那天起，陆沉才发现，这世上许多人看着风光，背后却欠着一笔不敢见人的旧账。有人借来的灵根迟迟未还，仙门占着别人的机缘不肯松手。他们有修为，也有靠山。陆沉只有一本账簿。“账可以赖。”“等我找上门的时候，连本带利。”', '', 'https://www.qidian.com/book/1050025655/', '2026-07-13', '2026-07-13 22:53:44');
INSERT INTO `t_ranking_snapshot` VALUES (65, 'fanqie', 'male-1141-hot_search', 1, '必死反派的学院地下城生存指南', '黑暗加鲁鲁兽', '西方奇幻·奇幻·玄幻·多女主·奇幻仙侠·迪化', 622778, 370929, '［日式西幻世界+剑与魔法+多女主+地下城+迪化+爆笑+修罗场］\n　　好消息：穿越到了百合系galgame里的世界，还是唯一一个有帅气立绘的男性角色。\n　　坏消息：穿越成的角色是遭到制作组的恶意，在原作中拥有高达1380张死亡CG的反派角色，格雷格·萨斯。\n　　于是为了逃避各种各样的死亡结局，他只能选择进入了同样充满危险的地下城。\n　　想要靠刚刚得到的外挂，在这里苟到主人公打通大结局，然后走上地表迎', 'https://p6-novel-sign.byteimg.com/novel-pic/p2obb41711418ec9e4e5d48a99468b1bd94~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=XI2rHBWfn6JzMO%2FLOTWPp4Tq%2Bwg%3D', 'https://fanqienovel.com/page/7601032456199736382', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (66, 'fanqie', 'male-1141-hot_search', 2, '领主：我在苦痛世界，养成少女', '嘎嘎乱写', '西方奇幻·奇幻仙侠·奇幻·玄幻·穿越·架空·开局·异世大陆', 3675252, 398568, '【种田+慢热+西幻+多种族+无系统+争霸】\n穿越中世纪，成为一名叫“菲尔德”的贵族。\n得知这个世界，女人有机会觉醒为能力各异，且美貌异常的“神选者”。\n菲尔德还没来得及高兴。\n自己的便宜老爹和美艳后妈，就要送去满是贫穷和怪物的腐化之地开拓！\n更糟糕的是，整个帝国，啊不是，整个世界都烂透了。\n残暴不仁的贵族，崇拜邪祟的恶徒，不可名状的怪物，随处可见的阴谋，并且疯狂迫害自己。\n好好好！这样玩是吧？\n我', 'https://p6-novel-sign.byteimg.com/novel-pic/999c8a1d05578d7aec77def618f7f4e6~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=wd4vhZvpVSPeP4jdH6q3CcaUAgI%3D', 'https://fanqienovel.com/page/7320218217488600126', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (67, 'fanqie', 'male-1141-hot_search', 3, '灰雾之上', '防静电', '西方奇幻·奇幻仙侠·玄幻·架空·穿越', 4457980, 252765, '【诡秘】+【魔药】+【种族】+【文明】\n      百年后我是英雄，经历化为故事，万民赞颂。\n      千年后我是传说，故事化为史诗，代代相传。\n      万年后我是信仰，史诗化为神话，香火不绝。\n\nps.本书别名：灰雾之上\nps.人族发展为背景，偏向个人史诗，不是种田文。\nps.不是完全诡秘流，随着发展，往上会涉及到些许科幻。', 'https://p6-novel-sign.byteimg.com/novel-pic/4b13bc3cabc9c77b885909a994263f16~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=2zN5OFn7JQG6flB9Yk506rTUH5g%3D', 'https://fanqienovel.com/page/7102397782719204385', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (68, 'fanqie', 'male-1141-hot_search', 4, '异世界：我的人生开了挂！', '一条咸鱼c', '西方奇幻·奇幻仙侠·奇幻·玄幻·系统·穿越·升级流', 5936152, 172982, '【吸血鬼，狼人，科技，魔药，鬼怪，生化人，占卜，傀儡，只要是你能想到的所有的可怖元素，这个世界都有。】\n\n林恩穿越到了这么一个诡异的异世界，成为了一个药剂店的学徒。\n\n“这个人他不对啊！给人做手术从来不打麻药！”\n\n“那家是黑店！只要进去没病也给你检查出一堆病来啊！”\n\n“但是不对啊？那家店不是说是方圆百里之内最好的药剂店吗？”\n\n“当然是最好的啊！因为方圆百里之内就只有他这一家店啊！！”\n\n对于', 'https://p9-novel-sign.byteimg.com/novel-pic/e340edb4574feb8218408b87334888c3~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=kq5kzUB8MGGZ%2FDydwUqdO6mWYWM%3D', 'https://fanqienovel.com/page/7080348306596957217', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (69, 'fanqie', 'male-1141-hot_search', 5, '我在西幻世界独断万古', '入机凹凸Man', '西方奇幻·奇幻·玄幻·穿越·奇幻仙侠·异世大陆', 581223, 183249, '【剑与魔法】【奇幻冒险】【半神人】【无系统】【偏日常偏日常偏日常！！！】【多女主(感情线发展的较慢，纯后宫文爱好者慎入)】【龙与史诗】【半步颠文】\n一心证道的网文魔怔人季天穿越到一个剑与魔法的世界。\n“这个世界最强的是谁？”\n“魔王，只有拔出圣剑的勇者才能将其击败。”\n季天微微一笑，“圣剑？此等宝物合该被我炼化！看来我便是那勇者了。”\n……\n“不好啦，魔王大人，又有勇者打过来啦！”\n“又来？这是第', 'https://p9-novel-sign.byteimg.com/novel-pic/p2oa43851f6e825f7d846e4393bb85c385a~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044968&x-signature=XC9C1DZAG5mGNd8ExscGcBZ3cu8%3D', 'https://fanqienovel.com/page/7454632389537451032', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (70, 'fanqie', 'male-1141-hot_search', 6, '早知道不这么玩了！', '洛然123', '西方奇幻·奇幻·玄幻·穿越·奇幻仙侠·异世大陆', 718535, 166817, '【剑与魔法】【奇幻冒险】【无系统】【修罗场】【龙与史诗】\n“养成一个BOSS需要几步？”\n“首先，我们需要找到一个天赋极佳且孤苦无依的幼崽。”\n“然后，要给她无限的温暖与关怀。”\n“最后，死她面前。”\n“哦哟！这个好，这个有意思！”\n一段时间后——\n“卧槽！你也没告诉我游戏通关后会穿进来啊！我现在重玩还来得及吗？”\n\nPS：简介有限，百来个字涵盖不了预计几百万字的书，修罗场也只是其中一个标签，见不', 'https://p3-novel-sign.byteimg.com/novel-pic/p2oacaf243563a30d5bb729f561a08788bc~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=1I%2F7IA%2BIQZoAYzAWj8jY0%2B7bArc%3D', 'https://fanqienovel.com/page/7560536855758785598', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (71, 'fanqie', 'male-1141-hot_search', 7, '西幻：从鹰人部落到天使帝国', '枫潇呀', '西方奇幻·玄幻·奇幻仙侠·无敌·穿越·架空', 3108846, 143986, '【快节奏+爆燃+皇者+从部落到帝国+纪年体西幻史诗+万族+王座登神+诸神争霸+清晰时间线】\n魔神：当你凝视深渊时，深渊也在凝视你！\n姜尤：错了，深渊啊，当你凝视天堂的时候，天堂也在凝视你！\n第一篇章，太古矇昧的时代。\n此时人类还不存在，精灵的先祖还是巨魔，泰坦巨人统治着大地，巨龙统治着天空。\n纪元之末，泰坦巨人和巨龙鏖战大地，两败俱伤。\n地精诸部乘势崛起，计划夺取大陆的统治权。\n此时，一个穿越者降', 'https://p3-novel-sign.byteimg.com/novel-pic/p2o2449088133468139974746cec5cf1bec~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044970&x-signature=duK1JmRnCN50CSnwhFDistTboDg%3D', 'https://fanqienovel.com/page/7362544544950275134', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (72, 'fanqie', 'male-1141-hot_search', 8, '巫师：让你学知识，你杀穿万界？', '沁园春薛', '西方奇幻·奇幻·玄幻·诸天万界·奇幻仙侠·无女主', 416900, 160846, '【巫师】、【诸天战争】、【位面战争】、【无女主】、【杀就完了】\n伊森穿越成侯爵独子，从小锦衣玉食，还有爱自己的父母，你说这日子，得有多爽？\n啥，还觉醒了无限被动系统？\n击杀就能无限解锁被动？\n解锁的被动还一个比一个逆天？\n什么叫长命百岁被动是每生存1日，寿命提高百年？\n什么有叫阎罗之祝被动是每次死亡可耗费1年寿命完美复活？\n什么还叫亚圣的瞩目被动是学习、理解、吸收知识速度提高10000%？\n没关就', 'https://p9-novel-sign.byteimg.com/novel-pic/p2o0add144b8ea40837b8f782ffb7d106f2~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=tUXoQXHmOrk2ytcGLqpLfqJ1H%2B0%3D', 'https://fanqienovel.com/page/7614012789639613502', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (73, 'fanqie', 'male-1141-hot_search', 9, '西幻：我有一本冒险者指南', '快速适应', '西方奇幻·奇幻·玄幻·穿越·奇幻仙侠·异世大陆', 950693, 149061, '【类DND+冒险者+战士+奇幻】\n一名地球的灵魂，意外穿越至剑与魔法的异世界。\n好消息：他有金手指，一本来历不明的《冒险者指南》，只要完成任务，就能获得经验升级，获得专长与属性。\n坏消息：他穿越在一场邪教徒的献祭仪式上，祭品恰好就是他自己。\n没有想象中的波澜壮阔，雷纳托的异界生活并不顺利，刚穿越过来的他，现在的首要目标是先从一群自称是竖琴手的杀人狂的手中逃脱。\n这是一段从零开始的异界人生，就是不知', 'https://p6-novel-sign.byteimg.com/novel-pic/p2o85a775aa92093d87bcea1308cdffce46~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=8ktAN755PFuN3obP0R6nBamQdkE%3D', 'https://fanqienovel.com/page/7581768205408930841', '2026-07-14', '2026-07-14 00:02:50');
INSERT INTO `t_ranking_snapshot` VALUES (74, 'fanqie', 'male-1141-hot_search', 10, '穿越异世界，我能看见经验条', '三条河', '西方奇幻·奇幻·玄幻·穿越·奇幻仙侠·克苏鲁', 1353042, 141260, '【克苏鲁+升级+谨慎+绝望】\n这是一个崩坏的世界，荒漠里的巨虫开始迁徙，深海中的阴影浮上了浅滩，而人类的城市，正在从地基开始腐烂。\n而陆渊穿越进来，得到了视野角落那一行灰白色的小字，看什么涨什么。\n【帝国语：+1】\n【药物学：+0.1】\n无数经验逐渐融入己身，化作养料。\n直到他看见港口城市沉入海底。\n直到他看见一棵血肉巨树破土而出，树冠上悬挂着千百颗呢喃着\"母亲\"的头颅。\n直到他看见那座高塔塔尖那', 'https://p6-novel-sign.byteimg.com/novel-pic/p2oe3dbd74f23fff7ed0b07c46aec9ec74a~tplv-resize:225:300.image?lk3s=191c1ecc&x-expires=1784044969&x-signature=TimSC3Jhp%2Bb4puXqvzHr%2BOl8v0s%3D', 'https://fanqienovel.com/page/7578123553401228350', '2026-07-14', '2026-07-14 00:02:50');

-- ----------------------------
-- Table structure for t_user
-- ----------------------------
DROP TABLE IF EXISTS `t_user`;
CREATE TABLE `t_user`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '用户名',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '邮箱',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '密码(BCrypt)',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '昵称',
  `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '头像URL',
  `signature` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '个性签名',
  `preferred_theme` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'light' COMMENT '偏好主题: light/dark/eye-care',
  `font_size` int NULL DEFAULT 16 COMMENT '字体大小',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态: 0-禁用 1-正常',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'USER' COMMENT '角色: USER-普通用户 ADMIN-管理员',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_username`(`username` ASC) USING BTREE,
  UNIQUE INDEX `uk_email`(`email` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_user
-- ----------------------------
